import { browser } from '$app/environment';
import { untrack } from 'svelte';
import { CONFIG_PREFIX } from '$lib/constants';

const STORAGE_KEY = `${CONFIG_PREFIX}:recent`;
const MAX_RECENT_ITEMS = 15;

function createRecentStore() {
    let items = $state<string[]>([]);

    if (browser) {
        const saved = localStorage.getItem(STORAGE_KEY);
        if (saved) {
            try {
                items = JSON.parse(saved);
            } catch (e) {
                console.error('Failed to parse recent items', e);
            }
        }
    }

    $effect.root(() => {
        $effect(() => {
            if (browser) {
                localStorage.setItem(STORAGE_KEY, JSON.stringify(items));
            }
        });
    });

    return {
        get items() { return items; },
        
        add: (id: string) => {
            untrack(() => {
                // Remove the id if it already exists, then push to the front
                const filtered = items.filter(i => i !== id);
                items = [id, ...filtered].slice(0, MAX_RECENT_ITEMS);
            });
        },

        clear: () => {
            items = [];
        }
    };
}

export const recentStore = createRecentStore();
