<script lang="ts">
  import { resolve } from '$app/paths';
  import { page } from '$app/stores';
  
  import { i18n } from '$lib/i18n';
  import { getStructuredCategories } from '$lib/registry';
  import { APP_VERSION } from '$lib/constants/app';

  import { layoutStore } from '$lib/stores/ui/layout.svelte';

  import { TOOL_ICON_MAP, FallbackIcon } from '$lib/registry';
  import { tooltip } from '$lib/actions/tooltip';
	import { Separator, ButtonIcon } from '$lib/components/ui';
  import { X, Route, ChevronDown } from 'lucide-svelte';
  import { slide } from 'svelte/transition';
  import { cubicOut } from 'svelte/easing';

  export interface SidebarProps {
    isOpen?: boolean;
  }

  let { isOpen = $bindable(false) }: SidebarProps = $props();

  let isActive = $derived((path: string) => $page.url.pathname.startsWith(path));

  let sidebarData = $derived.by(() => {
    return getStructuredCategories().map(category => ({
      ...category,
      translatedCategoryName: i18n.t(category.name),
      tools: category.tools.map(tool => ({
        ...tool,
        Icon: TOOL_ICON_MAP[tool.icon || ''] || FallbackIcon,
        translatedName: i18n.t(tool.name)
      }))
    }));
  });

  let collapsedCategories = $state<Record<string, boolean>>({});

  function toggleCategory(categoryId: string) {
    collapsedCategories[categoryId] = !collapsedCategories[categoryId];
  }
</script>

<aside class={`absolute inset-y-0 left-0 z-30 flex flex-col bg-white/80 dark:bg-gray-900/80 backdrop-blur-xl border-r border-gray-200/60 dark:border-gray-700/50 transition-all duration-300 ease-[cubic-bezier(0.4,0,0.2,1)] ${isOpen ? 'translate-x-0' : '-translate-x-full'} ${layoutStore.mode === 'vertical' ? 'lg:static lg:translate-x-0' : 'hidden'} ${layoutStore.isCollapsed ? 'lg:w-20' : 'w-72 lg:w-72'}`}>
  
  <div class="flex items-center justify-end h-16 px-4 lg:hidden border-b border-gray-100 dark:border-gray-800 shrink-0">
    <ButtonIcon color="gray" class="!p-2" onclick={() => isOpen = false}>
      <X class="w-5 h-5" />
    </ButtonIcon>
  </div>

  <nav class="flex-1 px-3 py-4 lg:pt-4 overflow-y-auto debox-scrollbar">
    {#each sidebarData as category, index (category.id)}
      <div class="mb-6">
        
        {#if layoutStore.isCollapsed}
          <div class="flex justify-center mb-4 {index > 0 ? '' : 'hidden'}">
            <Separator size="8" />
          </div>
        {:else}
          <button 
            class="group w-full flex items-center justify-between px-3 mb-2 text-xs font-semibold text-gray-400 uppercase tracking-wider hover:text-gray-600 dark:hover:text-gray-300 transition-colors"
            onclick={() => toggleCategory(category.id)}
            aria-expanded={!collapsedCategories[category.id]}
          >
            <span class="whitespace-nowrap overflow-hidden text-ellipsis">{i18n.t(category.name)}</span>
            <ChevronDown class={`w-3.5 h-3.5 shrink-0 transition-all duration-300 opacity-0 group-hover:opacity-100 ${collapsedCategories[category.id] ? '-rotate-90' : ''}`} />
          </button>
        {/if}

        {#if !collapsedCategories[category.id] || layoutStore.isCollapsed}
          <div transition:slide={{ duration: 300, easing: cubicOut, axis: 'y' }}>
            <ul class="space-y-1">
              {#each category.tools as tool (tool.id)}
                <li class="relative">
                    <a 
                      use:tooltip={{ position: 'right', content: tool.translatedName, disabled: !layoutStore.isCollapsed }}
                      href={resolve(`/${tool.slug}`)}
                      onclick={() => isOpen = false} 
                      class={`group flex items-center rounded-xl transition-all w-full ${layoutStore.isCollapsed ? 'justify-center p-3' : 'gap-3 px-3 py-2'} ${
                        isActive(`/${tool.slug}`) 
                          ? 'bg-blue-50 text-blue-700 font-medium dark:bg-blue-900/30 dark:text-blue-400' 
                          : 'text-gray-600 hover:bg-gray-100 dark:text-gray-400 dark:hover:bg-gray-800/80'
                      }`}
                    >
                      <tool.Icon class={`w-5 h-5 shrink-0 transition-colors ${isActive(`/${tool.slug}`) ? 'text-blue-600 dark:text-blue-400' : 'text-gray-400 group-hover:text-gray-600 dark:group-hover:text-gray-300'}`} />

                      <span class={`text-sm whitespace-nowrap overflow-hidden transition-all duration-300 ease-[cubic-bezier(0.4,0,0.2,1)] ${
                        layoutStore.isCollapsed 
                          ? 'max-w-0 opacity-0 ml-0' 
                          : 'max-w-[200px] opacity-100 ml-3'
                      }`}>
                          {tool.translatedName}
                      </span>
                    </a>
                </li>
              {/each}
            </ul>
          </div>
        {/if}
      </div>
    {/each}
  </nav>

  <div class={`${layoutStore.isCollapsed ? 'px-2 py-4' : 'p-4'} border-t border-gray-100 dark:border-gray-800 shrink-0 transition-all duration-300`}>
    <div class={`flex items-center text-xs text-gray-400 dark:text-gray-500 whitespace-nowrap overflow-hidden h-[24px] ${layoutStore.isCollapsed ? 'justify-center' : 'justify-between'}`}>
      <a href={resolve('/roadmap')} class={`flex items-center gap-1.5 font-medium transition-colors hover:text-gray-700 dark:hover:text-gray-300 ${isActive('/roadmap') ? 'text-blue-600 dark:text-blue-400' : 'text-gray-500 dark:text-gray-400'} ${layoutStore.isCollapsed ? 'hidden' : ''}`} title={i18n.t('page.roadmap.title')}>
        <Route class="w-3.5 h-3.5" />
        <span>Roadmap</span>
      </a>
      <a href={resolve('/changelog')} class={`font-mono px-1.5 py-0.5 rounded transition-all ${isActive('/changelog') ? 'bg-blue-100 text-blue-700 dark:bg-blue-900/30 dark:text-blue-400' : 'bg-gray-100 text-gray-500 dark:text-gray-400 dark:bg-gray-800 hover:bg-gray-200 dark:hover:bg-gray-700'} ${layoutStore.isCollapsed ? 'text-[10px] truncate max-w-full' : ''}`} title={i18n.t('page.changelog.title')}>{APP_VERSION}</a>
    </div>
  </div>
</aside>