<script lang="ts">
  import { i18n } from '$lib/i18n';
  import { ConverterLayout } from '$lib/components/layout';

  import type { ToolDefinition } from '$lib/types';

  export interface HtmlEntityConverterProps {
    tool: ToolDefinition;
  }

  let { tool }: HtmlEntityConverterProps = $props();

  // Handle Encode function (Convert special characters to Entity)
  function encodeHtml(str: string): string {
    return String(str)
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;')
      .replace(/'/g, '&#39;');
  }

  // Handle Decode function (Using DOMParser to let browser automatically translate all types of Entity)
  function decodeHtml(str: string): string {
    // Check window to avoid error when Svelte running on SSR (Server-Side Rendering)
    if (typeof window === 'undefined') return str;
    
    const doc = new DOMParser().parseFromString(str, 'text/html');
    return doc.documentElement.textContent || '';
  }

  // Handle Process function to pass it into ConverterLayout
  function processHtmlEntity(input: string, mode: 'encode' | 'decode') {
    try {
      if (mode === 'encode') {
        return { value: encodeHtml(input), error: false };
      } else {
        return { value: decodeHtml(input), error: false };
      }
    } catch (e) {
      return { value: i18n.t('tools.htmlEntity.error'), error: true };
    }
  }
</script>

<ConverterLayout {tool} processFn={processHtmlEntity} />