<script lang="ts">
  import { i18n } from '$lib/i18n';
  import SplitWorkspace from '$lib/components/layout/templates/SplitWorkspace.svelte';
  import { MonacoEditor, ButtonIcon } from '$lib/components/ui';
  import { Copy, Trash2, Code2, MonitorPlay, WrapText, Link2, Globe, Server, DoorOpen, Route, Hash, User, Key } from 'lucide-svelte';
  import { copyText } from '$lib/utils/clipboard';
  import { createTool } from '$lib/stores';
  import type { ToolDefinition } from '$lib/types';
  import { smartInputState } from '$lib/utils/smartInput';
  import { onMount } from 'svelte';

  export interface UrlParserProps {
    tool: ToolDefinition;
  }

  let { tool }: UrlParserProps = $props();

  const SAMPLE_URL = "https://admin:password@www.example.com:8080/path/to/resource?search=query&user=1&user=2#hash-section";

  let isFullFrame = $state(false);
  let activeTab = $state<'preview' | 'json'>('preview');
  let wordWrapLeft = $state(true);
  let wordWrapRight = $state(true);

  const propIcons: Record<string, any> = {
    protocol: Globe,
    hostname: Server,
    port: DoorOpen,
    pathname: Route,
    hash: Hash,
    username: User,
    password: Key
  };

  const storage = createTool(tool.slug, {
    input: SAMPLE_URL
  });

  onMount(() => {
    const passedData = smartInputState.consume();
    if (passedData) {
      storage.value.input = passedData;
    }
  });

  let parsedState = $derived.by(() => {
    if (!storage.value.input.trim()) return { value: null, json: '', error: false };
    
    try {
      let urlString = storage.value.input.trim();
      if (!/^https?:\/\//i.test(urlString) && !/^[\w-]+:\/\//i.test(urlString)) {
        urlString = 'http://' + urlString;
      }

      const url = new URL(urlString);
      
      const searchParams: Record<string, string | string[]> = {};
      for (const [key, value] of url.searchParams.entries()) {
        if (searchParams[key]) {
          if (Array.isArray(searchParams[key])) {
            (searchParams[key] as string[]).push(value);
          } else {
            searchParams[key] = [searchParams[key] as string, value];
          }
        } else {
          searchParams[key] = value;
        }
      }

      const parsedObject = {
        href: url.href,
        protocol: url.protocol,
        username: url.username || undefined,
        password: url.password || undefined,
        host: url.host,
        hostname: url.hostname,
        port: url.port || undefined,
        pathname: url.pathname,
        search: url.search || undefined,
        hash: url.hash || undefined,
        searchParams: Object.keys(searchParams).length > 0 ? searchParams : undefined
      };

      const cleanObject = Object.fromEntries(
        Object.entries(parsedObject).filter(([_, v]) => v !== undefined)
      );

      return { 
        value: cleanObject, 
        json: JSON.stringify(cleanObject, null, 4), 
        error: false 
      };
    } catch (e) {
      return { 
        value: null, 
        json: i18n.t('tools.urlParser.error') || '// Invalid URL format', 
        error: true 
      };
    }
  });

  function clearText() {
    storage.value.input = '';
  }
</script>

<SplitWorkspace {tool} bind:isFullFrame>
  {#snippet leftPanel()}
    <div class="flex items-center justify-between px-4 py-2 bg-gray-50 dark:bg-gray-900 border-b border-gray-200 dark:border-gray-800 h-11 shrink-0">
      <span class="flex items-center gap-1.5 text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider">
        <Link2 class="w-3.5 h-3.5" /> URL Input
      </span>
      <div class="flex items-center gap-1">
        <ButtonIcon onclick={() => wordWrapLeft = !wordWrapLeft} color="blue" active={wordWrapLeft} title={wordWrapLeft ? 'Disable Word Wrap' : 'Enable Word Wrap'}>
          <WrapText class="w-4 h-4" />
        </ButtonIcon>
        <ButtonIcon onclick={clearText} disabled={!storage.value.input} color="rose" title={i18n.t('common.clear')}>
          <Trash2 class="w-4 h-4" />
        </ButtonIcon>
      </div>
    </div>
    <div class="flex-1 w-full relative min-h-0">
      <MonacoEditor 
        bind:value={storage.value.input} 
        language="text" 
        wordWrap={wordWrapLeft}
      />
    </div>
  {/snippet}

  {#snippet rightPanel()}
    <div class="flex flex-col h-full bg-white dark:bg-[#1e1e1e]">
      <div class="flex items-center justify-between px-4 py-2 bg-gray-50 dark:bg-gray-900 border-b border-gray-200 dark:border-gray-800 h-11 shrink-0">
        
        <div class="flex space-x-1 bg-gray-200/50 dark:bg-gray-800/50 p-1 rounded-lg">
          <button 
            class="px-3 py-1 text-xs font-medium rounded-md transition-colors {activeTab === 'preview' ? 'bg-white dark:bg-gray-700 shadow-sm text-gray-900 dark:text-gray-100' : 'text-gray-500 hover:text-gray-700 dark:text-gray-400 dark:hover:text-gray-200'}"
            onclick={() => activeTab = 'preview'}
          >
            <span class="flex items-center gap-1.5"><MonitorPlay class="w-3.5 h-3.5" /> Preview</span>
          </button>
          <button 
            class="px-3 py-1 text-xs font-medium rounded-md transition-colors {activeTab === 'json' ? 'bg-white dark:bg-gray-700 shadow-sm text-gray-900 dark:text-gray-100' : 'text-gray-500 hover:text-gray-700 dark:text-gray-400 dark:hover:text-gray-200'}"
            onclick={() => activeTab = 'json'}
          >
            <span class="flex items-center gap-1.5"><Code2 class="w-3.5 h-3.5" /> JSON</span>
          </button>
        </div>
        
        <div class="flex items-center gap-1">
          {#if activeTab === 'json'}
            <ButtonIcon onclick={() => wordWrapRight = !wordWrapRight} color="blue" active={wordWrapRight} title={wordWrapRight ? 'Disable Word Wrap' : 'Enable Word Wrap'}>
              <WrapText class="w-4 h-4" />
            </ButtonIcon>
            <ButtonIcon 
              onclick={() => copyText(parsedState.json)} 
              color="blue"
              title={i18n.t('common.copy')} 
              disabled={parsedState.error}
            >
              <Copy class="w-4 h-4" />
            </ButtonIcon>
          {/if}
        </div>
      </div>

      <div class="flex-1 w-full relative min-h-0">
        {#if activeTab === 'preview'}
          <div class="absolute inset-0 w-full h-full p-4 md:p-6 overflow-y-auto custom-scrollbar bg-white dark:bg-gray-900">
            {#if parsedState.error}
              <div class="flex items-center justify-center h-full text-gray-400 dark:text-gray-500">
                Invalid URL format
              </div>
            {:else if !parsedState.value}
              <div class="flex items-center justify-center h-full text-gray-400 dark:text-gray-500">
                Enter a URL to preview
              </div>
            {:else}
              <div class="max-w-4xl mx-auto space-y-6">
                <!-- Main URL -->
                <div class="bg-gray-50 dark:bg-gray-800/50 rounded-xl p-4 border border-gray-200 dark:border-gray-700 overflow-hidden relative group">
                  <div class="flex items-center justify-between mb-2">
                    <h3 class="flex items-center gap-1.5 text-sm font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider">
                      <Link2 class="w-4 h-4 opacity-70" />
                      Full URL
                    </h3>
                    <button onclick={() => copyText(parsedState.value.href)} class="text-gray-400 hover:text-blue-500 transition-opacity opacity-0 md:group-hover:opacity-100 focus:opacity-100" title={i18n.t('common.copy')}>
                      <Copy class="w-4 h-4" />
                    </button>
                  </div>
                  <a href={parsedState.value.href} target="_blank" class="text-blue-600 dark:text-blue-400 hover:underline block truncate text-lg font-medium" title={parsedState.value.href}>
                    {parsedState.value.href}
                  </a>
                </div>

                <!-- URL Parts -->
                <div>
                  <h3 class="text-sm font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider mb-3">URL Properties</h3>
                  <div class="bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-xl overflow-hidden shadow-sm">
                    <table class="min-w-full divide-y divide-gray-200 dark:divide-gray-700">
                      <tbody class="divide-y divide-gray-200 dark:divide-gray-700">
                        {#each ['protocol', 'hostname', 'port', 'pathname', 'hash', 'username', 'password'] as prop (prop)}
                          {#if parsedState.value[prop]}
                            <tr class="hover:bg-gray-50 dark:hover:bg-gray-800/50 transition-colors group">
                              <td class="px-6 py-3 whitespace-nowrap text-sm font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider w-1/3 lg:w-1/4">
                                <div class="flex items-center gap-2">
                                  <svelte:component this={propIcons[prop]} class="w-4 h-4 text-gray-400 opacity-70" />
                                  {prop}
                                </div>
                              </td>
                              <td class="px-6 py-3 text-sm text-gray-900 dark:text-gray-100 font-mono break-all">
                                <div class="flex justify-between items-start gap-2">
                                  <span>{parsedState.value[prop]}</span>
                                  <button onclick={() => copyText(parsedState.value[prop])} class="text-gray-400 hover:text-blue-500 transition-opacity opacity-0 md:group-hover:opacity-100 focus:opacity-100 shrink-0 mt-0.5" title={i18n.t('common.copy')}>
                                    <Copy class="w-3.5 h-3.5" />
                                  </button>
                                </div>
                              </td>
                            </tr>
                          {/if}
                        {/each}
                      </tbody>
                    </table>
                  </div>
                </div>

                <!-- Search Params -->
                {#if parsedState.value.searchParams}
                  <div>
                    <h3 class="text-sm font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider mb-3">Query Parameters</h3>
                    <div class="bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-xl overflow-hidden shadow-sm">
                      <table class="min-w-full divide-y divide-gray-200 dark:divide-gray-700">
                        <thead class="bg-gray-50 dark:bg-gray-800/80">
                          <tr>
                            <th scope="col" class="px-6 py-3 text-left text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider w-1/3">Key</th>
                            <th scope="col" class="px-6 py-3 text-left text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider">Value</th>
                          </tr>
                        </thead>
                        <tbody class="divide-y divide-gray-200 dark:divide-gray-700">
                          {#each Object.entries(parsedState.value.searchParams) as [key, value] (key)}
                            <tr class="hover:bg-gray-50 dark:hover:bg-gray-800/50 transition-colors group">
                              <td class="px-6 py-3 whitespace-nowrap text-sm font-medium text-gray-900 dark:text-gray-100 font-mono">
                                {key}
                              </td>
                              <td class="px-6 py-3 text-sm text-gray-600 dark:text-gray-300 font-mono break-all">
                                <div class="flex justify-between items-start gap-2">
                                  {#if Array.isArray(value)}
                                    <div class="flex flex-wrap gap-1">
                                      {#each value as v (v)}
                                        <span class="inline-flex items-center px-2 py-0.5 rounded text-xs font-medium bg-blue-100 text-blue-800 dark:bg-blue-900/30 dark:text-blue-300 border border-blue-200 dark:border-blue-800">
                                          {v}
                                        </span>
                                      {/each}
                                    </div>
                                  {:else}
                                    <span>{value}</span>
                                  {/if}
                                  <button 
                                    onclick={() => copyText(Array.isArray(value) ? value.join(',') : value)} 
                                    class="text-gray-400 hover:text-blue-500 transition-opacity opacity-0 md:group-hover:opacity-100 focus:opacity-100 shrink-0 mt-0.5" 
                                    title={i18n.t('common.copy')}
                                  >
                                    <Copy class="w-3.5 h-3.5" />
                                  </button>
                                </div>
                              </td>
                            </tr>
                          {/each}
                        </tbody>
                      </table>
                    </div>
                  </div>
                {/if}
              </div>
            {/if}
          </div>
        {:else}
          <MonacoEditor 
            value={parsedState.json}
            language="json"
            readOnly={true}
            wordWrap={wordWrapRight}
          />
        {/if}
      </div>
    </div>
  {/snippet}
</SplitWorkspace>
