<script lang="ts">
  import { i18n } from '$lib/i18n';
  import SplitWorkspace from '$lib/components/layout/templates/SplitWorkspace.svelte';
  import { createTool } from '$lib/stores';
  import type { ToolDefinition } from '$lib/types';
  import { copyText } from '$lib/utils/clipboard';

  import { Copy, Download, MonitorPlay, Code2, FileCode2, Wand2, Trash2, ZoomIn, ZoomOut, Maximize, Settings2, ChevronDown } from 'lucide-svelte';

  export interface SvgOptimizerProps {
    tool: ToolDefinition;
  }

  let { tool }: SvgOptimizerProps = $props();

  const storage = createTool(tool.slug, {
    input: '',
    options: {
      removeXml: true,
      removeDoctype: true,
      removeComments: true,
      removeMetadata: true,
      removeTitleDesc: true,
      removeEmptyGroups: true,
      minifyOutput: true,
      prettyOutput: false
    }
  });

  let outputSvg = $state('');
  let inputSize = $state(0);
  let outputSize = $state(0);
  let zoom = $state(1);
  let isOptionsOpen = $state(false);
  let optionsContainer: HTMLElement;

  $effect(() => {
    inputSize = new Blob([storage.value.input]).size;
    outputSvg = optimizeSvg(storage.value.input, storage.value.options);
    outputSize = new Blob([outputSvg]).size;
  });

  function optimizeSvg(svg: string, options: any) {
    if (!svg.trim()) return '';
    let result = svg;

    if (options.removeXml) {
      result = result.replace(/<\?xml.*?\?>/gi, '');
    }
    if (options.removeDoctype) {
      result = result.replace(/<!DOCTYPE.*?>/gis, '');
    }
    if (options.removeComments) {
      result = result.replace(/<!--[\s\S]*?-->/g, '');
    }

    try {
      // Use DOMParser for deeper manipulations
      const parser = new DOMParser();
      const doc = parser.parseFromString(result, 'image/svg+xml');
      const isError = doc.querySelector('parsererror');

      if (!isError) {
        if (options.removeMetadata) {
          doc.querySelectorAll('metadata').forEach(el => el.remove());
        }
        if (options.removeTitleDesc) {
          doc.querySelectorAll('title, desc').forEach(el => el.remove());
        }
        if (options.removeEmptyGroups) {
          // Keep removing empty groups until no more are found (nested empty groups)
          let removed;
          do {
            removed = false;
            doc.querySelectorAll('g').forEach(g => {
              if (g.innerHTML.trim() === '' && g.attributes.length === 0) {
                g.remove();
                removed = true;
              }
            });
          } while (removed);
        }
        result = doc.documentElement.outerHTML;
      }
    } catch (e) {
      // Fallback to regex if parsing fails (very rare for XML strings)
      console.warn('SVG parse error', e);
    }

    if (options.prettyOutput) {
      result = formatXml(result);
    } else if (options.minifyOutput) {
      // Remove whitespace between tags, and condense multiple spaces
      result = result.replace(/>\s+</g, '><').replace(/\s{2,}/g, ' ').trim();
    }

    return result;
  }

  function formatXml(xml: string) {
    if (!xml) return '';
    let formatted = '';
    let pad = 0;
    xml = xml.replace(/>\s+</g, '><').replace(/(>)(<)(\/*)/g, '$1\n$2$3');
    xml.split('\n').forEach((node) => {
      let indent = 0;
      if (node.match(/.+<\/\w[^>]*>$/)) {
        indent = 0;
      } else if (node.match(/^<\/\w/)) {
        if (pad !== 0) pad -= 1;
      } else if (node.match(/^<\w[^>]*[^\/]>.*$/)) {
        indent = 1;
      } else {
        indent = 0;
      }
      formatted += '  '.repeat(pad) + node + '\n';
      pad += indent;
    });
    return formatted.trim();
  }

  function downloadSvg() {
    if (!outputSvg) return;
    const blob = new Blob([outputSvg], { type: 'image/svg+xml' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = 'optimized.svg';
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  }

  function formatBytes(bytes: number) {
    if (bytes === 0) return '0 B';
    const k = 1024;
    const sizes = ['B', 'KB', 'MB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
  }

  let savedPercent = $derived(inputSize > 0 ? Math.round(((inputSize - outputSize) / inputSize) * 100) : 0);

</script>

<svelte:window onclick={(e) => {
  if (isOptionsOpen && optionsContainer && !optionsContainer.contains(e.target as Node)) {
    isOptionsOpen = false;
  }
}} />

<SplitWorkspace {tool}>
  {#snippet headerLeftControls()}
    <div class="relative" bind:this={optionsContainer}>
      <div class="flex items-center gap-1.5 bg-gray-100 dark:bg-gray-900/80 p-1 rounded-lg shadow-sm border border-transparent dark:border-gray-800 transition-opacity shrink-0">
        <!-- svelte-ignore a11y_click_events_have_key_events -->
        <!-- svelte-ignore a11y_no_noninteractive_element_interactions -->
        <label 
          class="text-xs font-semibold text-gray-500 dark:text-gray-400 pl-2 cursor-pointer flex items-center gap-1.5 select-none" 
          onclick={() => isOptionsOpen = !isOptionsOpen}
        >
          <Settings2 class="w-3.5 h-3.5" />
          {i18n.t('common.options.label')}
        </label>
        <button 
          onclick={() => isOptionsOpen = !isOptionsOpen}
          class="flex items-center justify-between gap-3 bg-white dark:bg-gray-700 text-gray-900 dark:text-gray-100 text-xs font-medium rounded-md px-2 py-1.5 border-none shadow-sm outline-none cursor-pointer hover:bg-gray-50 dark:hover:bg-gray-600 transition-colors h-[28px] min-w-[100px]"
          title={i18n.t('ui.tooltips.optimizer.options')}
        >
          <span>Configure</span>
          <ChevronDown class="w-3.5 h-3.5 opacity-50 transition-transform duration-200 {isOptionsOpen ? 'rotate-180' : ''}" />
        </button>
      </div>

      {#if isOptionsOpen}
        <div class="absolute top-full left-4 mt-2 w-[240px] bg-white dark:bg-gray-900 rounded-xl border border-gray-200 dark:border-gray-700 shadow-xl z-50 overflow-hidden flex flex-col py-1.5 animate-in fade-in slide-in-from-top-2 duration-200">
           <!-- Title -->
           <div class="px-4 py-1.5 border-b border-gray-100 dark:border-gray-800 mb-1">
             <span class="text-[10px] font-bold uppercase text-gray-400 dark:text-gray-500 tracking-wider">Optimization Rules</span>
           </div>

           <!-- Toggles -->
           <label class="flex items-center justify-between px-4 py-2 hover:bg-gray-50 dark:hover:bg-gray-800 cursor-pointer transition-colors">
             <span class="text-xs font-medium text-gray-700 dark:text-gray-300">{i18n.t('tools.svgOptimizer.removeXml')}</span>
             <input type="checkbox" bind:checked={storage.value.options.removeXml} class="w-3.5 h-3.5 rounded border-gray-300 text-blue-600 focus:ring-blue-500 dark:border-gray-600 dark:bg-gray-700 cursor-pointer" />
           </label>
           <label class="flex items-center justify-between px-4 py-2 hover:bg-gray-50 dark:hover:bg-gray-800 cursor-pointer transition-colors">
             <span class="text-xs font-medium text-gray-700 dark:text-gray-300">{i18n.t('tools.svgOptimizer.removeDoctype')}</span>
             <input type="checkbox" bind:checked={storage.value.options.removeDoctype} class="w-3.5 h-3.5 rounded border-gray-300 text-blue-600 focus:ring-blue-500 dark:border-gray-600 dark:bg-gray-700 cursor-pointer" />
           </label>
           <label class="flex items-center justify-between px-4 py-2 hover:bg-gray-50 dark:hover:bg-gray-800 cursor-pointer transition-colors">
             <span class="text-xs font-medium text-gray-700 dark:text-gray-300">{i18n.t('tools.svgOptimizer.removeComments')}</span>
             <input type="checkbox" bind:checked={storage.value.options.removeComments} class="w-3.5 h-3.5 rounded border-gray-300 text-blue-600 focus:ring-blue-500 dark:border-gray-600 dark:bg-gray-700 cursor-pointer" />
           </label>
           <label class="flex items-center justify-between px-4 py-2 hover:bg-gray-50 dark:hover:bg-gray-800 cursor-pointer transition-colors">
             <span class="text-xs font-medium text-gray-700 dark:text-gray-300">{i18n.t('tools.svgOptimizer.removeMetadata')}</span>
             <input type="checkbox" bind:checked={storage.value.options.removeMetadata} class="w-3.5 h-3.5 rounded border-gray-300 text-blue-600 focus:ring-blue-500 dark:border-gray-600 dark:bg-gray-700 cursor-pointer" />
           </label>
           <label class="flex items-center justify-between px-4 py-2 hover:bg-gray-50 dark:hover:bg-gray-800 cursor-pointer transition-colors">
             <span class="text-xs font-medium text-gray-700 dark:text-gray-300">{i18n.t('tools.svgOptimizer.removeTitleDesc')}</span>
             <input type="checkbox" bind:checked={storage.value.options.removeTitleDesc} class="w-3.5 h-3.5 rounded border-gray-300 text-blue-600 focus:ring-blue-500 dark:border-gray-600 dark:bg-gray-700 cursor-pointer" />
           </label>
           <label class="flex items-center justify-between px-4 py-2 hover:bg-gray-50 dark:hover:bg-gray-800 cursor-pointer transition-colors">
             <span class="text-xs font-medium text-gray-700 dark:text-gray-300">{i18n.t('tools.svgOptimizer.removeEmptyGroups')}</span>
             <input type="checkbox" bind:checked={storage.value.options.removeEmptyGroups} class="w-3.5 h-3.5 rounded border-gray-300 text-blue-600 focus:ring-blue-500 dark:border-gray-600 dark:bg-gray-700 cursor-pointer" />
           </label>
           <div class="my-1 border-t border-gray-100 dark:border-gray-800"></div>
           <label class="flex items-center justify-between px-4 py-2 hover:bg-gray-50 dark:hover:bg-gray-800 cursor-pointer transition-colors">
             <span class="text-xs font-bold text-gray-800 dark:text-gray-200">{i18n.t('tools.svgOptimizer.minifyOutput')}</span>
             <input type="checkbox" bind:checked={storage.value.options.minifyOutput} class="w-3.5 h-3.5 rounded border-gray-300 text-blue-600 focus:ring-blue-500 dark:border-gray-600 dark:bg-gray-700 cursor-pointer" />
           </label>
        </div>
      {/if}
    </div>
  {/snippet}

  {#snippet leftPanel()}
    <div class="flex flex-col h-full bg-slate-50/50 dark:bg-slate-900/40 border-r border-gray-200 dark:border-gray-800">
      
      <!-- Top Half: Text Input -->
      <div class="flex-1 flex flex-col min-h-[40%] relative border-b border-gray-200 dark:border-gray-800">
        <div class="px-4 bg-gray-50 dark:bg-gray-800/50 border-b border-gray-200 dark:border-gray-800 shrink-0 flex items-center justify-between h-[46px]">
          <span class="text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider flex items-center gap-1.5"><FileCode2 class="w-3.5 h-3.5"/> {i18n.t('common.editor.input') || 'Input'}</span>
          <div class="flex items-center gap-2">
            <button 
              onclick={() => { storage.value.options.prettyOutput = !storage.value.options.prettyOutput; }}
              class="flex items-center gap-1.5 px-2.5 py-1.5 text-xs font-medium {storage.value.options.prettyOutput ? 'text-blue-600 dark:text-blue-400 bg-blue-50 dark:bg-blue-900/20 border-blue-200 dark:border-blue-800' : 'text-gray-600 dark:text-gray-300 bg-white dark:bg-gray-800 border-gray-200 dark:border-gray-700'} border rounded-md hover:bg-gray-50 dark:hover:bg-gray-700 transition-colors shadow-sm h-[28px]"
              title={i18n.t('ui.tooltips.optimizer.togglePretty')}
            >
              <Wand2 class="w-3.5 h-3.5" />
              Pretty
            </button>
            <button 
              onclick={() => storage.value.input = ''}
              class="flex items-center gap-1.5 px-2.5 py-1.5 text-xs font-medium text-red-600 dark:text-red-400 bg-white dark:bg-gray-800 border border-red-200 dark:border-red-800/30 rounded-md hover:bg-red-50 dark:hover:bg-red-900/20 transition-colors shadow-sm h-[28px]"
            >
              <Trash2 class="w-3.5 h-3.5" />
              {i18n.t('common.action.clear')}
            </button>
          </div>
        </div>
        <textarea
          bind:value={storage.value.input}
          placeholder={i18n.t('common.form.pasteInput', { format: 'SVG' })}
          class="flex-1 w-full p-4 text-sm font-mono bg-transparent border-none resize-none focus:ring-0 focus:outline-none custom-scrollbar"
          spellcheck="false"
        ></textarea>
      </div>

      <!-- Bottom Half: Code Output -->
      <div class="flex-1 flex flex-col bg-white dark:bg-gray-900 overflow-hidden min-h-[40%]">
        <div class="px-4 bg-gray-50 dark:bg-gray-800/50 border-b border-gray-200 dark:border-gray-800 shrink-0 flex items-center justify-between h-[46px]">
          <span class="text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider flex items-center gap-1.5"><Code2 class="w-3.5 h-3.5"/> {i18n.t('common.editor.output') || 'Output'}</span>
          <div class="flex items-center gap-2">
            <button 
              onclick={() => copyText(outputSvg)}
              class="flex items-center gap-1.5 px-2.5 py-1.5 text-xs font-medium text-gray-600 dark:text-gray-300 bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-md hover:bg-gray-50 dark:hover:bg-gray-700 transition-colors shadow-sm h-[28px]"
            >
              <Copy class="w-3.5 h-3.5" />
              {i18n.t('common.action.copy')}
            </button>
            <button 
              onclick={downloadSvg}
              disabled={!outputSvg}
              class="flex items-center gap-1.5 px-2.5 py-1.5 text-xs font-medium text-white bg-blue-600 rounded-md hover:bg-blue-700 disabled:opacity-50 disabled:hover:bg-blue-600 transition-colors shadow-sm h-[28px]"
            >
              <Download class="w-3.5 h-3.5" />
              {i18n.t('common.action.download')}
            </button>
          </div>
        </div>
        <div class="flex-1 relative">
          <textarea
            value={outputSvg}
            readonly
            placeholder={i18n.t('common.form.outputResult', { format: 'SVG' })}
            class="absolute inset-0 w-full h-full p-4 text-sm font-mono bg-transparent border-none resize-none focus:ring-0 focus:outline-none custom-scrollbar text-gray-600 dark:text-gray-400"
            spellcheck="false"
          ></textarea>
        </div>
      </div>
    </div>
  {/snippet}

  {#snippet rightPanel()}
    <div class="flex flex-col h-full bg-slate-100/50 dark:bg-slate-950/50 relative">
      
      <!-- Preview Header with Stats -->
      <div class="flex items-center justify-between px-4 bg-gray-50 dark:bg-gray-900/50 border-b border-gray-200 dark:border-gray-800 h-[46px] shrink-0">
        <span class="text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider flex items-center gap-1.5"><MonitorPlay class="w-3.5 h-3.5"/> {i18n.t('common.action.preview')}</span>
        
        <div class="flex items-center gap-4">
          <div class="flex flex-col text-right">
            <span class="text-[10px] uppercase font-bold text-gray-400 dark:text-gray-500 leading-none mb-0.5">{i18n.t('tools.svgOptimizer.originalSize')}</span>
            <span class="text-xs font-mono text-gray-700 dark:text-gray-300 leading-none">{formatBytes(inputSize)}</span>
          </div>
          <div class="flex flex-col text-right">
            <span class="text-[10px] uppercase font-bold text-gray-400 dark:text-gray-500 leading-none mb-0.5">{i18n.t('tools.svgOptimizer.optimizedSize')}</span>
            <span class="text-xs font-mono text-emerald-600 dark:text-emerald-400 font-medium leading-none">{formatBytes(outputSize)}</span>
          </div>
          {#if savedPercent > 0}
            <div class="px-2 py-1 rounded bg-emerald-100 dark:bg-emerald-900/30 text-emerald-700 dark:text-emerald-400 text-[10px] font-bold shadow-sm ml-1">
              {savedPercent}% {i18n.t('tools.svgOptimizer.saved')}
            </div>
          {/if}
        </div>
      </div>

      <div class="flex-1 flex flex-col p-4 overflow-hidden min-h-0">
        <!-- Visual Preview Canvas -->
        <div class="flex-1 rounded-xl border border-gray-200 dark:border-gray-800 shadow-sm overflow-hidden bg-[repeating-conic-gradient(#e5e7eb_0%_25%,_#fff_0%_50%)] bg-[length:16px_16px] dark:bg-[repeating-conic-gradient(#1f2937_0%_25%,_#111827_0%_50%)] relative">
          <div class="absolute inset-0 flex items-center justify-center p-4 overflow-auto custom-scrollbar">
            {#if outputSvg}
              <div class="svg-preview-content flex items-center justify-center" style="transform: scale({zoom}); transform-origin: center; transition: transform 0.15s ease-out;">
                {@html outputSvg}
              </div>
            {:else}
              <span class="text-sm text-gray-400 dark:text-gray-600 bg-white/80 dark:bg-black/50 px-3 py-1 rounded-md backdrop-blur-sm">No SVG content</span>
            {/if}
          </div>

          <!-- Zoom Controls -->
          {#if outputSvg}
            <div class="absolute bottom-4 right-4 flex items-center gap-1 bg-white/90 dark:bg-gray-800/90 backdrop-blur-sm p-1.5 rounded-lg border border-gray-200 dark:border-gray-700 shadow-sm">
              <button onclick={() => zoom = Math.max(0.1, zoom - 0.25)} class="p-1 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-md text-gray-600 dark:text-gray-300 transition-colors">
                <ZoomOut class="w-4 h-4" />
              </button>
              <span class="text-xs font-medium w-12 text-center text-gray-700 dark:text-gray-300 font-mono select-none">{Math.round(zoom * 100)}%</span>
              <button onclick={() => zoom = Math.min(5, zoom + 0.25)} class="p-1 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-md text-gray-600 dark:text-gray-300 transition-colors">
                <ZoomIn class="w-4 h-4" />
              </button>
              <div class="w-px h-4 bg-gray-300 dark:bg-gray-600 mx-0.5"></div>
              <button onclick={() => zoom = 1} class="p-1 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-md text-gray-600 dark:text-gray-300 transition-colors" title={i18n.t('ui.tooltips.screen.fit')}>
                <Maximize class="w-3.5 h-3.5" />
              </button>
            </div>
          {/if}
        </div>
      </div>
    </div>
  {/snippet}
</SplitWorkspace>

<style>
  .svg-preview-content {
    width: 100%;
    height: 100%;
  }
  .svg-preview-content :global(svg) {
    max-width: 100%;
    max-height: 100%;
    width: auto;
    height: auto;
  }
