<script lang="ts">
  import { onMount, onDestroy } from 'svelte';
  import { SplitWorkspace } from '$lib/components/layout';
  import { i18n } from '$lib/i18n';
  import type { ToolDefinition } from '$lib/types';
  import { copyText } from '$lib/utils/clipboard';
  import { Copy, RefreshCw, QrCode as QrCodeIcon, Settings, ShieldCheck, Terminal } from 'lucide-svelte';
  import { generateTOTP, getTOTPRemainingSeconds, getTOTPProgress, parseOTPAuthURI, generateOTPAuthURI, base32ToWordArray } from '$lib/utils/otp';
  import QRCodeStyling from 'qr-code-styling';
  import { Modal } from '$lib/components/ui';
  import CryptoJS from 'crypto-js';

  let { tool }: { tool: ToolDefinition } = $props();

  let isFullFrame = $state(false);

  let inputSecret = $state('JBSWY3DPEHPK3PXP');
  let isURI = $state(false);
  
  // OTP Settings
  let algorithm: 'SHA1' | 'SHA256' | 'SHA512' = $state('SHA1');
  let digits: number = $state(6);
  let period: number = $state(30);
  let issuer = $state('DeboxHub');
  let accountName = $state('user@example.com');

  let currentCode = $state('------');
  let prevCode = $state('------');
  let nextCode = $state('------');
  let remainingSeconds = $state(30);
  let progressPercentage = $state(0);

  let debugSecretHex = $state('');
  let debugCounter = $state(0);
  let debugCounterHex = $state('');
  let timerInterval: any;

  let isQrModalOpen = $state(false);
  let qrContainer: HTMLElement;
  let qrCodeGenerator: any;

  function formatCode(code: string) {
    if (code.length === 6) return `${code.slice(0,3)} ${code.slice(3)}`;
    if (code.length === 8) return `${code.slice(0,4)} ${code.slice(4)}`;
    return code;
  }

  function updateOTP() {
    try {
      // Clean up spaces from the secret
      const cleanSecret = inputSecret.replace(/\s+/g, '').toUpperCase();
      
      if (!cleanSecret) {
        currentCode = ''.padStart(digits, '-');
        prevCode = currentCode;
        nextCode = currentCode;
        return;
      }

      if (cleanSecret.startsWith('OTPAUTH://')) {
        isURI = true;
        const parsed = parseOTPAuthURI(inputSecret);
        if (parsed && parsed.type === 'totp') {
          const t = Date.now();
          currentCode = generateTOTP(parsed.secret, parsed.period, parsed.digits, parsed.algorithm, t);
          prevCode = generateTOTP(parsed.secret, parsed.period, parsed.digits, parsed.algorithm, t - parsed.period * 1000);
          nextCode = generateTOTP(parsed.secret, parsed.period, parsed.digits, parsed.algorithm, t + parsed.period * 1000);
          
          algorithm = parsed.algorithm;
          digits = parsed.digits;
          period = parsed.period;
          if (parsed.issuer) issuer = parsed.issuer;
          if (parsed.label) accountName = parsed.label;
        } else {
          currentCode = ''.padStart(digits, '-');
          prevCode = currentCode;
          nextCode = currentCode;
        }
      } else {
        isURI = false;
        const t = Date.now();
        currentCode = generateTOTP(cleanSecret, period, digits, algorithm, t);
        prevCode = generateTOTP(cleanSecret, period, digits, algorithm, t - period * 1000);
        nextCode = generateTOTP(cleanSecret, period, digits, algorithm, t + period * 1000);

        try {
          debugSecretHex = base32ToWordArray(cleanSecret).toString(CryptoJS.enc.Hex).toUpperCase();
          const epoch = Math.floor(Date.now() / 1000);
          debugCounter = Math.floor(epoch / period);
          debugCounterHex = debugCounter.toString(16).padStart(16, '0').toUpperCase();
        } catch(e) {
          debugSecretHex = 'Invalid base32 secret';
          debugCounter = 0;
          debugCounterHex = '0000000000000000';
        }
      }
    } catch (e) {
      currentCode = ''.padStart(digits, '-');
      prevCode = currentCode;
      nextCode = currentCode;
    }
  }

  function tick() {
    remainingSeconds = getTOTPRemainingSeconds(period);
    // Progress goes from 100% to 0%
    progressPercentage = 100 - getTOTPProgress(period);

    // Regenerate code at the start of a new window
    if (remainingSeconds === period) {
      updateOTP();
    }
  }

  function handleInput() {
    updateOTP();
    tick();
  }

  function copyCode() {
    copyText(currentCode);
  }

  async function openQrModal() {
    isQrModalOpen = true;
    
    // Determine the URI
    let uriStr = inputSecret;
    if (!isURI) {
      const cleanSecret = inputSecret.replace(/\s+/g, '').toUpperCase();
      uriStr = generateOTPAuthURI({
        type: 'totp',
        label: accountName,
        secret: cleanSecret,
        issuer: issuer,
        algorithm: algorithm,
        digits: digits,
        period: period
      });
    }

    setTimeout(() => {
      if (!qrCodeGenerator && qrContainer) {
        qrCodeGenerator = new QRCodeStyling({
          width: 250,
          height: 250,
          data: uriStr,
          margin: 0,
          qrOptions: {
            typeNumber: 0,
            mode: 'Byte',
            errorCorrectionLevel: 'M'
          },
          dotsOptions: {
            type: 'rounded',
            color: '#1a1a1a'
          },
          cornersSquareOptions: {
            type: 'extra-rounded',
            color: '#1a1a1a'
          },
          cornersDotOptions: {
            type: 'dot',
            color: '#1a1a1a'
          },
          backgroundOptions: {
            color: '#ffffff'
          }
        });
        qrCodeGenerator.append(qrContainer);
      } else if (qrCodeGenerator) {
        qrCodeGenerator.update({ data: uriStr });
      }
    }, 100);
  }

  onMount(() => {
    updateOTP();
    tick();
    timerInterval = setInterval(tick, 1000); // Check every second for UI, though generation logic handles the exact timing
    
    // A smoother interval for the circular progress bar (100ms)
    setInterval(() => {
      progressPercentage = 100 - getTOTPProgress(period);
    }, 100);
  });

  onDestroy(() => {
    if (timerInterval) clearInterval(timerInterval);
  });

</script>

<SplitWorkspace {tool} bind:isFullFrame>
  
  {#snippet leftPanel()}
    <div class="flex flex-col h-full bg-slate-50/50 dark:bg-slate-900/40 border-r border-gray-200 dark:border-gray-800 overflow-hidden">
      <div class="px-4 py-2 bg-gray-50 dark:bg-gray-900 border-b border-gray-200 dark:border-gray-800 shrink-0 flex items-center justify-between h-11">
        <span class="text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider flex items-center gap-1.5">
          <Settings class="w-3.5 h-3.5"/> Configuration
        </span>
      </div>
      <div class="flex-1 p-5 space-y-4 overflow-y-auto custom-scrollbar">
        <!-- Secret Key Section -->
        <div class="flex flex-col gap-4 bg-white dark:bg-gray-800/50 p-4 rounded-xl border border-gray-200 dark:border-gray-700 shadow-sm">
          <div class="flex flex-col gap-1.5">
            <label for="secret" class="text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider flex items-center gap-1.5">
              Secret Key or otpauth:// URI
            </label>
            <input 
              id="secret"
              type="text" 
              bind:value={inputSecret}
              oninput={handleInput}
              placeholder="e.g. JBSWY3DPEHPK3PXP"
              class="w-full h-9 px-3 bg-gray-50 dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-lg text-sm font-mono focus:ring-2 focus:ring-blue-500 outline-none transition-all placeholder:text-gray-400 placeholder:font-sans"
            />
            <p class="text-xs text-gray-500 dark:text-gray-400">
              Paste your Base32 secret key or full <code>otpauth://</code> provisioning URI.
            </p>
          </div>
        </div>

        <!-- Algorithm Settings Section -->
        {#if !isURI}
          <div class="flex flex-col gap-4 bg-white dark:bg-gray-800/50 p-4 rounded-xl border border-gray-200 dark:border-gray-700 shadow-sm">
            <div class="grid grid-cols-1 md:grid-cols-3 gap-4">
              <div class="flex flex-col gap-1.5">
                <label for="algorithm" class="text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider truncate">Algorithm</label>
                <select id="algorithm" bind:value={algorithm} onchange={handleInput} class="w-full h-9 px-3 bg-gray-50 dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-lg text-sm focus:ring-2 focus:ring-blue-500 outline-none">
                  <option value="SHA1">SHA-1 (Default)</option>
                  <option value="SHA256">SHA-256</option>
                  <option value="SHA512">SHA-512</option>
                </select>
              </div>
              <div class="flex flex-col gap-1.5">
                <label for="digits" class="text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider truncate">Digits</label>
                <select id="digits" bind:value={digits} onchange={handleInput} class="w-full h-9 px-3 bg-gray-50 dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-lg text-sm focus:ring-2 focus:ring-blue-500 outline-none">
                  <option value={6}>6 Digits</option>
                  <option value={8}>8 Digits</option>
                </select>
              </div>
              <div class="flex flex-col gap-1.5">
                <label for="period" class="text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider truncate">Period</label>
                <select id="period" bind:value={period} onchange={handleInput} class="w-full h-9 px-3 bg-gray-50 dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-lg text-sm focus:ring-2 focus:ring-blue-500 outline-none">
                  <option value={15}>15s</option>
                  <option value={30}>30s (Default)</option>
                  <option value={60}>60s</option>
                </select>
              </div>
            </div>
          </div>
        {/if}

        <!-- Technical Details Section -->
        {#if inputSecret.trim()}
          <div class="flex flex-col gap-4 bg-white dark:bg-gray-800/50 p-4 rounded-xl border border-gray-200 dark:border-gray-700 shadow-sm">
            <label class="text-sm font-semibold text-gray-800 dark:text-gray-200 flex items-center gap-1.5">
              <Terminal class="w-4 h-4 text-blue-500" />
              Technical Details
            </label>
            
            <div class="space-y-4">
              <div class="flex flex-col gap-1.5">
                <span class="text-xs font-medium text-gray-500 dark:text-gray-400 uppercase tracking-wider">Secret (Hex)</span>
                <code class="text-sm bg-gray-50 dark:bg-gray-900 px-3 py-2 rounded-lg border border-gray-200 dark:border-gray-700 text-gray-700 dark:text-gray-300 break-all font-mono shadow-sm">
                  {debugSecretHex || '...'}
                </code>
              </div>
              <div class="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div class="flex flex-col gap-1.5">
                  <span class="text-xs font-medium text-gray-500 dark:text-gray-400 uppercase tracking-wider">Iteration (Counter)</span>
                  <code class="text-sm bg-gray-50 dark:bg-gray-900 px-3 py-2 rounded-lg border border-gray-200 dark:border-gray-700 text-gray-700 dark:text-gray-300 font-mono shadow-sm truncate">
                    {debugCounter}
                  </code>
                </div>
                <div class="flex flex-col gap-1.5">
                  <span class="text-xs font-medium text-gray-500 dark:text-gray-400 uppercase tracking-wider">Padded Hex (Message)</span>
                  <code class="text-sm bg-gray-50 dark:bg-gray-900 px-3 py-2 rounded-lg border border-gray-200 dark:border-gray-700 text-gray-700 dark:text-gray-300 font-mono shadow-sm truncate" title={debugCounterHex}>
                    {debugCounterHex}
                  </code>
                </div>
              </div>
            </div>
          </div>
        {/if}
      </div>
    </div>
  {/snippet}

  {#snippet rightPanel()}
    <div class="flex flex-col h-full bg-white dark:bg-gray-900 relative">
      <div class="px-4 py-2 bg-gray-50 dark:bg-gray-900 border-b border-gray-200 dark:border-gray-800 shrink-0 flex items-center justify-between h-11">
        <span class="text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider flex items-center gap-1.5">
          <ShieldCheck class="w-3.5 h-3.5" /> {i18n.t('common.action.preview') || 'Preview'}
        </span>
      </div>
      
      <!-- Output Section -->
      <div class="flex-1 flex flex-col items-center justify-center relative">
      
        <!-- Progress Ring and Code -->
        <div class="relative flex items-center justify-center mb-8">
          <!-- SVG Progress Ring -->
          <svg viewBox="0 0 100 100" class="w-64 h-64 sm:w-80 sm:h-80 transform -rotate-90">
            <!-- Background circle -->
            <circle 
              cx="50" cy="50" r="45" 
              class="stroke-gray-100 dark:stroke-gray-800" 
              stroke-width="4" 
              fill="none" 
            />
            <!-- Progress circle -->
            <circle 
              cx="50" cy="50" r="45" 
              class="stroke-blue-500 transition-all duration-100 ease-linear" 
              stroke-width="4" 
              fill="none" 
              stroke-linecap="round"
              stroke-dasharray="283" 
              stroke-dashoffset={283 - (283 * progressPercentage) / 100}
              style="transform-origin: center;"
            />
          </svg>

          <!-- Centered Code -->
          <div class="absolute inset-0 flex flex-col items-center justify-center text-center">
            <p class="text-gray-500 dark:text-gray-400 font-medium tracking-widest mb-2 uppercase text-xs sm:text-sm">
              {isURI ? accountName : 'Generated Code'}
            </p>
            <div class="text-4xl sm:text-5xl font-black text-gray-900 dark:text-white font-mono tracking-widest mb-4">
              {formatCode(currentCode)}
            </div>
            <div class="flex items-center gap-2 text-blue-600 dark:text-blue-400 font-medium text-sm">
              <RefreshCw class="w-4 h-4 {remainingSeconds === period ? 'animate-spin' : ''}" />
              <span>Refreshes in {remainingSeconds}s</span>
            </div>
          </div>
        </div>

        <!-- Prev & Next Codes -->
        <div class="flex items-center justify-center gap-8 mb-8">
          <div class="flex flex-col items-center">
            <span class="text-[10px] font-bold text-gray-400 dark:text-gray-500 uppercase tracking-widest mb-1">Previous</span>
            <span class="font-mono text-xl font-medium text-gray-400 dark:text-gray-500 line-through decoration-gray-300 dark:decoration-gray-700">{formatCode(prevCode)}</span>
          </div>
          <div class="w-px h-8 bg-gray-200 dark:bg-gray-800"></div>
          <div class="flex flex-col items-center">
            <span class="text-[10px] font-bold text-gray-500 dark:text-gray-400 uppercase tracking-widest mb-1">Next</span>
            <span class="font-mono text-xl font-bold text-gray-600 dark:text-gray-300">{formatCode(nextCode)}</span>
          </div>
        </div>

        <!-- Actions -->
        <div class="flex items-center gap-4">
          <button 
            onclick={copyCode}
            class="flex items-center gap-2 px-6 py-3 bg-blue-600 hover:bg-blue-700 text-white font-medium rounded-xl transition-all active:scale-95 shadow-sm shadow-blue-600/20"
          >
            <Copy class="w-5 h-5" />
            Copy Code
          </button>

          <button 
            onclick={openQrModal}
            class="flex items-center gap-2 px-6 py-3 bg-gray-100 hover:bg-gray-200 dark:bg-gray-800 dark:hover:bg-gray-700 text-gray-700 dark:text-gray-200 font-medium rounded-xl transition-all active:scale-95"
          >
            <QrCodeIcon class="w-5 h-5" />
            Export QR
          </button>
        </div>

      </div>
    </div>
  {/snippet}

</SplitWorkspace>

<Modal bind:isOpen={isQrModalOpen} title="Export Authenticator Account" maxWidth="max-w-md">
  <div class="flex flex-col items-center justify-center py-6">
    <div class="bg-white p-4 rounded-2xl shadow-sm mb-6">
      <div bind:this={qrContainer} class="overflow-hidden rounded-xl"></div>
    </div>
    <h3 class="text-lg font-bold text-gray-900 dark:text-white mb-2">{isURI ? accountName : issuer}</h3>
    <p class="text-gray-500 dark:text-gray-400 text-center text-sm mb-6 px-4">
      Scan this QR code with Google Authenticator, Authy, or any standard 2FA application.
    </p>
  </div>
</Modal>
