// Function to generate random ID for each toast
const generateId = () => Math.random().toString(36).substring(2, 9);

export type ToastType = 'success' | 'error' | 'info';

export interface Toast {
    id: string;
    message: string;
    type: ToastType;
}

function createToastStore() {
    let toasts = $state<Toast[]>([]);

    function addToast(message: string, type: ToastType = 'info', duration: number = 4000) {
        const id = generateId();
        // Add new toast to the beginning of the array
        toasts = [{ id, message, type }, ...toasts];

        // Auto remove after X seconds
        setTimeout(() => {
            removeToast(id);
        }, duration);
    }

    function removeToast(id: string) {
        toasts = toasts.filter(t => t.id !== id);
    }

    return {
        get toasts() { return toasts; },
        success: (msg: string) => addToast(msg, 'success'),
        error: (msg: string) => addToast(msg, 'error'),
        info: (msg: string) => addToast(msg, 'info'),
        remove: removeToast
    };
}

export const toastStore = createToastStore();