<script lang="ts">
  import { i18n } from '$lib/i18n';
  import SplitWorkspace from '$lib/components/layout/templates/SplitWorkspace.svelte';
  import { createTool } from '$lib/stores';
  import type { ToolDefinition } from '$lib/types';
  import { Separator } from '$lib/components/ui';
  import { Lock, Unlock, ShieldAlert, ShieldCheck, Shield, Copy, Terminal } from 'lucide-svelte';

  export interface ChmodCalculatorProps {
    tool: ToolDefinition;
  }

  let { tool }: ChmodCalculatorProps = $props();

  const storage = createTool(tool.slug, {
    owner: { read: true, write: true, execute: false },
    group: { read: true, write: false, execute: false },
    public: { read: true, write: false, execute: false },
    special: { setuid: false, setgid: false, sticky: false },
    recursive: false,
    target: ''
  });

  let octalInput = $state('0644');
  let symbolicInput = $state('-rw-r--r--');

  let isUpdatingFromMatrix = false;
  let isUpdatingFromOctal = false;
  let isUpdatingFromSymbolic = false;

  function calculateOctalFromMatrix() {
    const v = storage.value;
    const special = (v.special.setuid ? 4 : 0) + (v.special.setgid ? 2 : 0) + (v.special.sticky ? 1 : 0);
    const owner = (v.owner.read ? 4 : 0) + (v.owner.write ? 2 : 0) + (v.owner.execute ? 1 : 0);
    const group = (v.group.read ? 4 : 0) + (v.group.write ? 2 : 0) + (v.group.execute ? 1 : 0);
    const pub = (v.public.read ? 4 : 0) + (v.public.write ? 2 : 0) + (v.public.execute ? 1 : 0);
    
    return `0${special}${owner}${group}${pub}`;
  }

  function calculateSymbolicFromMatrix() {
    const v = storage.value;
    let sym = '-';
    sym += v.owner.read ? 'r' : '-';
    sym += v.owner.write ? 'w' : '-';
    if (v.special.setuid) {
      sym += v.owner.execute ? 's' : 'S';
    } else {
      sym += v.owner.execute ? 'x' : '-';
    }

    sym += v.group.read ? 'r' : '-';
    sym += v.group.write ? 'w' : '-';
    if (v.special.setgid) {
      sym += v.group.execute ? 's' : 'S';
    } else {
      sym += v.group.execute ? 'x' : '-';
    }

    sym += v.public.read ? 'r' : '-';
    sym += v.public.write ? 'w' : '-';
    if (v.special.sticky) {
      sym += v.public.execute ? 't' : 'T';
    } else {
      sym += v.public.execute ? 'x' : '-';
    }
    return sym;
  }

  function updateMatrixFromOctal(octalStr: string) {
    const digits = octalStr.padStart(4, '0').slice(-4).split('').map(Number);
    const [special, owner, group, pub] = digits;

    storage.value.special.setuid = (special & 4) !== 0;
    storage.value.special.setgid = (special & 2) !== 0;
    storage.value.special.sticky = (special & 1) !== 0;

    storage.value.owner.read = (owner & 4) !== 0;
    storage.value.owner.write = (owner & 2) !== 0;
    storage.value.owner.execute = (owner & 1) !== 0;

    storage.value.group.read = (group & 4) !== 0;
    storage.value.group.write = (group & 2) !== 0;
    storage.value.group.execute = (group & 1) !== 0;

    storage.value.public.read = (pub & 4) !== 0;
    storage.value.public.write = (pub & 2) !== 0;
    storage.value.public.execute = (pub & 1) !== 0;
  }

  function updateMatrixFromSymbolic(sym: string) {
    if (sym.length < 9) return;
    const s = sym.length === 10 ? sym.slice(1) : sym;
    if (s.length !== 9) return;

    storage.value.owner.read = s[0] === 'r';
    storage.value.owner.write = s[1] === 'w';
    storage.value.owner.execute = s[2] === 'x' || s[2] === 's';
    storage.value.special.setuid = s[2] === 's' || s[2] === 'S';

    storage.value.group.read = s[3] === 'r';
    storage.value.group.write = s[4] === 'w';
    storage.value.group.execute = s[5] === 'x' || s[5] === 's';
    storage.value.special.setgid = s[5] === 's' || s[5] === 'S';

    storage.value.public.read = s[6] === 'r';
    storage.value.public.write = s[7] === 'w';
    storage.value.public.execute = s[8] === 'x' || s[8] === 't';
    storage.value.special.sticky = s[8] === 't' || s[8] === 'T';
  }

  $effect(() => {
    // Watch matrix changes
    JSON.stringify(storage.value.owner);
    JSON.stringify(storage.value.group);
    JSON.stringify(storage.value.public);
    JSON.stringify(storage.value.special);
    
    if (!isUpdatingFromOctal && !isUpdatingFromSymbolic) {
      isUpdatingFromMatrix = true;
      octalInput = calculateOctalFromMatrix();
      symbolicInput = calculateSymbolicFromMatrix();
      setTimeout(() => isUpdatingFromMatrix = false, 0);
    }
  });

  function handleOctalInput(e: Event) {
    const target = e.target as HTMLInputElement;
    const val = target.value.replace(/[^0-7]/g, '');
    target.value = val;
    octalInput = val;
    
    if (val.length >= 3 && val.length <= 4) {
      isUpdatingFromOctal = true;
      updateMatrixFromOctal(val);
      symbolicInput = calculateSymbolicFromMatrix();
      setTimeout(() => isUpdatingFromOctal = false, 0);
    }
  }

  function handleSymbolicInput(e: Event) {
    const target = e.target as HTMLInputElement;
    let val = target.value;
    symbolicInput = val;
    
    if (val.length === 9 || val.length === 10) {
      isUpdatingFromSymbolic = true;
      updateMatrixFromSymbolic(val);
      octalInput = calculateOctalFromMatrix();
      setTimeout(() => isUpdatingFromSymbolic = false, 0);
    }
  }

  function applyPreset(octalStr: string) {
    octalInput = octalStr;
    isUpdatingFromOctal = true;
    updateMatrixFromOctal(octalStr);
    symbolicInput = calculateSymbolicFromMatrix();
    setTimeout(() => isUpdatingFromOctal = false, 0);
  }

  let securityLevel = $derived.by(() => {
    const v = storage.value;
    if (v.public.write || v.public.execute && v.public.read) return 'danger';
    if (v.group.write || v.special.setuid) return 'warning';
    if (v.public.read || v.group.read) return 'moderate';
    return 'secure';
  });

  let terminalCommand = $derived.by(() => {
    const recursive = storage.value.recursive ? '-R ' : '';
    const target = storage.value.target.trim() || '/path/to/folder';
    // Remove leading '0' if it's not a special bit for standard 3-digit chmod
    const finalOctal = octalInput.startsWith('00') ? octalInput.slice(1) : octalInput;
    return `chmod ${recursive}${finalOctal} ${target}`;
  });

  let humanReadable = $derived.by(() => {
    const v = storage.value;
    const result = { owner: '', group: '', public: '' };
    
    const getPerms = (obj: any) => {
      const perms = [];
      if (obj.read) perms.push(i18n.t('tools.chmodCalculator.readDesc'));
      if (obj.write) perms.push(i18n.t('tools.chmodCalculator.writeDesc'));
      if (obj.execute) perms.push(i18n.t('tools.chmodCalculator.executeDesc'));
      
      if (perms.length === 3) return i18n.t('tools.chmodCalculator.all');
      if (perms.length === 0) return i18n.t('tools.chmodCalculator.none');
      return perms.join(` ${i18n.t('tools.chmodCalculator.and')} `);
    };

    result.owner = getPerms(v.owner);
    result.group = getPerms(v.group);
    result.public = getPerms(v.public);

    return result;
  });

  async function copyCommand() {
    try {
      await navigator.clipboard.writeText(terminalCommand);
    } catch (e) {
      console.error(e);
    }
  }
</script>

<SplitWorkspace {tool}>
  {#snippet leftPanel()}
    <div class="flex flex-col h-full bg-slate-50/50 dark:bg-slate-900/40 border-r border-gray-200 dark:border-gray-800 overflow-y-auto custom-scrollbar">
      <div class="p-4 space-y-6 flex-1">
        
        <!-- Quick Presets -->
        <div class="space-y-3">
          <label class="text-xs font-semibold text-gray-700 dark:text-gray-300">{i18n.t('tools.chmodCalculator.presets')}</label>
          <div class="grid grid-cols-4 gap-2">
            <button onclick={() => applyPreset('0600')} class="px-2 py-1.5 bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded text-xs font-mono font-medium hover:border-blue-500 hover:text-blue-600 dark:hover:text-blue-400 transition-colors">600</button>
            <button onclick={() => applyPreset('0644')} class="px-2 py-1.5 bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded text-xs font-mono font-medium hover:border-blue-500 hover:text-blue-600 dark:hover:text-blue-400 transition-colors">644</button>
            <button onclick={() => applyPreset('0755')} class="px-2 py-1.5 bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded text-xs font-mono font-medium hover:border-blue-500 hover:text-blue-600 dark:hover:text-blue-400 transition-colors">755</button>
            <button onclick={() => applyPreset('0777')} class="px-2 py-1.5 bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded text-xs font-mono font-medium hover:border-blue-500 hover:text-blue-600 dark:hover:text-blue-400 transition-colors text-red-500 dark:text-red-400 hover:border-red-500 hover:bg-red-50 dark:hover:bg-red-900/20">777</button>
          </div>
        </div>

        <Separator />

        <!-- Permissions Matrix -->
        <div class="space-y-4">
          <label class="text-xs font-semibold text-gray-700 dark:text-gray-300">{i18n.t('tools.chmodCalculator.permissions')}</label>
          <div class="border border-gray-200 dark:border-gray-700 rounded-lg overflow-hidden bg-white dark:bg-gray-800">
            <table class="w-full text-sm text-left">
              <thead class="bg-gray-50 dark:bg-gray-900/50 text-xs font-semibold text-gray-500 dark:text-gray-400 border-b border-gray-200 dark:border-gray-700">
                <tr>
                  <th class="px-4 py-2"></th>
                  <th class="px-4 py-2 text-center">{i18n.t('tools.chmodCalculator.read')}</th>
                  <th class="px-4 py-2 text-center">{i18n.t('tools.chmodCalculator.write')}</th>
                  <th class="px-4 py-2 text-center">{i18n.t('tools.chmodCalculator.execute')}</th>
                </tr>
              </thead>
              <tbody class="divide-y divide-gray-100 dark:divide-gray-800">
                <!-- Owner -->
                <tr class="hover:bg-gray-50 dark:hover:bg-gray-800/50">
                  <td class="px-4 py-3 font-medium text-gray-900 dark:text-gray-100">{i18n.t('tools.chmodCalculator.owner')}</td>
                  <td class="px-4 py-3 text-center"><input type="checkbox" bind:checked={storage.value.owner.read} class="w-4 h-4 text-blue-600 rounded border-gray-300" /></td>
                  <td class="px-4 py-3 text-center"><input type="checkbox" bind:checked={storage.value.owner.write} class="w-4 h-4 text-blue-600 rounded border-gray-300" /></td>
                  <td class="px-4 py-3 text-center"><input type="checkbox" bind:checked={storage.value.owner.execute} class="w-4 h-4 text-blue-600 rounded border-gray-300" /></td>
                </tr>
                <!-- Group -->
                <tr class="hover:bg-gray-50 dark:hover:bg-gray-800/50">
                  <td class="px-4 py-3 font-medium text-gray-900 dark:text-gray-100">{i18n.t('tools.chmodCalculator.group')}</td>
                  <td class="px-4 py-3 text-center"><input type="checkbox" bind:checked={storage.value.group.read} class="w-4 h-4 text-blue-600 rounded border-gray-300" /></td>
                  <td class="px-4 py-3 text-center"><input type="checkbox" bind:checked={storage.value.group.write} class="w-4 h-4 text-blue-600 rounded border-gray-300" /></td>
                  <td class="px-4 py-3 text-center"><input type="checkbox" bind:checked={storage.value.group.execute} class="w-4 h-4 text-blue-600 rounded border-gray-300" /></td>
                </tr>
                <!-- Public -->
                <tr class="hover:bg-gray-50 dark:hover:bg-gray-800/50">
                  <td class="px-4 py-3 font-medium text-gray-900 dark:text-gray-100">{i18n.t('tools.chmodCalculator.public')}</td>
                  <td class="px-4 py-3 text-center"><input type="checkbox" bind:checked={storage.value.public.read} class="w-4 h-4 text-blue-600 rounded border-gray-300" /></td>
                  <td class="px-4 py-3 text-center"><input type="checkbox" bind:checked={storage.value.public.write} class="w-4 h-4 text-blue-600 rounded border-gray-300" /></td>
                  <td class="px-4 py-3 text-center"><input type="checkbox" bind:checked={storage.value.public.execute} class="w-4 h-4 text-blue-600 rounded border-gray-300" /></td>
                </tr>
              </tbody>
            </table>
          </div>
        </div>

        <!-- Special Bits -->
        <div class="space-y-4">
          <label class="text-xs font-semibold text-gray-700 dark:text-gray-300">{i18n.t('tools.chmodCalculator.specialBits')}</label>
          <div class="flex gap-4">
            <label class="flex items-center gap-2 cursor-pointer group">
              <input type="checkbox" bind:checked={storage.value.special.setuid} class="w-4 h-4 text-purple-600 rounded border-gray-300 focus:ring-purple-500" />
              <span class="text-sm text-gray-700 dark:text-gray-300 group-hover:text-gray-900 dark:group-hover:text-white">{i18n.t('tools.chmodCalculator.setuid')} (4)</span>
            </label>
            <label class="flex items-center gap-2 cursor-pointer group">
              <input type="checkbox" bind:checked={storage.value.special.setgid} class="w-4 h-4 text-purple-600 rounded border-gray-300 focus:ring-purple-500" />
              <span class="text-sm text-gray-700 dark:text-gray-300 group-hover:text-gray-900 dark:group-hover:text-white">{i18n.t('tools.chmodCalculator.setgid')} (2)</span>
            </label>
            <label class="flex items-center gap-2 cursor-pointer group">
              <input type="checkbox" bind:checked={storage.value.special.sticky} class="w-4 h-4 text-purple-600 rounded border-gray-300 focus:ring-purple-500" />
              <span class="text-sm text-gray-700 dark:text-gray-300 group-hover:text-gray-900 dark:group-hover:text-white">{i18n.t('tools.chmodCalculator.sticky')} (1)</span>
            </label>
          </div>
        </div>

        <Separator />

        <!-- Direct Inputs -->
        <div class="flex gap-4">
          <div class="space-y-1.5 flex-1">
            <label class="text-xs font-semibold text-gray-700 dark:text-gray-300">{i18n.t('tools.chmodCalculator.octal')}</label>
            <input type="text" bind:value={octalInput} oninput={handleOctalInput} class="w-full bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-md px-3 py-2 text-sm font-mono focus:ring-2 focus:ring-blue-500 outline-none text-center tracking-widest" maxlength="4" />
          </div>
          <div class="space-y-1.5 flex-1">
            <label class="text-xs font-semibold text-gray-700 dark:text-gray-300">{i18n.t('tools.chmodCalculator.symbolic')}</label>
            <input type="text" bind:value={symbolicInput} oninput={handleSymbolicInput} class="w-full bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-md px-3 py-2 text-sm font-mono focus:ring-2 focus:ring-blue-500 outline-none text-center tracking-widest" maxlength="10" />
          </div>
        </div>

      </div>
    </div>
  {/snippet}

  {#snippet rightPanel()}
    <div class="flex flex-col h-full bg-white dark:bg-gray-900 overflow-hidden relative p-6 gap-6">
      
      <!-- Security Status Dashboard -->
      <div class="flex flex-col items-center justify-center p-8 border border-gray-200 dark:border-gray-800 rounded-xl shadow-sm transition-colors duration-500
        {securityLevel === 'secure' ? 'bg-emerald-50 dark:bg-emerald-900/10' : 
         securityLevel === 'moderate' ? 'bg-blue-50 dark:bg-blue-900/10' : 
         securityLevel === 'warning' ? 'bg-amber-50 dark:bg-amber-900/10' : 
         'bg-red-50 dark:bg-red-900/10'}">
        
        <div class="p-6 rounded-full shadow-inner mb-6 transition-colors duration-500
          {securityLevel === 'secure' ? 'bg-emerald-100 dark:bg-emerald-800/30 text-emerald-600 dark:text-emerald-400' : 
           securityLevel === 'moderate' ? 'bg-blue-100 dark:bg-blue-800/30 text-blue-600 dark:text-blue-400' : 
           securityLevel === 'warning' ? 'bg-amber-100 dark:bg-amber-800/30 text-amber-600 dark:text-amber-400' : 
           'bg-red-100 dark:bg-red-800/30 text-red-600 dark:text-red-400'}">
          {#if securityLevel === 'secure'}
            <ShieldCheck class="w-16 h-16" />
          {:else if securityLevel === 'moderate'}
            <Shield class="w-16 h-16" />
          {:else if securityLevel === 'warning'}
            <Lock class="w-16 h-16" />
          {:else}
            <ShieldAlert class="w-16 h-16 animate-pulse" />
          {/if}
        </div>
        
        <h2 class="text-2xl font-bold text-gray-900 dark:text-gray-100 mb-2">{i18n.t('tools.chmodCalculator.securityLevel')}: {i18n.t(`tools.chmodCalculator.${securityLevel}`)}</h2>
        
        <div class="grid grid-cols-1 gap-2 text-center text-sm mt-4 text-gray-600 dark:text-gray-300">
          <p><span class="font-semibold text-gray-900 dark:text-gray-100">{i18n.t('tools.chmodCalculator.owner')}:</span> {humanReadable.owner === i18n.t('tools.chmodCalculator.none') ? i18n.t('tools.chmodCalculator.cannotDoAnything') : humanReadable.owner}</p>
          <p><span class="font-semibold text-gray-900 dark:text-gray-100">{i18n.t('tools.chmodCalculator.group')}:</span> {humanReadable.group === i18n.t('tools.chmodCalculator.none') ? i18n.t('tools.chmodCalculator.cannotDoAnything') : humanReadable.group}</p>
          <p><span class="font-semibold text-gray-900 dark:text-gray-100">{i18n.t('tools.chmodCalculator.public')}:</span> {humanReadable.public === i18n.t('tools.chmodCalculator.none') ? i18n.t('tools.chmodCalculator.cannotDoAnything') : humanReadable.public}</p>
        </div>
      </div>

      <!-- Terminal Generator -->
      <div class="flex-1 flex flex-col gap-4">
        <h3 class="text-sm font-bold text-gray-900 dark:text-gray-100 flex items-center gap-2">
          <Terminal class="w-4 h-4 text-gray-500" />
          {i18n.t('tools.chmodCalculator.terminalCommand')}
        </h3>
        
        <div class="flex gap-4">
          <label class="flex items-center gap-2 cursor-pointer group">
            <input type="checkbox" bind:checked={storage.value.recursive} class="w-4 h-4 text-blue-600 rounded border-gray-300" />
            <span class="text-sm text-gray-700 dark:text-gray-300">{i18n.t('tools.chmodCalculator.recursive')}</span>
          </label>
          <input type="text" bind:value={storage.value.target} placeholder={i18n.t('tools.chmodCalculator.targetPlaceholder')} class="flex-1 min-w-0 bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-md px-3 py-1.5 text-sm focus:ring-2 focus:ring-blue-500 outline-none" />
        </div>

        <!-- Terminal Output -->
        <div class="relative bg-gray-900 rounded-xl p-4 shadow-inner mt-2 border border-gray-800 font-mono text-sm group overflow-hidden">
          <div class="flex items-center gap-2 mb-3">
            <div class="w-3 h-3 rounded-full bg-red-500"></div>
            <div class="w-3 h-3 rounded-full bg-yellow-500"></div>
            <div class="w-3 h-3 rounded-full bg-green-500"></div>
          </div>
          <div class="flex items-center gap-2 text-green-400 overflow-x-auto custom-scrollbar pb-2">
            <span class="text-blue-400 select-none">$</span>
            <span class="whitespace-nowrap">{terminalCommand}</span>
          </div>
          
          <button 
            onclick={copyCommand}
            class="absolute top-4 right-4 p-2 bg-gray-800/80 hover:bg-gray-700 text-gray-400 hover:text-white rounded-md transition-colors opacity-0 group-hover:opacity-100"
            title="Copy Command"
          >
            <Copy class="w-4 h-4" />
          </button>
        </div>
      </div>

    </div>
  {/snippet}

</SplitWorkspace>
