export interface ShellToken {
  text: string;
  type: 'command' | 'flag' | 'argument' | 'operator';
  explanations: Array<{ flag: string; desc: string }>;
}

import shellCommandsRaw from '$lib/data/shell_commands.json';
const shellCommands = shellCommandsRaw as Record<string, { desc: string, url: string, flags: Record<string, string> }>;

export function parseShellCommand(input: string): ShellToken[] {
  if (!input || !input.trim()) return [];
  
  // Basic tokenization respecting quotes
  // Regex to split by spaces but keep quoted strings together
  const regex = /[^\s"']+|"([^"]*)"|'([^']*)'/g;
  let match;
  const rawTokens: string[] = [];
  
  while ((match = regex.exec(input)) !== null) {
    rawTokens.push(match[0]);
  }
  
  if (rawTokens.length === 0) return [];

  const result: ShellToken[] = [];
  
  let baseCommand = rawTokens[0];
  let cmdDb = shellCommands[baseCommand];

  result.push({
    text: baseCommand,
    type: 'command',
    explanations: cmdDb ? [{ flag: baseCommand, desc: cmdDb.desc }] : []
  });

  for (let i = 1; i < rawTokens.length; i++) {
    const token = rawTokens[i];
    
    // Check if it's an operator
    if (['|', '>', '>>', '<', '&&', '||', ';'].includes(token)) {
      const operatorDesc = getOperatorDesc(token);
      result.push({
        text: token,
        type: 'operator',
        explanations: [{ flag: token, desc: operatorDesc }]
      });
      
      // If it's a pipe, the next token is likely a new command
      if (token === '|' && i + 1 < rawTokens.length) {
         let nextToken = rawTokens[i+1];
         let nextCmdDb = shellCommands[nextToken];
         result.push({
            text: nextToken,
            type: 'command',
            explanations: nextCmdDb ? [{ flag: nextToken, desc: nextCmdDb.desc }] : []
         });
         baseCommand = nextToken;
         cmdDb = nextCmdDb;
         i++; // skip next token
      }
      continue;
    }
    
    // Check if it's a flag
    if (token.startsWith('-') && token !== '-') {
      const explanations: {flag: string, desc: string}[] = [];
      
      if (token.startsWith('--')) {
        // Long flag
        const baseFlag = token.split('=')[0]; // handle --flag=value
        if (cmdDb && cmdDb.flags[baseFlag]) {
          explanations.push({ flag: baseFlag, desc: cmdDb.flags[baseFlag] });
        } else {
          explanations.push({ flag: token, desc: 'Unknown flag' });
        }
      } else {
        // Short flag(s) - could be combined like -xzvf
        // Check if exact match first (like docker -it)
        if (cmdDb && cmdDb.flags[token]) {
           explanations.push({ flag: token, desc: cmdDb.flags[token] });
        } else {
           // Break down into individual chars
           const chars = token.substring(1).split('');
           chars.forEach(char => {
             const singleFlag = '-' + char;
             if (cmdDb && cmdDb.flags[singleFlag]) {
               explanations.push({ flag: singleFlag, desc: cmdDb.flags[singleFlag] });
             } else {
               explanations.push({ flag: singleFlag, desc: 'Unknown flag' });
             }
           });
        }
      }
      
      result.push({
        text: token,
        type: 'flag',
        explanations
      });
      continue;
    }
    
    // Otherwise it's an argument
    result.push({
      text: token,
      type: 'argument',
      explanations: []
    });
  }

  return result;
}

function getOperatorDesc(op: string): string {
  switch (op) {
    case '|': return "Pipe: Passes the output of the previous command to the next command.";
    case '>': return "Redirect stdout: Overwrites the file with output.";
    case '>>': return "Redirect stdout: Appends output to the file.";
    case '<': return "Redirect stdin: Reads input from the file.";
    case '&&': return "Logical AND: Runs the next command only if the previous command succeeds.";
    case '||': return "Logical OR: Runs the next command only if the previous command fails.";
    case ';': return "Command separator: Runs the next command regardless of success or failure.";
    default: return "Shell operator";
  }
}
