<script lang="ts">
  import { resolve } from '$app/paths';
  import { page } from '$app/stores';
  import { i18n } from '$lib/i18n';
  import { layoutStore } from '$lib/stores/ui/layout.svelte';
  import { APP_VERSION } from '$lib/constants/app';

	import { Separator } from '$lib/components/ui';

  import { SOCIAL_LINKS } from '$lib/constants/social';


  const activeSocials = SOCIAL_LINKS
    .filter(social => social.enabled && social.placements?.includes('footer'))
    .sort((a, b) => a.order - b.order);

  const currentYear = new Date().getFullYear();

  let isChangelogActive = $derived($page.url.pathname.startsWith(resolve('/changelog')));
  let isActive = $derived((path: string) => $page.url.pathname.startsWith(resolve(path)));
</script>

<footer class="py-4 transition-colors">
  <div class="flex flex-col sm:flex-row items-center justify-between gap-4 text-sm text-gray-500 dark:text-gray-400">
    <div class="flex items-center gap-2">
      {#if layoutStore.mode === 'horizontal'}
        <a href={resolve('/changelog')} class={`font-mono text-[10px] px-1.5 py-0.5 rounded transition-colors ${isChangelogActive ? 'bg-blue-100 text-blue-700 dark:bg-blue-900/30 dark:text-blue-400' : 'bg-gray-100 dark:bg-gray-800 hover:bg-gray-200 dark:hover:bg-gray-700'}`} title={i18n.t('page.changelog.title')}>{APP_VERSION}</a>
        <Separator orientation="vertical" size="4" class="hidden sm:block" />
      {/if}
      <p>
        <span class="font-medium text-gray-700 dark:text-gray-300">{i18n.t('app.name')}</span>
        &copy; {currentYear}. {i18n.t('common.ui.allRightsReserved')}
      </p>
    </div>

    <div class="flex items-center gap-5">
      <div class="flex items-center gap-3">
        {#each activeSocials as social (social.id)}
          {@const Icon = social.icon}
          
          <a 
            href={social.url} 
            target={social.isExternal ? "_blank" : "_self"} 
            rel={social.isExternal ? "noopener noreferrer" : ""}
            class="text-gray-400 hover:text-gray-900 dark:text-gray-500 dark:hover:text-gray-100 transition-colors focus:outline-none"
            title={social.name}
            aria-label={social.ariaLabel || social.name}
          >
            <Icon class="w-5 h-5" />
          </a>
        {/each}
      </div>

      {#if activeSocials.length > 0}
        <Separator orientation="vertical" size="6" class="hidden sm:block -ml-px" />
      {/if}

      <a href={resolve('/about')} class="transition-colors {isActive('/about') ? 'text-blue-600 dark:text-blue-400 font-medium' : 'hover:text-gray-900 dark:hover:text-gray-100'}">{i18n.t('page.about.title')}</a>
      <a href={resolve('/privacy')} class="transition-colors {isActive('/privacy') ? 'text-blue-600 dark:text-blue-400 font-medium' : 'hover:text-gray-900 dark:hover:text-gray-100'}">{i18n.t('page.privacy.title')}</a>
      <a href={resolve('/terms')} class="transition-colors {isActive('/terms') ? 'text-blue-600 dark:text-blue-400 font-medium' : 'hover:text-gray-900 dark:hover:text-gray-100'}">{i18n.t('page.terms.title')}</a>
    </div>
  </div>
</footer>