<script lang="ts">
	import type { Snippet } from 'svelte';

	interface Props {
		active?: boolean;
		color?: 'amber' | 'blue' | 'rose' | 'gray' | 'green' | 'purple' | 'custom';
		class?: string;
		title?: string;
		href?: string;
		disabled?: boolean;
		onclick?: (e: MouseEvent) => void;
		children?: Snippet;
		[key: string]: unknown;
	}

	let {
		active = false,
		color = 'gray',
		class: className = '',
		title,
		href,
		disabled = false,
		onclick,
		children,
		...rest
	}: Props = $props();

	const colorStyles = {
		amber: {
			active: 'text-amber-500 hover:text-amber-600',
			inactive: 'text-gray-400 hover:text-amber-500',
			bgHover: 'hover:bg-amber-50 dark:hover:bg-amber-900/30'
		},
		blue: {
			active: 'text-blue-500 hover:text-blue-600',
			inactive: 'text-gray-400 hover:text-blue-500',
			bgHover: 'hover:bg-blue-50 dark:hover:bg-blue-900/30'
		},
		rose: {
			active: 'text-rose-500 hover:text-rose-600',
			inactive: 'text-gray-400 hover:text-rose-500',
			bgHover: 'hover:bg-rose-50 dark:hover:bg-rose-900/30'
		},
		gray: {
			active: 'text-gray-700 dark:text-gray-200 hover:text-gray-900 dark:hover:text-white',
			inactive: 'text-gray-400 hover:text-gray-700 dark:hover:text-gray-200',
			bgHover: 'hover:bg-gray-100 dark:hover:bg-gray-800'
		},
		green: {
			active: 'text-green-500 hover:text-green-600',
			inactive: 'text-gray-400 hover:text-green-500',
			bgHover: 'hover:bg-green-50 dark:hover:bg-green-900/30'
		},
		purple: {
			active: 'text-purple-500 hover:text-purple-600',
			inactive: 'text-gray-400 hover:text-purple-500',
			bgHover: 'hover:bg-purple-50 dark:hover:bg-purple-900/30'
		},
		custom: {
			active: '',
			inactive: '',
			bgHover: ''
		}
	};

	let currentState: 'active' | 'inactive' = $derived(active ? 'active' : 'inactive');
	let colorConfig = $derived(colorStyles[color]);
	let disabledClass = $derived(disabled ? 'opacity-30 hover:bg-transparent cursor-not-allowed' : '');
</script>

{#if href}
	<!-- svelte-ignore a11y_consider_explicit_label -->
	<a
		{href}
		{title}
		class="p-1.5 rounded-lg transition-all {colorConfig.bgHover} {colorConfig[currentState]} {disabledClass} {className}"
		{onclick}
		{...rest}
	>
		{@render children?.()}
	</a>
{:else}
	<!-- svelte-ignore a11y_consider_explicit_label -->
	<button
		{title}
		{disabled}
		class="p-1.5 rounded-lg transition-all {colorConfig.bgHover} {colorConfig[currentState]} {disabledClass} {className}"
		{onclick}
		{...rest}
	>
		{@render children?.()}
	</button>
{/if}
