<script lang="ts">
  import { i18n } from '$lib/i18n';
  import { ConverterLayout } from '$lib/components/layout';

  import type { ToolDefinition } from '$lib/types';

  export interface Base64ConverterProps {
    tool: ToolDefinition;
  }

  let { tool }: Base64ConverterProps = $props();

  function processBase64(input: string, mode: string) {
    try {
      if (mode === 'encode') {
        const bytes = new TextEncoder().encode(input);
        const binString = Array.from(bytes, (byte) => String.fromCharCode(byte)).join('');
        return { value: btoa(binString), error: false };
      } else {
        const binString = atob(input);
        const bytes = new Uint8Array(binString.length);
        for (let i = 0; i < binString.length; i++) {
          bytes[i] = binString.charCodeAt(i);
        }
        return { value: new TextDecoder().decode(bytes), error: false };
      }
    } catch (e) {
      return { value: i18n.t('tools.base64.error'), error: true };
    }
  }
</script>

<ConverterLayout
  {tool}
  processFn={processBase64}
/>