<script lang="ts">
	import { resolve } from '$app/paths';

	import { i18n } from '$lib/i18n';
	import type { RoadmapItem } from '$lib/types';
	import { categories } from '$lib/registry/categories';
	import { TOOL_ICON_MAP, FallbackIcon } from '$lib/registry/icons';
	import { roadmapStore } from '$lib/stores/roadmap.svelte';

	import { Separator, Badge, ButtonReaction } from '$lib/components/ui';

	import { Heart, ArrowRight } from 'lucide-svelte';

	let { item }: { item: RoadmapItem } = $props();

	// Resolve category info
	let category = $derived(categories.find((c) => c.id === item.categoryId));
	let categoryName = $derived(category ? i18n.t(category.name) : 'Tool');

	let DynamicIcon = $derived(TOOL_ICON_MAP[item.icon || 'Box'] || FallbackIcon);

	// Attempt to translate tool names/descriptions if they look like i18n keys
	let title = $derived(item.name.includes('.') ? i18n.t(item.name) : item.name);
	let description = $derived(
		item.description
			? item.description.includes('.')
				? i18n.t(item.description)
				: item.description
			: ''
	);

	// Status-based styles
	let isReleased = $derived(item.status === 'released');
	let isInProgress = $derived(item.status === 'in-progress');

	// Upvote logic
	let hasUpvoted = $derived(roadmapStore.hasUpvoted(item.id));
	let displayVotes = $derived((item.votes !== undefined ? item.votes : 0) + (hasUpvoted ? 1 : 0));

	function handleUpvote(e: MouseEvent) {
		e.preventDefault();
		roadmapStore.toggleUpvote(item.id);
	}
</script>

<svelte:element
	this={isReleased ? 'a' : 'div'}
	href={isReleased ? resolve('/' + item.slug) : undefined}
	class="group relative flex flex-col gap-4 overflow-hidden rounded-2xl border border-gray-200 bg-white/50 p-5 shadow-sm backdrop-blur-xl transition-all hover:-translate-y-1 hover:shadow-md dark:border-gray-800 dark:bg-gray-900/50"
>
	<!-- Card Header -->
	<div class="flex items-start justify-between gap-4">
		<div
			class="relative flex h-10 w-10 shrink-0 items-center justify-center rounded-xl border border-gray-100 bg-gradient-to-br from-white to-gray-50 shadow-sm dark:border-gray-800 dark:from-gray-800 dark:to-gray-900"
		>
			<DynamicIcon class="h-5 w-5 text-gray-700 dark:text-gray-300" />
			{#if isInProgress}
				<span class="absolute -left-1 -top-1 flex h-2.5 w-2.5">
					<span
						class="absolute inline-flex h-full w-full animate-ping rounded-full bg-blue-400 opacity-75"
					></span>
					<span class="relative inline-flex h-2.5 w-2.5 rounded-full bg-blue-500 ring-2 ring-white dark:ring-gray-900"></span>
				</span>
			{/if}
		</div>
		<div class="flex flex-col items-end gap-2">
			<div class="flex items-center gap-2">
				<!-- Category Badge -->
				<Badge variant={category?.slug === 'design' ? 'purple' : category?.slug === 'security' ? 'green' : 'blue'}>
					{categoryName}
				</Badge>
				{#if isReleased && item.version}
					<!-- Version Badge -->
					<Badge variant="gray">
						{item.version}
					</Badge>
				{/if}
			</div>
		</div>
	</div>

	<!-- Content -->
	<div class="flex-1">
		<h3 class="font-semibold text-gray-900 dark:text-gray-100">{title}</h3>
		<p class="mt-1 line-clamp-2 min-h-[40px] text-sm leading-5 text-gray-500 dark:text-gray-400">
			{description}
		</p>
	</div>

	<Separator />

	<!-- Footer -->
	<div class="mt-auto flex items-center justify-between">
		<div class="text-xs font-medium text-gray-500 dark:text-gray-400 {item.date ? 'cursor-help' : ''}" title={item.date || undefined}>
			{#if isReleased}
				<span class="text-green-600 dark:text-green-400">
					{i18n.t('page.roadmap.status.released')}{item.date ? `: ${item.date}` : ''}
				</span>
			{:else if item.expectedRelease}
				<span>{i18n.t('page.roadmap.status.planned')}{item.expectedRelease}</span>
			{:else}
				<span>{i18n.t('page.roadmap.status.noSchedule')}</span>
			{/if}
		</div>

		{#if !isReleased && item.votes !== undefined}
			<ButtonReaction
				onclick={handleUpvote}
				color="rose"
				active={hasUpvoted}
				count={displayVotes}
				title={hasUpvoted ? 'Remove Upvote' : 'Upvote'}
			>
				{#snippet icon()}
					<Heart class="h-3.5 w-3.5" />
				{/snippet}
			</ButtonReaction>
		{:else if isReleased}
			<span class="flex items-center gap-1 py-1 text-xs font-medium text-blue-600 transition-colors group-hover:text-blue-700 dark:text-blue-400 dark:group-hover:text-blue-300">
				{i18n.t('page.roadmap.openTool')} <ArrowRight class="h-3.5 w-3.5" />
			</span>
		{/if}
	</div>
</svelte:element>
