<script lang="ts">
  import { onMount, onDestroy } from 'svelte';
  import type * as Monaco from 'monaco-editor/esm/vs/editor/editor.api';

  interface EditorProps {
    value?: string;
    language?: string;
    readOnly?: boolean;
    wordWrap?: boolean;
  }

  let { 
    value = $bindable(''), 
    language = 'html', 
    readOnly = false,
    wordWrap = true
  }: EditorProps = $props();

  let editorContainer: HTMLDivElement;
  
  // Prevent $state to make Svelte not create Proxy
  let editor: Monaco.editor.IStandaloneCodeEditor;
  let monaco: typeof Monaco;
  let themeObserver: MutationObserver;

  function getSystemTheme() {
    if (typeof document === 'undefined') return 'vs-dark';
    return document.documentElement.classList.contains('dark') ? 'vs-dark' : 'vs';
  }

  const editorOptions = {
    automaticLayout: true,
    formatOnPaste: false,
    formatOnType: false,
    minimap: { enabled: false },
    fontSize: 14,
    fontFamily: "'Fira Code', 'Consolas', monospace",
    scrollBeyondLastLine: false,
    roundedSelection: true,
    padding: { top: 16, bottom: 16 },
    wordWrap: wordWrap ? 'on' : 'off'
  };

  onMount(async () => {
    monaco = (await import('$lib/utils/monaco')).default;

    editor = monaco.editor.create(editorContainer, {
      value,
      language,
      readOnly,
      theme: getSystemTheme(),
      ...editorOptions
    });

    editor.onDidChangeModelContent(() => {
      // Prevent override value if in Output mode (Read-only)
      if (readOnly) return;
      
      const currentValue = editor.getValue();
      if (currentValue !== value) {
        value = currentValue;
      }
    });

    themeObserver = new MutationObserver(() => {
      monaco.editor.setTheme(getSystemTheme());
    });
    themeObserver.observe(document.documentElement, { attributes: true, attributeFilter: ['class'] });
  });

  // This $effect will be automatically called whenever the `value` prop changes
  $effect(() => {
    const currentValue = value;
    if (editor && currentValue !== editor.getValue()) {
      editor.setValue(currentValue);
    }
  });

  // Similarly, this block will be automatically called whenever the `readOnly` prop changes
  $effect(() => {
    const currentReadOnly = readOnly;
    if (editor) {
      editor.updateOptions({ readOnly: currentReadOnly });
    }
  });

  // Automatically called whenever `wordWrap` prop changes
  $effect(() => {
    const currentWordWrap = wordWrap;
    if (editor) {
      editor.updateOptions({ wordWrap: currentWordWrap ? 'on' : 'off' });
    }
  });

  // Auto-detect language from file extension
  $effect(() => {
    if (editor && monaco) {
      const model = editor.getModel();
      if (model) {
        monaco.editor.setModelLanguage(model, language);
      }
    }
  });

  onDestroy(() => {
    if (editor) {
      editor.dispose(); 
    }
    if (themeObserver) {
      themeObserver.disconnect();
    }
  });
</script>

<div bind:this={editorContainer} class="w-full h-full min-h-[400px]"></div>