<script lang="ts">
	import { flip } from 'svelte/animate';
	import { fade } from 'svelte/transition';
	import { i18n } from '$lib/i18n';

	import type { RoadmapItem } from '$lib/types';
	import RoadmapCard from './RoadmapCard.svelte';
	import { ROADMAP_STATUS_GROUPS } from '$lib/registry/roadmap';

	let { items }: { items: RoadmapItem[] } = $props();

	// Group and sort items by status
	let groupedItems = $derived(() => {
		return ROADMAP_STATUS_GROUPS.map(group => {
			const groupItems = items.filter(item => item.status === group.id);
			
			// Sort logic
			groupItems.sort((a, b) => {
				if (group.id === 'released') {
					// Released items sort by date (newest first)
					const dateA = a.date ? new Date(a.date).getTime() : 0;
					const dateB = b.date ? new Date(b.date).getTime() : 0;
					return dateB - dateA;
				} else {
					// Upcoming items sort alphabetically by name
					return i18n.t(a.name).localeCompare(i18n.t(b.name));
				}
			});
			
			return { ...group, items: groupItems };
		}).filter(group => group.items.length > 0);
	});
</script>

<div class="relative w-full max-w-5xl mx-auto pl-4 sm:pl-8 md:pl-12 mb-20">
	<!-- Vertical line on the left -->
	<div class="absolute left-4 sm:left-8 md:left-12 top-0 bottom-0 w-px bg-gray-200 dark:bg-gray-800"></div>

	<div class="flex flex-col gap-16 py-8">
		{#each groupedItems() as group (group.id)}
			<div class="relative">
				<!-- Group Header Node -->
				<div class="sticky top-20 z-10 flex items-center mb-8">
					<div class="flex items-center gap-3 rounded-full border border-gray-200 bg-white/90 backdrop-blur-md px-5 py-2.5 shadow-sm dark:border-gray-700 dark:bg-gray-900/90 -ml-5 sm:-ml-9 md:-ml-12">
						<div class="flex h-5 w-5 items-center justify-center rounded-full ring-4 ring-white dark:ring-gray-950 {group.dotOuter}">
							<div class="h-2 w-2 rounded-full {group.dotInner}"></div>
						</div>
						<div class="flex items-center gap-1.5">
							<group.icon class="h-4 w-4 {group.iconColor}" />
							<span class="text-sm font-bold text-gray-900 dark:text-gray-100">{i18n.t(group.key)}</span>
						</div>
						<span class="ml-1 rounded-full bg-gray-100 px-2 py-0.5 text-xs font-medium text-gray-600 dark:bg-gray-800 dark:text-gray-400">
							{group.items.length}
						</span>
					</div>
				</div>

				<!-- Group Items (Grid Layout) -->
				<div class="pl-4 sm:pl-6 md:pl-8">
					<div class="grid grid-cols-1 lg:grid-cols-2 gap-6">
						{#each group.items as item (item.id)}
							<div 
								animate:flip={{ duration: 300 }} 
								transition:fade|local={{ duration: 200 }}
							>
								<RoadmapCard {item} />
							</div>
						{/each}
					</div>
				</div>
			</div>
		{/each}
	</div>
</div>
