<script lang="ts">
  import { i18n } from '$lib/i18n';
  import { FormatterLayout } from '$lib/components/layout';
  import { createEditorModes } from '$lib/utils/editorModes';
  import { format } from 'sql-formatter';
  import { Select } from '$lib/components/ui';

  import type { ToolDefinition } from '$lib/types';

  export interface SQLFormatterProps {
    tool: ToolDefinition;
  }

  let { tool }: SQLFormatterProps = $props();

  const SAMPLE_SQL = `SELECT customers.name, count(orders.id) AS total_orders, sum(orders.amount) AS total_spent FROM customers LEFT JOIN orders ON customers.id = orders.customer_id WHERE customers.active = true GROUP BY customers.name HAVING total_spent > 1000 ORDER BY total_spent DESC LIMIT 10;`;

  // Settings
  let dialect = $state('sql');
  let spaceCount = $state<number>(2);
  let keywordCase = $state<'preserve' | 'upper' | 'lower'>('upper');

  let sqlModes = $derived(createEditorModes(['pretty', 'minify']));

  // Available SQL Dialects in sql-formatter
  const dialects = [
    { value: 'sql', label: 'Standard SQL' },
    { value: 'postgresql', label: 'PostgreSQL' },
    { value: 'mysql', label: 'MySQL' },
    { value: 'mariadb', label: 'MariaDB' },
    { value: 'sqlite', label: 'SQLite' },
    { value: 'tsql', label: 'MS SQL (T-SQL)' },
    { value: 'plsql', label: 'Oracle (PL/SQL)' }
  ];

  function processSqlMode(input: string, mode: string): string {
    if (!input.trim()) return '';
    try {
      if (mode === 'pretty') {
        return format(input, {
          language: dialect as any,
          tabWidth: Number(spaceCount),
          keywordCase: keywordCase,
          linesBetweenQueries: 2,
        });
      } else if (mode === 'minify') {
        // sql-formatter doesn't have a native "minify" option
        // We do a basic minification: remove newlines and extra spaces
        return input
          .replace(/--.*$/gm, '') // Remove single line comments
          .replace(/\/\*[\s\S]*?\*\//g, '') // Remove block comments
          .replace(/\s+/g, ' ') // Collapse multiple spaces
          .trim();
      }
      return input;
    } catch (e) {
      return input; // If invalid SQL syntax, return as-is or we could show an error
    }
  }
</script>

<FormatterLayout 
  {tool} 
  language="sql" 
  modes={sqlModes}
  processFn={processSqlMode} 
  sampleCode={SAMPLE_SQL}
>
  {#snippet extraControls(currentMode)}
    <div class="flex items-center gap-2 overflow-x-auto custom-scrollbar pb-1 sm:pb-0 {currentMode === 'minify' ? 'opacity-50 cursor-not-allowed' : ''}">
      
      <!-- Dialect -->
      <Select 
        id="dialect" 
        label={i18n.t('tools.sqlFormatter.dialect') || 'Dialect'}
        bind:value={dialect}
        disabled={currentMode === 'minify'}
      >
        {#each dialects as d (d.value)}
          <option value={d.value}>{d.label}</option>
        {/each}
      </Select>

      <!-- Keyword Case -->
      <Select 
        id="keywordCase" 
        label={i18n.t('tools.sqlFormatter.keywordCase') || 'Keyword Case'}
        bind:value={keywordCase}
        disabled={currentMode === 'minify'}
      >
        <option value="upper">{i18n.t('common.options.uppercase') || 'Uppercase'}</option>
        <option value="lower">{i18n.t('common.options.lowercase') || 'Lowercase'}</option>
        <option value="preserve">{i18n.t('common.options.preserve') || 'Preserve'}</option>
      </Select>

      <!-- Spaces -->
      <Select 
        id="spaces" 
        label={i18n.t('common.editor.spaces') || 'Spaces'}
        bind:value={spaceCount}
        disabled={currentMode === 'minify'}
      >
        <option value={2}>2</option>
        <option value={4}>4</option>
        <option value={8}>8</option>
      </Select>

    </div>
  {/snippet}
</FormatterLayout>
