import { browser } from '$app/environment';

import type { AppearanceId } from '$lib/types';
import { APP_CONFIG, APPEARANCES } from '$lib/constants';

function createAppearanceStore() {
    let currentAppearance = $state<AppearanceId>(APP_CONFIG.defaults.appearance);

    // Helper function to handle adding/removing 'dark' class
    function applyAppearanceToDocument(appearance: AppearanceId) {
        if (!browser) return;

        // It will be dark if: user selects 'dark', OR user selects 'system' and OS is dark
        const isDark = appearance === 'dark' || (appearance === 'system' && window.matchMedia('(prefers-color-scheme: dark)').matches);

        if (isDark) {
            document.documentElement.classList.add('dark');
        } else {
            document.documentElement.classList.remove('dark');
        }
    }

    if (browser) {
        // Get saved data if available
        const saved = localStorage.getItem(APP_CONFIG.storageKeys.appearance);
        if (saved && APPEARANCES.some((t) => t.id === saved)) {
            currentAppearance = saved as AppearanceId;
        }

        // Required to apply appearance to document at the first time
        applyAppearanceToDocument(currentAppearance);

        // Listen to OS changes (if user is using system mode)
        window.matchMedia('(prefers-color-scheme: dark)').addEventListener('change', () => {
            if (currentAppearance === 'system') applyAppearanceToDocument('system');
        });
    }

    return {
        get appearance() { return currentAppearance; },
        setAppearance: (newAppearance: AppearanceId) => {
            currentAppearance = newAppearance;
            if (browser) {
                localStorage.setItem(APP_CONFIG.storageKeys.appearance, currentAppearance);
                applyAppearanceToDocument(currentAppearance);
            }
        }
    };
}

export const appearanceStore = createAppearanceStore();