<script lang="ts">
  import { i18n } from '$lib/i18n';
  import { FormatterLayout } from '$lib/components/layout';
  import { createEditorModes } from '$lib/utils/editorModes';
  import { Select } from '$lib/components/ui';
  import xmlFormat from 'xml-formatter';

  import type { ToolDefinition } from '$lib/types';

  export interface XMLFormatterProps {
    tool: ToolDefinition;
  }

  let { tool }: XMLFormatterProps = $props();

  const SAMPLE_XML = `<?xml version="1.0" encoding="UTF-8"?>
<library>
<book id="1">
<title>The Great Gatsby</title><author>F. Scott Fitzgerald</author><year>1925</year>
</book>
<book id="2">
<title>1984</title>
<author>George Orwell</author>
<year>1949</year></book>
</library>`;

  // Settings
  let spaceCount = $state<number>(2);
  let collapseContent = $state(true);

  let xmlModes = $derived(createEditorModes(['pretty', 'minify']));

  function processXmlMode(input: string, mode: string): string {
    if (!input.trim()) return '';
    try {
      if (mode === 'pretty') {
        const indentation = ' '.repeat(Number(spaceCount));
        return xmlFormat(input, {
          indentation,
          collapseContent: collapseContent,
          lineSeparator: '\n'
        });
      } else if (mode === 'minify') {
        // Simple XML minify: remove whitespace between tags
        return input
          .replace(/>\s+</g, '><')
          .replace(/<!--[\s\S]*?-->/g, '') // remove comments
          .trim();
      }
      return input;
    } catch (e) {
      // If formatting fails (e.g., invalid XML), return as-is
      return input;
    }
  }
</script>

<FormatterLayout 
  {tool} 
  language="xml" 
  modes={xmlModes}
  processFn={processXmlMode} 
  sampleCode={SAMPLE_XML}
>
  {#snippet extraControls(currentMode)}
    <div class="flex items-center gap-2 overflow-x-auto custom-scrollbar pb-1 sm:pb-0 {currentMode === 'minify' ? 'opacity-50 cursor-not-allowed' : ''}">
      
      <!-- Spaces -->
      <Select 
        id="spaces" 
        label={i18n.t('common.editor.spaces') || 'Spaces'}
        bind:value={spaceCount}
        disabled={currentMode === 'minify'}
      >
        <option value={2}>2</option>
        <option value={4}>4</option>
        <option value={8}>8</option>
      </Select>

      <!-- Collapse Content -->
      <label class="flex items-center gap-2 text-sm font-medium text-gray-600 dark:text-gray-400 group {currentMode === 'minify' ? 'opacity-50 cursor-not-allowed' : 'cursor-pointer hover:bg-gray-200 dark:hover:bg-gray-800'}">
        <input 
          type="checkbox" 
          bind:checked={collapseContent}
          disabled={currentMode === 'minify'}
          class="w-4 h-4 rounded border-gray-300 text-blue-600 focus:ring-blue-500 dark:border-gray-600 dark:bg-gray-800 transition-colors cursor-pointer disabled:cursor-not-allowed"
        />
        <span class="group-hover:text-gray-900 dark:group-hover:text-white transition-colors">
          {i18n.t('tools.xmlFormatter.collapseContent') || 'Collapse Content'}
        </span>
      </label>

    </div>
  {/snippet}
</FormatterLayout>
