<script lang="ts">
  import { i18n } from '$lib/i18n';

  interface Props {
    value?: number;
    // If true, binds value as 30, 50, 70. If false, binds as 0.3, 0.5, 0.7
    usePercentage?: boolean;
    class?: string;
  }

  let { value = $bindable(0.5), usePercentage = false, class: className = '' }: Props = $props();

  const ratios = [0.3, 0.5, 0.7];

  function getOptionValue(ratio: number) {
    return usePercentage ? Math.round(ratio * 100) : ratio;
  }

  function isSelected(ratio: number) {
    const optValue = getOptionValue(ratio);
    return Math.abs(value - optValue) < 0.02; // Tolerance for floats
  }
</script>

<div class="hidden sm:flex sm:gap-0.5 items-center bg-gray-200/50 dark:bg-gray-800/50 p-0.5 rounded border border-gray-300/50 dark:border-gray-700/50 {className}">
  {#each ratios as ratio (ratio)}
    <button 
      onclick={() => value = getOptionValue(ratio)} 
      class="p-1.5 rounded transition-all duration-200 group {isSelected(ratio) ? 'bg-white shadow-sm dark:bg-gray-600' : 'hover:bg-white/50 dark:hover:bg-gray-700'}" 
      title={i18n.t(`ui.tooltips.layout.split${Math.round(ratio*100)}${Math.round((1-ratio)*100)}`)}
    >
      <div class="w-3.5 h-2.5 border border-gray-500 dark:border-gray-400 rounded-[2px] flex overflow-hidden opacity-80 group-hover:opacity-100">
        <div class="h-full bg-gray-500 dark:bg-gray-400 transition-all duration-300" style="width: {ratio * 100}%"></div>
      </div>
    </button>
  {/each}
</div>
