<script lang="ts">
  // Define type data for Option
  type Option = {
    value: string;
    label: string;
    icon?: any;
  };

  export interface SegmentedControlProps {
    options: Option[];
    value: string;
    class?: string;
  }

  let {
    options,
    value = $bindable(), // $bindable helps parent component use bind:value
    class: className = ''
  }: SegmentedControlProps = $props();
</script>

<div class="flex items-center bg-gray-100 dark:bg-gray-900/80 p-1 rounded-lg border border-gray-200 dark:border-gray-800 transition-colors {className}">
  {#each options as option (option)}
    <button 
      onclick={() => value = option.value}
      class={`px-3 py-1.5 text-xs font-medium rounded-md transition-all ${
        value === option.value 
          ? 'bg-white text-gray-900 shadow-sm dark:bg-gray-700 dark:text-gray-100' 
          : 'text-gray-500 hover:text-gray-700 dark:text-gray-400 dark:hover:text-gray-300'
      }`}
    >
      <div class="flex items-center justify-center gap-1.5">
        {#if option.icon}
          <svelte:component this={option.icon} class="w-3.5 h-3.5" />
        {/if}
        {option.label}
      </div>
    </button>
  {/each}
</div>