<script lang="ts">
  import { env } from '$env/dynamic/public';
  import { page } from '$app/stores';

  import { i18n } from '$lib/i18n';

  interface Props {
    title?: string;
    description?: string;
    keywords?: string;
    image?: string;
    type?: 'website' | 'article' | 'WebApplication' | 'SoftwareApplication';
    isTool?: boolean;
  }

  let {
    title = i18n.t('app.title'),
    description = i18n.t('app.description.meta'),
    keywords = 'developer tools, utilities, json formatter, base64, url encode, css gradient, svg optimizer',
    image = '/og-image.png', // Assuming an og-image.png exists in static
    type = 'website',
    isTool = false
  }: Props = $props();

  let url = $derived($page.url.href);
  let domain = $derived($page.url.origin);
  let fullImage = $derived(image.startsWith('http') ? image : `${domain}${image}`);
  let siteName = $derived(i18n.t('app.name'));

  let formattedTitle = $derived.by(() => {
    if ($page.url.pathname === '/') {
      return `${i18n.t('app.title')} | ${i18n.t('app.tagline')}`;
    }
    return title === siteName || title === i18n.t('app.title') ? title : `${title} | ${siteName}`;
  });
</script>

<svelte:head>
  <!-- Primary Meta Tags -->
  <title>{formattedTitle}</title>
  <meta name="title" content={formattedTitle} />
  <meta name="description" content={description} />
  <meta name="keywords" content={keywords} />

  {#if import.meta.env.VITE_PUBLIC_BUILD !== 'true' && env.PUBLIC_ADSENSE_ACCOUNT}
    <meta name="google-adsense-account" content={env.PUBLIC_ADSENSE_ACCOUNT} />
  {/if}

  <!-- Open Graph / Facebook -->
  <meta property="og:type" content={type} />
  <meta property="og:url" content={url} />
  <meta property="og:title" content={formattedTitle} />
  <meta property="og:description" content={description} />
  <meta property="og:image" content={fullImage} />
  <meta property="og:site_name" content={siteName} />

  <!-- Twitter -->
  <meta property="twitter:card" content="summary_large_image" />
  <meta property="twitter:url" content={url} />
  <meta property="twitter:title" content={formattedTitle} />
  <meta property="twitter:description" content={description} />
  <meta property="twitter:image" content={fullImage} />

  <link rel="canonical" href={url} />

  <!-- Structured Data (JSON-LD) -->
  {#if isTool}
    {@html `<script type="application/ld+json">
      {
        "@context": "https://schema.org",
        "@type": "WebApplication",
        "name": "${title}",
        "description": "${description}",
        "url": "${url}",
        "applicationCategory": "DeveloperApplication",
        "operatingSystem": "Any"
      }
    </script>`}
  {:else}
    {@html `<script type="application/ld+json">
      {
        "@context": "https://schema.org",
        "@type": "WebSite",
        "name": "${siteName}",
        "url": "${domain}"
      }
    </script>`}
  {/if}

  {#if import.meta.env.VITE_PUBLIC_BUILD !== 'true' && env.PUBLIC_ADSENSE_ACCOUNT}
    <script async src={`https://pagead2.googlesyndication.com/pagead/js/adsbygoogle.js?client=${env.PUBLIC_ADSENSE_ACCOUNT}`} crossorigin="anonymous"></script>
  {/if}
</svelte:head>
