import CryptoJS from 'crypto-js';

export interface OTPURI {
  type: 'totp' | 'hotp';
  label: string;
  secret: string;
  issuer?: string;
  algorithm: 'SHA1' | 'SHA256' | 'SHA512';
  digits: number;
  period: number;
  counter?: number;
}

/**
 * Decodes a base32 string into a WordArray for crypto-js
 */
export function base32ToWordArray(base32: string): CryptoJS.lib.WordArray {
  const alphabet = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ234567';
  let bits = 0;
  let value = 0;
  let hex = '';

  for (let i = 0; i < base32.length; i++) {
    const val = alphabet.indexOf(base32.charAt(i).toUpperCase());
    if (val === -1) continue; // Skip padding or invalid characters

    value = (value << 5) | val;
    bits += 5;

    if (bits >= 8) {
      hex += ((value >>> (bits - 8)) & 0xff).toString(16).padStart(2, '0');
      bits -= 8;
    }
  }

  return CryptoJS.enc.Hex.parse(hex);
}

/**
 * Converts an integer to an 8-byte hex string WordArray
 */
function intToWordArray(num: number): CryptoJS.lib.WordArray {
  let hex = num.toString(16);
  hex = hex.padStart(16, '0');
  return CryptoJS.enc.Hex.parse(hex);
}

/**
 * Calculate the remaining seconds for a TOTP
 */
export function getTOTPRemainingSeconds(step: number = 30): number {
  const epoch = Math.floor(Date.now() / 1000);
  return step - (epoch % step);
}

/**
 * Calculate the progress percentage for a TOTP
 */
export function getTOTPProgress(step: number = 30): number {
  const epoch = Date.now();
  const currentStepTime = epoch % (step * 1000);
  return (currentStepTime / (step * 1000)) * 100;
}

/**
 * Parses an otpauth:// URI into its components
 */
export function parseOTPAuthURI(uri: string): OTPURI | null {
  try {
    const url = new URL(uri);
    if (url.protocol !== 'otpauth:') return null;

    const type = url.host as 'totp' | 'hotp';
    if (type !== 'totp' && type !== 'hotp') return null;

    // label can be "Issuer:Account"
    const label = decodeURIComponent(url.pathname.substring(1));
    const searchParams = url.searchParams;

    const secret = searchParams.get('secret') || '';
    if (!secret) return null;

    const issuer = searchParams.get('issuer') || undefined;
    const algoRaw = searchParams.get('algorithm') || 'SHA1';
    let algorithm: 'SHA1' | 'SHA256' | 'SHA512' = 'SHA1';
    if (algoRaw.toUpperCase() === 'SHA256') algorithm = 'SHA256';
    if (algoRaw.toUpperCase() === 'SHA512') algorithm = 'SHA512';

    const digits = parseInt(searchParams.get('digits') || '6', 10);
    const period = parseInt(searchParams.get('period') || '30', 10);
    const counter = searchParams.has('counter') ? parseInt(searchParams.get('counter') as string, 10) : undefined;

    return { type, label, secret, issuer, algorithm, digits, period, counter };
  } catch (e) {
    return null;
  }
}

/**
 * Generates an HOTP code
 */
export function generateHOTP(
  secretBase32: string,
  counter: number,
  digits: number = 6,
  algorithm: 'SHA1' | 'SHA256' | 'SHA512' = 'SHA1'
): string {
  try {
    const key = base32ToWordArray(secretBase32);
    const message = intToWordArray(counter);

    let hash: CryptoJS.lib.WordArray;
    if (algorithm === 'SHA256') {
      hash = CryptoJS.HmacSHA256(message, key);
    } else if (algorithm === 'SHA512') {
      hash = CryptoJS.HmacSHA512(message, key);
    } else {
      hash = CryptoJS.HmacSHA1(message, key);
    }

    const hashHex = CryptoJS.enc.Hex.stringify(hash);
    
    // Dynamic truncation
    const offset = parseInt(hashHex.substring(hashHex.length - 1), 16);
    let binary =
      ((parseInt(hashHex.substr(offset * 2, 2), 16) & 0x7f) << 24) |
      ((parseInt(hashHex.substr(offset * 2 + 2, 2), 16) & 0xff) << 16) |
      ((parseInt(hashHex.substr(offset * 2 + 4, 2), 16) & 0xff) << 8) |
      (parseInt(hashHex.substr(offset * 2 + 6, 2), 16) & 0xff);

    let otp = (binary % Math.pow(10, digits)).toString();
    return otp.padStart(digits, '0');
  } catch (err) {
    return ''.padStart(digits, '-');
  }
}

/**
 * Generates a TOTP code
 */
export function generateTOTP(
  secretBase32: string,
  step: number = 30,
  digits: number = 6,
  algorithm: 'SHA1' | 'SHA256' | 'SHA512' = 'SHA1',
  time: number = Date.now()
): string {
  const counter = Math.floor(time / 1000 / step);
  return generateHOTP(secretBase32, counter, digits, algorithm);
}

/**
 * Generates an otpauth:// URI
 */
export function generateOTPAuthURI(params: OTPURI): string {
  const url = new URL(`otpauth://${params.type}/${encodeURIComponent(params.label)}`);
  url.searchParams.set('secret', params.secret);
  if (params.issuer) {
    url.searchParams.set('issuer', params.issuer);
  }
  if (params.algorithm !== 'SHA1') {
    url.searchParams.set('algorithm', params.algorithm);
  }
  if (params.digits !== 6) {
    url.searchParams.set('digits', params.digits.toString());
  }
  if (params.type === 'totp' && params.period !== 30) {
    url.searchParams.set('period', params.period.toString());
  }
  if (params.type === 'hotp' && params.counter !== undefined) {
    url.searchParams.set('counter', params.counter.toString());
  }
  return url.toString();
}
