<script lang="ts">
  import { resolve } from '$app/paths';
  import { page } from '$app/stores';
  import { i18n } from '$lib/i18n';
  import { getStructuredCategories } from '$lib/registry';

  import { layoutStore } from '$lib/stores';
  import { ChevronDown, ChevronRight, MoreHorizontal } from 'lucide-svelte/icons';
  import { TOOL_ICON_MAP, FallbackIcon } from '$lib/registry';

  const VISIBLE_CATEGORIES_LIMIT = 5;

  let navigationMenu = $derived(getStructuredCategories());
  let visibleCategories = $derived(navigationMenu.slice(0, VISIBLE_CATEGORIES_LIMIT));
  let moreCategories = $derived(navigationMenu.slice(VISIBLE_CATEGORIES_LIMIT));

  let isToolActive = $derived((slug: string) => $page.url.pathname.startsWith(resolve(`/${slug}`)));
  let isCategoryActive = $derived((category: any) => category.tools.some((t: any) => isToolActive(t.slug)));
  let isMoreActive = $derived(moreCategories.some((c: any) => isCategoryActive(c)));
</script>

<nav class={`hidden lg:flex items-center gap-1 transition-all duration-300 ease-[cubic-bezier(0.4,0,0.2,1)] ${
  layoutStore.mode === 'vertical' 
    ? 'opacity-0 w-0 overflow-hidden' 
    : 'opacity-100'
}`}>
  {#each visibleCategories as category (category.id)}
    <div class="relative group">
      
      <button class="flex items-center gap-1.5 px-3 py-2 text-sm font-semibold rounded-lg transition-colors {isCategoryActive(category) ? 'text-blue-600 dark:text-blue-400 bg-blue-50/80 dark:bg-blue-900/30' : 'text-gray-600 dark:text-gray-300 hover:text-gray-900 dark:hover:text-white hover:bg-gray-100 dark:hover:bg-gray-800'}">
        {i18n.t(category.name)}
        <ChevronDown class={`w-3 h-3 transition-transform duration-200 ${isCategoryActive(category) ? 'text-blue-500/70' : 'opacity-50'} group-hover:rotate-180`} />
      </button>

      <div class="absolute top-full left-0 pt-2 opacity-0 translate-y-1 scale-95 origin-top-left pointer-events-none group-hover:opacity-100 group-hover:translate-y-0 group-hover:scale-100 group-hover:pointer-events-auto transition-all duration-200 ease-out z-50">
        <div class="w-max min-w-[220px] bg-white/90 dark:bg-gray-900/90 backdrop-blur-xl rounded-xl shadow-xl shadow-gray-200/50 dark:shadow-black/50 border border-gray-200/60 dark:border-gray-700/60 overflow-hidden py-1.5">
          {#each category.tools as tool (tool.id)}
            {@const Icon = TOOL_ICON_MAP[tool.icon || ''] || FallbackIcon}
            {@const active = isToolActive(tool.slug)}
            <a 
              href={resolve(`/${tool.slug}`)}
              class="flex items-center gap-3 px-4 py-2.5 text-sm font-medium whitespace-nowrap transition-colors {active ? 'text-blue-600 bg-blue-50/80 dark:text-blue-400 dark:bg-blue-900/30' : 'text-gray-600 dark:text-gray-400 hover:text-gray-900 hover:bg-gray-50/80 dark:hover:text-gray-100 dark:hover:bg-gray-800/50'}"
            >
              <Icon class="w-4 h-4 {active ? 'text-blue-500 dark:text-blue-400' : 'text-gray-400 group-hover:text-gray-500 dark:group-hover:text-gray-300'}" />
              <span>{i18n.t(tool.name)}</span>
            </a>
          {/each}
        </div>
      </div>
      
    </div>
  {/each}

  {#if moreCategories.length > 0}
    <div class="relative group">
      
      <button class="flex items-center justify-center w-9 h-9 rounded-lg transition-colors {isMoreActive ? 'text-blue-600 dark:text-blue-400 bg-blue-50/80 dark:bg-blue-900/30' : 'text-gray-600 dark:text-gray-300 hover:text-gray-900 dark:hover:text-white hover:bg-gray-100 dark:hover:bg-gray-800'}" title={i18n.t('common.more') || 'More categories'}>
        <MoreHorizontal class="w-5 h-5" />
      </button>

      <div class="absolute top-full right-0 pt-2 opacity-0 translate-y-1 scale-95 origin-top-right pointer-events-none group-hover:opacity-100 group-hover:translate-y-0 group-hover:scale-100 group-hover:pointer-events-auto transition-all duration-200 ease-out z-50">
        <div class="w-max min-w-[200px] bg-white/90 dark:bg-gray-900/90 backdrop-blur-xl rounded-xl shadow-xl shadow-gray-200/50 dark:shadow-black/50 border border-gray-200/60 dark:border-gray-700/60 py-1.5">
          {#each moreCategories as category (category.id)}
            <div class="relative group/sub">
              
              <!-- Category Name Item -->
              <button class="flex items-center justify-between w-full gap-3 px-4 py-2.5 text-sm font-medium transition-colors {isCategoryActive(category) ? 'text-blue-600 bg-blue-50/80 dark:text-blue-400 dark:bg-blue-900/30' : 'text-gray-600 dark:text-gray-400 hover:text-gray-900 hover:bg-gray-50/80 dark:hover:text-gray-100 dark:hover:bg-gray-800/50'}">
                <span>{i18n.t(category.name)}</span>
                <ChevronRight class="w-4 h-4 opacity-50" />
              </button>

              <!-- Tools Sub-menu Flyout (opens to the right) -->
              <div class="absolute top-0 left-full pl-1.5 opacity-0 -translate-x-1 scale-95 origin-top-left pointer-events-none group-hover/sub:opacity-100 group-hover/sub:translate-x-0 group-hover/sub:scale-100 group-hover/sub:pointer-events-auto transition-all duration-200 ease-out z-50">
                <div class="w-max min-w-[220px] bg-white/90 dark:bg-gray-900/90 backdrop-blur-xl rounded-xl shadow-xl shadow-gray-200/50 dark:shadow-black/50 border border-gray-200/60 dark:border-gray-700/60 overflow-hidden py-1.5">
                  {#each category.tools as tool (tool.id)}
                    {@const Icon = TOOL_ICON_MAP[tool.icon || ''] || FallbackIcon}
                    {@const active = isToolActive(tool.slug)}
                    <a 
                      href={resolve(`/${tool.slug}`)}
                      class="flex items-center gap-3 px-4 py-2.5 text-sm font-medium whitespace-nowrap transition-colors {active ? 'text-blue-600 bg-blue-50/80 dark:text-blue-400 dark:bg-blue-900/30' : 'text-gray-600 dark:text-gray-400 hover:text-gray-900 hover:bg-gray-50/80 dark:hover:text-gray-100 dark:hover:bg-gray-800/50'}"
                    >
                      <Icon class="w-4 h-4 {active ? 'text-blue-500 dark:text-blue-400' : 'text-gray-400 group-hover/sub:text-gray-500 dark:group-hover/sub:text-gray-300'}" />
                      <span>{i18n.t(tool.name)}</span>
                    </a>
                  {/each}
                </div>
              </div>

            </div>
          {/each}
        </div>
      </div>
      
    </div>
  {/if}
</nav>