<script lang="ts">
	import type { Snippet } from 'svelte';

	interface Props {
		variant?: 'solid' | 'outline' | 'ghost';
		color?: 'blue' | 'gray' | 'rose' | 'green' | 'amber';
		size?: 'sm' | 'md' | 'lg';
		type?: 'button' | 'submit' | 'reset';
		disabled?: boolean;
		href?: string;
		class?: string;
		title?: string;
		onclick?: (e: MouseEvent) => void;
		children?: Snippet;
		[key: string]: unknown;
	}

	let {
		variant = 'solid',
		color = 'blue',
		size = 'md',
		type = 'button',
		disabled = false,
		href,
		class: className = '',
		title,
		onclick,
		children,
		...rest
	}: Props = $props();

	const sizeClasses = {
		sm: 'px-3 h-8 text-xs gap-1',
		md: 'px-4 h-10 text-sm gap-1.5',
		lg: 'px-6 h-12 text-base gap-2'
	};

	const variantColorClasses = {
		solid: {
			blue: 'bg-blue-600 text-white hover:bg-blue-700 shadow-sm focus:ring-blue-500 border border-transparent',
			gray: 'bg-gray-800 text-white hover:bg-gray-900 shadow-sm focus:ring-gray-500 dark:bg-gray-100 dark:text-gray-900 dark:hover:bg-white border border-transparent',
			rose: 'bg-rose-600 text-white hover:bg-rose-700 shadow-sm focus:ring-rose-500 border border-transparent',
			green: 'bg-green-600 text-white hover:bg-green-700 shadow-sm focus:ring-green-500 border border-transparent',
			amber: 'bg-amber-500 text-white hover:bg-amber-600 shadow-sm focus:ring-amber-500 border border-transparent'
		},
		outline: {
			blue: 'bg-transparent text-blue-600 hover:bg-blue-50 border border-blue-200 focus:ring-blue-500 dark:text-blue-400 dark:border-blue-800 dark:hover:bg-blue-900/30',
			gray: 'bg-white text-gray-700 hover:bg-gray-50 border border-gray-300 focus:ring-gray-500 dark:bg-gray-900 dark:text-gray-300 dark:border-gray-700 dark:hover:bg-gray-800',
			rose: 'bg-transparent text-rose-600 hover:bg-rose-50 border border-rose-200 focus:ring-rose-500 dark:text-rose-400 dark:border-rose-800 dark:hover:bg-rose-900/30',
			green: 'bg-transparent text-green-600 hover:bg-green-50 border border-green-200 focus:ring-green-500 dark:text-green-400 dark:border-green-800 dark:hover:bg-green-900/30',
			amber: 'bg-transparent text-amber-600 hover:bg-amber-50 border border-amber-200 focus:ring-amber-500 dark:text-amber-500 dark:border-amber-800 dark:hover:bg-amber-900/30'
		},
		ghost: {
			blue: 'bg-transparent text-blue-600 hover:bg-blue-50 focus:ring-blue-500 dark:text-blue-400 dark:hover:bg-blue-900/30 border border-transparent',
			gray: 'bg-transparent text-gray-600 hover:bg-gray-100 focus:ring-gray-500 dark:text-gray-400 dark:hover:bg-gray-800 border border-transparent',
			rose: 'bg-transparent text-rose-600 hover:bg-rose-50 focus:ring-rose-500 dark:text-rose-400 dark:hover:bg-rose-900/30 border border-transparent',
			green: 'bg-transparent text-green-600 hover:bg-green-50 focus:ring-green-500 dark:text-green-400 dark:hover:bg-green-900/30 border border-transparent',
			amber: 'bg-transparent text-amber-600 hover:bg-amber-50 focus:ring-amber-500 dark:text-amber-500 dark:hover:bg-amber-900/30 border border-transparent'
		}
	};

	let baseClasses = 'flex items-center justify-center font-semibold rounded-xl transition-all focus:outline-none focus:ring-2 focus:ring-offset-2 dark:focus:ring-offset-gray-950 whitespace-nowrap active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed';
	
	let computedClass = $derived(
		`${baseClasses} ${sizeClasses[size]} ${variantColorClasses[variant][color]} ${className}`
	);
</script>

{#if href}
	<!-- svelte-ignore a11y_consider_explicit_label -->
	<a {href} {title} class={computedClass} {onclick} {...rest}>
		{@render children?.()}
	</a>
{:else}
	<!-- svelte-ignore a11y_consider_explicit_label -->
	<button {type} {title} {disabled} class={computedClass} {onclick} {...rest}>
		{@render children?.()}
	</button>
{/if}
