<script lang="ts">
	import type { Snippet } from 'svelte';

	interface Props {
		active?: boolean;
		count?: number | string;
		color?: 'rose' | 'blue' | 'amber' | 'green';
		disabled?: boolean;
		class?: string;
		title?: string;
		onclick?: (e: MouseEvent) => void;
		icon?: Snippet;
		[key: string]: unknown;
	}

	let {
		active = false,
		count,
		color = 'rose',
		disabled = false,
		class: className = '',
		title,
		onclick,
		icon,
		...rest
	}: Props = $props();

	const colorStyles = {
		rose: {
			active: 'bg-rose-50 text-rose-600 dark:bg-rose-500/20 dark:text-rose-400',
			inactive: 'text-gray-500 hover:bg-rose-50 hover:text-rose-600 dark:text-gray-400 dark:hover:bg-rose-500/10 dark:hover:text-rose-400'
		},
		blue: {
			active: 'bg-blue-50 text-blue-600 dark:bg-blue-500/20 dark:text-blue-400',
			inactive: 'text-gray-500 hover:bg-blue-50 hover:text-blue-600 dark:text-gray-400 dark:hover:bg-blue-500/10 dark:hover:text-blue-400'
		},
		amber: {
			active: 'bg-amber-50 text-amber-600 dark:bg-amber-500/20 dark:text-amber-400',
			inactive: 'text-gray-500 hover:bg-amber-50 hover:text-amber-600 dark:text-gray-400 dark:hover:bg-amber-500/10 dark:hover:text-amber-400'
		},
		green: {
			active: 'bg-green-50 text-green-600 dark:bg-green-500/20 dark:text-green-400',
			inactive: 'text-gray-500 hover:bg-green-50 hover:text-green-600 dark:text-gray-400 dark:hover:bg-green-500/10 dark:hover:text-green-400'
		}
	};

	let currentState = $derived(active ? 'active' : 'inactive');
	let colorConfig = $derived(colorStyles[color]);
	let disabledClass = $derived(disabled ? 'opacity-50 cursor-not-allowed' : '');
</script>

<!-- svelte-ignore a11y_consider_explicit_label -->
<button
	{title}
	{disabled}
	class="flex items-center gap-1.5 rounded-full px-2 py-1 text-xs font-medium transition-colors {colorConfig[currentState]} {disabledClass} {active ? '[&>svg]:fill-current [&>div>svg]:fill-current' : ''} {className}"
	{onclick}
	{...rest}
>
	{#if icon}
		<div class="flex items-center justify-center pointer-events-none">
			{@render icon()}
		</div>
	{/if}
	
	{#if count !== undefined}
		<span>{count}</span>
	{/if}
</button>
