<script lang="ts">
  import { slide } from 'svelte/transition';
  import { i18n } from '$lib/i18n';
  import { ToolWrapper } from '$lib/components/layout';
  import { Separator, SplitRatioControl, FullscreenToggle } from '$lib/components/ui';
  import { tooltip } from '$lib/actions/tooltip';
  import { Info } from 'lucide-svelte';
  import type { Snippet } from 'svelte';
  import type { ToolDefinition } from '$lib/types';

  export interface SplitWorkspaceProps {
    tool: ToolDefinition;
    isFullFrame?: boolean;
    headerLeftControls?: Snippet;
    headerRightControls?: Snippet;
    leftPanel: Snippet;
    rightPanel: Snippet;
  }

  let {
    tool,
    isFullFrame = $bindable(false),
    headerLeftControls,
    headerRightControls,
    leftPanel,
    rightPanel
  }: SplitWorkspaceProps = $props();

  // Resizing functions
  let containerRef: HTMLDivElement;
  let leftWidth = $state(50);
  let isDragging = $state(false);

  function startDrag(e: PointerEvent) {
    isDragging = true;
    document.body.style.userSelect = 'none';
    (e.target as HTMLElement).setPointerCapture(e.pointerId);
  }

  function stopDrag(e: PointerEvent) {
    if (isDragging) {
      isDragging = false;
      document.body.style.userSelect = '';
      try {
        (e.target as HTMLElement).releasePointerCapture(e.pointerId);
      } catch {
        // ignore
      }
    }
  }

  function handleDrag(e: PointerEvent) {
    if (!isDragging || !containerRef) return;
    const rect = containerRef.getBoundingClientRect();
    let newPercentage = ((e.clientX - rect.left) / rect.width) * 100;
    // Limit not to drag too far (at least 20% from the edges)
    if (newPercentage < 20) newPercentage = 20;
    if (newPercentage > 80) newPercentage = 80;
    leftWidth = newPercentage;
  }
</script>

<svelte:window onpointermove={handleDrag} onpointerup={stopDrag} />

<ToolWrapper toolId={tool.id} title={i18n.t(tool.name)} description={tool.description ? i18n.t(tool.description) : ''} isFullFrame={isFullFrame}>
  
  {#snippet headerAction()}
    <div class="flex items-center justify-between w-full gap-2 sm:gap-4 flex-wrap min-h-[38px]">
      
      <div class="flex items-center justify-start gap-3">
        {#if isFullFrame}
          <div 
            class="flex items-center gap-2.5" 
            transition:slide={{ axis: 'x', duration: 400 }}
          >
            <h2 class="text-3xl font-bold text-gray-800 dark:text-gray-100 whitespace-nowrap">
              {i18n.t(tool.name + 'Short')}
            </h2>

            {#if tool.description}
              <span use:tooltip={{ position: 'bottom', content: i18n.t(tool.description), contentClass: 'w-64 p-2 font-normal leading-relaxed text-left pointer-events-none' }}><Info class="w-4 h-4 text-gray-400 hover:text-blue-500 cursor-help transition-colors" /></span>
            {/if}
          </div>
        {/if}

        {#if headerLeftControls}
          {@render headerLeftControls()}
        {/if}
      </div>

      <div class="flex items-center justify-end gap-3">
        <SplitRatioControl bind:value={leftWidth} usePercentage={true} />

        <Separator orientation="vertical" size="4" class="hidden sm:block -ml-px" />

        {#if headerRightControls}
          {@render headerRightControls()}
        {/if}

        <FullscreenToggle bind:isFullFrame />
      </div>

    </div>
  {/snippet}

  <div 
    bind:this={containerRef}
    class="flex flex-row {isFullFrame ? 'h-[calc(100vh-266px)] sm:h-[calc(100vh-282px)]' : 'h-[600px]'} transition-all duration-300 bg-white dark:bg-[#1e1e1e] rounded-xl border border-gray-200 dark:border-gray-800 overflow-hidden shadow-sm"
  >
    <div
      style="width: {leftWidth}%"
      class="flex flex-col h-full bg-white dark:bg-[#1e1e1e] {isDragging ? 'pointer-events-none' : 'transition-all duration-300 ease-[cubic-bezier(0.4,0,0.2,1)]'}"
    >
      {@render leftPanel()}
    </div>

    <div 
      class="w-1.5 z-10 cursor-col-resize flex-shrink-0 flex items-center justify-center transition-colors {isDragging ? 'bg-blue-500' : 'bg-gray-200 dark:bg-gray-800'} hover:bg-blue-400 dark:hover:bg-blue-600"
      onpointerdown={startDrag} role="separator" tabindex="-1"
    ></div>

    <div
      style="width: {100 - leftWidth}%"
      class="flex flex-col h-full bg-white dark:bg-[#1e1e1e] {isDragging ? 'pointer-events-none' : 'transition-all duration-300 ease-[cubic-bezier(0.4,0,0.2,1)]'}"
    >
      {@render rightPanel()}
    </div>
  </div>

</ToolWrapper>
