<script lang="ts">
  import { Star, GripVertical, Trash2, X, Binary, Link, Code, Database, FileCode2, Palette, Braces, History } from 'lucide-svelte';
  import { i18n } from '$lib/i18n';
  import { favoritesStore } from '$lib/stores/favorites.svelte';
  import { recentStore } from '$lib/stores/recent.svelte';
  import { tools } from '$lib/registry';
  import { TOOL_ICON_MAP, FallbackIcon } from '$lib/registry';
  import { slide } from 'svelte/transition';
	import { Separator } from '$lib/components/ui';

  const iconMap: Record<string, any> = { Binary, Link, Code, Database, FileCode2, Palette, Braces };

  // Derived array of full tool objects for rendering
  let favoriteToolsList = $derived(
    favoritesStore.items.map(id => {
      const t = tools.find(t => t.id === id);
      if (!t) return null;
      return {
        ...t,
        Icon: TOOL_ICON_MAP[t.icon || ''] || FallbackIcon
      };
    }).filter(Boolean)
  );

  let draggingIndex = $state<number | null>(null);

  function handleDragStart(event: DragEvent, index: number) {
    draggingIndex = index;
    if (event.dataTransfer) {
      event.dataTransfer.effectAllowed = 'move';
    }
  }

  function handleDragOver(event: DragEvent, index: number) {
    event.preventDefault();
    if (draggingIndex === null || draggingIndex === index) return;

    // Swap items in the store's array
    const newItems = [...favoritesStore.items];
    const [draggedItem] = newItems.splice(draggingIndex, 1);
    newItems.splice(index, 0, draggedItem);
    
    favoritesStore.reorder(newItems);
    draggingIndex = index;
  }

  function handleDragEnd() {
    draggingIndex = null;
  }

  function clearAll() {
    if (confirm("Are you sure you want to remove all favorited tools?")) {
      favoritesStore.clear();
    }
  }

  function clearHistory() {
    if (confirm("Are you sure you want to clear your recent tools history?")) {
      recentStore.clear();
    }
  }
</script>

<div class="space-y-10">
  
  <!-- Page Header -->
  <div class="flex flex-col gap-2">
    <h2 class="text-xl font-bold text-gray-900 dark:text-gray-100">Workspace</h2>
    <p class="text-sm text-gray-500 dark:text-gray-400">Manage your workspace preferences, favorites, and history.</p>
  </div>

  <Separator variant="gradient-left" />

  <!-- Favorites Section -->
  <div class="space-y-6">
    <div class="flex flex-col sm:flex-row sm:items-end justify-between gap-4">
    <div class="flex flex-col gap-2">
      <h2 class="text-lg font-semibold text-gray-900 dark:text-gray-100 flex items-center gap-2">
        <Star class="w-5 h-5 text-amber-500" />
        Favorite Tools
      </h2>
      <p class="text-sm text-gray-500 dark:text-gray-400">Manage the tools that appear in your Favorites tab.</p>
    </div>
    
    {#if favoriteToolsList.length > 0}
      <button 
        onclick={clearAll}
        class="flex items-center gap-2 px-3 py-1.5 text-sm font-medium text-red-600 bg-red-50 hover:bg-red-100 dark:text-red-400 dark:bg-red-900/20 dark:hover:bg-red-900/40 rounded-lg transition-colors"
      >
        <Trash2 class="w-4 h-4" />
        Clear All
      </button>
    {/if}
  </div>

  <section class="bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-2xl shadow-sm overflow-hidden">
    {#if favoriteToolsList.length === 0}
      <div class="p-8 text-center flex flex-col items-center justify-center gap-3">
        <Star class="w-8 h-8 text-gray-300 dark:text-gray-600" />
        <h3 class="text-gray-500 dark:text-gray-400 font-medium">No favorites yet</h3>
        <p class="text-sm text-gray-400 dark:text-gray-500 max-w-sm">Star some tools on the Home page to see them here.</p>
      </div>
    {:else}
      <div class="divide-y divide-gray-100 dark:divide-gray-700/50">
        {#each favoriteToolsList as tool, index (tool?.id)}
          {#if tool}
            <div 
              class="flex items-center justify-between p-4 bg-white dark:bg-gray-800 hover:bg-gray-50 dark:hover:bg-gray-800/80 transition-colors group cursor-grab active:cursor-grabbing {draggingIndex === index ? 'opacity-50 bg-gray-50 dark:bg-gray-700' : ''}"
              draggable="true"
              ondragstart={(e) => handleDragStart(e, index)}
              ondragover={(e) => handleDragOver(e, index)}
              ondragend={handleDragEnd}
              transition:slide={{ duration: 200 }}
            >
              <div class="flex items-center gap-4 flex-1 overflow-hidden">
                <div class="cursor-grab active:cursor-grabbing text-gray-400 hover:text-gray-600 dark:text-gray-500 dark:hover:text-gray-300 transition-colors">
                  <GripVertical class="w-5 h-5" />
                </div>
                <div class="p-2 bg-blue-50 dark:bg-blue-900/20 rounded-lg text-blue-600 dark:text-blue-400 shrink-0">
                  <tool.Icon class="w-5 h-5" />
                </div>
                <div class="flex flex-col min-w-0">
                  <span class="font-semibold text-gray-900 dark:text-gray-100 truncate">
                    {i18n.t(tool.name)}
                  </span>
                  <span class="text-xs text-gray-500 dark:text-gray-400 truncate">
                    {i18n.t(tool.description || '')}
                  </span>
                </div>
              </div>

              <div class="flex items-center gap-2 pl-4">
                <button 
                  onclick={() => favoritesStore.toggle(tool.id)}
                  class="p-2 text-gray-400 hover:text-red-500 hover:bg-red-50 dark:hover:bg-red-900/30 rounded-lg transition-all"
                  title="Remove from favorites"
                >
                  <X class="w-4 h-4" />
                </button>
              </div>
            </div>
          {/if}
        {/each}
      </div>
    {/if}
  </section>
  
  {#if favoriteToolsList.length > 0}
    <p class="text-xs text-center text-gray-400 dark:text-gray-500 mt-4">
      Pro Tip: Drag and drop items to reorder how they appear on your Home page.
    </p>
  {/if}
  </div>

  <Separator variant="gradient" />

  <!-- Recent History Section -->
  <div class="space-y-6">
    <div class="flex flex-col sm:flex-row sm:items-end justify-between gap-4">
      <div class="flex flex-col gap-2">
        <h2 class="text-lg font-semibold text-gray-900 dark:text-gray-100 flex items-center gap-2">
          <History class="w-5 h-5 text-gray-500" />
          Recent Tools
        </h2>
        <p class="text-sm text-gray-500 dark:text-gray-400">Manage your recently used tools history.</p>
      </div>
      
      {#if recentStore.items.length > 0}
        <button 
          onclick={clearHistory}
          class="flex items-center gap-2 px-3 py-1.5 text-sm font-medium text-gray-600 bg-gray-100 hover:bg-gray-200 dark:text-gray-300 dark:bg-gray-800 dark:hover:bg-gray-700 rounded-lg transition-colors"
        >
          <Trash2 class="w-4 h-4" />
          Clear History
        </button>
      {/if}
    </div>

    <section class="bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-2xl shadow-sm p-6 flex flex-col sm:flex-row items-center justify-between gap-4">
      <div class="flex items-center gap-4">
        <div class="p-3 bg-gray-100 dark:bg-gray-900 rounded-xl text-gray-500 dark:text-gray-400">
          <History class="w-6 h-6" />
        </div>
        <div>
          <h3 class="font-medium text-gray-900 dark:text-gray-100">
            {recentStore.items.length} tools in history
          </h3>
          <p class="text-sm text-gray-500 dark:text-gray-400 mt-0.5">
            Your recently used tools appear dynamically on the Home page. We keep the last 15 tools.
          </p>
        </div>
      </div>
    </section>
  </div>
</div>
