<script lang="ts">
  import type { Snippet } from 'svelte';
  import ToolHeader from './ToolHeader.svelte';

  interface ToolWrapperProps {
    toolId?: string;
    title: string;
    description: string;
    isFullFrame?: boolean;
    headerAction?: Snippet; // Optional, some tools don't have mode buttons
    children: Snippet;
  }

  let {
    toolId,
    title,
    description,
    isFullFrame = false,
    headerAction, // For Toolbar (mode buttons)
    children      // For main content of Tool
  }: ToolWrapperProps = $props();

</script>

<div class="flex flex-col transition-all duration-400 {isFullFrame ? 'h-full' : ''}">
  <!-- Header section: Title & Description -->
  {#if !isFullFrame}
    <ToolHeader {toolId} {title} {description} />
  {/if}

  <!-- Box section of tool -->
  <div class="flex flex-col bg-white dark:bg-gray-800 transition-all duration-400 p-6 gap-6 border border-gray-200 rounded-2xl shadow-sm dark:border-gray-700 {
    isFullFrame ? 'flex-1' : ''
  }">

    <!-- Options/Modes -->
    {#if headerAction}
      <div class="flex flex-wrap items-center gap-6">
        {@render headerAction()}
      </div>
    {/if}

    <!-- Main content (Grid Input/Output) -->
    <div class="{isFullFrame ? 'flex-1' : ''}">
      {@render children()}
    </div>

  </div>
</div>
