<script lang="ts">
  import { i18n } from '$lib/i18n';
  import { FormatterLayout } from '$lib/components/layout';
  import { createEditorModes } from '$lib/utils/editorModes';
  import { Select } from '$lib/components/ui';
  import { toastStore } from '$lib/stores/ui/toast.svelte';

  import type { ToolDefinition } from '$lib/types';

  export interface JSONFormatterProps {
    tool: ToolDefinition;
  }

  let { tool }: JSONFormatterProps = $props();

  // Define JSON sample to save user when delete all
  const SAMPLE_JSON = `{\n  "project": "DeboxHub - Awesome tools",\n  "awesome": true,\n  "features": ["Converter", "Formatter", "Quick Parse"],\n  "status": {\n    "monacoEditor": "integrated",\n    "bugs": 0\n  }\n}`;
  const SAMPLE_PRINT_R = `Array
  (
      [project] => DeboxHub - Awesome tools
      [awesome] => true
      [features] => Array
          (
              [0] => Converter
              [1] => Formatter
              [2] => Quick Parse
          )
      [status] => Array
          (
              [monacoEditor] => integrated
              [bugs] => 0
          )
  )`;
  const SAMPLE_PYTHON_DICT = `{
    'project': 'DeboxHub - Awesome tools',
    'awesome': True,
    'features': ['Converter', 'Formatter', 'Quick Parse'],
    'status': {
        'monacoEditor': 'integrated',
        'bugs': 0
    }
  }`;

  let spaceCount = $state<number>(4);
  let inputFormat = $state<'standard' | 'print_r' | 'python_dict'>('standard');

  // Define modes for JSON Tool (JSON does not need Live Preview iframe)
  let jsonModes = $derived(createEditorModes(['pretty', 'minify']));
  let currentSample = $derived(
    inputFormat === 'print_r' ? SAMPLE_PRINT_R : 
    inputFormat === 'python_dict' ? SAMPLE_PYTHON_DICT : 
    SAMPLE_JSON
  );

  function parsePrintR(input) {
    // Normalize input and split into lines
    const lines = input.replace(/\r\n/g, '\n').split('\n');
    
    const root = {};
    const stack = [root]; // Stack to track array depth
    let lastKey = null;   // Store the keyword waiting to create a nested array

    // Regular expressions (Regex) to identify syntax
    const regexPair = /^\s*\[(.*?)\]\s*=>\s*(.*)$/;
    // const regexArrayStart = /^\s*(?:Array|[a-zA-Z0-9_\\]+\s+Object)\s*$/;
    const regexOpenBracket = /^\s*\(\s*$/;
    const regexCloseBracket = /^\s*\)\s*$/;

    for (let i = 0; i < lines.length; i++) {
      const line = lines[i].trimEnd(); // Remove trailing spaces, keep leading spaces
      if (!line) continue;

      // Case 1: Line contains Key => Value
      const matchPair = line.match(regexPair);
      if (matchPair) {
        const key = matchPair[1];
        let value = matchPair[2].trim();

        const currentContext = stack[stack.length - 1];

        // If value indicates this is a nested array/object
        if (value === 'Array' || value.endsWith('Object')) {
          currentContext[key] = {}; // Initialize empty object waiting for data insertion
          lastKey = key;            // Mark this key as ready to receive nested data
        } else {
          // Convert numerical values to standard JSON format
          if (!isNaN(value) && value !== '') {
            value = Number(value);
          } else if (value.toLowerCase() === 'true') {
            value = true;
          } else if (value.toLowerCase() === 'false') {
            value = false;
          } else if (value === '') {
            value = null; // Or leave as an empty string '' depending on your logic
          }

          currentContext[key] = value;
        }
        continue;
      }

      // Case 2: Encounter opening bracket '(' -> Enter deeper nesting level
      if (regexOpenBracket.test(line)) {
        if (lastKey !== null) {
          // Push the newly created child object onto the stack to start working with it
          const currentContext = stack[stack.length - 1];
          stack.push(currentContext[lastKey]);
          lastKey = null;
        }
        continue;
      }

      // Case 3: Encounter closing bracket ')' -> Exit current level
      if (regexCloseBracket.test(line)) {
        if (stack.length > 1) { // Ensure not to pop the root tag
          stack.pop();
        }
        continue;
      }

      // Skip other meaningless lines (like 'Array' standing alone without parentheses)
    }

    return root;
  }

  function parsePythonDict(input: string) {
    // Replace Python's True, False, None with JS's true, false, null
    const cleanInput = input
      .replace(/\bTrue\b/g, 'true')
      .replace(/\bFalse\b/g, 'false')
      .replace(/\bNone\b/g, 'null');
      
    // Use new Function to parse as a JS Object. This gracefully handles 
    // single quotes, trailing commas, and unquoted keys which are common in Python dicts.
    return new Function('return ' + cleanInput)();
  }

  // Processing function for JSON Tool
  function processJsonMode(input: string, mode: string): string {
    if (!input.trim()) return '';
    
    let parsedObject = null;
    let detectedFormat = inputFormat;

    const tryParse = (format: string) => {
      if (format === 'standard') {
        return JSON.parse(input);
      } else if (format === 'python_dict') {
        const obj = parsePythonDict(input);
        if (typeof obj === 'function' || typeof obj === 'undefined') throw new Error();
        return obj;
      } else if (format === 'print_r') {
        const obj = parsePrintR(input);
        if (Object.keys(obj).length === 0 && !input.includes('=>') && !input.includes('Array') && !input.includes('Object')) throw new Error();
        return obj;
      }
    };

    // First, try the user-selected format
    try {
      parsedObject = tryParse(inputFormat);
    } catch (e) {
      // Auto-detect fallback if it fails
      const fallbacks = ['standard', 'python_dict', 'print_r'].filter(f => f !== inputFormat);
      for (const f of fallbacks) {
        try {
          const obj = tryParse(f);
          if (obj !== null && typeof obj !== 'undefined') {
            parsedObject = obj;
            detectedFormat = f as 'standard' | 'print_r' | 'python_dict';
            break;
          }
        } catch (e2) {}
      }
    }

    if (parsedObject === null || typeof parsedObject === 'undefined') {
      return i18n.t('tools.json.error') || '// Invalid JSON data';
    }

    // Auto-switch the dropdown UI to the detected format (wrapped in setTimeout to avoid render-cycle warnings)
    if (detectedFormat !== inputFormat) {
      setTimeout(() => { 
        inputFormat = detectedFormat; 
        
        const formatNames = {
          'standard': 'Standard JSON',
          'print_r': 'PHP Print_r',
          'python_dict': 'Python Dict'
        };
        toastStore.success(`Auto-detected ${formatNames[detectedFormat]} format`);
      }, 0);
    }

    // Return the formatted string
    try {
      if (mode === 'pretty') {
        return JSON.stringify(parsedObject, null, Number(spaceCount));
      }
      return JSON.stringify(parsedObject);
    } catch (e) {
      return i18n.t('tools.json.error') || '// Invalid JSON data';
    }
  }
</script>

<FormatterLayout 
  {tool} 
  language="json" 
  modes={jsonModes}
  processFn={processJsonMode} 
  sampleCode={currentSample}
>
  {#snippet extraControls(currentMode)}
    <Select 
      id="inputFormat" 
      label="Input Format"
      bind:value={inputFormat}
    >
      <option value="standard">Standard JSON</option>
      <option value="print_r">PHP Print_r</option>
      <option value="python_dict">Python Dict</option>
    </Select>

    <Select 
      id="spaces" 
      label={i18n.t('common.editor.spaces') || 'Spaces'}
      bind:value={spaceCount}
      disabled={currentMode === 'minify'}
    >
      <option value={2}>2</option>
      <option value={4}>4</option>
      <option value={8}>8</option>
    </Select>
  {/snippet}
</FormatterLayout>