import { browser } from '$app/environment';

import type { LayoutProperties } from '$lib/types';
import { APP_CONFIG } from '$lib/constants/app';

function createLayoutStore() {
    // Initialize State as an Object
    const props = $state<LayoutProperties>({ ...APP_CONFIG.defaults.layout });

    if (browser) {
        // Read and parse JSON once at startup
        try {
            const saved = localStorage.getItem(APP_CONFIG.storageKeys.layout);
            if (saved) {
                const parsed = JSON.parse(saved) as Partial<LayoutProperties>;
                // Update state (combine with default values to prevent JSON from missing keys)
                Object.assign(props, parsed);
            }
        } catch (e) {
            console.error('Failed to parse layout preferences', e);
        }
    }

    // Helper function to write to storage
    function saveToStorage() {
        if (browser) {
            localStorage.setItem(APP_CONFIG.storageKeys.layout, JSON.stringify(props));
            document.body.dataset.sidebarCollapsed = props.isCollapsed.toString();
            document.body.dataset.layoutMode = props.mode;
        }
    }

    return {
        get mode() { return props.mode; },
        get isCollapsed() { return props.isCollapsed; },
        toggleMode: () => {
            props.mode = props.mode === 'vertical' ? 'horizontal' : 'vertical';
            saveToStorage();
        },
        toggleCollapse: () => {
            props.isCollapsed = !props.isCollapsed;
            saveToStorage();
        }
    };
}

export const layoutStore = createLayoutStore();