<script lang="ts">
  import type { Snippet } from 'svelte';

  let {
    children,
    content,
    position = 'top',
    align = 'center',
    wrapperClass = 'inline-block',
    contentClass = 'p-2 px-3',
    delay = 100,
    disabled = false
  }: {
    children: Snippet;
    content?: Snippet | string;
    position?: 'top' | 'bottom' | 'left' | 'right';
    align?: 'start' | 'center' | 'end';
    wrapperClass?: string;
    contentClass?: string;
    delay?: number;
    disabled?: boolean;
  } = $props();

  const positionClasses = {
    top: 'bottom-full mb-3',
    bottom: 'top-full mt-3',
    left: 'right-full mr-3',
    right: 'left-full ml-3'
  };

  const alignClasses = {
    top: { start: 'left-0', center: 'left-1/2 -translate-x-1/2', end: 'right-0' },
    bottom: { start: 'left-0', center: 'left-1/2 -translate-x-1/2', end: 'right-0' },
    left: { start: 'top-0', center: 'top-1/2 -translate-y-1/2', end: 'bottom-0' },
    right: { start: 'top-0', center: 'top-1/2 -translate-y-1/2', end: 'bottom-0' }
  };

  const arrowClasses = {
    top: {
      start: 'top-full left-4 -translate-y-1/2 border-b border-r',
      center: 'top-full left-1/2 -translate-x-1/2 -translate-y-1/2 border-b border-r',
      end: 'top-full right-4 -translate-y-1/2 border-b border-r'
    },
    bottom: {
      start: '-top-1.5 left-4 border-t border-l',
      center: '-top-1.5 left-1/2 -translate-x-1/2 border-t border-l',
      end: '-top-1.5 right-6 border-t border-l'
    },
    left: {
      start: 'left-full top-4 -translate-x-1/2 border-t border-r',
      center: 'left-full top-1/2 -translate-y-1/2 -translate-x-1/2 border-t border-r',
      end: 'left-full bottom-4 -translate-x-1/2 border-t border-r'
    },
    right: {
      start: '-left-1.5 top-4 border-b border-l',
      center: '-left-1.5 top-1/2 -translate-y-1/2 border-b border-l',
      end: '-left-1.5 bottom-4 border-b border-l'
    }
  };

  const transformClasses = {
    top: 'translate-y-2 group-hover/tooltip:translate-y-0',
    bottom: '-translate-y-2 group-hover/tooltip:translate-y-0',
    left: 'translate-x-2 group-hover/tooltip:translate-x-0',
    right: '-translate-x-2 group-hover/tooltip:translate-x-0'
  };
</script>

<div class="relative group/tooltip {wrapperClass}">
  {@render children()}
  
  {#if !disabled && content !== undefined && content !== null}
    <!-- svelte-ignore a11y_click_events_have_key_events -->
    <!-- svelte-ignore a11y_no_static_element_interactions -->
    <div 
      class="absolute {positionClasses[position]} {alignClasses[position][align]} z-50 opacity-0 invisible group-hover/tooltip:opacity-100 group-hover/tooltip:visible transition-all duration-300 transform {transformClasses[position]} cursor-default bg-white/95 dark:bg-gray-900/90 backdrop-blur-xl border border-gray-200/50 dark:border-gray-700/50 shadow-2xl rounded-xl text-xs font-medium text-gray-700 dark:text-gray-200 {contentClass}"
      style="transition-delay: {delay}ms"
      onclick={(e) => e.stopPropagation()}
      role="tooltip"
    >
      {#if typeof content === 'string'}
        {content}
      {:else if content}
        {@render content()}
      {/if}
      
      <div class="absolute w-3 h-3 bg-white dark:bg-gray-900 border-gray-200/50 dark:border-gray-700/50 rotate-45 {arrowClasses[position][align]}"></div>
    </div>
  {/if}
</div>
