<script lang="ts">
  import { goto } from '$app/navigation';
  import { i18n } from '$lib/i18n';
  import { searchStore } from '$lib/stores/ui/search.svelte';
  import { portal } from '$lib/actions/portal';
  import { Search, CornerDownLeft } from 'lucide-svelte';
  import { TOOL_ICON_MAP, FallbackIcon } from '$lib/registry';

  let selectedIndex = $state(0);
  let inputRef: HTMLInputElement;

  // Reset selection position to 0 every time the user types a new letter
  $effect(() => {
    searchStore.query; 
    selectedIndex = 0;
  });

  // Auto focus to the input field when Modal opens
  $effect(() => {
    if (searchStore.isOpen && inputRef) {
      setTimeout(() => inputRef.focus(), 50); 
    }
  });

  // Handle keyboard input (Up/Down/Enter/Esc)
  function handleKeydown(e: KeyboardEvent) {
    if (!searchStore.isOpen) return;

    const results = searchStore.results;

    switch (e.key) {
      case 'ArrowDown':
        e.preventDefault();
        selectedIndex = (selectedIndex + 1) % (results.length || 1);
        break;
      case 'ArrowUp':
        e.preventDefault();
        selectedIndex = (selectedIndex - 1 + results.length) % (results.length || 1);
        break;
      case 'Enter':
        e.preventDefault();
        if (results.length > 0 && results[selectedIndex]) {
          navigate(results[selectedIndex].slug);
        }
        break;
      case 'Escape':
        e.preventDefault();
        searchStore.close();
        break;
    }
  }

  // Navigate to tool and auto close Modal
  function navigate(toolSlug: string) {
    searchStore.close();
    goto(`/${toolSlug}`);
  }
</script>

<svelte:window onkeydown={handleKeydown} />

{#if searchStore.isOpen}
  <div use:portal>
    <div 
      class="fixed inset-0 z-[100] flex items-start justify-center pt-16 sm:pt-24 px-4 bg-gray-900/40 dark:bg-gray-950/60 backdrop-blur-sm animate-in fade-in duration-200"
      onclick={() => searchStore.close()}
    >
      
      <div 
        class="w-full max-w-2xl bg-white dark:bg-gray-900 rounded-2xl shadow-2xl overflow-hidden border border-gray-200 dark:border-gray-800 animate-in slide-in-from-top-4 fade-in duration-200"
        onclick={(e) => e.stopPropagation()} 
      >
        
        <div class="flex items-center px-4 py-4 border-b border-gray-100 dark:border-gray-800">
          <Search class="w-6 h-6 text-blue-500 mr-3 shrink-0" />
          <input 
            bind:this={inputRef}
            bind:value={searchStore.query}
            type="text" 
            placeholder="{i18n.t('common.ui.search')}" 
            class="flex-1 bg-transparent text-xl text-gray-900 dark:text-gray-100 placeholder:text-gray-400 outline-none ring-0 focus:outline-none focus:ring-0"
            autocomplete="off"
            spellcheck="false"
          >
          <div class="flex items-center gap-1 shrink-0 ml-3">
            <kbd class="px-2 py-1 text-[10px] font-sans font-bold text-gray-500 bg-gray-100 dark:bg-gray-800 rounded border border-gray-200 dark:border-gray-700">ESC</kbd>
          </div>
        </div>

        <div class="max-h-[60vh] overflow-y-auto custom-scrollbar p-2">
          {#if searchStore.query.trim() === ''}
            <div class="px-4 py-8 text-center text-sm text-gray-500 dark:text-gray-400">
              Start typing to search for tools...
            </div>
          {:else if searchStore.results.length === 0}
            <div class="px-4 py-8 text-center text-sm text-gray-500 dark:text-gray-400">
              No tools found for "<span class="text-gray-900 dark:text-gray-100 font-medium">{searchStore.query}</span>"
            </div>
          {:else}
            <div class="flex flex-col gap-1">
              {#each searchStore.results as tool, index (tool.id)}
                {@const Icon = TOOL_ICON_MAP[tool.icon || ''] || FallbackIcon}
                <button
                  onclick={() => navigate(tool.slug)}
                  class="flex items-center w-full px-3 py-3 rounded-xl transition-all cursor-pointer text-left {index === selectedIndex ? 'bg-blue-50 dark:bg-blue-900/20' : 'hover:bg-gray-50 dark:hover:bg-gray-800/50'}"
                  onmousemove={() => selectedIndex = index}
                >
                  <div class="flex items-center justify-center w-8 h-8 rounded-lg mr-3 shrink-0 {index === selectedIndex ? 'bg-blue-100 dark:bg-blue-800/50 text-blue-600 dark:text-blue-400' : 'bg-gray-100 dark:bg-gray-800 text-gray-500 dark:text-gray-400'}">
                    <Icon class="w-4 h-4" /> 
                  </div>
                  
                  <div class="flex flex-col flex-1 truncate pr-4">
                    <span class="text-sm font-semibold {index === selectedIndex ? 'text-blue-700 dark:text-blue-400' : 'text-gray-800 dark:text-gray-200'}">
                      {i18n.t(tool.name)}
                    </span>
                    <span class="text-xs text-gray-500 dark:text-gray-400 truncate">
                      {i18n.t(tool.description || '')}
                    </span>
                  </div>

                  {#if index === selectedIndex}
                    <CornerDownLeft class="w-4 h-4 text-blue-500 shrink-0 animate-pulse" />
                  {/if}
                </button>
              {/each}
            </div>
          {/if}
        </div>

      </div>
    </div>
  </div>
{/if}