import { browser } from '$app/environment';
import { APP_CONFIG } from '$lib/constants/app';
import type { RoadmapItem } from '$lib/types';

// Generate a random ID for new ideas
function generateId() {
	return 'idea-' + Math.random().toString(36).substring(2, 9);
}

function createRoadmapStore() {
	// Initialize states
	let upvotes = $state<string[]>([]);
	let userIdeas = $state<RoadmapItem[]>([]);

	// Load from localStorage when initializing
	if (browser) {
		const savedUpvotes = localStorage.getItem(APP_CONFIG.storageKeys.getViewKey('roadmap', 'upvotes'));
		if (savedUpvotes) {
			try {
				upvotes = JSON.parse(savedUpvotes);
			} catch (e) {
				console.error('Failed to parse roadmap upvotes', e);
			}
		}

		const savedIdeas = localStorage.getItem(APP_CONFIG.storageKeys.getViewKey('roadmap', 'userIdeas'));
		if (savedIdeas) {
			try {
				userIdeas = JSON.parse(savedIdeas);
			} catch (e) {
				console.error('Failed to parse roadmap userIdeas', e);
			}
		}
	}

	// Auto-save to localStorage when state changes
	$effect.root(() => {
		$effect(() => {
			if (browser) {
				localStorage.setItem(APP_CONFIG.storageKeys.getViewKey('roadmap', 'upvotes'), JSON.stringify(upvotes));
			}
		});

		$effect(() => {
			if (browser) {
				localStorage.setItem(APP_CONFIG.storageKeys.getViewKey('roadmap', 'userIdeas'), JSON.stringify(userIdeas));
			}
		});
	});

	return {
		get upvotes() {
			return upvotes;
		},
		get userIdeas() {
			return userIdeas;
		},

		hasUpvoted: (id: string) => {
			return upvotes.includes(id);
		},

		toggleUpvote: (id: string) => {
			if (upvotes.includes(id)) {
				upvotes = upvotes.filter((i) => i !== id);
			} else {
				upvotes = [...upvotes, id];
			}
		},

		addIdea: (idea: Omit<RoadmapItem, 'id' | 'status'>) => {
			const newItem: RoadmapItem = {
				...idea,
				id: generateId(),
				status: 'idea',
				votes: 0 // Base is 0, dynamic upvote will make it 1
			};
			
			userIdeas = [newItem, ...userIdeas];
			upvotes = [...upvotes, newItem.id]; // Auto-upvote their own idea
			return newItem;
		},

		deleteIdea: (id: string) => {
			userIdeas = userIdeas.filter((idea) => idea.id !== id);
			// Optional: Remove upvote if we want
			upvotes = upvotes.filter((upvoteId) => upvoteId !== id);
		}
	};
}

export const roadmapStore = createRoadmapStore();
