<script lang="ts">
  import { onMount, onDestroy } from 'svelte';
  import type * as Monaco from 'monaco-editor/esm/vs/editor/editor.api';

  interface DiffEditorProps {
    originalValue?: string;
    modifiedValue?: string;
    language?: string;
    renderSideBySide?: boolean;
    readOnly?: boolean;
    splitRatio?: number;
    gapWidth?: number;
    wordWrap?: boolean;
  }

  let {
    originalValue = $bindable(''),
    modifiedValue = $bindable(''),
    language = 'plaintext',
    renderSideBySide = true,
    readOnly = false,
    splitRatio = $bindable(0.5),
    gapWidth = $bindable(14),
    wordWrap = true
  }: DiffEditorProps = $props();

  let editorContainer: HTMLDivElement;
  
  // Prevent $state to make Svelte not create Proxy
  let diffEditor: Monaco.editor.IStandaloneDiffEditor;
  let isUpdatingFromLayout = false;

  let originalModel: Monaco.editor.ITextModel;
  let modifiedModel: Monaco.editor.ITextModel;
  let monaco: typeof Monaco;
  let themeObserver: MutationObserver;
  let containerResizeObserver: ResizeObserver;

  function getSystemTheme() {
    if (typeof document === 'undefined') return 'vs-dark';
    return document.documentElement.classList.contains('dark') ? 'vs-dark' : 'vs';
  }

  const editorOptions = {
    automaticLayout: true,
    formatOnPaste: false,
    formatOnType: false,
    minimap: { enabled: false },
    fontSize: 14,
    fontFamily: "'Fira Code', 'Consolas', monospace",
    scrollBeyondLastLine: false,
    roundedSelection: true,
    padding: { top: 16, bottom: 16 },
    renderSideBySide: true,
    readOnly: false,
    glyphMargin: false,
    folding: false,
    lineDecorationsWidth: 11,
    renderOverviewRuler: false,
    wordWrap: wordWrap ? 'on' : 'off'
  };

  onMount(async () => {
    monaco = (await import('$lib/utils/monaco')).default;

    diffEditor = monaco.editor.createDiffEditor(editorContainer, {
      theme: getSystemTheme(),
      ...editorOptions,
      renderSideBySide,
      splitViewDefaultRatio: splitRatio,
      readOnly,
      originalEditable: !readOnly
    });

    originalModel = monaco.editor.createModel(originalValue, language);
    modifiedModel = monaco.editor.createModel(modifiedValue, language);

    diffEditor.setModel({
      original: originalModel,
      modified: modifiedModel
    });

    // Optimize left pane (Original Editor) to have a narrower margin
    diffEditor.getOriginalEditor().updateOptions({
      lineNumbersMinChars: 1
    });

    // Optimize right pane (Modified Editor) to have a narrower margin
    diffEditor.getModifiedEditor().updateOptions({
      lineNumbersMinChars: 3
    });

    // Listen for layout changes (e.g. user dragging the sash) to sync the header
    const updateLayout = () => {
      if (!renderSideBySide || !editorContainer || editorContainer.clientWidth === 0) return;
      
      const originalWidth = diffEditor.getOriginalEditor().getLayoutInfo().width;
      const modifiedWidth = diffEditor.getModifiedEditor().getLayoutInfo().width;
      const containerWidth = editorContainer.clientWidth;
      
      const contentWidth = originalWidth + modifiedWidth;
      if (contentWidth === 0) return;
      
      const newRatio = originalWidth / contentWidth;
      if (Math.abs(splitRatio - newRatio) > 0.005) {
        isUpdatingFromLayout = true;
        splitRatio = newRatio;
        setTimeout(() => isUpdatingFromLayout = false, 10);
      }
      
      const newGap = containerWidth - originalWidth - modifiedWidth;
      if (newGap >= 0 && Math.abs(gapWidth - newGap) > 0.5) {
        gapWidth = newGap;
      }
    };

    diffEditor.getOriginalEditor().onDidLayoutChange(updateLayout);
    diffEditor.getModifiedEditor().onDidLayoutChange(updateLayout);

    // Listen for changes in the original model
    originalModel.onDidChangeContent(() => {
      if (readOnly) return;
      const currentValue = originalModel.getValue();
      if (currentValue !== originalValue) {
        originalValue = currentValue;
      }
    });

    // Listen for changes in the modified model
    modifiedModel.onDidChangeContent(() => {
      if (readOnly) return;
      const currentValue = modifiedModel.getValue();
      if (currentValue !== modifiedValue) {
        modifiedValue = currentValue;
      }
    });

    themeObserver = new MutationObserver(() => {
      monaco.editor.setTheme(getSystemTheme());
    });
    // Fix initial load and resize issues where Monaco loses the split ratio
    containerResizeObserver = new ResizeObserver(() => {
      if (diffEditor && !isUpdatingFromLayout) {
        // Enforce the Svelte splitRatio onto Monaco when container resizes
        diffEditor.updateOptions({ splitViewDefaultRatio: splitRatio });
        
        // Also force a layout recalculation for the gap
        setTimeout(updateLayout, 50);
      }
    });
    containerResizeObserver.observe(editorContainer);
  });

  // Watch for external changes to originalValue
  $effect(() => {
    const currentValue = originalValue;
    if (originalModel && currentValue !== originalModel.getValue()) {
      originalModel.setValue(currentValue);
    }
  });

  // Watch for external changes to modifiedValue
  $effect(() => {
    const currentValue = modifiedValue;
    if (modifiedModel && currentValue !== modifiedModel.getValue()) {
      modifiedModel.setValue(currentValue);
    }
  });

  // Watch for renderSideBySide option changes
  $effect(() => {
    const currentSideBySide = renderSideBySide;
    if (diffEditor) {
      diffEditor.updateOptions({ renderSideBySide: currentSideBySide });
    }
  });

  // Watch for readOnly option changes
  $effect(() => {
    const currentReadOnly = readOnly;
    if (diffEditor) {
      diffEditor.updateOptions({ readOnly: currentReadOnly, originalEditable: !currentReadOnly });
    }
  });

  $effect(() => {
    const currentWordWrap = wordWrap;
    if (diffEditor) {
      diffEditor.updateOptions({ wordWrap: currentWordWrap ? 'on' : 'off' });
    }
  });

  // Watch for splitRatio changes
  $effect(() => {
    const currentRatio = splitRatio;
    if (diffEditor && !isUpdatingFromLayout) {
      diffEditor.updateOptions({ splitViewDefaultRatio: currentRatio });
    }
  });

  // Watch for language changes
  $effect(() => {
    const currentLang = language;
    if (monaco && originalModel && modifiedModel) {
      monaco.editor.setModelLanguage(originalModel, currentLang);
      monaco.editor.setModelLanguage(modifiedModel, currentLang);
    }
  });

  onDestroy(() => {
    if (diffEditor) diffEditor.dispose();
    if (originalModel) originalModel.dispose();
    if (modifiedModel) modifiedModel.dispose();
    if (themeObserver) themeObserver.disconnect();
    if (containerResizeObserver) containerResizeObserver.disconnect();
  });
</script>

<div bind:this={editorContainer} class="w-full h-full min-h-[400px]"></div>
