<script lang="ts">
  import { i18n } from '$lib/i18n';
  import { ConverterLayout } from '$lib/components/layout';

  import type { ToolDefinition } from '$lib/types';

  export interface URLConverterProps {
    tool: ToolDefinition;
  }

  let { tool }: URLConverterProps = $props();

  function processUrl(input: string, mode: 'encode' | 'decode') {
    try {
      if (mode === 'encode') {
        return { value: encodeURIComponent(input), error: false };
      } else {
        return { value: decodeURIComponent(input), error: false };
      }
    } catch (e) {
      return { value: i18n.t('tools.url.error'), error: true };
    }
  }
</script>

<ConverterLayout {tool} processFn={processUrl} />