<script lang="ts">
  import { i18n } from '$lib/i18n';
  import { ButtonIcon } from '$lib/components/ui';
  import { Maximize, Minimize } from 'lucide-svelte';

  interface Props {
    isFullFrame?: boolean;
    class?: string;
  }

  let { isFullFrame = $bindable(false), class: className = '' }: Props = $props();
</script>

<ButtonIcon 
  onclick={() => isFullFrame = !isFullFrame}
  color="custom"
  class="group flex items-center justify-center w-8 h-8 text-gray-700 dark:text-gray-300 hover:text-blue-600 dark:hover:text-blue-400 bg-white dark:bg-gray-900 rounded-md border border-gray-200 dark:border-gray-800 hover:border-blue-300 dark:hover:border-blue-800 shadow-sm transition-all {className}"
  title={isFullFrame ? i18n.t('ui.tooltips.screen.exitFull') : i18n.t('ui.tooltips.screen.full')}
  aria-label={isFullFrame ? i18n.t('ui.tooltips.screen.exitFull') : i18n.t('ui.tooltips.screen.full')}
>
  {#if isFullFrame}
    <Minimize class="w-4 h-4 transition-transform duration-200 group-hover:scale-90" />
  {:else}
    <Maximize class="w-4 h-4 transition-transform duration-200 group-hover:scale-110" />
  {/if}
</ButtonIcon>
