<script lang="ts">
  import { i18n } from '$lib/i18n';

  import { FormatterLayout } from '$lib/components/layout';
  import { createEditorModes } from '$lib/utils/editorModes';
  import { Select } from '$lib/components/ui';

  import type { ToolDefinition } from '$lib/types';

  const SAMPLE_CODE = '<div class="hello">\n\t<h1>Hello Debox!</h1>\n\t<p>Live preview is awesome.</p>\n</div>';

  export interface HtmlFormatterProps {
    tool: ToolDefinition;
  }

  let { tool }: HtmlFormatterProps = $props();

  let spaceCount = $state<number>(2);

  let htmlModes = $derived(createEditorModes(['pretty', 'minify', 'preview']));

  // Format HTML minified
  function minifyHtml(raw: string): string {
    return raw
      .replace(/<!--[\s\S]*?-->/g, '') // Remove comments
      .replace(/\s+/g, ' ')            // Remove multiple spaces
      .replace(/>\s+</g, '><')         // Remove spaces between tags
      .trim();
  }

  // Algorithm format HTML basic (Indent)
  function prettyHtml(raw: string): string {
    let formatted = '';
    let pad = 0;
    const lines = raw.replace(/>\s*</g, '>\n<').split('\n');
    
    const voidTags = ['area', 'base', 'br', 'col', 'embed', 'hr', 'img', 'input', 'link', 'meta', 'param', 'source', 'track', 'wbr'];

    for (let i = 0; i < lines.length; i++) {
      let line = lines[i].trim();
      if (!line) continue;
      
      let indent = 0;
      
      if (line.match(/^<\/\w/)) {
        if (pad !== 0) pad -= 1;
      } else {
        const match = line.match(/^<([a-zA-Z][a-zA-Z0-9\-]*)/);
        if (match) {
          const tagName = match[1].toLowerCase();
          const hasClosingTag = new RegExp(`<\/${tagName}>`, 'i').test(line);
          if (!voidTags.includes(tagName) && !hasClosingTag && !line.match(/\/>$/)) {
            indent = 1;
          }
        }
      }
      
      formatted += ' '.repeat(pad * Number(spaceCount)) + line + '\n';
      pad += indent;
    }
    return formatted.trim();
  }

  function processHtmlMode(input: string, mode: string): string {
    if (mode === 'pretty') return prettyHtml(input);
    if (mode === 'minify') return minifyHtml(input);
    return input;
  }
</script>

<FormatterLayout 
  {tool}
  sampleCode={SAMPLE_CODE}
  language="html"
  modes={htmlModes}
  processFn={processHtmlMode} 
>
  {#snippet extraControls(currentMode)}
      <Select 
        id="spaces" 
        label={i18n.t('common.editor.spaces') || 'Spaces'}
        bind:value={spaceCount}
        disabled={currentMode === 'minify'}
      >
        <option value={2}>2</option>
        <option value={4}>4</option>
        <option value={8}>8</option>
      </Select>
  {/snippet}
</FormatterLayout>