<script lang="ts">
  import { slide } from 'svelte/transition';
  import { i18n } from '$lib/i18n';
  import { Badge, Modal, ButtonIcon, ButtonFavorite } from '$lib/components/ui';
  import { getCategoryByToolId, loadToolDoc } from '$lib/registry';
  import { copyText } from '$lib/utils/clipboard';
  import { SOCIAL_LINKS } from '$lib/constants/social';
  import { page } from '$app/stores';
  import { BookOpen, Link, Bug } from 'lucide-svelte';

  interface ToolHeaderProps {
    toolId?: string;
    title: string;
    description: string;
  }

  let { toolId, title, description }: ToolHeaderProps = $props();

  let category = $derived(toolId ? getCategoryByToolId(toolId) : undefined);
  let isDocsOpen = $state(false);

  function handleShare() {
    copyText($page.url.href);
  }
</script>

<div class="pb-6 flex flex-col md:flex-row md:items-start justify-between gap-4" transition:slide={{ duration: 400 }}>
  <div>
    <div class="flex items-center gap-3 mb-2">
      <h1 class="text-3xl font-bold tracking-tight text-gray-900 dark:text-gray-100">
        {title}
      </h1>
      {#if category}
        <Badge variant="blue" size="md">{i18n.t(category.name)}</Badge>
      {/if}
    </div>
    <p class="text-gray-500 dark:text-gray-400">
      {description}
    </p>
  </div>

  <!-- Action Group -->
  {#if toolId}
    <div class="flex items-center gap-2 shrink-0">
      <ButtonFavorite id={toolId} class="!p-2" size={20} />
      
      <ButtonIcon 
        onclick={handleShare}
        color="gray"
        class="!p-2"
        title="Share / Copy Link"
      >
        <Link class="w-5 h-5" />
      </ButtonIcon>

      <ButtonIcon 
        href={SOCIAL_LINKS.find(l => l.id === 'github-issues')?.url || '#'}
        target="_blank"
        color="gray"
        class="!p-2"
        title="Report Bug"
      >
        <Bug class="w-5 h-5" />
      </ButtonIcon>

      <ButtonIcon 
        onclick={() => isDocsOpen = true}
        color="gray"
        class="!p-2 text-blue-600 hover:bg-blue-50 dark:text-blue-400 dark:hover:bg-blue-900/30"
        title="Tool Information"
      >
        <BookOpen class="w-5 h-5" />
      </ButtonIcon>
    </div>
  {/if}
</div>

<Modal bind:isOpen={isDocsOpen} title="{title} - Documentation" maxWidth="max-w-3xl">
  {#if toolId}
    {#await loadToolDoc(toolId)}
      <div class="flex items-center gap-3 text-gray-500 dark:text-gray-400 py-8 justify-center">
        <div class="w-5 h-5 rounded-full border-2 border-gray-300 dark:border-gray-600 border-t-blue-600 animate-spin"></div>
        <span class="text-sm font-medium">Loading documentation...</span>
      </div>
    {:then DocComponent}
      {#if DocComponent}
        <div class="prose prose-blue dark:prose-invert max-w-none">
          <DocComponent />
        </div>
      {:else}
        <div class="prose prose-blue dark:prose-invert max-w-none text-gray-600 dark:text-gray-300 py-4 text-center border-2 border-dashed border-gray-200 dark:border-gray-800 rounded-2xl">
          <p>Documentation for <strong>{title}</strong> is currently being written.</p>
        </div>
      {/if}
    {/await}
  {/if}
</Modal>
