import { tools, allTools } from './tools';
import { categories } from './categories';

// -- Categories Zone --

// Get all categories sorted by order and include tools in each category
export function getStructuredCategories() {
	return categories
		.map((category) => ({
			...category,
			tools: tools.filter((t) => t.categoryId === category.id)
		}))
		.filter((category) => category.tools.length > 0)
		.sort((a, b) => a.order - b.order);
}

// Get Category by URL Slug
export function getCategoryBySlug(slug: string) {
	return categories.find((c) => c.slug === slug);
}

// Get Category by Internal ID
export function getCategoryById(id: string) {
	return categories.find((c) => c.id === id);
}

// Get parent Category of a Tool
export function getCategoryByToolId(toolId: string) {
	const tool = getToolById(toolId);
	if (!tool) return undefined;
	return categories.find((c) => c.id === tool.categoryId);
}

// -- Tools Zone --

// Get Tool by URL Slug
export function getToolBySlug(slug: string) {
	return allTools.find((t) => t.slug === slug && t.visibility !== 'private');
}

// Get Tool by Internal ID
export function getToolById(id: string) {
	return allTools.find((t) => t.id === id && t.visibility !== 'private');
}

// Get Tools by Category ID
export function getToolsByCategoryId(id: string) {
	return tools.filter((tool) => tool.categoryId === id);
}

// Get Tools Grouped by Category
export function getToolsGroupedByCategory() {
	return categories.map((category) => ({
		...category,
		tools: tools.filter((tool) => tool.categoryId === category.id)
	}));
}
