<script lang="ts">
  export interface SeparatorProps {
    orientation?: 'vertical' | 'horizontal';
    size?: '2' | '4' | '6' | '8' | 'f'; // Limit standard sizes
    variant?: 'gradient' | 'solid' | 'dashed' | 'gradient-left' | 'gradient-right';
    class?: string;
  }

  let {
    orientation = 'horizontal',
    size = 'f', 
    variant = 'gradient',
    class: className = ''
  }: SeparatorProps = $props();

  // Create size dictionary map kích thước chuẩn xác cho Tailwind
  const sizeClasses = {
    horizontal: {
      '2': 'h-px w-2',
      '4': 'h-px w-4',
      '6': 'h-px w-6',
      '8': 'h-px w-8',
      'f': 'h-px w-full'
    },
    vertical: {
      '2': 'w-px h-2',
      '4': 'w-px h-4',
      '6': 'w-px h-6',
      '8': 'w-px h-8',
      'f': 'w-px h-full'
    }
  };

  // Use $derived to automatically update class if props change
  let variantClasses = $derived({
    gradient: `${orientation === 'vertical' ? 'bg-gradient-to-b' : 'bg-gradient-to-r'} from-transparent via-gray-200 dark:via-gray-700 to-transparent`,
    'gradient-left': `${orientation === 'vertical' ? 'bg-gradient-to-b' : 'bg-gradient-to-r'} from-gray-200 dark:from-gray-700 to-transparent`,
    'gradient-right': `${orientation === 'vertical' ? 'bg-gradient-to-t' : 'bg-gradient-to-l'} from-gray-200 dark:from-gray-700 to-transparent`,
    solid: 'bg-gray-200 dark:bg-gray-800',
    dashed: `bg-transparent ${orientation === 'vertical' ? 'border-l border-dashed border-gray-200 dark:border-gray-700' : 'border-t border-dashed border-gray-200 dark:border-gray-700'}`
  });

  let computedClass = $derived(
    `shrink-0 transition-colors ${variantClasses[variant]} ${sizeClasses[orientation][size]} ${className}`
  );
</script>

<div 
  role="separator"
  aria-orientation={orientation}
  class={computedClass}
></div>