export function getRoadmapItems(): RoadmapItem[] {
	// Map existing public tools to 'released' status
	const releasedItems: RoadmapItem[] = tools.map((tool) => ({
		id: tool.id,
		name: tool.name, // Can be i18n key or string
		description: tool.description,
		categoryId: tool.categoryId,
		status: 'released',
		icon: tool.icon || 'Box',
		slug: tool.slug,
		date: tool.date || '2026-06-01', // Default mock date for released tools if missing
		version: tool.version || 'v1.0.0' // Default mock version for current tools
	}));

	// Return combined list
	return [...upcomingRoadmapItems, ...releasedItems];
}
