<script lang="ts">
  import { browser } from '$app/environment';

  import { i18n } from '$lib/i18n';
  import { searchStore } from '$lib/stores/ui/search.svelte';
  
  import {Search} from 'lucide-svelte';

  let modifierKey = $state('⌘');

  $effect(() => {
    if (browser) {
      modifierKey = window.navigator.userAgent.toLowerCase().includes('mac') ? '⌘' : 'Ctrl';
    }
  });

  // Put keyboard shortcut logic from Header into this Component
  function handleKeydown(e: KeyboardEvent) {
    if ((e.metaKey || e.ctrlKey) && (e.key === 'k' || e.key === '/')) {
      e.preventDefault(); 
      searchStore.open(); 
    }
  }
</script>

<svelte:window onkeydown={handleKeydown} />

<button 
  onclick={() => searchStore.open()}
  class="relative hidden sm:flex items-center h-9 px-2.5 rounded-xl border border-transparent bg-transparent text-gray-500 hover:bg-gray-100/50 dark:hover:bg-gray-800/50 hover:border-gray-200/60 dark:hover:border-gray-700/50 hover:text-gray-900 dark:hover:text-gray-100 transition-all duration-500 ease-[cubic-bezier(0.4,0,0.2,1)] outline-none group cursor-pointer overflow-hidden w-9 hover:w-48 md:hover:w-56"
  aria-label={i18n.t('common.ui.search')}
>
  <div class="absolute inset-0 flex items-center px-2.5">
    <Search class="w-4 h-4 shrink-0 transition-colors duration-300 group-hover:text-blue-500" />
    
    <div class="flex items-center justify-between opacity-0 group-hover:opacity-100 translate-x-2 group-hover:translate-x-0 w-full transition-all duration-500 ml-2.5 whitespace-nowrap overflow-hidden">
      <span class="text-sm font-medium">{i18n.t('common.ui.search')}</span>
      <kbd class="flex shrink-0 items-center gap-0.5 px-1.5 py-0.5 text-[10px] font-sans font-semibold text-gray-500 dark:text-gray-400 bg-white/80 dark:bg-gray-900/80 border border-gray-200/60 dark:border-gray-700/60 rounded shadow-sm mr-2">
        <span>{modifierKey}</span><span>K</span>
      </kbd>
    </div>
  </div>
</button>