<script lang="ts">
	import { browser } from '$app/environment';
	import { fade, fly } from 'svelte/transition';

	import { i18n } from '$lib/i18n';
	import { getRoadmapItems, ROADMAP_STATUS_GROUPS } from '$lib/registry/roadmap';
	import { categories } from '$lib/registry/categories';
	import { APP_CONFIG } from '$lib/constants/app';
	import { roadmapStore } from '$lib/stores/roadmap.svelte';

	import RoadmapColumn from './RoadmapColumn.svelte';
	import RoadmapTimeline from './RoadmapTimeline.svelte';
	import SubmitIdeaModal from './SubmitIdeaModal.svelte';
	import { FilterTab, SegmentedControl, SearchInput, Button } from '$lib/components/ui';
	import { Kanban, Route, Plus } from 'lucide-svelte';
	import { FEATURES } from '$lib/constants/features';

	let baseItems = $state(getRoadmapItems());
	let items = $derived([...roadmapStore.userIdeas, ...baseItems]); // Put ideas first
	
	let selectedCategory = $state<string>('all');
	let searchQuery = $state<string>('');

	// Modal State
	let isModalOpen = $state(false);

	// Default to 'timeline' unless 'kanban' is saved in localStorage
	let viewMode = $state<'kanban' | 'timeline'>('timeline');

	if (browser) {
		const savedView = localStorage.getItem(APP_CONFIG.storageKeys.getViewKey('roadmap', 'mode'));
		if (savedView === 'kanban' || savedView === 'timeline') {
			viewMode = savedView;
		}
	}

	// Save to localStorage when changed
	$effect(() => {
		if (browser) {
			localStorage.setItem(APP_CONFIG.storageKeys.getViewKey('roadmap', 'mode'), viewMode);
		}
	});

	// Filtering logic
	let filteredItems = $derived(
		items.filter((item) => {
			const matchCategory = selectedCategory === 'all' || item.categoryId === selectedCategory;
			const query = searchQuery.toLowerCase();
			const matchSearch = !query || 
				item.name.toLowerCase().includes(query) || 
				(item.description && item.description.toLowerCase().includes(query));
			
			return matchCategory && matchSearch;
		})
	);

	// Grouping into columns (for Kanban)
	// Reverse the array so Kanban flows from Idea (left) to Released (right)
	let kanbanColumns = $derived(
		[...ROADMAP_STATUS_GROUPS].reverse().map((group) => ({
			...group,
			items: filteredItems.filter((i) => i.status === group.id)
		}))
	);

	let viewOptions = $derived([
		{ value: 'timeline', label: i18n.t('page.roadmap.view.timeline') || 'Timeline', icon: Route },
		{ value: 'kanban', label: i18n.t('page.roadmap.view.kanban') || 'Kanban', icon: Kanban }
	]);


</script>

<div class="flex flex-col gap-8">
	<!-- Controls Row -->
	<div class="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
		<!-- Left: View Toggle -->
		<SegmentedControl
			bind:value={viewMode}
			options={viewOptions}
			class="w-fit shrink-0 rounded-xl hidden sm:flex"
		/>

		<!-- Right: Search & Submit -->
		<div class="flex items-center justify-end gap-3">
			<SearchInput bind:value={searchQuery} placeholder="Search ideas..." expandable={true} />

			{#if FEATURES.SUBMIT_IDEA}
				<Button 
					onclick={() => isModalOpen = true}
					color="blue"
				>
					<Plus class="w-4 h-4" /> <span>{i18n.t('page.roadmap.submit.button') || 'Submit Idea'}</span>
				</Button>
			{/if}
		</div>
	</div>

	<!-- Categories Row -->
	<div class="flex flex-wrap items-center gap-2">
		<FilterTab
			active={selectedCategory === 'all'}
			onclick={() => (selectedCategory = 'all')}
		>
			{i18n.t('common.all') || 'All'}
		</FilterTab>

		{#each categories as category (category.id)}
			<FilterTab
				active={selectedCategory === category.id}
				onclick={() => (selectedCategory = category.id)}
			>
				{i18n.t(category.name) || category.name}
			</FilterTab>
		{/each}
	</div>

	<!-- Board / Timeline -->
	<div class="grid" style="grid-template-areas: 'overlap'; align-items: start;">
		{#if viewMode === 'kanban'}
			<div 
				style="grid-area: overlap;"
				in:fly={{ y: 20, duration: 300, delay: 150 }}
				out:fade={{ duration: 150 }}
				class="grid grid-cols-1 gap-6 md:grid-cols-2 lg:grid-cols-4 lg:gap-8 w-full"
			>
				{#each kanbanColumns as col (col.id)}
					<RoadmapColumn 
						title={i18n.t(col.key) || col.id} 
						items={col.items} 
						icon={col.icon} 
						iconColor={col.iconColor} 
					/>
				{/each}
			</div>
		{:else}
			<div 
				style="grid-area: overlap;"
				in:fly={{ y: 20, duration: 300, delay: 150 }}
				out:fade={{ duration: 150 }}
				class="w-full"
			>
				<RoadmapTimeline items={filteredItems} />
			</div>
		{/if}
	</div>
</div>

<!-- Submit Idea Modal -->
<SubmitIdeaModal bind:isOpen={isModalOpen} />
