import { settingsStore } from '$lib/stores/settings.svelte';

/**
 * Convert a Date object to a YYYY-MM-DDTHH:mm:ss string for input datetime-local
 */
export function getDatetimeLocalString(d: Date): string {
	const pad = (n: number) => n.toString().padStart(2, '0');
	return `${d.getFullYear()}-${pad(d.getMonth() + 1)}-${pad(d.getDate())}T${pad(d.getHours())}:${pad(d.getMinutes())}:${pad(d.getSeconds())}`;
}

/**
 * Calculate the relative time (e.g., "3 minutes ago", "2 days later")
 */
export function getRelativeTime(targetDate: Date, locale: string): string {
	const rtf = new Intl.RelativeTimeFormat(locale === 'vi' ? 'vi-VN' : 'en-US', { numeric: 'auto' });
	const diffMs = targetDate.getTime() - Date.now();

	const diffDays = Math.round(diffMs / (1000 * 60 * 60 * 24));
	if (Math.abs(diffDays) >= 1) return rtf.format(diffDays, 'day');

	const diffHours = Math.round(diffMs / (1000 * 60 * 60));
	if (Math.abs(diffHours) >= 1) return rtf.format(diffHours, 'hour');

	const diffMinutes = Math.round(diffMs / (1000 * 60));
	return rtf.format(diffMinutes, 'minute');
}

/**
 * Generate formatted date string based on global settings
 */
export function getFormattedDate(date: Date, locale: string, timeZone?: string): string {
	const { timeFormat, dateFormat } = settingsStore.config;
	const currentLocale = locale === 'vi' ? 'vi-VN' : 'en-US';

	const textMonthFormatter = new Intl.DateTimeFormat(currentLocale, { month: 'short', timeZone });
	const monthText = textMonthFormatter.format(date);

	let dateStr = '';
	const yyyy = timeZone === 'UTC' ? date.getUTCFullYear() : date.getFullYear();
	const mm = String(timeZone === 'UTC' ? date.getUTCMonth() + 1 : date.getMonth() + 1).padStart(
		2,
		'0'
	);
	const dd = String(timeZone === 'UTC' ? date.getUTCDate() : date.getDate()).padStart(2, '0');

	switch (dateFormat) {
		case 'iso':
			dateStr = `${yyyy}-${mm}-${dd}`;
			break;
		case 'eu':
			dateStr = `${dd}/${mm}/${yyyy}`;
			break;
		case 'us':
			dateStr = `${mm}/${dd}/${yyyy}`;
			break;
		case 'text-us':
			dateStr = `${monthText} ${dd}, ${yyyy}`;
			break;
		case 'text-eu':
			dateStr = `${dd} ${monthText} ${yyyy}`;
			break;
		default:
			dateStr = `${yyyy}-${mm}-${dd}`;
	}

	const timeStr = new Intl.DateTimeFormat(currentLocale, {
		hour: '2-digit',
		minute: '2-digit',
		second: '2-digit',
		hour12: timeFormat === '12h',
		timeZone
	}).format(date);

	return `${dateStr}, ${timeStr}`;
}

export interface ConversionResult {
	type: 'date' | 'timestamp' | 'error';
	value: string;
	hint: string;
	tooltip?: {
		gmt: string;
		local: string;
		userSelected?: {
			label: string;
			value: string;
		};
		relative: string;
	};
}

/**
 * The core smart function to handle conversion between Date and Timestamp
 */
export function convertDateOrTimestamp(
	mode: 'decode' | 'encode',
	inputValue: string,
	timezone: string,
	locale: string,
	invalidFormatMsg: string
): ConversionResult | null {
	const val = inputValue.trim();
	if (!val) return null;

	let targetDate: Date;
	let type: 'date' | 'timestamp' | 'error';
	let value: string;
	let hint: string;

	let offsetHours = 0;
	let isOffset = false;
	if (timezone !== 'local' && timezone !== 'gmt') {
		offsetHours = parseFloat(timezone);
		isOffset = !isNaN(offsetHours);
	}

	if (mode === 'decode') {
		if (!/^\d+$/.test(val)) return { type: 'error', value: invalidFormatMsg, hint: '' };
		const ts = parseInt(val);
		targetDate = new Date(ts > 9999999999 ? ts : ts * 1000);
		type = 'date';

		if (timezone === 'local') {
			value = getFormattedDate(targetDate, locale);
			hint = 'Local Time';
		} else if (timezone === 'gmt') {
			value = getFormattedDate(targetDate, locale, 'UTC');
			hint = 'UTC';
		} else if (isOffset) {
			const shiftedDate = new Date(targetDate.getTime() + offsetHours * 60 * 60 * 1000);
			value = getFormattedDate(shiftedDate, locale, 'UTC');
			const sign = offsetHours >= 0 ? '+' : '';
			hint = `GMT${sign}${offsetHours}`;
		} else {
			value = getFormattedDate(targetDate, locale);
			hint = 'Local Time';
		}
	} else {
		let dateString = val;
		if (timezone === 'gmt') {
			dateString = `${val}Z`;
			targetDate = new Date(dateString);
		} else if (isOffset) {
			const sign = offsetHours >= 0 ? '+' : '-';
			const absOffset = Math.abs(offsetHours);
			const offsetH = String(Math.floor(absOffset)).padStart(2, '0');
			const offsetM = String(Math.floor((absOffset % 1) * 60)).padStart(2, '0');
			dateString = `${val}${sign}${offsetH}:${offsetM}`;
			targetDate = new Date(dateString);
		} else {
			targetDate = new Date(val);
		}

		if (isNaN(targetDate.getTime())) return { type: 'error', value: invalidFormatMsg, hint: '' };

		type = 'timestamp';
		value = Math.floor(targetDate.getTime() / 1000).toString();

		if (timezone === 'gmt') {
			hint = getFormattedDate(targetDate, locale) + ' (Local)';
		} else if (isOffset) {
			const sign = offsetHours >= 0 ? '+' : '';
			hint = getFormattedDate(targetDate, locale) + ` (Local) / from GMT${sign}${offsetHours}`;
		} else {
			hint = getFormattedDate(targetDate, locale, 'UTC') + ' (UTC)';
		}
	}

	const tooltip: ConversionResult['tooltip'] = {
		gmt: getFormattedDate(targetDate, locale, 'UTC'),
		local: getFormattedDate(targetDate, locale),
		relative: getRelativeTime(targetDate, locale)
	};

	if (isOffset) {
		const shiftedDate = new Date(targetDate.getTime() + offsetHours * 60 * 60 * 1000);
		const sign = offsetHours >= 0 ? '+' : '';
		tooltip.userSelected = {
			label: `GMT${sign}${offsetHours}`,
			value: getFormattedDate(shiftedDate, locale, 'UTC')
		};
	}

	return { type, value, hint, tooltip };
}
