<script lang="ts">
  import QRCodeStyling from 'qr-code-styling';
  import { onMount } from 'svelte';
  import { i18n } from '$lib/i18n';
  import SplitWorkspace from '$lib/components/layout/templates/SplitWorkspace.svelte';
  import { createTool } from '$lib/stores';
  import type { ToolDefinition } from '$lib/types';
  import { SegmentedControl, Separator, ButtonIcon, Button } from '$lib/components/ui';
  import { DownloadCloud, Link, Wifi, Contact, Mail, MessageSquare, Trash2, Upload, RefreshCw, QrCode, Palette, Shapes, Image, Settings } from 'lucide-svelte';

  export interface QrCodeGeneratorProps {
    tool: ToolDefinition;
  }

  let { tool }: QrCodeGeneratorProps = $props();

  const storage = createTool(tool.slug, {
    mode: 'text', // text, wifi, vcard, email, sms

    // Data
    dataText: 'https://deboxhub.com',
    dataWifiSsid: '',
    dataWifiPassword: '',
    dataWifiEncryption: 'WPA',
    dataWifiHidden: false,
    
    dataVcardFirstName: '',
    dataVcardLastName: '',
    dataVcardPhone: '',
    dataVcardEmail: '',
    dataVcardCompany: '',

    dataEmailTo: '',
    dataEmailSubject: '',
    dataEmailBody: '',

    dataSmsPhone: '',
    dataSmsMessage: '',
    
    // Style
    width: 512,
    height: 512,
    margin: 10,
    
    dotsType: 'rounded' as 'rounded' | 'dots' | 'classy' | 'classy-rounded' | 'square' | 'extra-rounded',
    dotsColor: '#000000',
    dotsGradient: false,
    dotsGradientType: 'linear' as 'linear' | 'radial',
    dotsGradientColor1: '#000000',
    dotsGradientColor2: '#3b82f6',
    dotsGradientRotation: 45,
    
    cornersSquareType: 'extra-rounded' as 'dot' | 'square' | 'extra-rounded',
    cornersSquareColor: '#000000',
    
    cornersDotType: 'dot' as 'dot' | 'square',
    cornersDotColor: '#000000',
    
    bgColor: '#ffffff',
    
    // Image/Logo
    image: null as string | null,
    imageMargin: 5,
    imageSize: 0.4, // 40% of QR code
    
    // Advanced
    errorCorrectionLevel: 'Q' as 'L' | 'M' | 'Q' | 'H'
  });

  const modeOptions = $derived([
    { value: 'text', label: i18n.t('tools.qrGenerator.contentTypes.text'), icon: Link },
    { value: 'wifi', label: i18n.t('tools.qrGenerator.contentTypes.wifi'), icon: Wifi },
    { value: 'vcard', label: i18n.t('tools.qrGenerator.contentTypes.vcard'), icon: Contact },
    { value: 'email', label: i18n.t('tools.qrGenerator.contentTypes.email'), icon: Mail },
    { value: 'sms', label: i18n.t('tools.qrGenerator.contentTypes.sms'), icon: MessageSquare }
  ]);

  const shapes = $derived([
    { value: 'square', label: i18n.t('tools.qrGenerator.styling.shapes.square') },
    { value: 'dots', label: i18n.t('tools.qrGenerator.styling.shapes.dots') },
    { value: 'rounded', label: i18n.t('tools.qrGenerator.styling.shapes.rounded') },
    { value: 'extra-rounded', label: i18n.t('tools.qrGenerator.styling.shapes.extraRounded') },
    { value: 'classy', label: i18n.t('tools.qrGenerator.styling.shapes.classy') },
    { value: 'classy-rounded', label: i18n.t('tools.qrGenerator.styling.shapes.classyRounded') }
  ]);

  let qrData = $derived.by(() => {
    const v = storage.value;
    switch (v.mode) {
      case 'text':
        return v.dataText || ' ';
      case 'wifi':
        return `WIFI:T:${v.dataWifiEncryption};S:${v.dataWifiSsid};P:${v.dataWifiPassword};H:${v.dataWifiHidden};;`;
      case 'vcard':
        return `BEGIN:VCARD\nVERSION:3.0\nN:${v.dataVcardLastName};${v.dataVcardFirstName}\nFN:${v.dataVcardFirstName} ${v.dataVcardLastName}\nORG:${v.dataVcardCompany}\nTEL:${v.dataVcardPhone}\nEMAIL:${v.dataVcardEmail}\nEND:VCARD`;
      case 'email':
        return `mailto:${v.dataEmailTo}?subject=${encodeURIComponent(v.dataEmailSubject)}&body=${encodeURIComponent(v.dataEmailBody)}`;
      case 'sms':
        return `smsto:${v.dataSmsPhone}:${v.dataSmsMessage}`;
      default:
        return ' ';
    }
  });

  let qrCode: any = null;
  let qrContainer: HTMLDivElement;
  let isGenerating = $state(false);
  let fileInput: HTMLInputElement;

  onMount(() => {
    if (typeof window !== 'undefined') {
      qrCode = new QRCodeStyling(getQrOptions());
      if (qrContainer) {
        qrCode.append(qrContainer);
      }
    }
  });

  function getQrOptions(): any {
    const v = storage.value;
    
    const options: any = {
      width: v.width,
      height: v.height,
      data: qrData,
      margin: v.margin,
      qrOptions: {
        errorCorrectionLevel: v.errorCorrectionLevel
      },
      imageOptions: {
        hideBackgroundDots: true,
        imageSize: v.imageSize,
        margin: v.imageMargin,
        crossOrigin: 'anonymous'
      },
      dotsOptions: {
        type: v.dotsType,
        color: v.dotsColor
      },
      backgroundOptions: {
        color: v.bgColor
      },
      cornersSquareOptions: {
        type: v.cornersSquareType
      },
      cornersDotOptions: {
        type: v.cornersDotType
      }
    };

    if (v.image) {
      options.image = v.image;
    }

    if (v.dotsGradient) {
      options.dotsOptions.gradient = {
        type: v.dotsGradientType,
        rotation: (v.dotsGradientRotation * Math.PI) / 180,
        colorStops: [
          { offset: 0, color: v.dotsColor },
          { offset: 1, color: v.dotsGradientColor2 }
        ]
      };
    } else {
      options.dotsOptions.gradient = undefined;
    }

    return options;
  }

  $effect(() => {
    if (qrCode) {
      // Re-evaluate reactive dependencies
      JSON.stringify(storage.value);
      qrData;
      
      qrCode.update(getQrOptions());
    }
  });

  async function download(ext: 'png' | 'svg' | 'webp') {
    if (!qrCode) return;
    isGenerating = true;
    try {
      await qrCode.download({ name: 'debox-qrcode', extension: ext });
    } catch (e) {
      console.error('Download failed', e);
    } finally {
      isGenerating = false;
    }
  }

  function handleImageUpload(e: Event) {
    const target = e.target as HTMLInputElement;
    if (target.files && target.files[0]) {
      const reader = new FileReader();
      reader.onload = (evt) => {
        storage.value.image = evt.target?.result as string;
      };
      reader.readAsDataURL(target.files[0]);
    }
  }
  // End of script
</script>

<SplitWorkspace {tool}>
  {#snippet headerLeftControls()}
    <div class="border-gray-200 dark:border-gray-800 flex items-center w-full overflow-hidden">
      <div class="overflow-x-auto custom-scrollbar w-full">
        <SegmentedControl bind:value={storage.value.mode} options={modeOptions} class="shadow-sm whitespace-nowrap min-w-max" />
      </div>
    </div>
  {/snippet}

  {#snippet leftPanel()}
    <div class="flex flex-col h-full bg-slate-50/50 dark:bg-slate-900/40 border-r border-gray-200 dark:border-gray-800 overflow-hidden">
      
      <!-- Top Part: Dynamic Content Inputs -->
      <div class="p-5 shrink-0 bg-white dark:bg-gray-900 border-b border-gray-200 dark:border-gray-800 shadow-sm z-10">
        <div class="space-y-4">
          {#if storage.value.mode === 'text'}
            <div class="space-y-1.5">
              <label class="text-xs font-semibold text-gray-700 dark:text-gray-300">{i18n.t('tools.qrGenerator.contentTypes.text')}</label>
              <textarea bind:value={storage.value.dataText} rows="3" placeholder={i18n.t('tools.qrGenerator.inputs.urlPlaceholder')} class="w-full bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-md px-3 py-2 text-sm focus:ring-2 focus:ring-blue-500 outline-none resize-y"></textarea>
            </div>
            
          {:else if storage.value.mode === 'wifi'}
            <div class="space-y-3">
              <div class="flex gap-3">
                <div class="space-y-1.5 flex-1">
                  <label class="text-xs font-semibold text-gray-700 dark:text-gray-300">{i18n.t('tools.qrGenerator.inputs.ssid')}</label>
                  <input type="text" bind:value={storage.value.dataWifiSsid} class="w-full bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-md px-3 py-2 text-sm focus:ring-2 focus:ring-blue-500 outline-none" />
                </div>
                <div class="space-y-1.5 flex-1">
                  <label class="text-xs font-semibold text-gray-700 dark:text-gray-300">{i18n.t('tools.qrGenerator.inputs.password')}</label>
                  <input type="password" bind:value={storage.value.dataWifiPassword} class="w-full bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-md px-3 py-2 text-sm focus:ring-2 focus:ring-blue-500 outline-none" />
                </div>
              </div>
              <div class="flex gap-4">
                <div class="space-y-1.5 flex-1">
                  <label class="text-xs font-semibold text-gray-700 dark:text-gray-300">{i18n.t('tools.qrGenerator.inputs.encryption')}</label>
                  <select bind:value={storage.value.dataWifiEncryption} aria-label={i18n.t('tools.qrGenerator.inputs.encryption')} class="w-full bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-md px-3 py-2 text-sm focus:ring-2 focus:ring-blue-500 outline-none">
                    <option value="WPA">WPA/WPA2</option>
                    <option value="WEP">WEP</option>
                    <option value="nopass">None</option>
                  </select>
                </div>
                <div class="flex items-center gap-2 pt-6">
                  <input type="checkbox" bind:checked={storage.value.dataWifiHidden} id="wifiHidden" class="w-4 h-4 text-blue-600 rounded border-gray-300" />
                  <label for="wifiHidden" class="text-xs text-gray-700 dark:text-gray-300">{i18n.t('tools.qrGenerator.inputs.hiddenNetwork')}</label>
                </div>
              </div>
            </div>
            
          {:else if storage.value.mode === 'vcard'}
            <div class="space-y-3">
              <div class="flex gap-3">
                <div class="space-y-1.5 flex-1">
                  <label class="text-xs font-semibold text-gray-700 dark:text-gray-300">{i18n.t('tools.qrGenerator.inputs.firstName')}</label>
                  <input type="text" bind:value={storage.value.dataVcardFirstName} class="w-full bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-md px-3 py-2 text-sm focus:ring-2 focus:ring-blue-500 outline-none" />
                </div>
                <div class="space-y-1.5 flex-1">
                  <label class="text-xs font-semibold text-gray-700 dark:text-gray-300">{i18n.t('tools.qrGenerator.inputs.lastName')}</label>
                  <input type="text" bind:value={storage.value.dataVcardLastName} class="w-full bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-md px-3 py-2 text-sm focus:ring-2 focus:ring-blue-500 outline-none" />
                </div>
              </div>
              <div class="flex gap-3">
                <div class="space-y-1.5 flex-1">
                  <label class="text-xs font-semibold text-gray-700 dark:text-gray-300">{i18n.t('tools.qrGenerator.inputs.smsPhone')}</label>
                  <input type="tel" bind:value={storage.value.dataVcardPhone} class="w-full bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-md px-3 py-2 text-sm focus:ring-2 focus:ring-blue-500 outline-none" />
                </div>
                <div class="space-y-1.5 flex-1">
                  <label class="text-xs font-semibold text-gray-700 dark:text-gray-300">Email</label>
                  <input type="email" bind:value={storage.value.dataVcardEmail} class="w-full bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-md px-3 py-2 text-sm focus:ring-2 focus:ring-blue-500 outline-none" />
                </div>
                <div class="space-y-1.5 flex-1">
                  <label class="text-xs font-semibold text-gray-700 dark:text-gray-300">{i18n.t('tools.qrGenerator.inputs.company')}</label>
                  <input type="text" bind:value={storage.value.dataVcardCompany} class="w-full bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-md px-3 py-2 text-sm focus:ring-2 focus:ring-blue-500 outline-none" />
                </div>
              </div>
            </div>
            
          {:else if storage.value.mode === 'email'}
            <div class="space-y-3">
              <div class="flex gap-3">
                <div class="space-y-1.5 flex-1">
                  <label class="text-xs font-semibold text-gray-700 dark:text-gray-300">{i18n.t('tools.qrGenerator.inputs.emailTo')}</label>
                  <input type="email" bind:value={storage.value.dataEmailTo} class="w-full bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-md px-3 py-2 text-sm focus:ring-2 focus:ring-blue-500 outline-none" />
                </div>
                <div class="space-y-1.5 flex-1">
                  <label class="text-xs font-semibold text-gray-700 dark:text-gray-300">{i18n.t('tools.qrGenerator.inputs.emailSubject')}</label>
                  <input type="text" bind:value={storage.value.dataEmailSubject} class="w-full bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-md px-3 py-2 text-sm focus:ring-2 focus:ring-blue-500 outline-none" />
                </div>
              </div>
              <div class="space-y-1.5">
                <label class="text-xs font-semibold text-gray-700 dark:text-gray-300">{i18n.t('tools.qrGenerator.inputs.emailBody')}</label>
                <textarea bind:value={storage.value.dataEmailBody} rows="2" class="w-full bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-md px-3 py-2 text-sm focus:ring-2 focus:ring-blue-500 outline-none resize-y"></textarea>
              </div>
            </div>
            
          {:else if storage.value.mode === 'sms'}
            <div class="space-y-3">
              <div class="space-y-1.5">
                <label class="text-xs font-semibold text-gray-700 dark:text-gray-300">{i18n.t('tools.qrGenerator.inputs.smsPhone')}</label>
                <input type="tel" bind:value={storage.value.dataSmsPhone} class="w-full bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-md px-3 py-2 text-sm focus:ring-2 focus:ring-blue-500 outline-none" />
              </div>
              <div class="space-y-1.5">
                <label class="text-xs font-semibold text-gray-700 dark:text-gray-300">{i18n.t('tools.qrGenerator.inputs.smsMessage')}</label>
                <textarea bind:value={storage.value.dataSmsMessage} rows="2" class="w-full bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-md px-3 py-2 text-sm focus:ring-2 focus:ring-blue-500 outline-none resize-y"></textarea>
              </div>
            </div>
          {/if}
        </div>
      </div>

      <!-- Bottom Part: Common Styling Options -->
      <div class="p-5 flex-1 overflow-y-auto custom-scrollbar space-y-4">

        <!-- Styling Options -->
        <div class="flex flex-col gap-4 bg-white dark:bg-gray-800/50 p-4 rounded-xl border border-gray-200 dark:border-gray-700 shadow-sm">
          <div class="flex items-center justify-between">
