              {i18n.t('tools.qrGenerator.styling.colors')}
            </label>
            <div class="flex items-center gap-2">
              <input type="checkbox" bind:checked={storage.value.dotsGradient} id="useGradient" class="w-3.5 h-3.5 text-blue-600 rounded border-gray-300 cursor-pointer" />
              <label for="useGradient" class="text-[11px] font-semibold text-gray-500 dark:text-gray-400 cursor-pointer uppercase tracking-wider">{i18n.t('tools.qrGenerator.styling.useGradient')}</label>
            </div>
          </div>
          
          <div class={storage.value.dotsGradient ? 'grid grid-cols-4 gap-3' : 'grid grid-cols-2 gap-4'}>
            <!-- Background -->
            <div class="space-y-1.5">
              <label class="text-xs font-semibold text-gray-700 dark:text-gray-300 truncate">{i18n.t('tools.qrGenerator.styling.background')}</label>
              <div class="flex flex-col gap-2">
                <input type="color" bind:value={storage.value.bgColor} class="w-full h-8 rounded border border-gray-200 dark:border-gray-700 cursor-pointer p-0.5 bg-white dark:bg-gray-800" />
                <input type="text" bind:value={storage.value.bgColor} class="w-full bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-md px-2 py-1.5 text-[10px] font-mono focus:ring-2 focus:ring-blue-500 outline-none uppercase text-center" />
              </div>
            </div>
            
            <!-- Foreground / Color 1 -->
            <div class="space-y-1.5">
              <label class="text-xs font-semibold text-gray-700 dark:text-gray-300 truncate">
                {storage.value.dotsGradient ? 'Color 1' : i18n.t('tools.qrGenerator.styling.foreground')}
              </label>
              <div class="flex flex-col gap-2">
                <input type="color" bind:value={storage.value.dotsColor} class="w-full h-8 rounded border border-gray-200 dark:border-gray-700 cursor-pointer p-0.5 bg-white dark:bg-gray-800" />
                <input type="text" bind:value={storage.value.dotsColor} class="w-full bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-md px-2 py-1.5 text-[10px] font-mono focus:ring-2 focus:ring-blue-500 outline-none uppercase text-center" />
              </div>
            </div>
            
            {#if storage.value.dotsGradient}
              <!-- Color 2 -->
              <div class="space-y-1.5">
                <label class="text-xs font-semibold text-gray-700 dark:text-gray-300 truncate">Color 2</label>
                <div class="flex flex-col gap-2">
                  <input type="color" bind:value={storage.value.dotsGradientColor2} class="w-full h-8 rounded border border-gray-200 dark:border-gray-700 cursor-pointer p-0.5 bg-white dark:bg-gray-800" />
                  <input type="text" bind:value={storage.value.dotsGradientColor2} class="w-full bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-md px-2 py-1.5 text-[10px] font-mono focus:ring-2 focus:ring-blue-500 outline-none uppercase text-center" />
                </div>
              </div>
              
              <!-- Angle Slider -->
              <div class="space-y-1.5">
                <label class="text-xs font-semibold text-gray-700 dark:text-gray-300 truncate">Angle</label>
                <div class="flex flex-col gap-2 w-full">
                  <div class="h-8 rounded border border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-800 flex items-center px-2">
                    <input type="range" bind:value={storage.value.dotsGradientRotation} min="0" max="360" class="w-full accent-blue-600" />
                  </div>
                  <div class="relative w-full">
                    <input 
                      type="number" 
                      bind:value={storage.value.dotsGradientRotation} 
                      min="0" max="360"
                      class="w-full bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-md pr-4 pl-1 py-1.5 text-[10px] font-mono focus:ring-2 focus:ring-blue-500 outline-none text-center appearance-none"
                    />
