                  </div>
                </div>
              </div>
            {/if}
          </div>
        </div>

        <!-- Shapes -->
        <div class="flex flex-col gap-4 bg-white dark:bg-gray-800/50 p-4 rounded-xl border border-gray-200 dark:border-gray-700 shadow-sm">
