          <div class="grid grid-cols-5 gap-4">
          
          <!-- Logo Column -->
          <div class="space-y-4 flex flex-col h-full col-span-2">
            <label class="text-sm font-semibold text-gray-800 dark:text-gray-200 flex items-center gap-1.5 shrink-0">
              <Image class="w-4 h-4 text-blue-500" />
              {i18n.t('tools.qrGenerator.logo.title')}
            </label>
            
            <div class="flex-1">
              {#if !storage.value.image}
                <!-- svelte-ignore a11y_click_events_have_key_events -->
                <!-- svelte-ignore a11y_no_static_element_interactions -->
                <div 
                  class="h-full min-h-[100px] border-2 border-dashed border-gray-300 dark:border-gray-600 rounded-lg p-4 flex flex-col items-center justify-center gap-2 cursor-pointer hover:bg-white dark:hover:bg-gray-800/50 transition-colors text-center"
                  onclick={() => fileInput.click()}
                >
                  <Upload class="w-5 h-5 text-gray-400" />
                  <span class="text-[11px] text-gray-500 font-medium">{i18n.t('tools.qrGenerator.logo.upload')}</span>
                </div>
                <input type="file" bind:this={fileInput} onchange={handleImageUpload} accept="image/*" class="hidden" />
              {:else}
                <div class="p-3 border border-gray-200 dark:border-gray-700 rounded-lg bg-white dark:bg-gray-800/50 space-y-3 shadow-sm h-full flex flex-col">
                  <div class="flex items-center justify-between shrink-0">
                    <img src={storage.value.image} alt="Logo" class="h-8 w-auto object-contain bg-white/50 rounded" />
                    <button onclick={() => storage.value.image = null} class="text-red-500 hover:text-red-700 p-1 bg-gray-50 dark:bg-gray-800 rounded-md shadow-sm border border-gray-200 dark:border-gray-700">
                      <Trash2 class="w-3.5 h-3.5" />
                    </button>
                  </div>
                  
                  <div class="space-y-1.5 mt-auto">
                    <div class="flex justify-between">
                      <label class="text-[10px] text-gray-600 dark:text-gray-400">{i18n.t('tools.qrGenerator.logo.imageSize')}</label>
                      <span class="text-[9px] text-gray-500">{Math.round(storage.value.imageSize * 100)}%</span>
                    </div>
                    <input type="range" bind:value={storage.value.imageSize} min="0.1" max="0.5" step="0.05" class="w-full accent-blue-600" />
                  </div>
                  
                  <div class="space-y-1.5">
                    <div class="flex justify-between">
                      <label class="text-[10px] text-gray-600 dark:text-gray-400">{i18n.t('tools.qrGenerator.logo.imageMargin')}</label>
                      <span class="text-[9px] text-gray-500">{storage.value.imageMargin}px</span>
                    </div>
                    <input type="range" bind:value={storage.value.imageMargin} min="0" max="20" class="w-full accent-blue-600" />
                  </div>
                </div>
              {/if}
            </div>
          </div>

          <!-- Advanced Column -->
          <div class="space-y-4 flex flex-col h-full col-span-3">
            <label class="text-sm font-semibold text-gray-800 dark:text-gray-200 flex items-center gap-1.5 shrink-0">
              <Settings class="w-4 h-4 text-blue-500" />
              Advanced
            </label>
            
            <div class="flex-1 border border-gray-200 dark:border-gray-700 rounded-lg p-3 bg-white dark:bg-gray-800/50 shadow-sm flex flex-col justify-center">
              <div class="space-y-2">
                <label class="text-[11px] font-semibold text-gray-700 dark:text-gray-300">{i18n.t('tools.qrGenerator.styling.errorCorrection')}</label>
                <select bind:value={storage.value.errorCorrectionLevel} aria-label={i18n.t('tools.qrGenerator.styling.errorCorrection')} class="w-full bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-md px-2 py-1.5 text-xs focus:ring-2 focus:ring-blue-500 outline-none">
                  <option value="L">L - 7%</option>
                  <option value="M">M - 15%</option>
                  <option value="Q">Q - 25%</option>
                  <option value="H">H - 30%</option>
                </select>
                <p class="text-[10px] text-gray-500 dark:text-gray-400 leading-relaxed pt-1">
                  Higher correction allows for larger logos but increases pattern density.
                </p>
              </div>
            </div>
          </div>

          </div>
        </div>
      </div>
    </div>
  {/snippet}

  {#snippet rightPanel()}
    <div class="flex flex-col h-full bg-white dark:bg-[#1e1e1e] overflow-hidden">
      <!-- Right Panel Header -->
      <div class="flex items-center justify-between px-4 py-2 bg-gray-50 dark:bg-gray-900 border-b border-gray-200 dark:border-gray-800 h-11 shrink-0 z-20">
        <span class="flex items-center gap-1.5 text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider">
          <QrCode class="w-3.5 h-3.5" /> {i18n.t('common.action.preview') || 'Preview'}
        </span>
        
        <div class="flex items-center gap-1.5">
          <Button 
            variant="ghost"
            color="gray"
            size="sm"
            onclick={() => download('svg')}
            disabled={isGenerating}
          >
            {#if isGenerating}
              <RefreshCw class="w-3.5 h-3.5 animate-spin" />
            {:else}
              <DownloadCloud class="w-3.5 h-3.5" />
            {/if}
            SVG
          </Button>
          
          <Separator orientation="vertical" size="4" />

          <Button 
            variant="ghost"
            color="gray"
            size="sm"
            onclick={() => download('webp')}
            disabled={isGenerating}
          >
            {#if isGenerating}
              <RefreshCw class="w-3.5 h-3.5 animate-spin" />
            {:else}
              <DownloadCloud class="w-3.5 h-3.5" />
            {/if}
            WEBP
          </Button>
          
          <Separator orientation="vertical" size="4" />

          <Button 
            variant="ghost"
            color="blue"
            size="sm"
            onclick={() => download('png')}
            disabled={isGenerating}
          >
            {#if isGenerating}
              <RefreshCw class="w-3.5 h-3.5 animate-spin" />
            {:else}
              <DownloadCloud class="w-3.5 h-3.5" />
            {/if}
            PNG
          </Button>
        </div>
      </div>
      
      <!-- Main Preview -->
      <div class="flex-1 relative w-full h-full flex items-center justify-center bg-slate-50/50 dark:bg-[#161616]">
        <div class="absolute inset-0 pointer-events-none" style="background-image: repeating-linear-gradient(45deg, #e5e7eb 25%, transparent 25%, transparent 75%, #e5e7eb 75%, #e5e7eb), repeating-linear-gradient(45deg, #e5e7eb 25%, #f9fafb 25%, #f9fafb 75%, #e5e7eb 75%, #e5e7eb); background-position: 0 0, 10px 10px; background-size: 20px 20px; opacity: 0.5;"></div>
        
        <div class="relative z-10 w-full max-w-[280px] sm:max-w-[340px] aspect-square rounded-2xl shadow-xl overflow-hidden flex items-center justify-center bg-white p-4 sm:p-6 transition-transform hover:scale-[1.02]">
          <div bind:this={qrContainer} class="w-full h-full flex items-center justify-center [&>canvas]:max-w-full [&>canvas]:h-auto [&>svg]:max-w-full [&>svg]:h-auto"></div>
        </div>
      </div>
    </div>
  {/snippet}

</SplitWorkspace>
