<script lang="ts">
  import { resolve } from '$app/paths';

  import { recentStore } from '$lib/stores/recent.svelte';
  import { ButtonFavorite } from '$lib/components/ui';

  import { Clock, type LucideIcon } from 'lucide-svelte';

  export interface ToolCardProps {
    id: string;
    href: string;
    icon: LucideIcon;
    name: string;
    description: string;
    hideRecentIcon?: boolean;
  }

  let { 
    id,
    href, 
    icon: Icon, 
    name, 
    description,
    hideRecentIcon = false
  }: ToolCardProps = $props();

  let isRecent = $derived(recentStore.items.includes(id));
</script>

<a
  href={resolve(`/${href}`)}
  class="group flex flex-col p-5 bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-2xl shadow-sm hover:shadow-md hover:border-blue-200 dark:hover:border-blue-500/50 transition-all duration-200 relative"
>
  <div class="absolute top-2 right-2 flex items-center gap-0.5">
    {#if !hideRecentIcon}
      <div 
        class="p-1.5 transition-colors {isRecent ? 'text-blue-500' : 'text-gray-300 dark:text-gray-600'}"
        title={isRecent ? 'Recently used' : ''}
      >
        <Clock class="w-4 h-4" />
      </div>
    {/if}

    <ButtonFavorite {id} />
  </div>

  <div class="flex items-center gap-3 mb-3">
    <div class="p-2.5 bg-gray-50 dark:bg-gray-900 rounded-xl group-hover:bg-blue-50 dark:group-hover:bg-blue-900/40 transition-colors">
      <Icon class="w-5 h-5 text-gray-600 dark:text-gray-400 group-hover:text-blue-600 dark:group-hover:text-blue-400 transition-colors" />
    </div>

    <h3 class="font-semibold text-gray-900 dark:text-gray-100 group-hover:text-blue-700 dark:group-hover:text-blue-400 transition-colors">
      {name}
    </h3>
  </div>

  <p class="text-sm text-gray-500 dark:text-gray-400 h-10 line-clamp-2 transition-colors">
    {description}
  </p>
</a>