import { browser } from '$app/environment';
import { CONFIG_PREFIX } from '$lib/constants';
import type { DateFormat, TimeFormat } from '$lib/constants/date';

interface SettingsConfig {
    timeFormat: TimeFormat;
    dateFormat: DateFormat;
    smartInput: {
        autoSuggest: boolean;
        cmdEnterToRun: boolean;
    };
}

const DEFAULT_SETTINGS: SettingsConfig = {
    timeFormat: '24h',
    dateFormat: 'iso',
    smartInput: {
        autoSuggest: true,
        cmdEnterToRun: true
    }
};

const STORAGE_KEY = `${CONFIG_PREFIX}:settings`;

function createSettingsStore() {
    let config = $state<SettingsConfig>({ ...DEFAULT_SETTINGS });

    // Load from localStorage when initializing
    if (browser) {
        const saved = localStorage.getItem(STORAGE_KEY);
        if (saved) {
            try {
                config = { ...DEFAULT_SETTINGS, ...JSON.parse(saved) };
            } catch (e) {
                console.error('Failed to parse settings', e);
            }
        }
    }

    // Every time config changes, automatically save to localStorage
    $effect.root(() => {
        $effect(() => {
            if (browser) {
                localStorage.setItem(STORAGE_KEY, JSON.stringify(config));
            }
        });
    });

    return {
        get config() { return config; },
        
        // Provide specific update functions
        setTimeFormat: (format: TimeFormat) => { config.timeFormat = format; },
        setDateFormat: (format: DateFormat) => { config.dateFormat = format; },
        toggleAutoSuggest: () => { config.smartInput.autoSuggest = !config.smartInput.autoSuggest; },
        toggleCmdEnter: () => { config.smartInput.cmdEnterToRun = !config.smartInput.cmdEnterToRun; },
        
        // Reset to default
        reset: () => { config = { ...DEFAULT_SETTINGS }; }
    };
}

export const settingsStore = createSettingsStore();