<script lang="ts">
  import { Star } from 'lucide-svelte';
  import { favoritesStore } from '$lib/stores/favorites.svelte';
  import { ButtonIcon } from '$lib/components/ui';

  export interface ButtonFavoriteProps {
    id: string;
    class?: string;
    size?: number;
  }

  let { id, class: className = '', size = 16 }: ButtonFavoriteProps = $props();

  let isFavorite = $derived(favoritesStore.has(id));
</script>

<ButtonIcon 
  color="amber"
  active={isFavorite}
  class={className}
  onclick={(e) => {
    e.preventDefault();
    e.stopPropagation();
    favoritesStore.toggle(id);
  }}
  title={isFavorite ? "Remove from Favorites" : "Add to Favorites"}
>
  <Star {size} class={isFavorite ? 'fill-current' : ''} />
</ButtonIcon>
