<script lang="ts">
  import { i18n } from '$lib/i18n';
  import { ToolWrapper } from '$lib/components/layout';
  import type { ToolDefinition } from '$lib/types';
  import { parseShellCommand, type ShellToken } from '$lib/utils/shellParser';
  import shellCommandsRaw from '$lib/data/shell_commands.json';
  import { Terminal, Info } from 'lucide-svelte/icons';

  export interface ShellExplainerProps {
    tool: ToolDefinition;
  }

  let { tool }: ShellExplainerProps = $props();

  let inputCommand = $state('tar -xzvf archive.tar.gz');
  let parsedTokens = $derived(parseShellCommand(inputCommand));
  
  // Provide shellCommands mapping
  const shellCommands = shellCommandsRaw as Record<string, { desc: string, url: string, flags: Record<string, string> }>;

  // Helper to determine text color based on token type
  function getTokenColor(type: string) {
    switch (type) {
      case 'command': return 'text-blue-600 dark:text-blue-400 font-bold';
      case 'flag': return 'text-orange-600 dark:text-orange-400';
      case 'operator': return 'text-purple-600 dark:text-purple-400 font-bold';
      case 'argument': return 'text-gray-600 dark:text-gray-300';
      default: return 'text-gray-900 dark:text-white';
    }
  }

  function getTokenBg(type: string) {
    switch (type) {
      case 'command': return 'bg-blue-50 dark:bg-blue-900/30 border-blue-200 dark:border-blue-800';
      case 'flag': return 'bg-orange-50 dark:bg-orange-900/30 border-orange-200 dark:border-orange-800';
      case 'operator': return 'bg-purple-50 dark:bg-purple-900/30 border-purple-200 dark:border-purple-800';
      case 'argument': return 'bg-gray-50 dark:bg-gray-800 border-gray-200 dark:border-gray-700';
      default: return 'bg-white dark:bg-gray-900 border-gray-200 dark:border-gray-700';
    }
  }
</script>

<ToolWrapper
  toolId={tool.id}
  title={i18n.t(tool.name)}
  description={i18n.t(tool.description)}
>
  <div class="space-y-8">
    <!-- Input Section -->
    <div class="bg-white dark:bg-gray-900 rounded-2xl shadow-sm border border-gray-200/60 dark:border-gray-700/60 overflow-hidden">
      <div class="bg-gray-900 px-4 py-3 flex items-center gap-3">
        <Terminal class="w-5 h-5 text-gray-400" />
        <span class="text-sm font-medium text-gray-300 tracking-wide">Terminal</span>
      </div>
      <div class="p-4 sm:p-6 bg-[#0d1117]">
        <div class="flex gap-3 items-start">
          <span class="text-green-400 font-mono mt-0.5">$</span>
          <textarea 
            bind:value={inputCommand}
            placeholder={i18n.t('tools.shellExplainer.inputPlaceholder')}
            class="w-full bg-transparent text-gray-100 font-mono text-lg outline-none resize-none placeholder:text-gray-600 custom-scrollbar"
            rows="3"
            spellcheck="false"
          ></textarea>
        </div>
      </div>
    </div>

    <!-- Output Section -->
    {#if inputCommand.trim()}
      <div class="space-y-6">
        
        <!-- Token Highlighter Overview -->
        <div class="bg-white dark:bg-gray-900 rounded-2xl p-6 shadow-sm border border-gray-200/60 dark:border-gray-700/60">
          <h3 class="text-sm font-semibold text-gray-900 dark:text-white mb-4 flex items-center gap-2">
            <Info class="w-4 h-4 text-blue-500" />
            {i18n.t('tools.shellExplainer.explanation')}
          </h3>
          <div class="flex flex-wrap gap-2.5">
            {#each parsedTokens as token (token.type)}
              <div class="px-3 py-1.5 rounded-lg border font-mono text-sm shadow-sm transition-transform hover:-translate-y-0.5 {getTokenBg(token.type)}">
                <span class={getTokenColor(token.type)}>{token.text}</span>
              </div>
            {/each}
          </div>
        </div>

        <!-- Detailed Breakdown Cards -->
        <div class="space-y-4">
          {#each parsedTokens as token (token.type)}
            <div class="bg-white dark:bg-gray-900 rounded-xl p-5 shadow-sm border border-gray-200/60 dark:border-gray-700/60 flex flex-col sm:flex-row gap-4 sm:gap-6 items-start">
              
              <!-- Token Badge -->
              <div class="shrink-0 w-40 sm:w-48 flex flex-col gap-2">
                <div class="px-3 py-2 rounded-lg border font-mono text-center font-bold text-base break-all {getTokenBg(token.type)}">
                  <span class={getTokenColor(token.type)}>{token.text}</span>
                </div>
                <div class="text-[11px] font-bold text-gray-400 uppercase tracking-widest text-center">
                  {i18n.t(`tools.shellExplainer.${token.type}`)}
                </div>
              </div>

              <!-- Explanations -->
              <div class="flex-1 min-w-0">
                {#if token.explanations.length > 0}
                  <div class="space-y-3">
                    {#each token.explanations as exp (exp.flag)}
                      <div class="flex gap-3">
                        {#if token.type === 'flag' && token.text !== exp.flag}
                          <span class="shrink-0 inline-flex items-center px-2 py-0.5 rounded text-xs font-mono font-medium bg-gray-100 dark:bg-gray-800 text-gray-600 dark:text-gray-300 border border-gray-200 dark:border-gray-700">
                            {exp.flag}
                          </span>
                        {/if}
                        <p class="text-gray-700 dark:text-gray-300 text-sm leading-relaxed pt-0.5">
                          {exp.desc}
                        </p>
                      </div>
                    {/each}
                  </div>
                {:else}
                  <div class="h-full flex items-center text-sm text-gray-500 dark:text-gray-400 italic py-1">
                    {i18n.t('tools.shellExplainer.noExplanation') || 'No specific explanation found.'}
                  </div>
                {/if}
              </div>

            </div>
          {/each}
        </div>
        
      </div>
    {:else}
      <!-- Empty State -->
      <div class="py-12 text-center text-gray-500 dark:text-gray-400">
        <Terminal class="w-12 h-12 mx-auto mb-4 opacity-20" />
        <p>{i18n.t('tools.shellExplainer.emptyState') || 'Enter a shell command above to see its breakdown and explanation.'}</p>
      </div>
    {/if}

  </div>
</ToolWrapper>
