<script lang="ts">
  import { slide } from 'svelte/transition';

  import { i18n } from '$lib/i18n';

  import { copyText } from '$lib/utils/clipboard';
  import SplitWorkspace from './SplitWorkspace.svelte';
  import { TextPanel, SegmentedControl, Separator, ButtonIcon } from '$lib/components/ui';

  import { Download, Copy, Trash2, ArrowRightLeft, Binary, Type } from 'lucide-svelte';
  import { downloadFile, generateDownloadFilename } from '$lib/utils/file';

  import { createTool } from '$lib/stores';
  import type { ModeOption, ToolDefinition } from '$lib/types';
  import { smartInputState } from '$lib/utils/smartInput';
  import { onMount } from 'svelte';

  // Define types for the process function passed as a prop
  type OutputState = { value: string; error: boolean };
  type ProcessFunction = (input: string, mode: string) => OutputState;

  interface ConverterProps {
    mode?: string;
    modeOptions?: ModeOption[];
    tool: ToolDefinition;
    processFn: ProcessFunction;
  }

  let {
    mode = 'encode',
    modeOptions,
    tool,
    processFn
  }: ConverterProps = $props();

  let isFullFrame = $state(false);

  let loadModeOptions = $derived(modeOptions || [
    { value: 'encode', label: i18n.t('common.action.encode') || 'Encode', icon: Binary },
    { value: 'decode', label: i18n.t('common.action.decode') || 'Decode', icon: Type }
  ]);

  const storage = createTool(tool.slug, {
    input: '',
    mode: mode
  });

  onMount(() => {
    const passedData = smartInputState.consume();
    if (passedData) {
      storage.value.input = passedData;
    }
  });

  // UI Component calls the processFn passed from the parent file
  let outputState = $derived.by(() => {
    if (!storage.value.input) return { value: '', error: false };
    return processFn(storage.value.input, storage.value.mode);
  });

  function clearText() {
    storage.value.input = '';
  }

  function handleSwap() {
    if (outputState.error || !outputState.value) return;
    storage.value.input = outputState.value;
    
    // Find index of current mode and automatically switch to the other mode
    const currentIndex = loadModeOptions.findIndex(opt => opt.value === storage.value.mode);
    const nextIndex = currentIndex === 0 ? 1 : 0;
    
    storage.value.mode = loadModeOptions[nextIndex].value;
  }
</script>

<SplitWorkspace {tool} bind:isFullFrame>
  {#snippet headerLeftControls()}
    <SegmentedControl bind:value={storage.value.mode} options={loadModeOptions} class="bg-gray-100 dark:bg-gray-900/80 shadow-sm" />

    <Separator orientation="vertical" size="4" class="hidden sm:block -ml-px" />

    <ButtonIcon 
      onclick={handleSwap}
      disabled={!outputState.value || outputState.error}
      color="blue"
      class="!p-2"
      title={i18n.t('common.action.swap') || 'Swap sides'}
    >
      <ArrowRightLeft class="w-4 h-4" />
    </ButtonIcon>
  {/snippet}

  {#snippet leftPanel()}
    <TextPanel label={i18n.t('common.editor.input') || 'Input'} bind:value={storage.value.input} placeholder={i18n.t('common.form.pasteInput', { format: 'text' })}>
      {#snippet actionButton()}
        <ButtonIcon onclick={clearText} disabled={!storage.value.input} color="rose" title={i18n.t('common.action.clear') || 'Clear'}>
          <Trash2 class="w-4 h-4" />
        </ButtonIcon>
      {/snippet}
    </TextPanel>
  {/snippet}

  {#snippet rightPanel()}
    <TextPanel label={i18n.t('common.editor.output') || 'Output'} value={outputState.value} readonly={true} hasError={outputState.error} placeholder={i18n.t('common.form.outputResult', { format: 'text' })}>
      {#snippet actionButton()}
        <ButtonIcon 
          onclick={() => downloadFile(outputState.value, generateDownloadFilename(tool.id))} 
          color="green"
          title={i18n.t('common.action.download') || 'Download'} 
          disabled={!outputState.value || outputState.error}
        >
          <Download class="w-4 h-4" />
        </ButtonIcon>

        <ButtonIcon 
          onclick={() => copyText(outputState.value)} 
          color="blue"
          title={i18n.t('common.action.copy') || 'Copy'} 
          disabled={!outputState.value || outputState.error}
        >
          <Copy class="w-4 h-4" />
        </ButtonIcon>
      {/snippet}
    </TextPanel>
  {/snippet}
</SplitWorkspace>