<script lang="ts">
  import { i18n } from '$lib/i18n';
  import { colord, extend } from 'colord';
  import namesPlugin from 'colord/plugins/names';
  import cmykPlugin from 'colord/plugins/cmyk';
  import hwbPlugin from 'colord/plugins/hwb';
  import lchPlugin from 'colord/plugins/lch';
  import labPlugin from 'colord/plugins/lab';
  import xyzPlugin from 'colord/plugins/xyz';
  import harmoniesPlugin from 'colord/plugins/harmonies';
  import a11yPlugin from 'colord/plugins/a11y';
  import mixPlugin from 'colord/plugins/mix';
  import twColors from 'tailwindcss/colors';

  import { Copy, RefreshCw, Palette, CheckCircle2, XCircle, LayoutGrid, Eye, Layers, AlertTriangle, Contrast, Droplet, Info, Star } from 'lucide-svelte';
  import { copyText } from '$lib/utils/clipboard';
  import { tooltip } from '$lib/actions/tooltip';
  import { Select } from '$lib/components/ui';
  import { smartInputState } from '$lib/utils/smartInput';
  import { favoritesStore } from '$lib/stores/favorites.svelte';
  import { onMount } from 'svelte';

  import type { ToolDefinition } from '$lib/types';

  // Initialize plugins
  extend([namesPlugin, cmykPlugin, hwbPlugin, lchPlugin, labPlugin, xyzPlugin, harmoniesPlugin, a11yPlugin, mixPlugin]);

  export interface ColorConverterProps {
    tool: ToolDefinition;
  }

  let { tool }: ColorConverterProps = $props();

  let isFavorite = $derived(favoritesStore.has(tool.id));

  // Internal state holding the master color
  let activeColor = $state(colord('#3b82f6')); // Default Tailwind Blue 500
  let isAlphaEnabled = $state(false);

  onMount(() => {
    const passedData = smartInputState.consume();
    if (passedData) {
      const parsed = colord(passedData);
      if (parsed.isValid()) {
        activeColor = parsed;
      }
    }
  });

  // Helper formatting functions
  function formatHsv(obj: any) { return `hsv(${Math.round(obj.h)}, ${Math.round(obj.s)}%, ${Math.round(obj.v)}%${obj.a !== 1 ? `, ${obj.a}` : ''})`; }
  function formatHwb(obj: any) { return `hwb(${Math.round(obj.h)}, ${Math.round(obj.w)}%, ${Math.round(obj.b)}%${obj.a !== 1 ? `, ${obj.a}` : ''})`; }
  function formatLch(obj: any) { return `lch(${Math.round(obj.l)}% ${Math.round(obj.c)} ${Math.round(obj.h)}${obj.a !== 1 ? ` / ${obj.a}` : ''})`; }
  function formatLab(obj: any) { return `lab(${Math.round(obj.l)}% ${Math.round(obj.a)} ${Math.round(obj.b)}${obj.a !== 1 ? ` / ${obj.a}` : ''})`; }
  function formatXyz(obj: any) { return `xyz(${Math.round(obj.x)}, ${Math.round(obj.y)}, ${Math.round(obj.z)}${obj.a !== 1 ? `, ${obj.a}` : ''})`; }

  // Derived formats
  let hexString = $derived(isAlphaEnabled ? activeColor.toHex() : activeColor.toHex().substring(0, 7));
  let rgbString = $derived(activeColor.toRgbString());
  let hslString = $derived(activeColor.toHslString());
  let cmykString = $derived(activeColor.toCmykString());
  let hsvString = $derived(formatHsv(activeColor.toHsv()));
  let hwbString = $derived(formatHwb(activeColor.toHwb()));
  let lchString = $derived(formatLch(activeColor.toLch()));
  let labString = $derived(formatLab(activeColor.toLab()));
  let xyzString = $derived(formatXyz(activeColor.toXyz()));
  
  let cssNameString = $derived(activeColor.toName({ closest: true }) || 'none');

  // Input bindings
  let inputHex = $state(hexString);
  let inputRgb = $state(rgbString);
  let inputHsl = $state(hslString);
  let inputCmyk = $state(cmykString);
  let inputHsv = $state(hsvString);
  let inputHwb = $state(hwbString);
  let inputLch = $state(lchString);
  let inputLab = $state(labString);
  let inputXyz = $state(xyzString);

  $effect(() => {
    inputHex = hexString;
    inputRgb = rgbString;
    inputHsl = hslString;
    inputCmyk = cmykString;
    inputHsv = hsvString;
    inputHwb = hwbString;
    inputLch = lchString;
    inputLab = labString;
    inputXyz = xyzString;
  });

  function handleChange(e: Event, setter: (val: string) => void) {
    const val = (e.target as HTMLInputElement).value;
    setter(val);
    const c = colord(val);
    if (c.isValid()) activeColor = c;
  }

  function setRandomColor() {
    const randomHex = '#' + Math.floor(Math.random()*16777215).toString(16).padStart(6, '0');
    activeColor = colord(randomHex);
  }

  function handleCopy(text: string) {
    copyText(text);
  }

  // A11y
  let contrastWhite = $derived(activeColor.contrast('#ffffff').toFixed(2));
  let contrastBlack = $derived(activeColor.contrast('#000000').toFixed(2));
  let isReadableWhite = $derived(activeColor.isReadable('#ffffff'));
  let isReadableBlack = $derived(activeColor.isReadable('#000000'));

  // Harmonies
  let analogous = $derived(activeColor.harmonies('analogous').map(c => c.toHex().substring(0, 7)));
  let complementary = $derived(activeColor.harmonies('complementary').map(c => c.toHex().substring(0, 7)));
  let triadic = $derived(activeColor.harmonies('triadic').map(c => c.toHex().substring(0, 7)));

  // Shades & Tints (Tailwind style)
  let tailwindScale = $derived([
    { label: '50', color: activeColor.mix('#ffffff', 0.95).toHex().substring(0, 7) },
    { label: '100', color: activeColor.mix('#ffffff', 0.9).toHex().substring(0, 7) },
    { label: '200', color: activeColor.mix('#ffffff', 0.7).toHex().substring(0, 7) },
    { label: '300', color: activeColor.mix('#ffffff', 0.5).toHex().substring(0, 7) },
    { label: '400', color: activeColor.mix('#ffffff', 0.3).toHex().substring(0, 7) },
    { label: '500', color: activeColor.toHex().substring(0, 7) },
    { label: '600', color: activeColor.mix('#000000', 0.2).toHex().substring(0, 7) },
    { label: '700', color: activeColor.mix('#000000', 0.4).toHex().substring(0, 7) },
    { label: '800', color: activeColor.mix('#000000', 0.6).toHex().substring(0, 7) },
    { label: '900', color: activeColor.mix('#000000', 0.8).toHex().substring(0, 7) },
    { label: '950', color: activeColor.mix('#000000', 0.9).toHex().substring(0, 7) }
  ]);

  // Tailwind Default Palettes
  const deprecatedColors = ['lightBlue', 'warmGray', 'trueGray', 'coolGray', 'blueGray'];
  const singleColors = ['inherit', 'current', 'transparent', 'black', 'white'];
  
  const tailwindPalettes = Object.keys(twColors)
    .filter(name => !deprecatedColors.includes(name) && !singleColors.includes(name))
    .map(name => ({
      name,
      // @ts-expect-error twColors[name] is valid
      colors: twColors[name]
    }));

  let selectedTailwindPaletteName = $state('blue');
  let selectedTailwindPalette = $derived(
    tailwindPalettes.find(p => p.name === selectedTailwindPaletteName)?.colors || {}
  );
  let tailwindPaletteSteps = $derived(Object.entries(selectedTailwindPalette).map(([label, color]) => ({ label, color: color as string })));

  const primaryInputs = [
    { label: 'HEX', value: inputHex, setter: (v: string) => inputHex = v, get str() { return hexString; } },
    { label: 'RGB', value: inputRgb, setter: (v: string) => inputRgb = v, get str() { return rgbString; } },
    { label: 'HSL', value: inputHsl, setter: (v: string) => inputHsl = v, get str() { return hslString; } },
    { label: 'CMYK', value: inputCmyk, setter: (v: string) => inputCmyk = v, get str() { return cmykString; } },
  ];

  const advancedInputs = [
    { label: 'HSV', value: inputHsv, setter: (v: string) => inputHsv = v, get str() { return hsvString; } },
    { label: 'HWB', value: inputHwb, setter: (v: string) => inputHwb = v, get str() { return hwbString; } },
    { label: 'LCH', value: inputLch, setter: (v: string) => inputLch = v, get str() { return lchString; } },
    { label: 'LAB', value: inputLab, setter: (v: string) => inputLab = v, get str() { return labString; } },
    { label: 'XYZ', value: inputXyz, setter: (v: string) => inputXyz = v, get str() { return xyzString; } },
  ];
</script>

<div class="h-[calc(100vh-8rem)] lg:h-[calc(100vh-10.6rem)] bg-white dark:bg-[#1e1e1e] rounded-2xl border border-gray-200 dark:border-gray-800 shadow-sm overflow-hidden flex flex-col lg:flex-row">
  
  <!-- Left/Top: Color Preview Pane -->
  <div class="relative w-full lg:w-2/5 xl:w-1/3 flex flex-col items-center justify-center p-8 shrink-0 border-b lg:border-b-0 lg:border-r border-gray-200 dark:border-gray-800 transition-colors duration-300" style="background-color: {activeColor.toHex()};">
    
    <!-- Pattern Overlay for Alpha transparency -->
    <div class="absolute inset-0 z-0 opacity-20 pointer-events-none" style="background-image: repeating-conic-gradient(#808080 0% 25%, transparent 0% 50%); background-size: 20px 20px;"></div>
    <div class="absolute inset-0 z-0 transition-colors duration-300" style="background-color: {activeColor.toHex()};"></div>

    <div class="relative z-10 w-full max-w-xs p-6 bg-white/20 dark:bg-black/20 backdrop-blur-xl border border-white/30 dark:border-white/10 rounded-3xl shadow-2xl flex flex-col items-center gap-4">
      <div class="relative">
        <!-- Native Color Picker Hidden behind custom button -->
        <input 
          type="color" 
          value={activeColor.toHex().substring(0, 7)}
          oninput={(e) => {
            const c = colord(e.currentTarget.value);
            c.alpha(activeColor.alpha()); // preserve alpha
            activeColor = c;
          }}
          class="absolute inset-0 opacity-0 cursor-pointer w-full h-full z-20"
        />
        <div class="w-20 h-20 rounded-full border-4 border-white shadow-lg flex items-center justify-center transition-colors duration-300 z-10 relative pointer-events-none" style="background-color: {activeColor.toHex()};">
          <Palette class="w-6 h-6 text-white mix-blend-difference" />
        </div>
      </div>
      
      <div class="text-center">
        <h2 class="text-3xl font-bold text-white drop-shadow-md tracking-wider uppercase">{hexString}</h2>
        <p class="text-white/80 text-sm font-medium drop-shadow uppercase">{cssNameString}</p>
      </div>

      <button 
        onclick={setRandomColor}
        class="mt-2 flex items-center gap-2 px-4 py-2 bg-white/20 hover:bg-white/30 dark:bg-black/20 dark:hover:bg-black/40 text-white rounded-full font-medium text-sm transition-all shadow-sm backdrop-blur-md"
      >
        <RefreshCw class="w-4 h-4" /> Random Color
      </button>
    </div>
  </div>

  <!-- Right/Bottom: Inputs Pane -->
  <div class="flex-1 p-6 lg:p-10 overflow-y-auto custom-scrollbar bg-gray-50/50 dark:bg-gray-900/50">
    <div class="max-w-5xl mx-auto space-y-10">
      
      <!-- Header -->
      <div>
        <div class="flex items-center gap-3">
          <h1 class="text-2xl font-bold text-gray-900 dark:text-gray-100 flex items-center gap-2">
            {i18n.t(tool.name)}
          </h1>
          <button 
            class="p-1 mt-0.5 rounded-lg text-gray-400 hover:text-amber-500 hover:bg-amber-50 dark:hover:bg-amber-900/30 transition-all {isFavorite ? 'text-amber-500' : ''}"
            onclick={() => favoritesStore.toggle(tool.id)}
            title={isFavorite ? i18n.t('ui.tooltips.favorites.remove') : i18n.t('ui.tooltips.favorites.add')}
          >
            <Star class="w-5 h-5 {isFavorite ? 'fill-current' : ''}" />
          </button>
        </div>
        <p class="text-sm text-gray-500 dark:text-gray-400 mt-1">
          {i18n.t(tool.description || '')}
        </p>
      </div>

      <div class="flex flex-col xl:flex-row gap-8 items-stretch">
        
        <!-- Left Column: Alpha & Forms -->
        <div class="flex-1 space-y-10">
          
          <!-- Alpha Toggle -->
          <div class="flex items-center justify-between p-4 bg-white dark:bg-gray-800 rounded-xl border border-gray-200 dark:border-gray-700 shadow-sm">
            <div class="flex flex-col">
              <span class="text-sm font-bold text-gray-800 dark:text-gray-200">Opacity (Alpha)</span>
              <span class="text-xs text-gray-500 dark:text-gray-400">Enable transparency support (RGBA, HSLA)</span>
            </div>
            <label class="relative inline-flex items-center cursor-pointer">
              <input type="checkbox" bind:checked={isAlphaEnabled} class="sr-only peer">
              <div class="w-11 h-6 bg-gray-200 peer-focus:outline-none peer-focus:ring-4 peer-focus:ring-blue-300 dark:peer-focus:ring-blue-800 rounded-full peer dark:bg-gray-700 peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-5 after:w-5 after:transition-all dark:border-gray-600 peer-checked:bg-blue-600"></div>
            </label>
          </div>

          {#if isAlphaEnabled}
            <div class="p-4 bg-white dark:bg-gray-800 rounded-xl border border-gray-200 dark:border-gray-700 shadow-sm flex items-center gap-4">
              <span class="text-sm font-bold text-gray-800 dark:text-gray-200 w-16">Alpha</span>
              <input 
                type="range" 
                min="0" max="1" step="0.01" 
                value={activeColor.alpha()}
                oninput={(e) => {
                  const val = parseFloat(e.currentTarget.value);
                  activeColor = activeColor.alpha(val);
                }}
                class="flex-1 h-2 bg-gray-200 rounded-lg appearance-none cursor-pointer dark:bg-gray-700"
              >
              <span class="text-sm font-mono text-gray-500 dark:text-gray-400 w-12 text-right">
                {Math.round(activeColor.alpha() * 100)}%
              </span>
            </div>
          {/if}

          <div class="flex flex-col md:flex-row gap-8 items-start">
            <!-- Form Inputs Left -->
            <div class="flex-1 min-w-0 space-y-6 w-full">
              
              <div class="space-y-3">
                <h3 class="text-sm font-bold text-gray-800 dark:text-gray-200 mb-2 flex items-center gap-1.5">
                  <Palette class="w-4 h-4 text-blue-500"/> Core Formats
                  <span use:tooltip={{ content: 'Standard color formats widely used in web development and design.', position: 'top', contentClass: 'w-48 text-center p-2 font-normal leading-relaxed pointer-events-none' }}>
                    <Info class="w-3.5 h-3.5 text-gray-400 hover:text-blue-500 cursor-help transition-colors" />
                  </span>
                </h3>
                {#each primaryInputs as inputItem (inputItem.label)}
                  <div class="group relative bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-xl shadow-sm focus-within:ring-2 focus-within:ring-blue-500 focus-within:border-blue-500 transition-all flex overflow-hidden">
                    <div class="bg-gray-100 dark:bg-gray-900 w-16 flex items-center justify-center border-r border-gray-200 dark:border-gray-700 shrink-0">
                      <span class="text-[10px] font-bold text-gray-600 dark:text-gray-400 tracking-wider">{inputItem.label}</span>
                    </div>
                    <input 
                      type="text" 
                      value={inputItem.value} 
                      oninput={(e) => handleChange(e, inputItem.setter)}
                      class="flex-1 bg-transparent border-none focus:ring-0 text-xs font-mono text-gray-800 dark:text-gray-200 px-3 py-2 outline-none"
                      spellcheck="false"
                    />
                    <button 
                      onclick={() => handleCopy(inputItem.str)}
                      class="px-3 text-gray-400 hover:text-blue-500 hover:bg-gray-50 dark:hover:bg-gray-700 transition-colors border-l border-gray-200 dark:border-gray-700 shrink-0 flex items-center justify-center"
                      title={i18n.t('common.copy')}
                    >
                      <Copy class="w-3.5 h-3.5" />
                    </button>
                  </div>
                {/each}
              </div>

              <div class="space-y-3">
                <h3 class="text-sm font-bold text-gray-800 dark:text-gray-200 mb-2 flex items-center gap-1.5 mt-6">
                  <Layers class="w-4 h-4 text-blue-500"/> Advanced Formats
                  <span use:tooltip={{ content: 'Modern, perceptually uniform color spaces like LCH, LAB, and XYZ.', position: 'top', contentClass: 'w-48 text-center p-2 font-normal leading-relaxed pointer-events-none' }}>
                    <Info class="w-3.5 h-3.5 text-gray-400 hover:text-blue-500 cursor-help transition-colors" />
                  </span>
                </h3>
                {#each advancedInputs as inputItem (inputItem.label)}
                  <div class="group relative bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-xl shadow-sm focus-within:ring-2 focus-within:ring-blue-500 focus-within:border-blue-500 transition-all flex overflow-hidden">
                    <div class="bg-gray-100 dark:bg-gray-900 w-16 flex items-center justify-center border-r border-gray-200 dark:border-gray-700 shrink-0">
                      <span class="text-[10px] font-bold text-gray-600 dark:text-gray-400 tracking-wider">{inputItem.label}</span>
                    </div>
                    <input 
                      type="text" 
                      value={inputItem.value} 
                      oninput={(e) => handleChange(e, inputItem.setter)}
                      class="flex-1 bg-transparent border-none focus:ring-0 text-xs font-mono text-gray-800 dark:text-gray-200 px-3 py-2 outline-none"
                      spellcheck="false"
                    />
                    <button 
                      onclick={() => handleCopy(inputItem.str)}
                      class="px-3 text-gray-400 hover:text-blue-500 hover:bg-gray-50 dark:hover:bg-gray-700 transition-colors border-l border-gray-200 dark:border-gray-700 shrink-0 flex items-center justify-center"
                      title={i18n.t('common.copy')}
                    >
                      <Copy class="w-3.5 h-3.5" />
                    </button>
                  </div>
                {/each}
              </div>

            </div>

            <!-- Extra Features Right -->
            <div class="flex-1 shrink-0 space-y-6">
              
              <!-- Accessibility Checker -->
              <div class="bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-xl p-4 shadow-sm">
                <h3 class="text-sm font-bold text-gray-800 dark:text-gray-200 mb-4 flex items-center gap-1.5">
                  <Eye class="w-4 h-4 text-purple-500"/> WCAG Accessibility
                  <span use:tooltip={{ content: 'Check contrast ratio against WCAG AA requirements (4.5:1 minimum) for both white and black text.', position: 'top', contentClass: 'w-56 text-center p-2 font-normal leading-relaxed pointer-events-none' }}>
                    <Info class="w-3.5 h-3.5 text-gray-400 hover:text-blue-500 cursor-help transition-colors" />
                  </span>
                </h3>
                
                <div class="space-y-3">
                  <!-- White Text -->
                  <div class="flex items-center justify-between p-3 rounded-lg border border-gray-100 dark:border-gray-700" style="background-color: {activeColor.toHex()};">
                    <span class="text-sm font-semibold text-white drop-shadow-md">White Text</span>
                    <div class="flex items-center gap-2 bg-white/90 backdrop-blur-sm px-2 py-1 rounded text-xs font-bold shadow-sm">
                      <span class="text-gray-700">{contrastWhite}:1</span>
                      {#if isReadableWhite}
                        <span class="text-green-600 flex items-center gap-1"><CheckCircle2 class="w-3.5 h-3.5"/> Pass</span>
                      {:else}
                        <span class="text-red-500 flex items-center gap-1"><XCircle class="w-3.5 h-3.5"/> Fail</span>
                      {/if}
                    </div>
                  </div>

                  <!-- Black Text -->
                  <div class="flex items-center justify-between p-3 rounded-lg border border-gray-100 dark:border-gray-700" style="background-color: {activeColor.toHex()};">
                    <span class="text-sm font-semibold text-black drop-shadow-sm">Black Text</span>
                    <div class="flex items-center gap-2 bg-white/90 backdrop-blur-sm px-2 py-1 rounded text-xs font-bold shadow-sm">
                      <span class="text-gray-700">{contrastBlack}:1</span>
                      {#if isReadableBlack}
                        <span class="text-green-600 flex items-center gap-1"><CheckCircle2 class="w-3.5 h-3.5"/> Pass</span>
                      {:else}
                        <span class="text-red-500 flex items-center gap-1"><XCircle class="w-3.5 h-3.5"/> Fail</span>
                      {/if}
                    </div>
                  </div>
                </div>
                <p class="text-[10px] text-gray-500 mt-2 flex items-center gap-1">
                  <AlertTriangle class="w-3 h-3"/> Checked against WCAG AA requirements (4.5:1 ratio).
                </p>
              </div>

              <!-- Harmonies -->
              <div class="bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-xl p-4 shadow-sm">
                <h3 class="text-sm font-bold text-gray-800 dark:text-gray-200 mb-4 flex items-center gap-1.5">
                  <LayoutGrid class="w-4 h-4 text-pink-500"/> Harmonies
                  <span use:tooltip={{ content: 'Classic color combinations based on traditional color theory.', position: 'top', contentClass: 'w-48 text-center p-2 font-normal leading-relaxed pointer-events-none' }}>
                    <Info class="w-3.5 h-3.5 text-gray-400 hover:text-blue-500 cursor-help transition-colors" />
                  </span>
                </h3>

                <div class="space-y-4">
                  <!-- Analogous -->
                  <div>
                    <p class="text-[10px] font-bold text-gray-500 dark:text-gray-400 uppercase tracking-wider mb-1">Analogous</p>
                    <div class="flex h-8 rounded-lg overflow-hidden border border-gray-200 dark:border-gray-700">
                      {#each analogous as c (c)}
                        <!-- svelte-ignore a11y_click_events_have_key_events -->
                        <!-- svelte-ignore a11y_no_static_element_interactions -->
                        <div onclick={() => { activeColor = colord(c); handleCopy(c); }} class="flex-1 cursor-pointer hover:opacity-90 transition-opacity" style="background-color: {c};" title="{i18n.t('ui.tooltips.action.clickToUse')} {c}"></div>
                      {/each}
                    </div>
                  </div>

                  <!-- Complementary -->
                  <div>
                    <p class="text-[10px] font-bold text-gray-500 dark:text-gray-400 uppercase tracking-wider mb-1">Complementary</p>
                    <div class="flex h-8 rounded-lg overflow-hidden border border-gray-200 dark:border-gray-700">
                      {#each complementary as c (c)}
                        <!-- svelte-ignore a11y_click_events_have_key_events -->
                        <!-- svelte-ignore a11y_no_static_element_interactions -->
                        <div onclick={() => { activeColor = colord(c); handleCopy(c); }} class="flex-1 cursor-pointer hover:opacity-90 transition-opacity" style="background-color: {c};" title="{i18n.t('ui.tooltips.action.clickToUse')} {c}"></div>
                      {/each}
                    </div>
                  </div>

                  <!-- Triadic -->
                  <div>
                    <p class="text-[10px] font-bold text-gray-500 dark:text-gray-400 uppercase tracking-wider mb-1">Triadic</p>
                    <div class="flex h-8 rounded-lg overflow-hidden border border-gray-200 dark:border-gray-700">
                      {#each triadic as c (c)}
                        <!-- svelte-ignore a11y_click_events_have_key_events -->
                        <!-- svelte-ignore a11y_no_static_element_interactions -->
                        <div onclick={() => { activeColor = colord(c); handleCopy(c); }} class="flex-1 cursor-pointer hover:opacity-90 transition-opacity" style="background-color: {c};" title="{i18n.t('ui.tooltips.action.clickToUse')} {c}"></div>
                      {/each}
                    </div>
                  </div>
                </div>
              </div>

            </div>
          </div>
        </div>

        <!-- Right Column: Vertical Shades & Tints Scale -->
        <div class="w-full xl:w-44 shrink-0 flex flex-col">
          <!-- Shades & Tints Scale -->
          <div class="bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-xl p-4 shadow-sm flex flex-col h-full">
            <h3 class="text-sm font-bold text-gray-800 dark:text-gray-200 mb-4 flex items-center justify-start gap-1.5">
              <Contrast class="w-4 h-4 text-orange-500"/> 
              <span class="hidden xl:flex items-center gap-1">
                Color Scale
                <span use:tooltip={{ content: 'Tailwind Color Scale (Shades & Tints)', position: 'top', contentClass: 'w-48 text-center p-2 font-normal leading-relaxed pointer-events-none' }}>
                  <Info class="w-3.5 h-3.5 text-gray-400 hover:text-blue-500 cursor-help transition-colors" />
                </span>
              </span>
              <span class="inline xl:hidden">Tailwind Color Scale (Shades & Tints)</span>
            </h3>
            
            <div class="flex xl:flex-row flex-col gap-2 flex-1 min-h-[60px] xl:min-h-0">
              <div class="flex xl:flex-col flex-row gap-1 flex-1">
                {#each tailwindScale as step (step.color)}
                  <!-- svelte-ignore a11y_click_events_have_key_events -->
                  <!-- svelte-ignore a11y_no_static_element_interactions -->
                  <div 
                    onclick={() => { activeColor = colord(step.color); handleCopy(step.color); }}
                    class="flex flex-col items-center justify-center rounded border border-gray-200 dark:border-gray-700 cursor-pointer hover:scale-105 transition-transform duration-200 relative group overflow-hidden flex-1 w-full min-h-[30px]"
                    style="background-color: {step.color};"
                    title="{i18n.t('ui.tooltips.action.apply')} {step.color}"
                  >
                    <div class="opacity-0 group-hover:opacity-100 transition-opacity absolute inset-0 flex flex-col items-center justify-center bg-black/60 text-white drop-shadow-md">
                      <span class="text-[10px] font-bold leading-tight">{step.label}</span>
                      <button 
                        class="text-[8px] sm:text-[9px] font-mono hover:text-blue-300 hover:scale-110 transition-all z-10 p-0.5 leading-tight"
                        onclick={(e) => { e.stopPropagation(); handleCopy(step.color); }}
                        title={i18n.t('ui.tooltips.copy.hex')}
                      >
                        {step.color}
                      </button>
                    </div>
                  </div>
                {/each}
              </div>

              <!-- Vertical / Horizontal Labels -->
              <div class="flex flex-row xl:flex-col justify-between px-1 xl:px-0 py-0 xl:py-1 items-center">
                <span class="text-[10px] font-bold text-gray-400 text-center leading-none tracking-widest xl:[writing-mode:vertical-rl]">50</span>
                <span class="text-[10px] font-bold text-gray-400 text-center leading-none tracking-widest xl:[writing-mode:vertical-rl]">500</span>
                <span class="text-[10px] font-bold text-gray-400 text-center leading-none tracking-widest xl:[writing-mode:vertical-rl]">950</span>
              </div>
            </div>
            
          </div>
        </div>

      </div>

      <!-- Tailwind Default Palettes -->
      <div class="bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-xl p-4 shadow-sm mt-8 mb-4">
        <div class="flex flex-col sm:flex-row sm:items-center justify-between mb-4 gap-3">
          <h3 class="text-sm font-bold text-gray-800 dark:text-gray-200 flex items-center gap-1.5">
            <Droplet class="w-4 h-4 text-emerald-500"/> Tailwind CSS Default Palettes
            <span use:tooltip={{ content: 'Pick a color from the default Tailwind CSS v3 palette.', position: 'top', contentClass: 'w-48 text-center p-2 font-normal leading-relaxed pointer-events-none' }}>
              <Info class="w-3.5 h-3.5 text-gray-400 hover:text-blue-500 cursor-help transition-colors" />
            </span>
          </h3>
          <Select 
            id="tailwind-palette"
            label="Palette"
            bind:value={selectedTailwindPaletteName}
            selectClass="capitalize"
          >
            {#each tailwindPalettes as palette (palette.name)}
              <option value={palette.name} class="capitalize">{palette.name}</option>
            {/each}
          </Select>
        </div>
        
        <div class="grid grid-cols-2 sm:grid-cols-11 gap-1 h-auto sm:h-20">
          {#each tailwindPaletteSteps as step (step.color)}
            <!-- svelte-ignore a11y_click_events_have_key_events -->
            <!-- svelte-ignore a11y_no_static_element_interactions -->
            <div 
              onclick={() => { activeColor = colord(step.color); handleCopy(step.color); }}
              class="flex flex-col items-center justify-center rounded border border-gray-200 dark:border-gray-700 cursor-pointer hover:scale-105 transition-transform duration-200 relative group overflow-hidden h-16 sm:h-full"
              style="background-color: {step.color};"
              title="{i18n.t('ui.tooltips.action.apply')} {step.color}"
            >
              <div class="opacity-0 group-hover:opacity-100 transition-opacity absolute inset-0 flex flex-col items-center justify-center bg-black/60 text-white drop-shadow-md">
                <span class="text-[10px] font-bold leading-tight">{step.label}</span>
                <button 
                  class="text-[8px] sm:text-[9px] font-mono hover:text-blue-300 hover:scale-110 transition-all z-10 p-0.5 leading-tight"
                  onclick={(e) => { e.stopPropagation(); handleCopy(step.color); }}
                  title={i18n.t('ui.tooltips.copy.hex')}
                >
                  {step.color}
                </button>
              </div>
            </div>
          {/each}
        </div>
        <div class="flex justify-between mt-2 px-1">
          <span class="text-[10px] font-bold text-gray-400">50</span>
          <span class="text-[10px] font-bold text-gray-400">500</span>
          <span class="text-[10px] font-bold text-gray-400">950</span>
        </div>
      </div>

    </div>
  </div>

</div>
