import { i18n } from '$lib/i18n';
import { Wand2, Minimize2, MonitorPlay } from 'lucide-svelte';

export type EditorModeType = 'pretty' | 'minify' | 'preview';

export type EditorMode = {
	value: string;
	label: string;
	type: 'code' | 'preview';
	icon?: any;
};

// Factory function to automatically generate the Mode array based on the needs of each Tool
export function createEditorModes(includes: EditorModeType[]): EditorMode[] {
	const allModes: Record<EditorModeType, EditorMode> = {
		pretty: {
			value: 'pretty',
			label: i18n.t('common.action.pretty') || 'Pretty',
			type: 'code',
			icon: Wand2
		},
		minify: {
			value: 'minify',
			label: i18n.t('common.action.minify') || 'Minify',
			type: 'code',
			icon: Minimize2
		},
		preview: {
			value: 'preview',
			label: i18n.t('common.action.preview') || 'Preview',
			type: 'preview',
			icon: MonitorPlay
		}
	};

	// Filter and return only the modes that are required
	return includes.map((mode) => allModes[mode]);
}
