import type { Component } from 'svelte';

// Mapping from toolId to its documentation component using dynamic imports.
// This ensures that documentation chunks are lazy-loaded only when the user opens the modal or visits the docs page.
export const TOOL_DOCS_MAP: Record<string, () => Promise<{ default: Component }>> = {
	'tool-base64': () => import('$lib/components/docs/tools/Base64Doc.svelte'),
	'tool-json-formatter': () => import('$lib/components/docs/tools/JsonFormatterDoc.svelte'),
	'tool-color': () => import('$lib/components/docs/tools/ColorDoc.svelte'),
	'tool-shell-explainer': () => import('$lib/components/docs/tools/ShellExplainerDoc.svelte')
};

export async function loadToolDoc(toolId: string): Promise<Component | null> {
	if (TOOL_DOCS_MAP[toolId]) {
		try {
			const module = await TOOL_DOCS_MAP[toolId]();
			return module.default;
		} catch (error) {
			console.error(`Failed to load documentation for ${toolId}:`, error);
			return null;
		}
	}
	return null;
}
