<script lang="ts">
  import { i18n } from '$lib/i18n';
  import { createTool } from '$lib/stores';
  import { ToolWrapper } from '$lib/components/layout';
  import SplitWorkspace from '$lib/components/layout/templates/SplitWorkspace.svelte';
  import { SegmentedControl, Button, ButtonIcon, Separator, Select, FullscreenToggle } from '$lib/components/ui';
  import { FileText, Map, ListStart, Calculator, Copy, Clock, Check, Code2, FileCode2, Trash2, ChevronDown, ArrowRightLeft, Hash, CalendarDays } from 'lucide-svelte';
  import { copyText } from '$lib/utils/clipboard';
  import { slide } from 'svelte/transition';
  import type { ToolDefinition } from '$lib/types';

  export interface DateConverterProps {
    tool: ToolDefinition;
  }
  let { tool }: DateConverterProps = $props();

  let isFullFrame = $state(false);
  let isTimezoneDropdownOpen = $state(false);
  let inputType = $state<'text' | 'datetime-local'>('text');

  function toggleInputType() {
    if (inputType === 'text') {
      inputType = 'datetime-local';
      if (parsedDate) {
        const tzoffset = parsedDate.getTimezoneOffset() * 60000;
        storage.value.source = (new Date(parsedDate.getTime() - tzoffset)).toISOString().slice(0, 19);
      }
    } else {
      inputType = 'text';
      if (parsedDate) {
        storage.value.source = Math.floor(parsedDate.getTime() / 1000).toString();
      }
    }
  }

  function handleQuickFill() {
    if (inputType === 'text') {
      storage.value.source = Math.floor(Date.now() / 1000).toString();
    } else {
      const now = new Date();
      const tzoffset = now.getTimezoneOffset() * 60000;
      storage.value.source = (new Date(now.getTime() - tzoffset)).toISOString().slice(0, 19);
    }
  }

  const storage = createTool(tool.slug, {
    mode: 'single_convert', // 'single_convert', 'batch_conversion'
    source: '',
    selectedTimezones: ['UTC', 'America/New_York', 'Europe/London', 'Asia/Tokyo', 'Australia/Sydney'],
    batchInput: '',
    batchFormat: 'iso', // iso, utc, local, unix_s, unix_ms
    mathAmount: 1,
    mathUnit: 'days', // years, months, days, hours, minutes, seconds
    mathOp: 'add' // add, subtract
  });

  const COMMON_TIMEZONES = [
    { value: 'UTC', label: 'UTC / GMT' },
    { value: 'America/New_York', label: 'New York (EST/EDT)' },
    { value: 'America/Los_Angeles', label: 'Los Angeles (PST/PDT)' },
    { value: 'Europe/London', label: 'London (GMT/BST)' },
    { value: 'Europe/Paris', label: 'Paris (CET/CEST)' },
    { value: 'Asia/Dubai', label: 'Dubai (GST)' },
    { value: 'Asia/Tokyo', label: 'Tokyo (JST)' },
    { value: 'Asia/Shanghai', label: 'Shanghai (CST)' },
    { value: 'Asia/Singapore', label: 'Singapore (SGT)' },
    { value: 'Asia/Ho_Chi_Minh', label: 'Ho Chi Minh (ICT)' },
    { value: 'Australia/Sydney', label: 'Sydney (AEST/AEDT)' },
    { value: 'Pacific/Auckland', label: 'Auckland (NZST/NZDT)' }
  ];

  function toggleTimezone(tz: string) {
    if (storage.value.selectedTimezones.includes(tz)) {
      storage.value.selectedTimezones = storage.value.selectedTimezones.filter((t: string) => t !== tz);
    } else {
      storage.value.selectedTimezones = [...storage.value.selectedTimezones, tz];
    }
  }

  let parsedDate = $derived.by(() => {
    const val = storage.value.source.trim();
    if (!val) return new Date(); // Auto use now if empty
    
    if (/^\d+$/.test(val)) {
      const ts = parseInt(val);
      return new Date(ts > 9999999999 ? ts : ts * 1000);
    }
    
    const d = new Date(val);
    if (!isNaN(d.getTime())) return d;
    
    return null; // Invalid
  });

  const formatMatrix = $derived.by(() => {
    if (!parsedDate) return [];
    
    return [
      { label: 'Unix Epoch (Seconds)', value: Math.floor(parsedDate.getTime() / 1000).toString() },
      { label: 'Unix Epoch (Milliseconds)', value: parsedDate.getTime().toString() },
      { label: 'ISO 8601', value: parsedDate.toISOString() },
      { label: 'UTC String', value: parsedDate.toUTCString() },
      { label: 'Local String', value: parsedDate.toString() },
      { label: 'Date String', value: parsedDate.toDateString() },
      { label: 'Time String', value: parsedDate.toTimeString() }
    ];
  });

  const batchOutput = $derived.by(() => {
    if (!storage.value.batchInput.trim()) return '';
    const lines = storage.value.batchInput.split('\n');
    return lines.map(line => {
      const val = line.trim();
      if (!val) return '';
      let d: Date | null = null;
      if (/^\d+$/.test(val)) {
        const ts = parseInt(val);
        d = new Date(ts > 9999999999 ? ts : ts * 1000);
      } else {
        const parsed = new Date(val);
        if (!isNaN(parsed.getTime())) d = parsed;
      }
      
      if (!d) return 'Invalid format';
      
      switch (storage.value.batchFormat) {
        case 'utc': return d.toUTCString();
        case 'local': return d.toString();
        case 'unix_s': return Math.floor(d.getTime() / 1000).toString();
        case 'unix_ms': return d.getTime().toString();
        case 'iso':
        default: return d.toISOString();
      }
    }).join('\n');
  });

  const mathResult = $derived.by(() => {
    if (!parsedDate) return null;
    const result = new Date(parsedDate.getTime());
    const amount = storage.value.mathOp === 'add' ? storage.value.mathAmount : -storage.value.mathAmount;
    
    switch (storage.value.mathUnit) {
      case 'years': result.setFullYear(result.getFullYear() + amount); break;
      case 'months': result.setMonth(result.getMonth() + amount); break;
      case 'days': result.setDate(result.getDate() + amount); break;
      case 'hours': result.setHours(result.getHours() + amount); break;
      case 'minutes': result.setMinutes(result.getMinutes() + amount); break;
      case 'seconds': result.setSeconds(result.getSeconds() + amount); break;
    }
    return result;
  });

  const modeOptions = $derived([
    { value: 'single_convert', label: i18n.t('tools.dateConverter.modes.singleConvert') || 'Single Convert', icon: FileText },
    { value: 'batch_conversion', label: i18n.t('tools.dateConverter.modes.batchConversion') || 'Batch Conversion', icon: ListStart }
  ]);

</script>

{#if storage.value.mode === 'batch_conversion'}
  <SplitWorkspace {tool}>
    {#snippet headerLeftControls()}
      <div class="flex items-center gap-2">
        <SegmentedControl bind:value={storage.value.mode} options={modeOptions} class="shadow-sm" />
        <Separator orientation="vertical" size="4" class="hidden sm:block" />
        <Select 
          id="batchFormat" 
          label="Target Format"
          bind:value={storage.value.batchFormat}
        >
          <option value="iso">ISO 8601</option>
          <option value="utc">UTC String</option>
          <option value="local">Local String</option>
          <option value="unix_s">Unix Epoch (Sec)</option>
          <option value="unix_ms">Unix Epoch (MS)</option>
        </Select>
      </div>
    {/snippet}

    {#snippet leftPanel()}
      <div class="flex flex-col h-full overflow-hidden">
        <div class="flex items-center justify-between px-4 py-2 bg-gray-50 dark:bg-gray-900 border-b border-gray-200 dark:border-gray-800 h-11 shrink-0">
          <div class="flex items-center gap-3">
            <span class="flex items-center gap-1.5 text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider">
              <Code2 class="w-3.5 h-3.5" /> Input
            </span>
          </div>
          <ButtonIcon onclick={() => storage.value.batchInput = ''} disabled={!storage.value.batchInput} color="rose" title={i18n.t('common.action.clear') || 'Clear'}>
            <Trash2 class="w-4 h-4" />
          </ButtonIcon>
        </div>
        <div class="flex-1 w-full relative">
          <textarea
            bind:value={storage.value.batchInput}
            placeholder="1719061413&#10;2024-01-01T12:00:00Z&#10;yesterday"
            class="w-full h-full p-4 bg-transparent text-sm font-mono text-gray-900 dark:text-gray-100 placeholder:text-gray-400 outline-none resize-none custom-scrollbar"
          ></textarea>
        </div>
      </div>
    {/snippet}

    {#snippet rightPanel()}
      <div class="flex flex-col h-full overflow-hidden">
        <div class="flex items-center justify-between px-4 py-2 bg-gray-50 dark:bg-gray-900 border-b border-gray-200 dark:border-gray-800 h-11 shrink-0">
          <div class="flex items-center gap-2 px-2">
            <span class="flex items-center gap-1.5 text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider">
              <FileCode2 class="w-3.5 h-3.5" /> Output
            </span>
          </div>
          <div class="flex items-center gap-1">
            <ButtonIcon onclick={() => copyText(batchOutput)} disabled={!batchOutput} color="blue" title={i18n.t('common.action.copy') || 'Copy'}>
              <Copy class="w-4 h-4" />
            </ButtonIcon>
          </div>
        </div>
        <div class="flex-1 w-full relative">
          <textarea
            readonly
            value={batchOutput}
            placeholder="Results will appear here..."
            class="w-full h-full p-4 bg-transparent text-sm font-mono text-gray-900 dark:text-gray-100 placeholder:text-gray-500 outline-none resize-none custom-scrollbar"
          ></textarea>
        </div>
      </div>
    {/snippet}
  </SplitWorkspace>
{:else}
  <ToolWrapper toolId={tool.id} title={i18n.t(tool.name)} description={tool.description ? i18n.t(tool.description) : ''} {isFullFrame}>
    {#snippet headerAction()}
      <div class="flex items-center justify-between w-full gap-2 sm:gap-4 flex-wrap max-h-[38px]">
        <div class="flex items-center justify-start gap-3">
          {#if isFullFrame}
            <div class="flex items-center gap-2.5" transition:slide={{ axis: 'x', duration: 400 }}>
              <h2 class="text-3xl font-bold text-gray-800 dark:text-gray-100 whitespace-nowrap">
                {i18n.t(tool.name + 'Short')}
              </h2>
            </div>
          {/if}
          <SegmentedControl bind:value={storage.value.mode} options={modeOptions} class="shadow-sm" />
        </div>
        <div class="flex items-center justify-end gap-3">
          <FullscreenToggle bind:isFullFrame />
        </div>
      </div>
    {/snippet}

    <div class="flex flex-col {isFullFrame ? 'h-[calc(100vh-266px)] sm:h-[calc(100vh-282px)]' : 'h-[600px]'} transition-all duration-300 bg-white dark:bg-[#1e1e1e] rounded-xl border border-gray-200 dark:border-gray-800 overflow-hidden shadow-sm">
      <!-- TOP PANEL: Inputs and Controls -->
      <div class="flex-shrink-0 grid grid-cols-1 lg:grid-cols-2 gap-4 px-4 py-3 bg-gray-50 dark:bg-gray-900 border-b border-gray-200 dark:border-gray-800">
        
        <!-- LEFT HALF: Base Time & Math (Aligns with Left Bottom Panel) -->
        <div class="grid grid-cols-1 sm:grid-cols-2 gap-4">
          <!-- Column 1: Input Value -->
          <div class="flex flex-col gap-1.5 relative">
            <label class="text-xs font-semibold text-gray-600 dark:text-gray-400 uppercase tracking-wider flex items-center justify-between">
              <span>Base Time</span>
              <button onclick={handleQuickFill} class="text-blue-500 hover:text-blue-600 transition-colors" title="Auto-fill current time"><Clock class="w-3.5 h-3.5" /></button>
            </label>
            <div class="relative flex items-center h-[34px] rounded-lg border border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-800 overflow-hidden focus-within:ring-2 focus-within:ring-blue-500/20 focus-within:border-blue-500 transition-colors">
              
              <button 
                onclick={toggleInputType}
                class="flex items-center justify-center h-full px-2.5 bg-gray-100 dark:bg-gray-700/80 hover:bg-gray-200 dark:hover:bg-gray-600 border-r border-gray-200 dark:border-gray-700 transition-colors shrink-0 group/btn"
                title="Toggle input mode"
              >
                <ArrowRightLeft class="w-3.5 h-3.5 text-gray-500 group-hover/btn:text-blue-500 transition-transform duration-300 {inputType === 'datetime-local' ? '-rotate-180' : ''}" />
              </button>

              {#if inputType === 'text'}
                <div class="absolute inset-y-0 left-[35px] flex items-center pl-2 pointer-events-none text-gray-400">
                  <Hash class="w-3.5 h-3.5" />
                </div>
                <input
                  type="text"
                  bind:value={storage.value.source}
                  placeholder="Timestamp or ISO date..."
                  class="w-full h-full pl-8 pr-3 bg-transparent text-sm text-gray-900 dark:text-gray-100 placeholder:text-gray-400 outline-none border-none ring-0"
                />
              {:else}
                <div class="absolute inset-y-0 left-[35px] flex items-center pl-2 pointer-events-none text-gray-400 z-10">
                  <CalendarDays class="w-3.5 h-3.5" />
                </div>
                <input
                  type="datetime-local"
                  step="1"
                  bind:value={storage.value.source}
                  class="[&::-webkit-calendar-picker-indicator]:opacity-0 [&::-webkit-calendar-picker-indicator]:absolute [&::-webkit-calendar-picker-indicator]:top-0 [&::-webkit-calendar-picker-indicator]:left-0 [&::-webkit-calendar-picker-indicator]:w-full [&::-webkit-calendar-picker-indicator]:h-full [&::-webkit-calendar-picker-indicator]:cursor-pointer relative z-0 w-full h-full pl-8 pr-3 bg-transparent text-sm text-gray-900 dark:text-gray-100 outline-none border-none ring-0 cursor-pointer"
                />
              {/if}
            </div>
            {#if !parsedDate && storage.value.source.trim()}
              <div class="text-[10px] text-red-500 font-medium absolute -bottom-4">Invalid date</div>
            {/if}
          </div>

          <!-- Column 2: Time Math -->
          <div class="flex flex-col gap-1.5">
            <label class="text-xs font-semibold text-gray-600 dark:text-gray-400 uppercase tracking-wider">Time Math</label>
            <div class="flex items-center gap-1.5 h-[34px]">
              <Select bind:value={storage.value.mathOp} id="mathOp" label="" class="w-[45px] h-full shrink-0">
                <option value="add">+</option>
                <option value="subtract">-</option>
              </Select>
              <input 
                type="number" 
                bind:value={storage.value.mathAmount} 
                min="0" 
                class="w-16 h-full px-2 bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-lg text-sm text-center text-gray-900 dark:text-gray-100 outline-none focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 transition-colors" 
              />
              <Select bind:value={storage.value.mathUnit} id="mathUnit" label="" class="flex-1 h-full">
                <option value="years">Years</option>
                <option value="months">Months</option>
                <option value="days">Days</option>
                <option value="hours">Hours</option>
                <option value="minutes">Mins</option>
                <option value="seconds">Secs</option>
              </Select>
            </div>
          </div>
        </div>

        <!-- RIGHT HALF: Timezones (Aligns with Right Bottom Panel) -->
        <div class="flex flex-col gap-1.5 relative">
          <label class="text-xs font-semibold text-gray-600 dark:text-gray-400 uppercase tracking-wider flex justify-between items-center">
            <span>Timezones</span>
            <span class="text-[10px] font-bold text-blue-600 bg-blue-50 dark:text-blue-300 dark:bg-blue-900/30 px-1.5 py-0.5 rounded-full">{storage.value.selectedTimezones.length} selected</span>
          </label>
          <button
            onclick={() => isTimezoneDropdownOpen = !isTimezoneDropdownOpen}
            class="w-full h-[34px] px-3 flex items-center justify-between bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 hover:border-blue-300 dark:hover:border-blue-700 rounded-lg text-sm text-gray-700 dark:text-gray-300 transition-colors"
          >
            <span class="truncate pr-2">
              {storage.value.selectedTimezones.length > 0 
                ? storage.value.selectedTimezones.map((tz: string) => COMMON_TIMEZONES.find(t => t.value === tz)?.label.split(' (')[0] || tz).join(', ') 
                : 'Select timezones...'}
            </span>
            <ChevronDown class="w-4 h-4 text-gray-400 shrink-0" />
          </button>
          
          {#if isTimezoneDropdownOpen}
            <!-- svelte-ignore a11y_no_static_element_interactions -->
            <div 
              class="fixed inset-0 z-40" 
              onclick={() => isTimezoneDropdownOpen = false}
              onkeydown={(e) => e.key === 'Escape' && (isTimezoneDropdownOpen = false)}
            ></div>
            <div class="absolute z-50 top-full left-0 right-0 mt-1 bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-lg shadow-xl max-h-64 overflow-y-auto custom-scrollbar p-1.5">
              {#each COMMON_TIMEZONES as tz (tz.value)}
                <label class="flex items-center gap-2.5 p-2 hover:bg-blue-50 dark:hover:bg-blue-900/20 rounded-md cursor-pointer group transition-colors">
                  <input 
                    type="checkbox" 
                    checked={storage.value.selectedTimezones.includes(tz.value)} 
                    onchange={() => toggleTimezone(tz.value)} 
                    class="w-4 h-4 rounded border-gray-300 text-blue-600 focus:ring-blue-500 dark:border-gray-600 dark:bg-gray-700 cursor-pointer"
                  />
                  <div class="flex flex-col">
                    <span class="text-sm font-medium text-gray-900 dark:text-gray-100 group-hover:text-blue-700 dark:group-hover:text-blue-300">{tz.label}</span>
                  </div>
                </label>
              {/each}
            </div>
          {/if}
        </div>

      </div>
      
      <!-- BOTTOM PANEL: Previews -->
      <div class="flex-1 min-h-0 bg-white dark:bg-[#1e1e1e]">
        {#if !parsedDate && storage.value.source.trim()}
          <div class="w-full h-full flex items-center justify-center">
            <div class="text-center text-gray-500 dark:text-gray-400">
              Please enter a valid date or timestamp to see the output.
            </div>
          </div>
        {:else}
          <div class="grid grid-cols-1 lg:grid-cols-2 h-full">
            <!-- COL 1: Format Matrix & Math Result -->
            <div class="flex flex-col border-r border-gray-200 dark:border-gray-800 overflow-hidden">
              <div class="px-4 py-2 bg-gray-50 dark:bg-gray-900 border-b border-gray-200 dark:border-gray-800 flex justify-between items-center shrink-0 h-11">
                <span class="text-xs font-bold text-gray-600 dark:text-gray-300 uppercase tracking-wider">Format Matrix & Math Result</span>
              </div>
              <div class="flex-1 overflow-y-auto custom-scrollbar p-4 space-y-4">
                
                <!-- Math Banner -->
                <div class="bg-blue-50 dark:bg-blue-900/20 p-4 rounded-xl border border-blue-200 dark:border-blue-800/50 shadow-sm flex items-center justify-between group">
                  <div>
                    <div class="text-[10px] font-bold text-blue-600 dark:text-blue-400 mb-1 tracking-wider uppercase">
                      Math Result: {storage.value.mathOp === 'add' ? '+' : '-'} {storage.value.mathAmount} {storage.value.mathUnit}
                    </div>
                    <div class="text-sm sm:text-base font-mono font-bold text-gray-900 dark:text-gray-100">
                      {#if mathResult}
                        {new Intl.DateTimeFormat(i18n.locale, { dateStyle: 'full', timeStyle: 'long' }).format(mathResult)}
                      {/if}
                    </div>
                  </div>
                  <button 
                    onclick={() => mathResult && copyText(mathResult.toISOString())}
                    class="shrink-0 w-8 h-8 flex items-center justify-center rounded-lg bg-blue-100 dark:bg-blue-900/40 text-blue-600 dark:text-blue-400 hover:bg-blue-200 dark:hover:bg-blue-800 opacity-0 group-hover:opacity-100 transition-all hover:scale-105 active:scale-95"
                    title="Copy ISO string"
                  >
                    <Copy class="w-4 h-4" />
                  </button>
                </div>

                <!-- Format Matrix -->
                <div class="grid grid-cols-1 gap-2">
                  {#each formatMatrix as format (format.value)}
                    <div class="bg-gray-50/50 dark:bg-gray-800/30 p-3 rounded-lg border border-gray-200 dark:border-gray-700 flex items-center justify-between group hover:border-blue-300 dark:hover:border-blue-700 transition-colors">
                      <div class="min-w-0 pr-4">
                        <div class="text-[10px] font-bold text-gray-500 dark:text-gray-400 mb-0.5 tracking-wider uppercase">{format.label}</div>
                        <div class="text-sm font-mono font-medium text-gray-900 dark:text-gray-100 truncate select-all">{format.value}</div>
                      </div>
                      
                      <button 
                        onclick={() => copyText(format.value)}
                        class="shrink-0 w-7 h-7 flex items-center justify-center rounded-md bg-white dark:bg-gray-700 border border-gray-200 dark:border-gray-600 text-gray-500 hover:text-blue-600 hover:border-blue-300 dark:hover:text-blue-400 dark:hover:border-blue-700 opacity-0 group-hover:opacity-100 transition-all"
                        title="Copy to clipboard"
                      >
                        <Copy class="w-3.5 h-3.5" />
                      </button>
                    </div>
                  {/each}
                </div>
              </div>
            </div>

            <!-- COL 2: Timezone Explorer Result -->
            <div class="flex flex-col overflow-hidden">
              <div class="px-4 py-2 bg-gray-50 dark:bg-gray-900 border-b border-gray-200 dark:border-gray-800 flex justify-between items-center shrink-0 h-11">
                <span class="text-xs font-bold text-gray-600 dark:text-gray-300 uppercase tracking-wider">Timezone Comparison</span>
              </div>
              <div class="flex-1 overflow-y-auto custom-scrollbar p-4 space-y-2">
                <div class="bg-indigo-50 dark:bg-indigo-900/20 p-3 rounded-lg border border-indigo-200 dark:border-indigo-800/50 flex items-center justify-between">
                  <div class="min-w-0 pr-4">
                    <div class="text-[10px] font-bold text-indigo-600 dark:text-indigo-400 mb-0.5 tracking-wider uppercase">Local Time (Browser)</div>
                    <div class="text-sm font-mono font-bold text-gray-900 dark:text-gray-100 truncate">
                      {new Intl.DateTimeFormat(i18n.locale, { dateStyle: 'full', timeStyle: 'long' }).format(parsedDate)}
                    </div>
                  </div>
                </div>

                {#each storage.value.selectedTimezones as tz (tz)}
                  <div class="bg-gray-50/50 dark:bg-gray-800/30 p-3 rounded-lg border border-gray-200 dark:border-gray-700 flex items-center justify-between group hover:border-indigo-300 dark:hover:border-indigo-700 transition-colors">
                    <div class="min-w-0 pr-4">
                      <div class="text-[10px] font-bold text-gray-500 dark:text-gray-400 mb-0.5 tracking-wider uppercase">{COMMON_TIMEZONES.find(t => t.value === tz)?.label || tz}</div>
                      <div class="text-sm font-mono font-medium text-gray-900 dark:text-gray-100 truncate">
                        {new Intl.DateTimeFormat(i18n.locale, { dateStyle: 'full', timeStyle: 'long', timeZone: tz }).format(parsedDate)}
                      </div>
                    </div>
                    <button 
                      onclick={() => copyText(new Intl.DateTimeFormat(i18n.locale, { dateStyle: 'full', timeStyle: 'long', timeZone: tz }).format(parsedDate as Date))}
                      class="shrink-0 w-7 h-7 flex items-center justify-center rounded-md bg-white dark:bg-gray-700 border border-gray-200 dark:border-gray-600 text-gray-500 hover:text-indigo-600 hover:border-indigo-300 dark:hover:text-indigo-400 dark:hover:border-indigo-700 opacity-0 group-hover:opacity-100 transition-all"
                      title="Copy to clipboard"
                    >
                      <Copy class="w-3.5 h-3.5" />
                    </button>
                  </div>
                {/each}
                {#if storage.value.selectedTimezones.length === 0}
                  <div class="text-center text-sm text-gray-400 py-6">
                    No timezones selected.
                  </div>
                {/if}
              </div>
            </div>

          </div>
        {/if}
      </div>
    </div>
  </ToolWrapper>
{/if}
