<script lang="ts">
	import { categories } from '$lib/registry/categories';
	import { roadmapStore } from '$lib/stores/roadmap.svelte';
	import { toastStore } from '$lib/stores/ui/toast.svelte';
	import { submitIdeaToWeb3Forms } from '$lib/services/web3forms';
	import { env } from '$env/dynamic/public';
	import { i18n } from '$lib/i18n';
	
	import { Modal, Button } from '$lib/components/ui';
	import { Send, LoaderCircle, AlertTriangle } from 'lucide-svelte';

	interface Props {
		isOpen: boolean;
	}

	let { isOpen = $bindable(false) }: Props = $props();

	let isSubmitting = $state(false);
	let ideaTitle = $state('');
	let ideaDesc = $state('');
	let userName = $state('');
	let userEmail = $state('');
	let userPhone = $state('');
	
	let hasAccessKey = $derived(!!env.PUBLIC_W3F_ACCESS_KEY);

	async function submitIdea() {
		if (!ideaTitle.trim() || !userName.trim() || !ideaDesc.trim() || isSubmitting || !hasAccessKey) return;
		
		isSubmitting = true;

		const success = await submitIdeaToWeb3Forms({
			ideaName: ideaTitle,
			description: ideaDesc,
			userName,
			userEmail,
			userPhone
		});

		if (!success) {
			toastStore.error(i18n.t('page.roadmap.submit.toast.error') || 'Failed to submit idea. Please try again.');
			isSubmitting = false;
			return;
		}

		roadmapStore.addIdea({
			name: ideaTitle,
			description: ideaDesc,
			categoryId: categories[0]?.id // Default category for local board
		});

		toastStore.success(i18n.t('page.roadmap.submit.toast.success') || 'Idea submitted successfully!');

		ideaTitle = '';
		ideaDesc = '';
		userName = '';
		userEmail = '';
		userPhone = '';
		isOpen = false;
		isSubmitting = false;
	}
</script>

<Modal bind:isOpen title={i18n.t('page.roadmap.submit.title') || 'Submit New Idea'} description={i18n.t('page.roadmap.submit.description') || 'Suggest a new tool or feature for Debox. It will be sent via email and saved locally in your browser.'}>
	<div class="flex flex-col gap-4">
		{#if !hasAccessKey}
			<div class="flex items-start gap-2 p-3 text-amber-700 bg-amber-50 dark:bg-amber-500/10 dark:text-amber-400 rounded-lg border border-amber-200 dark:border-amber-500/20 text-sm">
				<AlertTriangle class="w-5 h-5 shrink-0 mt-0.5" />
				<div>
					<p class="font-semibold">{i18n.t('page.roadmap.submit.maintenance.title') || 'Maintenance Mode'}</p>
					<p>{i18n.t('page.roadmap.submit.maintenance.description') || 'Idea submission is currently unavailable. Please try again later.'}</p>
				</div>
			</div>
		{/if}

		<div class="flex flex-col gap-1.5">
			<label for="user-name" class="text-sm font-medium text-gray-700 dark:text-gray-300">{i18n.t('common.form.name') || 'Your Name'} <span class="text-red-500">*</span></label>
			<input 
				id="user-name"
				type="text" 
				bind:value={userName} 
				placeholder={i18n.t('common.form.namePlaceholder') || 'e.g. John Doe'} 
				disabled={!hasAccessKey}
				class="w-full px-3 py-2 bg-white dark:bg-gray-900 border border-gray-300 dark:border-gray-700 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 dark:text-white disabled:opacity-50 disabled:cursor-not-allowed"
			/>
		</div>

		<div class="grid grid-cols-1 sm:grid-cols-2 gap-4">
			<div class="flex flex-col gap-1.5">
				<label for="user-email" class="text-sm font-medium text-gray-700 dark:text-gray-300">{i18n.t('common.form.email') || 'Email'} <span class="text-gray-400 font-normal">{i18n.t('common.form.optional') || '(Optional)'}</span></label>
				<input 
					id="user-email"
					type="email" 
					bind:value={userEmail} 
					placeholder={i18n.t('common.form.emailPlaceholder') || 'you@example.com'} 
					disabled={!hasAccessKey}
					class="w-full px-3 py-2 bg-white dark:bg-gray-900 border border-gray-300 dark:border-gray-700 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 dark:text-white disabled:opacity-50 disabled:cursor-not-allowed"
				/>
			</div>

			<div class="flex flex-col gap-1.5">
				<label for="user-phone" class="text-sm font-medium text-gray-700 dark:text-gray-300">{i18n.t('common.form.phone') || 'Phone'} <span class="text-gray-400 font-normal">{i18n.t('common.form.optional') || '(Optional)'}</span></label>
				<input 
					id="user-phone"
					type="tel" 
					bind:value={userPhone} 
					placeholder={i18n.t('common.form.phonePlaceholder') || 'e.g. +1 234 567 890'} 
					disabled={!hasAccessKey}
					class="w-full px-3 py-2 bg-white dark:bg-gray-900 border border-gray-300 dark:border-gray-700 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 dark:text-white disabled:opacity-50 disabled:cursor-not-allowed"
				/>
			</div>
		</div>

		<div class="flex flex-col gap-1.5">
			<label for="idea-title" class="text-sm font-medium text-gray-700 dark:text-gray-300">{i18n.t('page.roadmap.submit.form.ideaName') || 'Tool / Feature Name'} <span class="text-red-500">*</span></label>
			<input 
				id="idea-title"
				type="text" 
				bind:value={ideaTitle} 
				placeholder={i18n.t('page.roadmap.submit.form.ideaNamePlaceholder') || 'e.g. JWT Decoder'} 
				disabled={!hasAccessKey}
				class="w-full px-3 py-2 bg-white dark:bg-gray-900 border border-gray-300 dark:border-gray-700 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 dark:text-white disabled:opacity-50 disabled:cursor-not-allowed"
			/>
		</div>
		
		<div class="flex flex-col gap-1.5">
			<label for="idea-desc" class="text-sm font-medium text-gray-700 dark:text-gray-300">{i18n.t('common.form.description') || 'Description'} <span class="text-red-500">*</span></label>
			<textarea 
				id="idea-desc"
				bind:value={ideaDesc} 
				placeholder={i18n.t('page.roadmap.submit.form.descriptionPlaceholder') || 'Briefly describe what this tool does...'} 
				rows="3"
				disabled={!hasAccessKey}
				class="w-full px-3 py-2 bg-white dark:bg-gray-900 border border-gray-300 dark:border-gray-700 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 dark:text-white resize-none disabled:opacity-50 disabled:cursor-not-allowed"
			></textarea>
		</div>
	</div>

	{#snippet footer()}
		<Button 
			variant="outline"
			color="gray"
			onclick={() => isOpen = false}
		>
			{i18n.t('common.action.cancel') || 'Cancel'}
		</Button>
		<Button 
			onclick={submitIdea}
			disabled={!ideaTitle.trim() || !userName.trim() || !ideaDesc.trim() || isSubmitting || !hasAccessKey}
			color="blue"
		>
			{#if isSubmitting}
				<LoaderCircle class="w-4 h-4 animate-spin" /> {i18n.t('common.action.submitting') || 'Submitting...'}
			{:else}
				<Send class="w-4 h-4" /> {i18n.t('common.action.submit') || 'Submit'}
			{/if}
		</Button>
	{/snippet}
</Modal>
