<script lang="ts">
  import { slide } from 'svelte/transition';
  import { ComparatorWorkspace } from '$lib/components/layout';
  import { MonacoDiffEditor, SegmentedControl, ButtonIcon, SplitRatioControl } from '$lib/components/ui';
  import { Select } from '$lib/components/ui';
  import { createTool } from '$lib/stores';
  import { i18n } from '$lib/i18n';
  import { Columns, Rows, ArrowRightLeft, FileText, FileCode, Trash2, WrapText } from 'lucide-svelte';
  import type { ToolDefinition } from '$lib/types';
  import { PROGRAM_LANGUAGES } from '$lib/constants';

  export interface TextDiffProps {
    tool: ToolDefinition;
  }

  let { tool }: TextDiffProps = $props();

  const storage = createTool(tool.slug, {
    originalValue: '',
    modifiedValue: '',
    language: 'plaintext',
    viewMode: 'side-by-side', // 'side-by-side' | 'inline'
    splitRatio: 0.5,
    gapWidth: 14
  });

  let wordWrap = $state(true);

  // Migration for old localStorage data
  if (storage.value.gapWidth === undefined) {
    storage.value.gapWidth = 14;
  }

  let isFullFrame = $state(false);

  function handleSwap() {
    const temp = storage.value.originalValue;
    storage.value.originalValue = storage.value.modifiedValue;
    storage.value.modifiedValue = temp;
  }

  const viewOptions = $derived([
    { value: 'side-by-side', label: i18n.t('tools.textDiff.sideBySideView'), icon: Columns },
    { value: 'inline', label: i18n.t('tools.textDiff.inlineView'), icon: Rows }
  ]);
</script>

<ComparatorWorkspace {tool} bind:isFullFrame>
  
  {#snippet headerLeftControls()}
    <SegmentedControl
      options={viewOptions}
      bind:value={storage.value.viewMode}
      class="shadow-sm hidden sm:flex"
    />

    <Select
      id="language-select"
      label={i18n.t('tools.textDiff.language')}
      bind:value={storage.value.language}
    >
      {#each PROGRAM_LANGUAGES as lang (lang.value)}
        <option value={lang.value}>{lang.label}</option>
      {/each}
    </Select>

    <button 
      class="flex items-center justify-center gap-2 px-3 h-[34px] text-sm font-medium text-gray-700 dark:text-gray-300 hover:text-blue-600 dark:hover:text-blue-400 bg-white dark:bg-gray-900 rounded-md border border-gray-200 dark:border-gray-800 hover:border-blue-300 dark:hover:border-blue-800 shadow-sm transition-all active:scale-95"
      onclick={handleSwap}
      title={i18n.t('tools.textDiff.swap')}
    >
      <ArrowRightLeft class="w-4 h-4" />
      <span class="hidden sm:inline">{i18n.t('tools.textDiff.swap')}</span>
    </button>
  {/snippet}

  {#snippet headerRightControls()}
    {#if storage.value.viewMode === 'side-by-side'}
      <div transition:slide={{ axis: 'x', duration: 200 }}>
        <SplitRatioControl bind:value={storage.value.splitRatio} />
      </div>
    {/if}
  {/snippet}

  {#snippet mainPanel()}
    <div class="flex-1 w-full h-full flex flex-col bg-white dark:bg-[#1e1e1e]">
      {#if storage.value.viewMode === 'side-by-side'}
        <div class="flex w-full bg-white dark:bg-[#1e1e1e] h-11 shrink-0 relative overflow-hidden">
          <!-- Cột trái (Original Header) -->
          <div style="width: calc((100% - {storage.value.gapWidth}px) * {storage.value.splitRatio})" class="flex items-center justify-between px-4 py-2 border-r border-b border-gray-200 dark:border-gray-800 transition-all duration-300 bg-gray-50 dark:bg-gray-900">
             <span class="flex items-center gap-1.5 text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider">
               <FileText class="w-3.5 h-3.5" /> {i18n.t('tools.textDiff.original')}
             </span>
             <ButtonIcon onclick={() => storage.value.originalValue = ''} disabled={!storage.value.originalValue} color="rose" title={i18n.t('common.clear')}>
               <Trash2 class="w-4 h-4" />
             </ButtonIcon>
          </div>
          
          <!-- Khoảng trống ở giữa (Gap) -->
          <div style="width: {storage.value.gapWidth}px" class="transition-all duration-300 border-b border-gray-200 dark:border-gray-800 shrink-0"></div>

          <!-- Cột phải (Modified Header) -->
          <div style="width: calc((100% - {storage.value.gapWidth}px) * (1 - {storage.value.splitRatio}))" class="flex items-center justify-between px-4 py-2 transition-all duration-300 bg-gray-50 dark:bg-gray-900 border-l border-b border-gray-200 dark:border-gray-800">
             <span class="flex items-center gap-1.5 text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider">
               <FileCode class="w-3.5 h-3.5" /> {i18n.t('tools.textDiff.modified')}
             </span>
             <div class="flex items-center gap-1">
               <ButtonIcon onclick={() => wordWrap = !wordWrap} color="blue" active={wordWrap} title={wordWrap ? 'Disable Word Wrap' : 'Enable Word Wrap'}>
                 <WrapText class="w-4 h-4" />
               </ButtonIcon>
               <ButtonIcon onclick={() => storage.value.modifiedValue = ''} disabled={!storage.value.modifiedValue} color="rose" title={i18n.t('common.clear')}>
                 <Trash2 class="w-4 h-4" />
               </ButtonIcon>
             </div>
          </div>
        </div>
      {:else}
        <div class="flex w-full bg-gray-50 dark:bg-gray-900 border-b border-gray-200 dark:border-gray-800 h-11 shrink-0 items-center justify-between px-4 py-2">
          <span class="flex items-center gap-1.5 text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider">
            <FileCode class="w-3.5 h-3.5" /> {i18n.t('tools.textDiff.diff')}
          </span>
          <div class="flex items-center gap-2">
            <button onclick={() => wordWrap = !wordWrap} class="flex items-center gap-1.5 px-2 py-1 text-xs font-semibold rounded transition-colors {wordWrap ? 'text-blue-600 dark:text-blue-400 bg-blue-50 dark:bg-blue-900/30 hover:bg-blue-100 dark:hover:bg-blue-900/50' : 'text-gray-500 dark:text-gray-400 hover:text-blue-500 hover:bg-gray-200 dark:hover:bg-gray-800'}" title={wordWrap ? 'Disable Word Wrap' : 'Enable Word Wrap'}>
               <WrapText class="w-3.5 h-3.5 inline" /> {wordWrap ? 'Wrap On' : 'Wrap Off'}
            </button>
            <div class="w-px h-4 bg-gray-300 dark:bg-gray-700 mx-1"></div>
            <button onclick={() => storage.value.originalValue = ''} disabled={!storage.value.originalValue} class="flex items-center gap-1.5 px-2 py-1 text-xs font-semibold text-gray-500 dark:text-gray-400 hover:text-red-500 hover:bg-gray-200 dark:hover:bg-gray-800 rounded disabled:opacity-30 transition-colors" title={i18n.t('common.clear') + ' ' + i18n.t('tools.textDiff.original')}>
               {i18n.t('tools.textDiff.original')} <Trash2 class="w-3.5 h-3.5 inline" />
            </button>
            <button onclick={() => storage.value.modifiedValue = ''} disabled={!storage.value.modifiedValue} class="flex items-center gap-1.5 px-2 py-1 text-xs font-semibold text-gray-500 dark:text-gray-400 hover:text-red-500 hover:bg-gray-200 dark:hover:bg-gray-800 rounded disabled:opacity-30 transition-colors" title={i18n.t('common.clear') + ' ' + i18n.t('tools.textDiff.modified')}>
               {i18n.t('tools.textDiff.modified')} <Trash2 class="w-3.5 h-3.5 inline" />
            </button>
          </div>
        </div>
      {/if}

      <div class="flex-1 w-full relative">
        <MonacoDiffEditor
          bind:originalValue={storage.value.originalValue}
          bind:modifiedValue={storage.value.modifiedValue}
          language={storage.value.language}
          renderSideBySide={storage.value.viewMode === 'side-by-side'}
          bind:splitRatio={storage.value.splitRatio}
          bind:gapWidth={storage.value.gapWidth}
          readOnly={false}
          {wordWrap}
        />
      </div>
    </div>
  {/snippet}

</ComparatorWorkspace>
