<script lang="ts">
	import { Search } from 'lucide-svelte';

	interface Props {
		value?: string;
		placeholder?: string;
		expandable?: boolean;
		class?: string;
		[key: string]: unknown;
	}

	let {
		value = $bindable(''),
		placeholder = 'Search...',
		expandable = false,
		class: className = '',
		...rest
	}: Props = $props();

	let isFocused = $state(false);

	let baseClasses = 'h-10 bg-transparent border hover:bg-gray-100/50 hover:border-gray-200/60 focus:bg-white focus:border-blue-500 focus:ring-2 focus:ring-blue-500/20 dark:hover:bg-gray-800/50 dark:hover:border-gray-700/50 dark:focus:bg-gray-900 rounded-xl outline-none text-sm dark:text-gray-100 transition-all duration-500 ease-[cubic-bezier(0.4,0,0.2,1)]';
	
	let expandableClasses = $derived(
		expandable 
			? `w-10 hover:w-48 focus:w-64 cursor-pointer focus:cursor-text pr-10 pl-4 border-transparent ${value || isFocused ? 'w-64 cursor-text placeholder-gray-400 bg-white border-gray-300 dark:bg-gray-900 dark:border-gray-700' : 'placeholder-transparent focus:placeholder-gray-400'}` 
			: 'w-full pl-10 pr-4 border-gray-200 dark:border-gray-800 bg-white dark:bg-gray-900 placeholder-gray-400'
	);
</script>

<div class="relative group flex items-center {className}">
	{#if expandable}
		<!-- Icon on the right for expandable (so it stays visible when collapsed) -->
		<div class="absolute inset-y-0 right-0 w-10 flex items-center justify-center pointer-events-none">
			<Search class="h-4 w-4 text-gray-500 group-hover:text-blue-500 group-focus-within:text-blue-500 transition-colors" />
		</div>
	{:else}
		<!-- Icon on the left for static -->
		<div class="absolute inset-y-0 left-0 w-10 flex items-center justify-center pointer-events-none">
			<Search class="h-4 w-4 text-gray-500 group-hover:text-blue-500 group-focus-within:text-blue-500 transition-colors" />
		</div>
	{/if}

	<input
		type="text"
		bind:value
		{placeholder}
		onfocus={() => isFocused = true}
		onblur={() => isFocused = false}
		class="{baseClasses} {expandableClasses}"
		{...rest}
	/>
</div>
