<script lang="ts">
  import { onMount } from 'svelte';
  import { fade, fly } from 'svelte/transition';
  import { getColorSync, getPaletteSync } from 'colorthief';
  import { UploadCloud, Image as ImageIcon, Copy, Check, FileJson, Code, Palette as PaletteIcon, Pipette, Trash2, Link } from 'lucide-svelte';

  import { i18n } from '$lib/i18n';
  import SplitWorkspace from '$lib/components/layout/templates/SplitWorkspace.svelte';
  import { ButtonIcon } from '$lib/components/ui';
  import { createTool, toastStore } from '$lib/stores';
  import type { ToolDefinition } from '$lib/types';

  export interface ColorExtractorProps {
    tool: ToolDefinition;
  }

  let { tool }: ColorExtractorProps = $props();

  const storage = createTool(tool.slug, {
    imageUrl: '',
    paletteSize: 5
  });

  let imageRef = $state<HTMLImageElement | null>(null);
  let fileInput = $state<HTMLInputElement | null>(null);

  let dominantColor = $state<number[] | null>(null);
  let palette = $state<number[][]>([]);
  let isDragging = $state(false);
  let loading = $state(false);
  
  let urlInput = $state('');
  let isFetchingUrl = $state(false);

  let isEyedropperSupported = $state(false);
  let pickedColor = $state<string | null>(null);

  onMount(() => {
    if (typeof window !== 'undefined' && 'EyeDropper' in window) {
      isEyedropperSupported = true;
    }
  });

  async function openEyedropper() {
    if (!isEyedropperSupported) return;
    try {
      // @ts-ignore
      const eyeDropper = new window.EyeDropper();
      const result = await eyeDropper.open();
      pickedColor = result.sRGBHex;
      copyToClipboard(result.sRGBHex, 'picked');
    } catch (e) {
      console.log('Eyedropper cancelled', e);
    }
  }

  function rgbToHex(r: number, g: number, b: number) {
    return "#" + (1 << 24 | r << 16 | g << 8 | b).toString(16).slice(1).toUpperCase();
  }

  function rgbToCss(r: number, g: number, b: number) {
    return `rgb(${r}, ${g}, ${b})`;
  }

  function extractColors() {
    if (!imageRef || !imageRef.complete || !imageRef.src) return;
    try {
      const dom = getColorSync(imageRef);
      dominantColor = dom ? dom.array() : null;
      
      const pal = getPaletteSync(imageRef, { colorCount: parseInt(storage.value.paletteSize.toString()) || 5 });
      palette = pal ? pal.map(c => c.array()) : [];
    } catch (e) {
      console.error("ColorThief Error:", e);
    }
  }

  function handleImageLoad() {
    loading = false;
    extractColors();
  }

  function handleFile(file: File) {
    if (!file || !file.type.startsWith('image/')) return;
    loading = true;
    const reader = new FileReader();
    reader.onload = (e) => {
      storage.value.imageUrl = e.target?.result as string;
    };
    reader.readAsDataURL(file);
  }

  function onDrop(e: DragEvent) {
    e.preventDefault();
    isDragging = false;
    if (e.dataTransfer?.files.length) {
      handleFile(e.dataTransfer.files[0]);
    }
  }

  async function fetchFromUrl() {
    if (!urlInput.trim()) return;
    isFetchingUrl = true;
    try {
      const proxyUrl = `/api/proxy-image?url=${encodeURIComponent(urlInput)}`;
      const res = await fetch(proxyUrl);
      if (!res.ok) throw new Error('Failed to fetch image');
      const blob = await res.blob();
      
      if (!blob.type.startsWith('image/')) {
        throw new Error('Not a valid image');
      }
      
      const reader = new FileReader();
      reader.onload = (e) => {
        storage.value.imageUrl = e.target?.result as string;
        isFetchingUrl = false;
        urlInput = '';
      };
      reader.readAsDataURL(blob);
    } catch (e) {
      console.error(e);
      toastStore.error(i18n.t('tools.colorExtractor.invalidUrl') || 'Invalid image URL');
      isFetchingUrl = false;
    }
  }

  function clearImage() {
    storage.value.imageUrl = '';
    dominantColor = null;
    palette = [];
    pickedColor = null;
  }

  $effect(() => {
    // Watch paletteSize changes to re-extract
    storage.value.paletteSize;
    if (storage.value.imageUrl && imageRef?.complete) {
      extractColors();
    }
  });

  let copiedState = $state('');
  
  async function copyToClipboard(text: string, type: string, isExport: boolean = false) {
    if (!text) return;
    try {
      await navigator.clipboard.writeText(text);
      copiedState = type;
      if (isExport) {
        toastStore.success(i18n.t('tools.colorExtractor.copied') || 'Copied to clipboard!');
      }
      setTimeout(() => copiedState = '', 2000);
    } catch (e) {
      console.error(e);
      if (isExport) toastStore.error('Failed to copy');
    }
  }

  function generateCss() {
    if (!palette.length) return '';
    let css = `:root {\n`;
    palette.forEach((color, i) => {
      css += `  --color-${i + 1}: ${rgbToHex(color[0], color[1], color[2])};\n`;
    });
    css += `}`;
    return css;
  }

  function generateTailwind() {
    if (!palette.length) return '';
    let tw = `module.exports = {\n  theme: {\n    extend: {\n      colors: {\n        brand: {\n`;
    palette.forEach((color, i) => {
      const key = i === 0 ? '50' : i * 100;
      tw += `          ${key}: '${rgbToHex(color[0], color[1], color[2])}',\n`;
    });
    tw += `        }\n      }\n    }\n  }\n}`;
    return tw;
  }

  function generateJson() {
    if (!palette.length) return '';
    const obj: any = {};
    palette.forEach((color, i) => {
      obj[`color${i+1}`] = rgbToHex(color[0], color[1], color[2]);
    });
    return JSON.stringify(obj, null, 2);
  }

  let secondaryColor = $derived(palette.length > 1 ? palette[1] : null);
  let paletteGrid = $derived(palette.length > 2 ? palette.slice(2) : []);
</script>

<SplitWorkspace {tool}>
  {#snippet headerLeftControls()}
    <div class="flex items-center gap-2 bg-gray-100 dark:bg-gray-900/80 p-1 rounded-lg shadow-sm border border-transparent dark:border-gray-800 shrink-0 transition-opacity">
      <label class="text-xs font-semibold text-gray-500 dark:text-gray-400 pl-2 cursor-pointer whitespace-nowrap flex items-center gap-1">
        {i18n.t('tools.colorExtractor.paletteSize') || 'Palette Size'}: <span class="text-gray-900 dark:text-gray-100 w-4 text-center inline-block">{storage.value.paletteSize}</span>
      </label>
      <div class="bg-white dark:bg-gray-700 rounded-md px-3 h-7 shadow-sm border-none outline-none flex items-center">
        <input 
          type="range" 
          bind:value={storage.value.paletteSize} 
          min="3" 
          max="15" 
          class="w-24 h-1 bg-gray-200 dark:bg-gray-600 rounded-lg appearance-none cursor-pointer accent-blue-500" 
        />
      </div>
    </div>
  {/snippet}

  {#snippet headerRightControls()}
  {/snippet}

  {#snippet leftPanel()}
    <div class="flex flex-col h-full bg-white dark:bg-[#1e1e1e]">
      <!-- Left Panel Header -->
      <div class="flex items-center justify-between px-4 py-2 bg-gray-50 dark:bg-gray-900 border-b border-gray-200 dark:border-gray-800 h-11 shrink-0 z-20">
        <span class="flex items-center gap-1.5 text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider">
          <ImageIcon class="w-3.5 h-3.5" /> {i18n.t('tools.colorExtractor.uploadImage') || 'Upload Image'}
        </span>
        
        {#if storage.value.imageUrl}
          <ButtonIcon onclick={clearImage} color="rose" title={i18n.t('common.action.clear') || 'Clear'}>
            <Trash2 class="w-4 h-4" />
          </ButtonIcon>
        {/if}
      </div>

      <div class="flex-1 w-full relative min-h-0 overflow-hidden bg-slate-50/50 dark:bg-slate-900/20">
        {#if !storage.value.imageUrl}
          <!-- Upload Zone -->
          <div 
            in:fade={{duration: 300, delay: 150}}
            out:fade={{duration: 150}}
            class="absolute inset-0 flex flex-col items-center justify-center p-4 sm:p-6"
          >
            <div class="w-full max-w-md flex flex-col gap-6">
              <!-- URL Input -->
              <div class="flex flex-col gap-1">
                <div class="relative w-full">
                  <input 
                    type="text" 
                    bind:value={urlInput} 
                    placeholder={i18n.t('tools.colorExtractor.pasteUrl') || 'Paste Image URL...'} 
                    class="w-full h-11 pl-10 pr-4 bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-xl shadow-sm text-sm focus:ring-2 focus:ring-blue-500 outline-none transition-all disabled:opacity-50"
                    disabled={isFetchingUrl}
                    onkeydown={(e) => e.key === 'Enter' && fetchFromUrl()}
                  />
                  <div class="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400">
                    {#if isFetchingUrl}
                      <div class="w-4 h-4 border-2 border-blue-500 border-t-transparent rounded-full animate-spin"></div>
                    {:else}
                      <Link class="w-4 h-4" />
                    {/if}
                  </div>
                </div>
                <p class="text-[11px] text-gray-400 dark:text-gray-500">{i18n.t('tools.colorExtractor.urlHint') || 'Supports direct image links (.jpg, .png, .webp) up to 5MB.'}</p>
              </div>

              <div class="flex items-center gap-3 text-xs font-semibold text-gray-400 dark:text-gray-500 uppercase">
                <div class="flex-1 h-px bg-gray-200 dark:bg-gray-700"></div>
                OR
                <div class="flex-1 h-px bg-gray-200 dark:bg-gray-700"></div>
              </div>

              <!-- svelte-ignore a11y_click_events_have_key_events -->
              <!-- svelte-ignore a11y_no_static_element_interactions -->
              <div 
                class="w-full border-2 border-dashed rounded-xl p-8 sm:p-10 text-center cursor-pointer transition-all duration-200 
                  {isDragging ? 'border-blue-500 bg-blue-50 dark:bg-blue-900/20' : 'border-gray-300 dark:border-gray-700 hover:border-blue-400 hover:bg-gray-50 dark:hover:bg-gray-800'}"
                ondragover={(e) => { e.preventDefault(); isDragging = true; }}
                ondragleave={() => isDragging = false}
                ondrop={onDrop}
                onclick={() => fileInput?.click()}
              >
                <input 
                  type="file" 
                  bind:this={fileInput} 
                  accept="image/*" 
                  class="hidden" 
                  onchange={(e) => {
                    const target = e.target as HTMLInputElement;
                    if (target.files?.length) handleFile(target.files[0]);
                  }} 
                />
                <div class="flex flex-col items-center justify-center gap-3 text-gray-500 dark:text-gray-400">
                  <UploadCloud class="w-12 h-12 {isDragging ? 'text-blue-500 animate-bounce' : ''}" />
                  <span class="text-sm font-medium">{i18n.t('tools.colorExtractor.dragAndDrop')}</span>
                </div>
              </div>
            </div>
          </div>
        {:else}
          <!-- Full Bleed Image Preview -->
          <div 
            in:fade={{duration: 400, delay: 150}}
            out:fade={{duration: 150}}
            class="absolute inset-0 group flex items-center justify-center overflow-hidden">
            <!-- Subtle checkerboard background for transparent images -->
            <div class="absolute inset-0 pointer-events-none" style="background-image: repeating-linear-gradient(45deg, #e5e7eb 25%, transparent 25%, transparent 75%, #e5e7eb 75%, #e5e7eb), repeating-linear-gradient(45deg, #e5e7eb 25%, #f9fafb 25%, #f9fafb 75%, #e5e7eb 75%, #e5e7eb); background-position: 0 0, 10px 10px; background-size: 20px 20px; opacity: 0.5;"></div>
            
            {#if loading}
              <div class="absolute inset-0 flex items-center justify-center bg-white/50 dark:bg-black/50 backdrop-blur-sm z-10">
                <div class="w-8 h-8 border-4 border-blue-500 border-t-transparent rounded-full animate-spin"></div>
              </div>
            {/if}
            
            <img 
              bind:this={imageRef} 
              src={storage.value.imageUrl} 
              alt="Preview" 
              class="w-full h-full object-contain relative z-10 p-4 drop-shadow-md"
              onload={handleImageLoad}
              crossorigin="anonymous"
            />

            {#if isEyedropperSupported}
              <button
                onclick={openEyedropper}
                class="absolute bottom-6 right-6 bg-white/95 dark:bg-gray-800/95 backdrop-blur-md shadow-xl px-4 py-3 rounded-2xl flex items-center gap-2 opacity-0 group-hover:opacity-100 transition-all duration-300 hover:-translate-y-1 hover:bg-white dark:hover:bg-gray-700 text-sm font-bold text-gray-700 dark:text-gray-200 hover:text-blue-600 dark:hover:text-blue-400 border border-gray-200 dark:border-gray-700 z-20"
                title={i18n.t('tools.colorExtractor.pickColor')}
              >
                <Pipette class="w-5 h-5" /> {i18n.t('tools.colorExtractor.pickColor') || 'Pick Color'}
              </button>
            {/if}
          </div>
        {/if}
      </div>
    </div>
  {/snippet}

  {#snippet rightPanel()}
    <div class="flex flex-col h-full bg-white dark:bg-[#1e1e1e]">
      <!-- Right Panel Header -->
      <div class="flex items-center justify-between px-4 py-2 bg-gray-50 dark:bg-gray-900 border-b border-gray-200 dark:border-gray-800 h-11 shrink-0 z-20">
        <span class="flex items-center gap-1.5 text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider">
          <PaletteIcon class="w-3.5 h-3.5" /> {i18n.t('tools.colorExtractor.colorPalette') || 'Color Palette'}
        </span>
        
        {#if palette.length > 0}
          <div class="flex items-center gap-1">
            <ButtonIcon onclick={() => copyToClipboard(generateCss(), 'css', true)} title={i18n.t('tools.colorExtractor.exportCss')}>
              {#if copiedState === 'css'}<Check class="w-4 h-4 text-green-500" />{:else}<Code class="w-4 h-4 text-blue-500" />{/if}
            </ButtonIcon>
            <ButtonIcon onclick={() => copyToClipboard(generateTailwind(), 'tailwind', true)} title={i18n.t('tools.colorExtractor.exportTailwind')}>
              {#if copiedState === 'tailwind'}<Check class="w-4 h-4 text-green-500" />{:else}<PaletteIcon class="w-4 h-4 text-teal-500" />{/if}
            </ButtonIcon>
            <ButtonIcon onclick={() => copyToClipboard(generateJson(), 'json', true)} title={i18n.t('tools.colorExtractor.exportJson')}>
              {#if copiedState === 'json'}<Check class="w-4 h-4 text-green-500" />{:else}<FileJson class="w-4 h-4 text-amber-500" />{/if}
            </ButtonIcon>
          </div>
        {/if}
      </div>
      
      <div class="flex-1 w-full relative min-h-0 bg-slate-50/50 dark:bg-[#161616]">
        {#if !storage.value.imageUrl || palette.length === 0}
          <div 
            in:fade={{duration: 300, delay: 150}}
            out:fade={{duration: 150}}
            class="absolute inset-0 flex flex-col items-center justify-center text-gray-400 dark:text-gray-600 p-6 text-center">
            <PaletteIcon class="w-16 h-16 mb-4 opacity-30" />
            <p class="text-sm font-medium">{i18n.t('tools.colorExtractor.noImage')}</p>
          </div>
        {:else}
          <div 
            in:fly={{y: 20, duration: 400, delay: 150}}
            out:fade={{duration: 150}}
            class="absolute inset-0 w-full h-full flex flex-col p-4 sm:p-6 gap-6 overflow-y-auto custom-scrollbar">
            
            <!-- Top Row: Primary (44%) + Secondary (36%) + Picked Color (20%) -->
            <div class="flex gap-3 h-40 sm:h-48 shrink-0">
              
              <!-- Primary Color -->
              <div class="w-[44%] flex flex-col gap-2">
                <h3 class="text-xs font-bold text-gray-500 dark:text-gray-400 uppercase tracking-wider flex items-center gap-2">
                  <span class="w-2 h-2 rounded-full bg-blue-500 shrink-0"></span>
                  <span class="truncate">{i18n.t('tools.colorExtractor.dominantColor') || 'Primary Color'}</span>
                </h3>
                
                <button 
                  onclick={() => copyToClipboard(rgbToHex(dominantColor![0], dominantColor![1], dominantColor![2]), 'dominant')}
                  class="w-full h-full rounded-2xl shadow-sm border border-black/5 dark:border-white/5 group relative overflow-hidden transition-transform hover:scale-[1.01] active:scale-[0.99]"
                  style="background-color: {rgbToCss(dominantColor![0], dominantColor![1], dominantColor![2])};"
                >
                  <div class="absolute inset-0 bg-black/0 group-hover:bg-black/10 dark:group-hover:bg-white/10 transition-colors flex items-center justify-center">
                    <div class="opacity-0 group-hover:opacity-100 transform translate-y-4 group-hover:translate-y-0 transition-all duration-300">
                      <span class="px-3 py-1.5 sm:px-4 sm:py-2 bg-white/90 dark:bg-black/80 backdrop-blur-md rounded-full shadow-md text-xs sm:text-sm font-bold text-gray-900 dark:text-white flex items-center gap-1.5 sm:gap-2">
                        {#if copiedState === 'dominant'}
                          <Check class="w-3.5 h-3.5 text-green-500 shrink-0" /> {rgbToHex(dominantColor![0], dominantColor![1], dominantColor![2])}
                        {:else}
                          <Copy class="w-3.5 h-3.5 shrink-0" /> {rgbToHex(dominantColor![0], dominantColor![1], dominantColor![2])}
                        {/if}
                      </span>
                    </div>
                  </div>
                </button>
              </div>

              <!-- Secondary Color -->
              <div class="w-[36%] flex flex-col gap-2">
                <h3 class="text-xs font-bold text-gray-500 dark:text-gray-400 uppercase tracking-wider flex items-center gap-2">
                  <span class="w-2 h-2 rounded-full bg-emerald-500 shrink-0"></span>
                  <span class="truncate">{i18n.t('tools.colorExtractor.secondaryColor') || 'Secondary Color'}</span>
                </h3>
                
                <button 
                  onclick={() => secondaryColor && copyToClipboard(rgbToHex(secondaryColor[0], secondaryColor[1], secondaryColor[2]), 'secondary')}
                  disabled={!secondaryColor}
                  class="w-full h-full rounded-2xl shadow-sm border border-black/5 dark:border-white/5 group relative overflow-hidden transition-transform hover:scale-[1.01] active:scale-[0.99] {!secondaryColor ? 'bg-gray-100 dark:bg-gray-800' : ''}"
                  style={secondaryColor ? `background-color: ${rgbToCss(secondaryColor[0], secondaryColor[1], secondaryColor[2])};` : ''}
                >
                  {#if secondaryColor}
                    <div class="absolute inset-0 bg-black/0 group-hover:bg-black/10 dark:group-hover:bg-white/10 transition-colors flex items-center justify-center">
                      <div class="opacity-0 group-hover:opacity-100 transform translate-y-4 group-hover:translate-y-0 transition-all duration-300">
                        <span class="px-3 py-1.5 bg-white/90 dark:bg-black/80 backdrop-blur-md rounded-full shadow-md text-xs font-bold text-gray-900 dark:text-white flex items-center gap-1.5">
                          {#if copiedState === 'secondary'}
                            <Check class="w-3 h-3 text-green-500 shrink-0" /> {rgbToHex(secondaryColor[0], secondaryColor[1], secondaryColor[2])}
                          {:else}
                            <Copy class="w-3 h-3 shrink-0" /> {rgbToHex(secondaryColor[0], secondaryColor[1], secondaryColor[2])}
                          {/if}
                        </span>
                      </div>
                    </div>
                  {/if}
                </button>
              </div>

              <!-- Picked Color (Always Visible) -->
              <div class="w-[20%] flex flex-col gap-2">
                <h3 class="text-xs font-bold text-gray-500 dark:text-gray-400 uppercase tracking-wider flex items-center gap-2">
                  <span class="w-2 h-2 rounded-full bg-pink-500 shrink-0"></span>
                  <span class="truncate">{i18n.t('tools.colorExtractor.pickedColor') || 'Picked Color'}</span>
                </h3>
                
                <button 
                  onclick={() => pickedColor && copyToClipboard(pickedColor, 'picked')}
                  class="w-full h-full rounded-2xl shadow-sm border group/pick relative overflow-hidden transition-transform hover:scale-[1.02] active:scale-[0.98] {pickedColor ? 'border-black/5 dark:border-white/5' : 'border-dashed border-gray-300 dark:border-gray-700 bg-white dark:bg-gray-800'}"
                  style={pickedColor ? `background-color: ${pickedColor};` : ''}
                  disabled={!pickedColor}
                >
                  {#if pickedColor}
                    <div class="absolute inset-0 bg-black/0 group-hover/pick:bg-black/10 dark:group-hover/pick:bg-white/10 transition-colors flex items-center justify-center">
                      <div class="opacity-0 group-hover/pick:opacity-100 transform translate-y-4 group-hover/pick:translate-y-0 transition-all duration-300 max-w-[90%]">
                        <span class="px-2.5 py-1.5 bg-white/90 dark:bg-black/80 backdrop-blur-md rounded-full shadow-md text-[10px] xl:text-xs font-bold text-gray-900 dark:text-white flex items-center justify-center gap-1.5">
                          {#if copiedState === 'picked'}
                            <Check class="w-3 h-3 text-green-500 shrink-0" /> <span class="truncate uppercase">{pickedColor}</span>
                          {:else}
                            <Copy class="w-3 h-3 shrink-0" /> <span class="truncate uppercase">{pickedColor}</span>
                          {/if}
                        </span>
                      </div>
                    </div>
                  {:else}
                    <div class="flex flex-col items-center justify-center h-full w-full text-gray-400 dark:text-gray-500 group-hover/pick:text-blue-500 transition-colors px-1 text-center">
                      <Pipette class="w-5 h-5 opacity-50 group-hover/pick:opacity-100" />
                    </div>
                  {/if}
                </button>
              </div>
            </div>

            <!-- Palette Grid -->
            <div class="flex flex-col gap-2 flex-1 min-h-0 mt-2">
              <h3 class="text-xs font-bold text-gray-500 dark:text-gray-400 uppercase tracking-wider flex items-center gap-2">
                <span class="w-2 h-2 rounded-full bg-purple-500"></span>
                {i18n.t('tools.colorExtractor.colorPalette')}
              </h3>
              
              <div class="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 gap-3 h-full content-start">
                {#each paletteGrid as color, i (color)}
                  {@const hex = rgbToHex(color[0], color[1], color[2])}
                  <button 
                    onclick={() => copyToClipboard(hex, `color-${i}`)}
                    class="group relative h-24 rounded-xl shadow-sm border border-black/5 dark:border-white/5 overflow-hidden flex flex-col transition-transform hover:scale-105 active:scale-95"
                  >
                    <!-- Color block -->
                    <div class="flex-1 w-full" style="background-color: {rgbToCss(color[0], color[1], color[2])};"></div>
                    
                    <!-- Hex code label -->
                    <div class="h-8 bg-white dark:bg-gray-800 flex items-center justify-center border-t border-gray-100 dark:border-gray-700">
                      <span class="text-xs font-mono font-bold text-gray-600 dark:text-gray-300 group-hover:text-blue-500 transition-colors">
                        {#if copiedState === `color-${i}`}
                          <span class="text-green-500">Copied!</span>
                        {:else}
                          {hex}
                        {/if}
                      </span>
                    </div>
                  </button>
                {/each}
              </div>
            </div>
          </div>
        {/if}
      </div>
    </div>
  {/snippet}
</SplitWorkspace>
