<script lang="ts">
  import { i18n } from '$lib/i18n';
  import SplitWorkspace from '$lib/components/layout/templates/SplitWorkspace.svelte';
  import { createTool } from '$lib/stores';
  import type { ToolDefinition } from '$lib/types';
  import { copyText } from '$lib/utils/clipboard';
  import { Copy, FileCode2, Lock, Unlock, Shield, Trash2, KeyRound, Play, Eye, EyeOff, Dices } from 'lucide-svelte';
  import CryptoJS from 'crypto-js';
  import { SegmentedControl, Separator, ButtonIcon } from '$lib/components/ui';
  import { Select } from '$lib/components/ui';
  import { CRYPTO_ALGORITHMS, CRYPTO_MODES, CRYPTO_PADDINGS, CRYPTO_FORMATS } from '$lib/constants';

  export interface EncryptorProps {
    tool: ToolDefinition;
  }

  let { tool }: EncryptorProps = $props();

  const storage = createTool(tool.slug, {
    input: '',
    key: '',
    iv: '',
    algorithm: 'AES', // Represents RIJNDAEL_128
    mode: 'CBC',
    padding: 'Pkcs7',
    action: 'encrypt', // 'encrypt' or 'decrypt'
    inputFormat: 'text', // 'text', 'hex', 'base64'
    outputFormat: 'base64' // 'text', 'hex', 'base64'
  });

  let outputResult = $state('');
  let isError = $state(false);
  let showKey = $state(false);

  const algorithms: Record<string, any> = {
    'AES': CryptoJS.AES,
    'DES': CryptoJS.DES,
    'TripleDES': CryptoJS.TripleDES,
    'Rabbit': CryptoJS.Rabbit,
    'RC4': CryptoJS.RC4
  };

  const modes: Record<string, any> = {
    'CBC': CryptoJS.mode.CBC,
    'ECB': CryptoJS.mode.ECB,
    'CFB': CryptoJS.mode.CFB,
    'OFB': CryptoJS.mode.OFB,
    'CTR': CryptoJS.mode.CTR
  };

  const paddings: Record<string, any> = {
    'Pkcs7': CryptoJS.pad.Pkcs7,
    'ZeroPadding': CryptoJS.pad.ZeroPadding,
    'NoPadding': CryptoJS.pad.NoPadding,
    'Iso97971': CryptoJS.pad.Iso97971,
    'AnsiX923': CryptoJS.pad.AnsiX923,
    'Iso10126': CryptoJS.pad.Iso10126
  };

  let debounceTimer: ReturnType<typeof setTimeout>;
  let isRealtimeMode = $state(true);

  $effect(() => {
    // Read dependencies to trigger $effect
    const trigger = [
      storage.value.input,
      storage.value.key,
      storage.value.iv,
      storage.value.action,
      storage.value.algorithm,
      storage.value.mode,
      storage.value.padding,
      storage.value.inputFormat,
      storage.value.outputFormat
    ];

    if (isRealtimeMode) {
      clearTimeout(debounceTimer);
      debounceTimer = setTimeout(() => {
        processMcrypt();
      }, 500);
    }
  });

  function handleApply() {
    processMcrypt();
  }

  function processMcrypt() {
    if (!storage.value.input || !storage.value.key) {
      outputResult = '';
      isError = false;
      return;
    }

    try {
      const algo = algorithms[storage.value.algorithm] || CryptoJS.AES;
      const mode = modes[storage.value.mode] || CryptoJS.mode.CBC;
      const padding = paddings[storage.value.padding] || CryptoJS.pad.Pkcs7;
      
      let keyData = CryptoJS.enc.Utf8.parse(storage.value.key);
      let ivData = storage.value.iv ? CryptoJS.enc.Utf8.parse(storage.value.iv) : CryptoJS.enc.Utf8.parse('');

      const options = {
        mode: mode,
        padding: padding,
        iv: ivData
      };

      if (storage.value.action === 'encrypt') {
        let inputData;
        if (storage.value.inputFormat === 'hex') {
            inputData = CryptoJS.enc.Hex.parse(storage.value.input);
        } else if (storage.value.inputFormat === 'base64') {
            inputData = CryptoJS.enc.Base64.parse(storage.value.input);
        } else {
            inputData = storage.value.input;
        }

        const encrypted = algo.encrypt(inputData, keyData, options);
        
        if (storage.value.outputFormat === 'hex') {
            outputResult = encrypted.ciphertext.toString(CryptoJS.enc.Hex);
        } else if (storage.value.outputFormat === 'text') {
            outputResult = encrypted.ciphertext.toString(CryptoJS.enc.Utf8);
        } else {
            outputResult = encrypted.toString();
        }
        isError = false;

      } else {
        // Decrypt
        let cipherParams;
        if (storage.value.inputFormat === 'hex') {
            cipherParams = CryptoJS.lib.CipherParams.create({
                ciphertext: CryptoJS.enc.Hex.parse(storage.value.input)
            });
        } else if (storage.value.inputFormat === 'base64') {
            cipherParams = storage.value.input; // Default decrypt assumes base64 string
        } else {
            // raw string might be complex due to encoding, usually base64 or hex is used.
            // Let's assume it's base64 if format is set to text.
            cipherParams = storage.value.input; 
        }

        const decrypted = algo.decrypt(cipherParams, keyData, options);
        
        if (storage.value.outputFormat === 'hex') {
            outputResult = decrypted.toString(CryptoJS.enc.Hex);
        } else if (storage.value.outputFormat === 'base64') {
            outputResult = CryptoJS.enc.Base64.stringify(decrypted);
        } else {
            outputResult = decrypted.toString(CryptoJS.enc.Utf8);
        }

        if (!outputResult && storage.value.input) {
            throw new Error('Decryption failed');
        }
        isError = false;
      }
    } catch (e) {
      isError = true;
      outputResult = storage.value.action === 'encrypt' ? i18n.t('tools.encryptor.errorEnc') : i18n.t('tools.encryptor.errorDec');
    }
  }

  function generateRandomKey() {
    // Generate a 256-bit (32 bytes) random hex string
    storage.value.key = CryptoJS.lib.WordArray.random(32).toString(CryptoJS.enc.Hex);
    showKey = true; // Briefly show the key so the user can copy/see it
  }

  function generateRandomIV() {
    const algo = storage.value.algorithm;
    // DES, TripleDES, and Rabbit use 64-bit (8 bytes) block size/IV. AES uses 128-bit (16 bytes).
    const bytes = (algo === 'DES' || algo === 'TripleDES' || algo === 'Rabbit') ? 8 : 16;
    storage.value.iv = CryptoJS.lib.WordArray.random(bytes).toString(CryptoJS.enc.Hex);
  }
  const actionOptions = $derived([
    { value: 'encrypt', label: i18n.t('tools.encryptor.encrypt') || 'Encrypt', icon: Lock },
    { value: 'decrypt', label: i18n.t('tools.encryptor.decrypt') || 'Decrypt', icon: Unlock }
  ]);
</script>

<SplitWorkspace {tool}>
  {#snippet headerLeftControls()}
    <SegmentedControl 
      options={actionOptions}
      bind:value={storage.value.action}
      class="shadow-sm"
    />

    <Separator orientation="vertical" size="4" class="hidden sm:block -ml-px" />

    <Select 
      id="inputFormat" 
      label={i18n.t('tools.encryptor.inputFormat') || 'In'}
      bind:value={storage.value.inputFormat}
    >
      {#each CRYPTO_FORMATS as format (format.value)}
        <option value={format.value}>{format.label}</option>
      {/each}
    </Select>

    <Select 
      id="outputFormat" 
      label={i18n.t('tools.encryptor.outputFormat') || 'Out'}
      bind:value={storage.value.outputFormat}
    >
      {#each CRYPTO_FORMATS as format (format.value)}
        <option value={format.value}>{format.label}</option>
      {/each}
    </Select>

    <Separator orientation="vertical" size="4" class="hidden sm:block -ml-px" />

    <label class="flex items-center gap-2 text-sm font-medium text-gray-600 dark:text-gray-400 cursor-pointer group">
      <input 
        type="checkbox" 
        bind:checked={isRealtimeMode}
        class="w-4 h-4 rounded border-gray-300 text-blue-600 focus:ring-blue-500 dark:border-gray-600 dark:bg-gray-800 transition-colors cursor-pointer"
      />
      <span class="group-hover:text-gray-900 dark:group-hover:text-white transition-colors">
        {i18n.t('common.editor.realtimeMode') || 'Real-time Mode'}
      </span>
    </label>

    <button 
      onclick={handleApply}
      disabled={isRealtimeMode || !storage.value.input || !storage.value.key}
      class="flex items-center gap-1.5 px-3 py-1.5 text-sm font-semibold text-white bg-blue-600 rounded-md hover:bg-blue-700 shadow-sm transition-all focus:ring-2 focus:ring-blue-500 focus:ring-offset-2 dark:focus:ring-offset-gray-950 active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed"
    >
      <Play class="w-4 h-4 fill-current" /> <span class="hidden sm:inline">{i18n.t('common.action.apply') || 'Apply'}</span>
    </button>
  {/snippet}

  {#snippet leftPanel()}
    <div class="flex flex-col h-full bg-slate-50/50 dark:bg-slate-900/40 border-r border-gray-200 dark:border-gray-800">
      
      <!-- Top Section: Settings -->
      <div class="p-4 border-b border-gray-200 dark:border-gray-800 bg-white dark:bg-gray-900/50 space-y-4 shrink-0 overflow-y-auto custom-scrollbar max-h-[50%]">
        <div class="grid grid-cols-1 sm:grid-cols-3 gap-4">
          <div class="flex flex-col gap-1.5">
            <label class="text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider">{i18n.t('tools.encryptor.algorithm')}</label>
            <select bind:value={storage.value.algorithm} aria-label={i18n.t('tools.encryptor.algorithm')} class="w-full h-9 px-3 bg-gray-50 dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-lg text-sm focus:ring-2 focus:ring-blue-500 outline-none">
              {#each CRYPTO_ALGORITHMS as algo (algo.value)}
                <option value={algo.value}>{algo.label}</option>
              {/each}
            </select>
          </div>
          <div class="flex flex-col gap-1.5">
            <label class="text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider">{i18n.t('tools.encryptor.mode')}</label>
            <select bind:value={storage.value.mode} aria-label={i18n.t('tools.encryptor.mode')} class="w-full h-9 px-3 bg-gray-50 dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-lg text-sm focus:ring-2 focus:ring-blue-500 outline-none">
              {#each CRYPTO_MODES as modeOption (modeOption.value)}
                <option value={modeOption.value}>{modeOption.label}</option>
              {/each}
            </select>
          </div>
          <div class="flex flex-col gap-1.5">
            <label class="text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider">{i18n.t('tools.encryptor.padding') || 'Padding'}</label>
            <select bind:value={storage.value.padding} aria-label={i18n.t('tools.encryptor.padding') || 'Padding'} class="w-full h-9 px-3 bg-gray-50 dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-lg text-sm focus:ring-2 focus:ring-blue-500 outline-none">
              {#each CRYPTO_PADDINGS as pad (pad.value)}
                <option value={pad.value}>{pad.label}</option>
              {/each}
            </select>
          </div>
        </div>

        <div class="flex flex-col gap-1.5">
          <label class="text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider flex items-center gap-1.5">
            {i18n.t('tools.encryptor.key')} <KeyRound class="w-3.5 h-3.5" />
          </label>
          <div class="relative flex items-center">
            <input 
              type={showKey ? "text" : "password"} 
              bind:value={storage.value.key} 
              class="w-full h-9 pl-3 pr-16 bg-gray-50 dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-lg text-sm font-mono focus:ring-2 focus:ring-blue-500 outline-none placeholder:font-sans placeholder:text-gray-400" 
              placeholder="Secret Key"
            >
            <div class="absolute right-1.5 flex items-center gap-0.5">
              <ButtonIcon 
                onclick={() => showKey = !showKey}
                title={showKey ? "Hide key" : "Show key"}
                color="gray"
                class="!p-1.5"
              >
                {#if showKey}
                  <EyeOff class="w-3.5 h-3.5" />
                {:else}
                  <Eye class="w-3.5 h-3.5" />
                {/if}
              </ButtonIcon>
              <Separator orientation="vertical" size="4" class="hidden sm:block mx-0.5" />
              <ButtonIcon 
                onclick={generateRandomKey}
                title="Generate Random Key"
                color="gray"
                class="!p-1.5 hover:text-blue-600 dark:hover:text-blue-400"
              >
                <Dices class="w-3.5 h-3.5" />
              </ButtonIcon>
            </div>
          </div>
        </div>

        {#if storage.value.mode !== 'ECB'}
          <div class="flex flex-col gap-1.5">
            <label class="text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider">{i18n.t('tools.encryptor.iv')}</label>
            <div class="relative flex items-center">
              <input type="text" bind:value={storage.value.iv} class="w-full h-9 pl-3 pr-9 bg-gray-50 dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-lg text-sm font-mono focus:ring-2 focus:ring-blue-500 outline-none placeholder:font-sans placeholder:text-gray-400" placeholder="Initialization Vector">
              <div class="absolute right-1.5 flex items-center">
                <ButtonIcon 
                  onclick={generateRandomIV}
                  title="Generate Random IV"
                  color="gray"
                  class="!p-1.5 hover:text-blue-600 dark:hover:text-blue-400"
                >
                  <Dices class="w-3.5 h-3.5" />
                </ButtonIcon>
              </div>
            </div>
          </div>
        {/if}
      </div>

      <!-- Bottom Section: Text Input -->
      <div class="flex-1 flex flex-col relative">
        <div class="px-4 py-2 bg-gray-50 dark:bg-gray-900 border-b border-gray-200 dark:border-gray-800 shrink-0 flex items-center justify-between h-11">
          <span class="text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider flex items-center gap-1.5"><FileCode2 class="w-3.5 h-3.5"/> {i18n.t('common.editor.input') || 'Input'}</span>
          <div class="flex items-center gap-2">
            <ButtonIcon 
              onclick={() => storage.value.input = ''}
              disabled={!storage.value.input}
              color="rose"
              title={i18n.t('common.clear')}
            >
              <Trash2 class="w-4 h-4" />
            </ButtonIcon>
          </div>
        </div>
        <textarea
          bind:value={storage.value.input}
          placeholder={i18n.t('tools.common.inputPlaceholder')}
          class="flex-1 w-full p-4 text-sm font-mono bg-transparent border-none resize-none focus:ring-0 focus:outline-none custom-scrollbar"
          spellcheck="false"
        ></textarea>
      </div>
    </div>
  {/snippet}

  {#snippet rightPanel()}
    <div class="flex flex-col h-full bg-white dark:bg-gray-900 relative">
      <div class="px-4 py-2 bg-gray-50 dark:bg-gray-900 border-b border-gray-200 dark:border-gray-800 shrink-0 flex items-center justify-between h-11">
        <span class="text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider flex items-center gap-1.5">
          <Shield class="w-3.5 h-3.5" /> 
          {storage.value.action === 'encrypt' ? i18n.t('tools.encryptor.encrypt') : i18n.t('tools.encryptor.decrypt')} {i18n.t('common.editor.output') || 'Output'}
        </span>
        <div class="flex items-center gap-2">
          <ButtonIcon 
            onclick={() => copyText(outputResult)}
            disabled={!outputResult || isError}
            color="blue"
            title={i18n.t('common.copy')}
          >
            <Copy class="w-4 h-4" />
          </ButtonIcon>
        </div>
      </div>
      
      <div class="flex-1 relative">
        <textarea
          value={outputResult}
          readonly
          placeholder={i18n.t('tools.common.outputPlaceholder')}
          class={`absolute inset-0 w-full h-full p-4 text-sm font-mono bg-transparent border-none resize-none focus:ring-0 focus:outline-none custom-scrollbar ${isError ? 'text-red-500 dark:text-red-400' : 'text-gray-700 dark:text-gray-300'}`}
          spellcheck="false"
        ></textarea>
      </div>
    </div>
  {/snippet}
</SplitWorkspace>
