<script lang="ts">
  import { onMount } from 'svelte';
  import { i18n } from '$lib/i18n';
  import { copyText } from '$lib/utils/clipboard';
  import SplitWorkspace from '$lib/components/layout/templates/SplitWorkspace.svelte';
  import { TextPanel, SegmentedControl, Separator, ButtonIcon, Select } from '$lib/components/ui';
  import { Download, Copy, Trash2, ArrowRightLeft, Binary, Type } from 'lucide-svelte';
  import { downloadFile, generateDownloadFilename } from '$lib/utils/file';
  import { createTool } from '$lib/stores';
  import type { ToolDefinition } from '$lib/types';
  import { smartInputState } from '$lib/utils/smartInput';

  export interface StringEscaperProps {
    tool: ToolDefinition;
  }

  let { tool }: StringEscaperProps = $props();

  let isFullFrame = $state(false);

  let modeOptions = $derived([
    { value: 'encode', label: i18n.t('common.action.encode') || 'Escape', icon: Binary },
    { value: 'decode', label: i18n.t('common.action.decode') || 'Unescape', icon: Type }
  ]);

  let typeOptions = $derived([
    { value: 'unicode', label: i18n.t('tools.stringEscaper.type.unicode') || 'Unicode (\\uXXXX)' },
    { value: 'hex', label: i18n.t('tools.stringEscaper.type.hex') || 'Hexadecimal (\\xXX)' },
    { value: 'standard', label: i18n.t('tools.stringEscaper.type.standard') || 'Standard (\\n, \\t)' }
  ]);

  const storage = createTool(tool.slug, {
    input: '',
    mode: 'decode',
    type: 'unicode'
  });

  onMount(() => {
    const passedData = smartInputState.consume();
    if (passedData) {
      storage.value.input = passedData;
    }
  });

  function processString(input: string, mode: string, type: string) {
    if (!input) return { value: '', error: false };
    
    try {
      if (mode === 'encode') {
        if (type === 'unicode') {
          return {
            value: input.split('').map(c => {
              const code = c.charCodeAt(0);
              // Escape non-ASCII characters and backslashes
              if (code > 127) return '\\u' + code.toString(16).padStart(4, '0');
              if (c === '\\') return '\\\\';
              return c;
            }).join(''),
            error: false
          };
        } else if (type === 'hex') {
          // Encode string to UTF-8 bytes first to properly support multi-byte characters
          const bytes = new TextEncoder().encode(input);
          return {
            value: Array.from(bytes).map(b => '\\x' + b.toString(16).padStart(2, '0')).join(''),
            error: false
          };
        } else {
          // Standard: JSON.stringify handles \n, \t, ", \ 
          let escaped = JSON.stringify(input);
          // Remove the starting and ending quotes added by JSON.stringify
          return { value: escaped.substring(1, escaped.length - 1), error: false };
        }
      } else {
        // Decode (Unescape)
        if (type === 'unicode') {
          // Replace \uXXXX
          let unescaped = input.replace(/\\u([0-9a-fA-F]{4})/g, (match, grp) => {
            return String.fromCharCode(parseInt(grp, 16));
          });
          // Unescape \\ to \
          unescaped = unescaped.replace(/\\\\/g, '\\');
          return { value: unescaped, error: false };
        } else if (type === 'hex') {
          // Convert \xXX to %XX to let decodeURIComponent handle UTF-8 decoding
          try {
            const pctEncoded = input.replace(/\\x([0-9a-fA-F]{2})/g, '%$1');
            // Check if there are still any unhandled backslashes (like \\)
            let decoded = decodeURIComponent(pctEncoded);
            decoded = decoded.replace(/\\\\/g, '\\');
            return { value: decoded, error: false };
          } catch(e) {
            // Fallback if not valid UTF-8
            let unescaped = input.replace(/\\x([0-9a-fA-F]{2})/g, (match, grp) => {
              return String.fromCharCode(parseInt(grp, 16));
            });
            unescaped = unescaped.replace(/\\\\/g, '\\');
            return { value: unescaped, error: false };
          }
        } else {
          // Standard unescape
          try {
            const map: Record<string, string> = { '\\n': '\n', '\\t': '\t', '\\r': '\r', '\\b': '\b', '\\f': '\f', '\\v': '\v', '\\"': '"', "\\'": "'", '\\\\': '\\' };
            const unescaped = input.replace(/\\([ntrbvf"'\\])/g, (match) => map[match] || match);
            return { value: unescaped, error: false };
          } catch(e) {
            return { value: input, error: true };
          }
        }
      }
    } catch (e) {
      return { value: i18n.t('common.error.generic') || 'Error processing string', error: true };
    }
  }

  let outputState = $derived.by(() => {
    return processString(storage.value.input, storage.value.mode, storage.value.type);
  });

  function clearText() { storage.value.input = ''; }
  
  function handleSwap() {
    if (outputState.error || !outputState.value) return;
    storage.value.input = outputState.value;
    storage.value.mode = storage.value.mode === 'encode' ? 'decode' : 'encode';
  }
</script>

<SplitWorkspace {tool} bind:isFullFrame>
  {#snippet headerLeftControls()}
    <SegmentedControl bind:value={storage.value.mode} options={modeOptions} class="bg-gray-100 dark:bg-gray-900/80 shadow-sm" />

    <Select 
      id="escape-type"
      label={i18n.t('common.form.type') || 'Type'}
      bind:value={storage.value.type}
    >
      {#each typeOptions as opt (opt.value)}
        <option value={opt.value}>{opt.label}</option>
      {/each}
    </Select>

    <Separator orientation="vertical" size="4" class="hidden sm:block -ml-px" />

    <ButtonIcon 
      onclick={handleSwap}
      disabled={!outputState.value || outputState.error}
      color="blue"
      class="!p-2"
      title={i18n.t('common.action.swap') || 'Swap sides'}
    >
      <ArrowRightLeft class="w-4 h-4" />
    </ButtonIcon>
  {/snippet}

  {#snippet leftPanel()}
    <TextPanel label={i18n.t('common.editor.input') || 'Input'} bind:value={storage.value.input} placeholder={i18n.t('common.form.pasteInput', { format: 'text' })}>
      {#snippet actionButton()}
        <ButtonIcon onclick={clearText} disabled={!storage.value.input} color="rose" title={i18n.t('common.action.clear') || 'Clear'}>
          <Trash2 class="w-4 h-4" />
        </ButtonIcon>
      {/snippet}
    </TextPanel>
  {/snippet}

  {#snippet rightPanel()}
    <TextPanel label={i18n.t('common.editor.output') || 'Output'} value={outputState.value} readonly={true} hasError={outputState.error} placeholder={i18n.t('common.form.outputResult', { format: 'text' })}>
      {#snippet actionButton()}
        <ButtonIcon 
          onclick={() => downloadFile(outputState.value, generateDownloadFilename(tool.id))} 
          color="green"
          title={i18n.t('common.action.download') || 'Download'} 
          disabled={!outputState.value || outputState.error}
        >
          <Download class="w-4 h-4" />
        </ButtonIcon>

        <ButtonIcon 
          onclick={() => copyText(outputState.value)} 
          color="blue"
          title={i18n.t('common.action.copy') || 'Copy'} 
          disabled={!outputState.value || outputState.error}
        >
          <Copy class="w-4 h-4" />
        </ButtonIcon>
      {/snippet}
    </TextPanel>
  {/snippet}
</SplitWorkspace>
