interface TooltipOptions {
    content: string;
    position?: 'top' | 'bottom' | 'left' | 'right';
    align?: 'start' | 'center' | 'end';
    contentClass?: string;
    delay?: number;
    disabled?: boolean;
}

export function tooltip(node: HTMLElement, options: TooltipOptions | string) {
    let tooltipEl: HTMLElement | null = null;
    let timer: ReturnType<typeof setTimeout>;
    
    let opts = typeof options === 'string' ? { content: options } : options;
    
    function show() {
        if (opts.disabled || !opts.content) return;
        
        // Remove existing if any
        if (tooltipEl) {
            document.body.removeChild(tooltipEl);
            tooltipEl = null;
        }

        const delay = opts.delay ?? 100;

        timer = setTimeout(() => {
            tooltipEl = document.createElement('div');
            tooltipEl.className = `fixed z-[9999] opacity-0 transition-all duration-200 pointer-events-none bg-white/95 dark:bg-gray-900/90 backdrop-blur-xl border border-gray-200/50 dark:border-gray-700/50 shadow-2xl rounded-xl text-xs font-medium text-gray-700 dark:text-gray-200 ${opts.contentClass || 'p-2 px-3'}`;
            
            const contentSpan = document.createElement('span');
            contentSpan.innerHTML = opts.content;
            tooltipEl.appendChild(contentSpan);

            // Add arrow
            const arrowEl = document.createElement('div');
            arrowEl.className = 'absolute w-3 h-3 bg-white dark:bg-gray-900 border-gray-200/50 dark:border-gray-700/50';
            
            const position = opts.position || 'top';
            const align = opts.align || 'center';

            if (position === 'top') {
                arrowEl.style.top = '100%';
                arrowEl.style.transform = 'translateY(-50%) rotate(45deg)';
                arrowEl.style.borderBottomWidth = '1px';
                arrowEl.style.borderRightWidth = '1px';
                if (align === 'start') arrowEl.style.left = '16px';
                else if (align === 'center') arrowEl.style.left = 'calc(50% - 6px)';
                else if (align === 'end') arrowEl.style.right = '16px';
            } else if (position === 'bottom') {
                arrowEl.style.top = '0';
                arrowEl.style.transform = 'translateY(-50%) rotate(45deg)';
                arrowEl.style.borderTopWidth = '1px';
                arrowEl.style.borderLeftWidth = '1px';
                if (align === 'start') arrowEl.style.left = '16px';
                else if (align === 'center') arrowEl.style.left = 'calc(50% - 6px)';
                else if (align === 'end') arrowEl.style.right = '16px';
            } else if (position === 'left') {
                arrowEl.style.left = '100%';
                arrowEl.style.transform = 'translateX(-50%) rotate(45deg)';
                arrowEl.style.borderTopWidth = '1px';
                arrowEl.style.borderRightWidth = '1px';
                if (align === 'start') arrowEl.style.top = '16px';
                else if (align === 'center') arrowEl.style.top = 'calc(50% - 6px)';
                else if (align === 'end') arrowEl.style.bottom = '16px';
            } else if (position === 'right') {
                arrowEl.style.left = '0';
                arrowEl.style.transform = 'translateX(-50%) rotate(45deg)';
                arrowEl.style.borderBottomWidth = '1px';
                arrowEl.style.borderLeftWidth = '1px';
                if (align === 'start') arrowEl.style.top = '16px';
                else if (align === 'center') arrowEl.style.top = 'calc(50% - 6px)';
                else if (align === 'end') arrowEl.style.bottom = '16px';
            }

            tooltipEl.appendChild(arrowEl);
            document.body.appendChild(tooltipEl);

            const nodeRect = node.getBoundingClientRect();
            const tooltipRect = tooltipEl.getBoundingClientRect();

            let top = 0;
            let left = 0;
            const gap = 8; // 8px spacing

            switch (position) {
                case 'top':
                    top = nodeRect.top - tooltipRect.height - gap;
                    break;
                case 'bottom':
                    top = nodeRect.bottom + gap;
                    break;
                case 'left':
                    left = nodeRect.left - tooltipRect.width - gap;
                    break;
                case 'right':
                    left = nodeRect.right + gap;
                    break;
            }

            if (position === 'top' || position === 'bottom') {
                if (align === 'start') left = nodeRect.left;
                else if (align === 'center') left = nodeRect.left + (nodeRect.width / 2) - (tooltipRect.width / 2);
                else if (align === 'end') left = nodeRect.right - tooltipRect.width;
            } else {
                if (align === 'start') top = nodeRect.top;
                else if (align === 'center') top = nodeRect.top + (nodeRect.height / 2) - (tooltipRect.height / 2);
                else if (align === 'end') top = nodeRect.bottom - tooltipRect.height;
            }

            // Ensure tooltip stays within viewport
            if (left < 8) left = 8;
            if (top < 8) top = 8;
            if (left + tooltipRect.width > window.innerWidth - 8) left = window.innerWidth - tooltipRect.width - 8;
            if (top + tooltipRect.height > window.innerHeight - 8) top = window.innerHeight - tooltipRect.height - 8;

            tooltipEl.style.top = `${top}px`;
            tooltipEl.style.left = `${left}px`;
            
            // Trigger animation
            requestAnimationFrame(() => {
                if (tooltipEl) {
                    tooltipEl.style.opacity = '1';
                    if (position === 'top') tooltipEl.style.transform = 'translateY(-4px)';
                    else if (position === 'bottom') tooltipEl.style.transform = 'translateY(4px)';
                    else if (position === 'left') tooltipEl.style.transform = 'translateX(-4px)';
                    else if (position === 'right') tooltipEl.style.transform = 'translateX(4px)';
                }
            });
        }, delay);
    }

    function hide() {
        clearTimeout(timer);
        if (tooltipEl) {
            tooltipEl.style.opacity = '0';
            tooltipEl.style.transform = 'translate(0)';
            const elToRemove = tooltipEl;
            setTimeout(() => {
                if (document.body.contains(elToRemove)) {
                    document.body.removeChild(elToRemove);
                }
            }, 200); // match transition duration
            tooltipEl = null;
        }
    }

    node.addEventListener('mouseenter', show);
    node.addEventListener('mouseleave', hide);
    node.addEventListener('focus', show);
    node.addEventListener('blur', hide);

    return {
        update(newOptions: TooltipOptions | string) {
            opts = typeof newOptions === 'string' ? { content: newOptions } : newOptions;
            if (tooltipEl) {
                const contentSpan = tooltipEl.querySelector('span');
                if (contentSpan) contentSpan.innerHTML = opts.content;
            }
        },
        destroy() {
            hide();
            node.removeEventListener('mouseenter', show);
            node.removeEventListener('mouseleave', hide);
            node.removeEventListener('focus', show);
            node.removeEventListener('blur', hide);
        }
    };
}
