<script lang="ts">
  import { i18n } from '$lib/i18n';
  import SplitWorkspace from '$lib/components/layout/templates/SplitWorkspace.svelte';
  import { MonacoEditor, SegmentedControl, Separator, ButtonIcon } from '$lib/components/ui';
  import { Download, Copy, Trash2, ArrowRightLeft, FileText, Code2, MonitorPlay, WrapText } from 'lucide-svelte';
  import { downloadFile, generateDownloadFilename } from '$lib/utils/file';
  import { copyText } from '$lib/utils/clipboard';
  import { createTool } from '$lib/stores';
  import type { ToolDefinition } from '$lib/types';
  import { smartInputState } from '$lib/utils/smartInput';
  import { onMount } from 'svelte';
  import { marked } from 'marked';
  import TurndownService from 'turndown';

  export interface MarkdownHtmlProps {
    tool: ToolDefinition;
  }

  let { tool }: MarkdownHtmlProps = $props();

  let isFullFrame = $state(false);
  let activeTab = $state<'preview' | 'source'>('preview');
  let wordWrapLeft = $state(true);
  let wordWrapRight = $state(true);

  const modeOptions = [
    { value: 'markdown-to-html', label: i18n.t('tools.markdownHtml.markdownToHtml') },
    { value: 'html-to-markdown', label: i18n.t('tools.markdownHtml.htmlToMarkdown') }
  ];

  const storage = createTool(tool.slug, {
    input: '',
    mode: 'markdown-to-html'
  });

  const turndownService = new TurndownService();

  onMount(() => {
    const passedData = smartInputState.consume();
    if (passedData) {
      storage.value.input = passedData;
    }
  });

  let outputState = $derived.by(() => {
    if (!storage.value.input) return { value: '', error: false };
    
    try {
      if (storage.value.mode === 'markdown-to-html') {
        const html = marked.parse(storage.value.input) as string;
        return { value: html, error: false };
      } else {
        const markdown = turndownService.turndown(storage.value.input);
        return { value: markdown, error: false };
      }
    } catch (e) {
      return { value: 'Error parsing input', error: true };
    }
  });

  function clearText() {
    storage.value.input = '';
  }

  function handleSwap() {
    if (outputState.error || !outputState.value) return;
    storage.value.input = outputState.value;
    storage.value.mode = storage.value.mode === 'markdown-to-html' ? 'html-to-markdown' : 'markdown-to-html';
  }
</script>

<SplitWorkspace {tool} bind:isFullFrame>
  {#snippet headerLeftControls()}
    <SegmentedControl bind:value={storage.value.mode} options={modeOptions} class="bg-gray-100 dark:bg-gray-900/80 shadow-sm" />

    <Separator orientation="vertical" size="4" class="hidden sm:block -ml-px" />

    <ButtonIcon 
      onclick={handleSwap}
      disabled={!outputState.value || outputState.error}
      color="blue"
      class="!p-2"
      title={i18n.t('common.swap')}
    >
      <ArrowRightLeft class="w-4 h-4" />
    </ButtonIcon>
  {/snippet}

  {#snippet leftPanel()}
    <div class="flex items-center justify-between px-4 py-2 bg-gray-50 dark:bg-gray-900 border-b border-gray-200 dark:border-gray-800 h-11 shrink-0">
      <span class="flex items-center gap-1.5 text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider">
        {#if storage.value.mode === 'markdown-to-html'}
          <FileText class="w-3.5 h-3.5" /> {i18n.t('tools.markdownHtml.markdownSource')}
        {:else}
          <Code2 class="w-3.5 h-3.5" /> {i18n.t('tools.markdownHtml.htmlSource')}
        {/if}
      </span>
      <div class="flex items-center gap-1">
        <ButtonIcon onclick={() => wordWrapLeft = !wordWrapLeft} color="blue" active={wordWrapLeft} title={wordWrapLeft ? 'Disable Word Wrap' : 'Enable Word Wrap'}>
          <WrapText class="w-4 h-4" />
        </ButtonIcon>
        <ButtonIcon onclick={clearText} disabled={!storage.value.input} color="rose" title={i18n.t('common.clear')}>
          <Trash2 class="w-4 h-4" />
        </ButtonIcon>
      </div>
    </div>
    <div class="flex-1 w-full relative min-h-0">
      <MonacoEditor 
        bind:value={storage.value.input} 
        language={storage.value.mode === 'markdown-to-html' ? 'markdown' : 'html'} 
        wordWrap={wordWrapLeft}
      />
    </div>
  {/snippet}

  {#snippet rightPanel()}
    <div class="flex flex-col h-full bg-white dark:bg-[#1e1e1e]">
      <div class="flex items-center justify-between px-4 py-2 bg-gray-50 dark:bg-gray-900 border-b border-gray-200 dark:border-gray-800 h-11 shrink-0">
        
        {#if storage.value.mode === 'markdown-to-html'}
          <div class="flex space-x-1 bg-gray-200/50 dark:bg-gray-800/50 p-1 rounded-lg">
            <button 
              class="px-3 py-1 text-xs font-medium rounded-md transition-colors {activeTab === 'source' ? 'bg-white dark:bg-gray-700 shadow-sm text-gray-900 dark:text-gray-100' : 'text-gray-500 hover:text-gray-700 dark:text-gray-400 dark:hover:text-gray-200'}"
              onclick={() => activeTab = 'source'}
            >
              <span class="flex items-center gap-1.5"><Code2 class="w-3.5 h-3.5" /> {i18n.t('tools.markdownHtml.htmlSource')}</span>
            </button>
            <button 
              class="px-3 py-1 text-xs font-medium rounded-md transition-colors {activeTab === 'preview' ? 'bg-white dark:bg-gray-700 shadow-sm text-gray-900 dark:text-gray-100' : 'text-gray-500 hover:text-gray-700 dark:text-gray-400 dark:hover:text-gray-200'}"
              onclick={() => activeTab = 'preview'}
            >
              <span class="flex items-center gap-1.5"><MonitorPlay class="w-3.5 h-3.5" /> {i18n.t('tools.markdownHtml.preview')}</span>
            </button>
          </div>
        {:else}
          <span class="flex items-center gap-1.5 text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider">
            <FileText class="w-3.5 h-3.5" /> {i18n.t('tools.markdownHtml.markdownSource')}
          </span>
        {/if}
        
        <div class="flex items-center gap-1">
          {#if (storage.value.mode === 'markdown-to-html' && activeTab === 'source') || storage.value.mode === 'html-to-markdown'}
            <ButtonIcon onclick={() => wordWrapRight = !wordWrapRight} color="blue" active={wordWrapRight} title={wordWrapRight ? 'Disable Word Wrap' : 'Enable Word Wrap'}>
              <WrapText class="w-4 h-4" />
            </ButtonIcon>
          {/if}
          <ButtonIcon 
            onclick={() => downloadFile(outputState.value, generateDownloadFilename(tool.id, storage.value.mode === 'markdown-to-html' ? 'html' : 'md'))} 
            color="green"
            title={i18n.t('common.download')} 
            disabled={!outputState.value || outputState.error}
          >
            <Download class="w-4 h-4" />
          </ButtonIcon>

          <ButtonIcon 
            onclick={() => copyText(outputState.value)} 
            color="blue"
            title={i18n.t('common.copy')} 
            disabled={!outputState.value || outputState.error}
          >
            <Copy class="w-4 h-4" />
          </ButtonIcon>
        </div>
      </div>

      <div class="flex-1 w-full relative min-h-0">
        {#if storage.value.mode === 'markdown-to-html' && activeTab === 'preview'}
          <div class="absolute inset-0 w-full h-full p-4 overflow-y-auto prose dark:prose-invert max-w-none custom-scrollbar bg-white dark:bg-[#1e1e1e]">
            {@html outputState.value}
          </div>
        {:else}
          <MonacoEditor 
            value={outputState.value}
            language={storage.value.mode === 'markdown-to-html' ? 'html' : 'markdown'}
            readOnly={true}
            wordWrap={wordWrapRight}
          />
        {/if}
      </div>
    </div>
  {/snippet}
</SplitWorkspace>
