import { env } from '$env/dynamic/public';

interface SubmitIdeaPayload {
	ideaName: string;
	description: string;
	userName: string;
	userEmail?: string;
	userPhone?: string;
}

export async function submitIdeaToWeb3Forms(payload: SubmitIdeaPayload): Promise<boolean> {
	const accessKey = env.PUBLIC_W3F_ACCESS_KEY;
	if (!accessKey) {
		console.warn('PUBLIC_W3F_ACCESS_KEY is not set');
		return false;
	}

	try {
		const response = await fetch('https://api.web3forms.com/submit', {
			method: 'POST',
			headers: {
				'Content-Type': 'application/json',
				'Accept': 'application/json'
			},
			body: JSON.stringify({
				access_key: accessKey,
				subject: `[DeboxHub - Idea Suggestion] ${payload.userName} has requested: ${payload.ideaName}`,
				from_name: payload.userName || 'DeboxHub User',
				user_name: payload.userName,
				user_email: payload.userEmail,
				user_phone: payload.userPhone,
				idea_name: payload.ideaName,
				description: payload.description
			})
		});
		
		const result = await response.json();
		if (!result.success) {
			console.error('Web3Forms Error:', result);
			return false;
		}
		
		return true;
	} catch (error) {
		console.error('Failed to submit idea to Web3Forms', error);
		return false;
	}
}
