<script lang="ts">
  import { i18n } from '$lib/i18n';
  
  // Icons
  import { SettingsIcon, Palette, Code2, Database, Wrench } from 'lucide-svelte/icons';

  // Tab Components
  import General from './settings/General.svelte';
  import Appearance from './settings/Appearance.svelte';
  import Editor from './settings/Editor.svelte';
  import Data from './settings/Data.svelte';
  import ToolsSettings from './settings/Tools.svelte';

  const TABS = [
    { id: 'general', icon: SettingsIcon, label: 'General', component: General },
    { id: 'tools', icon: Wrench, label: 'Workspace', component: ToolsSettings },
    { id: 'appearance', icon: Palette, label: 'Appearance', component: Appearance },
    { id: 'editor', icon: Code2, label: 'Editor', component: Editor },
    { id: 'data', icon: Database, label: 'Data & Storage', component: Data }
  ];

  let activeTabId = $state(TABS[0].id);
  let activeTab = $derived(TABS.find(t => t.id === activeTabId) || TABS[0]);
  let ActiveComponent = $derived(activeTab.component);
</script>

<div class="max-w-5xl mx-auto h-[calc(100vh-8rem)] min-h-[600px] flex flex-col md:flex-row gap-8">
  
  <!-- Left Sidebar (Navigation) -->
  <aside class="w-full md:w-64 shrink-0 flex flex-col gap-2">
    <div class="mb-4 px-2">
      <h1 class="text-2xl font-bold tracking-tight text-gray-900 dark:text-gray-100">Settings</h1>
      <p class="text-sm text-gray-500 dark:text-gray-400 mt-1">Manage your preferences.</p>
    </div>

    <nav class="flex md:flex-col gap-1 overflow-x-auto md:overflow-visible pb-2 md:pb-0 custom-scrollbar">
      {#each TABS as tab (tab.id)}
        <button 
          onclick={() => activeTabId = tab.id}
          class="flex items-center gap-3 px-3 py-2.5 rounded-lg transition-colors text-sm font-medium whitespace-nowrap {
            activeTabId === tab.id 
              ? 'bg-gray-100 dark:bg-gray-800 text-gray-900 dark:text-gray-100' 
              : 'text-gray-600 dark:text-gray-400 hover:bg-gray-50 dark:hover:bg-gray-800/50 hover:text-gray-900 dark:hover:text-gray-200'
          }"
        >
          <tab.icon class="w-4 h-4 shrink-0 {activeTabId === tab.id ? 'text-blue-600 dark:text-blue-400' : 'text-gray-400 dark:text-gray-500'}" />
          {tab.label}
        </button>
      {/each}
    </nav>
  </aside>

  <!-- Right Content Area -->
  <main class="flex-1 overflow-y-auto custom-scrollbar pb-8 px-2 md:px-0">
    <!-- Render the active tab component -->
    <ActiveComponent />
  </main>
  
</div>