import { browser } from '$app/environment';

import { APP_CONFIG } from '$lib/constants/app';
import type { Locale } from '$lib/types';
import { dictionaries } from '$lib/i18n/locales';

function createI18nStore() {
	const state = $state({ locale: (APP_CONFIG.defaults.locale || 'en') as Locale });

	if (browser) {
		const saved = localStorage.getItem(APP_CONFIG.storageKeys.locale) as Locale;

		if (saved === 'vi' || saved === 'en') {
			state.locale = saved;
		} else {
			// If there is no saved configuration, automatically check the browser language
			const browserLang = window.navigator.language.split('-')[0];
			if (browserLang === 'vi' || browserLang === 'en') {
				state.locale = browserLang as Locale;
			}
		}
		document.documentElement.lang = state.locale;
	}

	return {
		get locale() {
			return state.locale;
		},
		set locale(lang: Locale) {
			state.locale = lang;
			if (browser) {
				localStorage.setItem(APP_CONFIG.storageKeys.locale, lang);
				document.documentElement.lang = lang;
			}
		},

		/**
		 * Safe Nested Translation
		 * @param path example: 'widget.quickDate'
		 * @param params optional object for string interpolation example: { format: 'JSON' }
		 */
		t: (path: string, params?: Record<string, string | number>): string => {
			const keys = path.split('.');
			let result: any = dictionaries[state.locale];

			for (const key of keys) {
				// If the intermediate result is not a valid object, break the loop immediately
				if (result === null || typeof result !== 'object') {
					return path;
				}
				result = result[key];
			}

			// In case the final result is not found or not a string, return the key
			if (typeof result !== 'string') return path;

			// If parameters are provided, replace {key} with value
			if (params) {
				return result.replace(/\{(\w+)\}/g, (_, key) => {
					return params[key] !== undefined ? String(params[key]) : `{${key}}`;
				});
			}

			return result;
		}
	};
}

export const i18n = createI18nStore();
