<script lang="ts">
  import { appearanceStore } from '$lib/stores/ui/appearance.svelte';
  import { APPEARANCES } from '$lib/constants';
  import { i18n } from '$lib/i18n';

  import { Sun, Moon, Monitor, Check } from 'lucide-svelte';

  const iconMap: Record<string, typeof Sun> = { Sun, Moon, Monitor };

  let CurrentIcon = $derived(iconMap[APPEARANCES.find(t => t.id === appearanceStore.appearance)?.icon || 'Monitor']);
</script>

<div class="relative inline-block text-left group">
  <button 
    class="flex items-center justify-center p-2 rounded-xl text-gray-500 bg-gray-50 border border-gray-200 hover:bg-gray-100 hover:text-gray-900 transition-colors focus:outline-none dark:bg-gray-800 dark:border-gray-700 dark:text-gray-400 dark:hover:bg-gray-700 dark:hover:text-gray-100"
    title={i18n.t('common.action.switch.theme')}
  >
    {#key appearanceStore.appearance}
      <CurrentIcon class="w-4 h-4" />
    {/key}
  </button>

  <div 
    class="absolute right-0 mt-1 w-36 origin-top-right rounded-xl bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 shadow-xl invisible opacity-0 scale-95 group-hover:visible group-hover:opacity-100 group-hover:scale-100 transition-all duration-150 z-50 p-1"
  >
    <div class="absolute -top-2 left-0 right-0 h-2"></div>

    <div class="flex flex-col gap-0.5">
      {#each APPEARANCES as appearance (appearance.id)}
        {@const Icon = iconMap[appearance.icon]}
        <button
          onclick={() => appearanceStore.setAppearance(appearance.id)}
          class={`flex items-center justify-between w-full text-left px-3 py-2 text-xs font-medium rounded-lg transition-colors ${
            appearanceStore.appearance === appearance.id
              ? 'bg-blue-50 text-blue-700 dark:bg-blue-900/30 dark:text-blue-400'
              : 'text-gray-600 hover:bg-gray-50 hover:text-gray-900 dark:text-gray-400 dark:hover:bg-gray-700/50 dark:hover:text-gray-200'
          }`}
        >
          <div class="flex items-center gap-2">
            <Icon class="w-3.5 h-3.5" />
            <span>{i18n.t(appearance.name)}</span>
          </div>
          {#if appearanceStore.appearance === appearance.id}
            <Check class="w-3.5 h-3.5 text-blue-600 dark:text-blue-400" />
          {/if}
        </button>
      {/each}
    </div>
  </div>
</div>