<script lang="ts">
  import JSZip from 'jszip';
  import { i18n } from '$lib/i18n';
  import SplitWorkspace from '$lib/components/layout/templates/SplitWorkspace.svelte';
  import { createTool } from '$lib/stores';
  import type { ToolDefinition } from '$lib/types';
  import { SegmentedControl, Separator } from '$lib/components/ui';
  import { DownloadCloud, Type, Smile, Image as ImageIcon, RefreshCw, Upload, Square, Circle, AppWindow } from 'lucide-svelte';

  export interface FaviconGeneratorProps {
    tool: ToolDefinition;
  }

  let { tool }: FaviconGeneratorProps = $props();

  const storage = createTool(tool.slug, {
    mode: 'text', // 'text', 'emoji', 'image'
    text: 'D',
    emoji: '🚀',
    image: null as string | null,
    bgColor: '#3b82f6',
    textColor: '#ffffff',
    shape: 'rounded', // 'square', 'rounded', 'circle'
    padding: 20, // percentage 0-50
    fontSize: 60, // percentage relative to inner box
    fontFamily: 'system-ui, sans-serif'
  });

  let previewCanvas: HTMLCanvasElement;
  let previewDataUrl = $state('');
  let isGenerating = $state(false);
  let imageElement: HTMLImageElement | null = null;
  let fileInput: HTMLInputElement;

  const fontFamilies = [
    { label: 'System UI', value: 'system-ui, sans-serif' },
    { label: 'Serif', value: 'Georgia, serif' },
    { label: 'Monospace', value: '"Courier New", monospace' },
    { label: 'Cursive', value: 'cursive' },
    { label: 'Inter', value: '"Inter", sans-serif' },
    { label: 'Roboto', value: '"Roboto", sans-serif' },
    { label: 'Montserrat', value: '"Montserrat", sans-serif' },
    { label: 'Playfair', value: '"Playfair Display", serif' },
    { label: 'Lobster', value: '"Lobster", cursive' },
    { label: 'Bangers', value: '"Bangers", cursive' },
    { label: 'Pacifico', value: '"Pacifico", cursive' }
  ];

  const modeOptions = $derived([
    { value: 'text', label: i18n.t('common.options.text') || 'Text', icon: Type },
    { value: 'emoji', label: i18n.t('common.options.emoji') || 'Emoji', icon: Smile },
    { value: 'image', label: i18n.t('common.options.image') || 'Image', icon: ImageIcon }
  ]);

  function handleImageUpload(e: Event) {
    const target = e.target as HTMLInputElement;
    if (target.files && target.files[0]) {
      const reader = new FileReader();
      reader.onload = (e) => {
        storage.value.image = e.target?.result as string;
        storage.value.mode = 'image';
      };
      reader.readAsDataURL(target.files[0]);
    }
  }

  $effect(() => {
    // Whenever settings change, trigger a redraw
    JSON.stringify(storage.value);
    document.fonts.ready.then(() => {
      requestAnimationFrame(renderPreview);
    });
  });

  function renderToContext(ctx: CanvasRenderingContext2D, size: number) {
    ctx.clearRect(0, 0, size, size);

    // Draw Background
    if (storage.value.bgColor !== 'transparent') {
      ctx.fillStyle = storage.value.bgColor;
      ctx.beginPath();
      if (storage.value.shape === 'circle') {
        ctx.arc(size / 2, size / 2, size / 2, 0, Math.PI * 2);
      } else if (storage.value.shape === 'rounded') {
        const radius = size * 0.22; // standard apple-like rounding
        ctx.roundRect(0, 0, size, size, radius);
      } else {
        ctx.rect(0, 0, size, size);
      }
      ctx.fill();
    }

    // Calculate inner content box based on padding
    const paddingPx = (storage.value.padding / 100) * size;
    const innerSize = size - paddingPx * 2;
    const centerX = size / 2;
    const centerY = size / 2;

    ctx.save();
    // Clip to shape if necessary, though content usually fits
    
    if (storage.value.mode === 'text' && storage.value.text) {
      ctx.fillStyle = storage.value.textColor;
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';
      const fSize = (storage.value.fontSize / 100) * innerSize;
      ctx.font = `bold ${fSize}px ${storage.value.fontFamily}`;
      // Slight vertical adjustment for some fonts to look centered
      ctx.fillText(storage.value.text.substring(0, 2), centerX, centerY + (fSize * 0.05));
    } 
    else if (storage.value.mode === 'emoji' && storage.value.emoji) {
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';
      const fSize = (storage.value.fontSize / 100) * innerSize;
      ctx.font = `${fSize}px "Apple Color Emoji", "Segoe UI Emoji", "Noto Color Emoji", sans-serif`;
      ctx.fillText(storage.value.emoji, centerX, centerY + (fSize * 0.05));
    }
    else if (storage.value.mode === 'image' && storage.value.image) {
      if (!imageElement || imageElement.src !== storage.value.image) {
        const img = new Image();
        img.onload = () => {
          imageElement = img;
          renderPreview(); // re-render when image loads
        };
        img.src = storage.value.image;
      } else {
        // Draw image keeping aspect ratio
        const imgAspect = imageElement.width / imageElement.height;
        let drawWidth = innerSize;
        let drawHeight = innerSize;
        if (imgAspect > 1) {
          drawHeight = innerSize / imgAspect;
        } else {
          drawWidth = innerSize * imgAspect;
        }
        ctx.drawImage(imageElement, centerX - drawWidth / 2, centerY - drawHeight / 2, drawWidth, drawHeight);
      }
    }
    ctx.restore();
  }

  function renderPreview() {
    if (!previewCanvas) return;
    const size = 512;
    previewCanvas.width = size;
    previewCanvas.height = size;
    const ctx = previewCanvas.getContext('2d');
    if (!ctx) return;
    
    renderToContext(ctx, size);
    previewDataUrl = previewCanvas.toDataURL('image/png');
  }

  async function downloadZip() {
    isGenerating = true;
    try {
      const zip = new JSZip();
      
      const sizes = [16, 32, 192, 512];
      const canvas = document.createElement('canvas');
      const ctx = canvas.getContext('2d');
      if (!ctx) throw new Error("Canvas not supported");

      // Generate PNGs
      for (const s of sizes) {
        canvas.width = s;
        canvas.height = s;
        renderToContext(ctx, s);
        const dataUrl = canvas.toDataURL('image/png');
        const base64 = dataUrl.split(',')[1];
        if (s === 192 || s === 512) {
          zip.file(`android-chrome-${s}x${s}.png`, base64, {base64: true});
        } else {
          zip.file(`favicon-${s}x${s}.png`, base64, {base64: true});
        }
      }

      // Apple Touch Icon (180x180, often forced to no transparency or specific shapes, but we'll use standard render)
      canvas.width = 180;
      canvas.height = 180;
      renderToContext(ctx, 180);
      zip.file('apple-touch-icon.png', canvas.toDataURL('image/png').split(',')[1], {base64: true});

      // favicon.ico (We can just use the 32x32 png data, many modern browsers accept PNG inside ICO or just rename it. Better: use 32x32 png as ICO).
      // A true ICO requires a specific header, but for a simple tool, returning the 32x32 PNG renamed to .ico works in most modern contexts. 
      // Actually, we'll just include the 32x32 file as favicon.ico directly.
      canvas.width = 32;
      canvas.height = 32;
      renderToContext(ctx, 32);
      zip.file('favicon.ico', canvas.toDataURL('image/png').split(',')[1], {base64: true});

      // Generate manifest
      const manifest = {
        "name": "My App",
        "short_name": "App",
        "icons": [
          {
            "src": "/android-chrome-192x192.png",
            "sizes": "192x192",
            "type": "image/png"
          },
          {
            "src": "/android-chrome-512x512.png",
            "sizes": "512x512",
            "type": "image/png"
          }
        ],
        "theme_color": storage.value.bgColor !== 'transparent' ? storage.value.bgColor : '#ffffff',
        "background_color": "#ffffff",
        "display": "standalone"
      };
      zip.file('site.webmanifest', JSON.stringify(manifest, null, 2));

      // Generate HTML snippet
      const htmlSnippet = `<link rel="apple-touch-icon" sizes="180x180" href="/apple-touch-icon.png">
<link rel="icon" type="image/png" sizes="32x32" href="/favicon-32x32.png">
<link rel="icon" type="image/png" sizes="16x16" href="/favicon-16x16.png">
<link rel="manifest" href="/site.webmanifest">`;
      zip.file('instructions.html', htmlSnippet);

      const content = await zip.generateAsync({type: "blob"});
      const url = URL.createObjectURL(content);
      const a = document.createElement('a');
      a.href = url;
      a.download = "favicon_package.zip";
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      URL.revokeObjectURL(url);
    } catch (e) {
      console.error(e);
    } finally {
      isGenerating = false;
    }
  }

</script>

<svelte:head>
  <link href="https://fonts.googleapis.com/css2?family=Bangers&family=Inter:wght@700&family=Lobster&family=Montserrat:wght@700&family=Pacifico&family=Playfair+Display:wght@700&family=Roboto:wght@700&display=swap" rel="stylesheet">
</svelte:head>

<SplitWorkspace {tool}>
  {#snippet headerLeftControls()}
    <div class="border-gray-200 dark:border-gray-800 flex items-center">
      <SegmentedControl bind:value={storage.value.mode} options={modeOptions} class="shadow-sm" />
    </div>
  {/snippet}

  {#snippet leftPanel()}
    <div class="flex flex-col h-full bg-slate-50/50 dark:bg-slate-900/40 border-r border-gray-200 dark:border-gray-800 overflow-y-auto custom-scrollbar">
      
      <div class="p-4 space-y-6 flex-1">
        
        <!-- Input Settings -->
        <div class="flex flex-col gap-4 bg-white dark:bg-gray-800/50 p-4 rounded-xl border border-gray-200 dark:border-gray-700 shadow-sm">
          {#if storage.value.mode === 'text'}
            <div class="grid grid-cols-2 gap-4">
              <div class="space-y-1.5">
                <label class="text-xs font-semibold text-gray-700 dark:text-gray-300">{i18n.t('tools.faviconGenerator.textToDisplay')}</label>
                <input type="text" bind:value={storage.value.text} maxlength="2" class="w-full bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-md px-3 py-2 text-sm font-medium focus:ring-2 focus:ring-blue-500 outline-none uppercase text-center tracking-widest transition-all" />
              </div>
              
              <div class="space-y-1.5">
                <label class="text-xs font-semibold text-gray-700 dark:text-gray-300">{i18n.t('tools.faviconGenerator.fontFamily')}</label>
                <select bind:value={storage.value.fontFamily} aria-label={i18n.t('tools.faviconGenerator.fontFamily')} class="w-full bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-md px-3 py-2 text-sm focus:ring-2 focus:ring-blue-500 outline-none">
                  {#each fontFamilies as font (font.value)}
                    <option value={font.value}>{font.label}</option>
                  {/each}
                </select>
              </div>
            </div>
            
            <div class="space-y-1.5">
              <label class="text-xs font-semibold text-gray-700 dark:text-gray-300">{i18n.t('tools.faviconGenerator.textColor')}</label>
              <div class="flex items-center gap-2">
                <input type="color" bind:value={storage.value.textColor} class="w-8 h-8 rounded border border-gray-200 dark:border-gray-700 cursor-pointer p-0.5 bg-white dark:bg-gray-800" />
                <input type="text" bind:value={storage.value.textColor} class="flex-1 bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-md px-3 py-1.5 text-sm font-mono focus:ring-2 focus:ring-blue-500 outline-none uppercase" />
              </div>
            </div>

          {:else if storage.value.mode === 'emoji'}
            <div class="space-y-1.5">
              <label class="text-xs font-semibold text-gray-700 dark:text-gray-300">{i18n.t('common.options.emoji') || 'Emoji'}</label>
              <input type="text" bind:value={storage.value.emoji} class="w-full bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-md px-3 py-4 text-3xl text-center focus:ring-2 focus:ring-blue-500 outline-none transition-all" placeholder="🚀" />
            </div>
          
          {:else if storage.value.mode === 'image'}
            <div class="space-y-1.5">
              <label class="text-xs font-semibold text-gray-700 dark:text-gray-300">{i18n.t('tools.faviconGenerator.uploadImage')}</label>
              <!-- svelte-ignore a11y_click_events_have_key_events -->
              <!-- svelte-ignore a11y_no_static_element_interactions -->
              <div 
                class="border-2 border-dashed border-gray-300 dark:border-gray-600 rounded-lg p-6 flex flex-col items-center justify-center gap-2 cursor-pointer hover:bg-gray-50 dark:hover:bg-gray-800/50 transition-colors text-center"
                onclick={() => fileInput.click()}
              >
                <Upload class="w-6 h-6 text-gray-400" />
                <span class="text-xs text-gray-500">{i18n.t('tools.faviconGenerator.dropImage')}</span>
              </div>
              <input type="file" bind:this={fileInput} onchange={handleImageUpload} accept="image/png, image/jpeg, image/svg+xml" class="hidden" />
              
              {#if storage.value.image}
                <div class="mt-4 p-2 border border-gray-200 dark:border-gray-700 rounded-lg flex items-center justify-center bg-gray-50 dark:bg-gray-900/50">
                  <img src={storage.value.image} alt="Uploaded" class="max-h-20 max-w-full object-contain" />
                </div>
              {/if}
            </div>
          {/if}
        </div>

        <!-- Global Settings -->
        <div class="flex flex-col gap-4 bg-white dark:bg-gray-800/50 p-4 rounded-xl border border-gray-200 dark:border-gray-700 shadow-sm">
          <div class="space-y-1.5">
            <label class="text-xs font-semibold text-gray-700 dark:text-gray-300">{i18n.t('tools.faviconGenerator.backgroundColor')}</label>
            <div class="flex items-center gap-2">
              <input type="color" bind:value={storage.value.bgColor} class="w-8 h-8 rounded border border-gray-200 dark:border-gray-700 cursor-pointer p-0.5 bg-white dark:bg-gray-800" />
              <input type="text" bind:value={storage.value.bgColor} class="flex-1 bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-md px-3 py-1.5 text-sm font-mono focus:ring-2 focus:ring-blue-500 outline-none uppercase" />
            </div>
          </div>

          <div class="space-y-1.5">
            <label class="text-xs font-semibold text-gray-700 dark:text-gray-300">{i18n.t('tools.faviconGenerator.shape')}</label>
            <div class="flex bg-gray-100 dark:bg-gray-800 p-1 rounded-lg">
              <button onclick={() => storage.value.shape = 'square'} class="flex-1 flex justify-center py-1.5 rounded-md transition-colors {storage.value.shape === 'square' ? 'bg-white dark:bg-gray-700 text-blue-600 shadow-sm' : 'text-gray-500 hover:text-gray-700'}">
                <Square class="w-4 h-4" />
              </button>
              <button onclick={() => storage.value.shape = 'rounded'} class="flex-1 flex justify-center py-1.5 rounded-md transition-colors {storage.value.shape === 'rounded' ? 'bg-white dark:bg-gray-700 text-blue-600 shadow-sm' : 'text-gray-500 hover:text-gray-700'}">
                <AppWindow class="w-4 h-4" />
              </button>
              <button onclick={() => storage.value.shape = 'circle'} class="flex-1 flex justify-center py-1.5 rounded-md transition-colors {storage.value.shape === 'circle' ? 'bg-white dark:bg-gray-700 text-blue-600 shadow-sm' : 'text-gray-500 hover:text-gray-700'}">
                <Circle class="w-4 h-4" />
              </button>
            </div>
          </div>

          <div class="space-y-1.5">
            <div class="flex justify-between">
              <label class="text-xs font-semibold text-gray-700 dark:text-gray-300">{i18n.t('common.form.padding') || 'Padding'}</label>
              <span class="text-xs text-gray-500">{storage.value.padding}%</span>
            </div>
            <input type="range" bind:value={storage.value.padding} min="0" max="40" class="w-full accent-blue-600" />
          </div>

          <div class="space-y-1.5">
            <div class="flex justify-between">
              <label class="text-xs font-semibold text-gray-700 dark:text-gray-300">{i18n.t('common.form.fontSize') || 'Font Size'}</label>
              <span class="text-xs text-gray-500">{storage.value.fontSize}%</span>
            </div>
            <input type="range" bind:value={storage.value.fontSize} min="20" max="150" class="w-full accent-blue-600" />
          </div>

        </div>

      </div>
    </div>
  {/snippet}

  {#snippet rightPanel()}
    <div class="flex-1 flex flex-col h-full bg-white dark:bg-gray-900 overflow-hidden relative p-6 gap-6">
      
      <!-- Hidden canvas for rendering -->
      <canvas bind:this={previewCanvas} class="hidden"></canvas>

      <!-- Browser Tab Mockup -->
      <div class="w-full bg-[#dee1e6] dark:bg-[#1e1e1e] rounded-t-xl pt-2 px-3 flex items-end shadow-sm gap-3">
        <!-- macOS buttons -->
        <div class="flex items-center gap-1.5 pb-2.5 px-1">
          <div class="w-3 h-3 rounded-full bg-[#ff5f56] border border-black/10 dark:border-white/10"></div>
          <div class="w-3 h-3 rounded-full bg-[#ffbd2e] border border-black/10 dark:border-white/10"></div>
          <div class="w-3 h-3 rounded-full bg-[#27c93f] border border-black/10 dark:border-white/10"></div>
        </div>
        
        <!-- Tab -->
        <div class="bg-white dark:bg-[#2b2b2b] rounded-t-lg px-4 py-2 flex items-center gap-2 max-w-[240px] w-full border-b-0 relative z-10 shadow-[0_-1px_2px_rgba(0,0,0,0.05)] dark:shadow-[0_-1px_2px_rgba(0,0,0,0.2)]">
          {#if previewDataUrl}
            <img src={previewDataUrl} alt="Favicon" class="w-4 h-4 rounded-sm" />
          {:else}
            <div class="w-4 h-4 bg-gray-200 dark:bg-gray-700 rounded-sm"></div>
          {/if}
          <span class="text-xs text-gray-800 dark:text-gray-200 font-medium truncate">DeboxHub is awesome</span>
        </div>
        
        <!-- Plus Button Mockup -->
        <div class="pb-2 pl-1 opacity-50 hover:opacity-100 transition-opacity">
           <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" class="text-gray-600 dark:text-gray-400"><path d="M5 12h14"/><path d="M12 5v14"/></svg>
        </div>
      </div>

      <!-- Main Large Preview -->
      <div class="flex-1 flex items-center justify-center border border-gray-200 dark:border-gray-800 rounded-xl bg-[repeating-conic-gradient(#e5e7eb_0%_25%,_#fff_0%_50%)] bg-[length:16px_16px] dark:bg-[repeating-conic-gradient(#1f2937_0%_25%,_#111827_0%_50%)] shadow-inner p-8">
        {#if previewDataUrl}
          <img src={previewDataUrl} alt="Large Preview" class="w-64 h-64 object-contain shadow-2xl rounded-2xl transition-all" />
        {/if}
      </div>

      <!-- Footer Action & Sizes Preview -->
      <div class="flex items-center justify-between bg-gray-50 dark:bg-gray-800/50 border border-gray-200 dark:border-gray-800 rounded-xl p-4 shadow-sm">
        <div class="flex flex-col gap-1">
          <span class="text-xs font-semibold text-gray-500 dark:text-gray-400">{i18n.t('tools.faviconGenerator.previewSizes')}</span>
          <div class="flex items-end gap-3">
            {#if previewDataUrl}
              <div class="flex flex-col items-center gap-1"><img src={previewDataUrl} class="w-16 h-16 rounded-lg shadow" alt="64"/><span class="text-[10px] text-gray-400">64x</span></div>
              <div class="flex flex-col items-center gap-1"><img src={previewDataUrl} class="w-8 h-8 rounded-md shadow" alt="32"/><span class="text-[10px] text-gray-400">32x</span></div>
              <div class="flex flex-col items-center gap-1"><img src={previewDataUrl} class="w-4 h-4 rounded-sm shadow" alt="16"/><span class="text-[10px] text-gray-400">16x</span></div>
            {/if}
          </div>
        </div>
        
        <button 
          onclick={downloadZip}
          disabled={isGenerating}
          class="flex items-center gap-2 bg-blue-600 hover:bg-blue-700 text-white font-medium px-5 py-2.5 rounded-lg shadow-md transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
        >
          {#if isGenerating}
            <RefreshCw class="w-4 h-4 animate-spin" />
            Generating...
          {:else}
            <DownloadCloud class="w-4 h-4" />
            {i18n.t('common.action.download') || 'Download'}
          {/if}
        </button>
      </div>

    </div>
  {/snippet}

</SplitWorkspace>

