import { browser } from '$app/environment';
import { CONFIG_PREFIX } from '$lib/constants';

const STORAGE_KEY = `${CONFIG_PREFIX}:favorites`;

function createFavoritesStore() {
    // Initialize state
    let items = $state<string[]>([]);

    // Load from localStorage when initializing
    if (browser) {
        const saved = localStorage.getItem(STORAGE_KEY);
        if (saved) {
            try {
                items = JSON.parse(saved);
            } catch (e) {
                console.error('Failed to parse favorites', e);
            }
        }
    }

    // Every time items changes, automatically save to localStorage
    $effect.root(() => {
        $effect(() => {
            if (browser) {
                localStorage.setItem(STORAGE_KEY, JSON.stringify(items));
            }
        });
    });

    return {
        get items() { return items; },
        
        toggle: (id: string) => {
            if (items.includes(id)) {
                items = items.filter(i => i !== id);
            } else {
                items = [...items, id];
            }
        },

        has: (id: string) => {
            return items.includes(id);
        },

        clear: () => {
            items = [];
        },

        reorder: (newItems: string[]) => {
            items = newItems;
        }
    };
}

export const favoritesStore = createFavoritesStore();
