export function downloadFile(content: string | Blob, filename: string, mimeType = 'text/plain') {
  let blob: Blob;
  if (content instanceof Blob) {
    blob = content;
  } else {
    blob = new Blob([content], { type: mimeType });
  }
  
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = filename;
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  URL.revokeObjectURL(url);
}

export function generateDownloadFilename(toolId: string, extension: string = 'txt') {
  // Format: deboxhub-{toolId-prefix-removed}-YYYYMMDD-HHMMSS.txt
  const date = new Date();
  const yyyy = date.getFullYear();
  const MM = String(date.getMonth() + 1).padStart(2, '0');
  const dd = String(date.getDate()).padStart(2, '0');
  const hh = String(date.getHours()).padStart(2, '0');
  const mm = String(date.getMinutes()).padStart(2, '0');
  const ss = String(date.getSeconds()).padStart(2, '0');

  const timestamp = `${yyyy}${MM}${dd}-${hh}${mm}${ss}`;
  const cleanToolId = toolId.replace(/^tool-/, '');
  
  return `deboxhub-${cleanToolId}-${timestamp}.${extension}`;
}
