<script lang="ts">
  import { resolve } from '$app/paths';
  import { i18n } from '$lib/i18n';
  import { getStructuredCategories } from '$lib/registry';
  import { portal } from '$lib/actions/portal';
  import { X } from 'lucide-svelte/icons';
  import { TOOL_ICON_MAP, FallbackIcon } from '$lib/registry';
	import { Separator } from '..';
  
  interface ToolsExplorerProps {
    isOpen?: boolean;
  }
  
  let { isOpen = $bindable(false) }: ToolsExplorerProps = $props();

  // Mapping tools to categories and sort by order
  let structuredTools = $derived(getStructuredCategories());

  // Keyboard ESC to close menu
  function handleKeydown(e: KeyboardEvent) {
    if (e.key === 'Escape' && isOpen) isOpen = false;
  }
</script>

<svelte:window onkeydown={handleKeydown} />

{#if isOpen}
  <div use:portal>
    <div 
      class="fixed inset-0 z-[100] bg-gray-900/30 dark:bg-gray-900/60 backdrop-blur-md transition-opacity" 
      onclick={() => isOpen = false}
    ></div>

    <div class="fixed inset-0 z-[100] flex items-start justify-center pt-16 px-4 pb-4 pointer-events-none sm:pt-24">
      <div class="bg-white/95 dark:bg-gray-900/95 backdrop-blur-xl w-full max-w-5xl max-h-[80vh] rounded-3xl shadow-2xl border border-gray-200/50 dark:border-gray-700/50 flex flex-col pointer-events-auto overflow-hidden animate-in fade-in zoom-in-95 duration-200">
        
        <div class="flex items-center justify-between px-8 py-5 border-b border-gray-100/50 dark:border-gray-800/50">
          <h2 class="text-xl font-bold tracking-tight text-gray-900 dark:text-gray-100">{i18n.t('common.ui.launcher') || 'App Launcher'}</h2>
          <button
            onclick={() => isOpen = false}
            class="p-2 text-gray-400 hover:text-gray-900 hover:bg-gray-100 dark:hover:bg-gray-800 dark:hover:text-gray-100 rounded-xl transition-all"
          >
            <X class="w-5 h-5" />
          </button>
        </div>

        <div class="p-8 overflow-y-auto custom-scrollbar">
          <div class="flex flex-col gap-10">
              
              {#each structuredTools as category (category.id)}
              <div>
                  <h3 class="text-xs font-bold text-gray-400 dark:text-gray-500 uppercase tracking-wider mb-5 flex items-center gap-3">
                    {i18n.t(category.name)}
                    <Separator variant="gradient" />
                  </h3>

                  <div class="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 gap-4">
                  {#each category.tools as tool (tool.id)}
                      {@const Icon = TOOL_ICON_MAP[tool.icon || ''] || FallbackIcon}
                      <a 
                        href={resolve(`/${tool.slug}`)}
                        onclick={() => isOpen = false}
                        class="flex flex-col items-center justify-center p-4 gap-3 bg-gray-50/50 dark:bg-gray-800/30 hover:bg-white dark:hover:bg-gray-800 border border-gray-100/80 dark:border-gray-700/50 hover:border-blue-200 dark:hover:border-blue-700 rounded-2xl hover:shadow-lg transition-all duration-200 group"
                      >
                        <div class="p-3.5 bg-white dark:bg-gray-900 border border-gray-100 dark:border-gray-700 group-hover:border-blue-200 dark:group-hover:border-blue-700/50 rounded-xl group-hover:scale-110 transition-all duration-300 shadow-sm">
                          <Icon class="w-6 h-6 text-gray-500 dark:text-gray-400 group-hover:text-blue-600 dark:group-hover:text-blue-400 transition-colors" />
                        </div>
                        <span class="text-[13px] font-bold text-gray-700 dark:text-gray-300 group-hover:text-blue-700 dark:group-hover:text-blue-400 text-center px-1 transition-colors">
                          {i18n.t(tool.name)}
                        </span>
                      </a>
                  {/each}
                  </div>
              </div>
              {/each}

          </div>
        </div>
      </div>
    </div>
  </div>
{/if}