<script lang="ts">
  import { i18n } from '$lib/i18n';
  import SplitWorkspace from './SplitWorkspace.svelte';
  import { copyText } from '$lib/utils/clipboard';
  import { createTool } from '$lib/stores';
  import { smartInputState } from '$lib/utils/smartInput';
  import { onMount } from 'svelte';
  import { fade } from 'svelte/transition';

  import { SegmentedControl, MonacoEditor, Separator, ButtonIcon } from '$lib/components/ui';
  import { Copy, Trash2, Download, Code2, Play, Lock, Unlock, FileCode2, Command, WrapText } from 'lucide-svelte';
  import { downloadFile, generateDownloadFilename } from '$lib/utils/file';

  import type { ToolDefinition } from '$lib/types';

  type EditorMode = {
    value: string;
    label: string;
    type: 'code' | 'preview'; // For Layout known to set Monaco or Iframe
    icon?: unknown;
  };

  interface FormatterProps {
    tool: ToolDefinition;
    sampleCode?: string;
    language?: string;
    modes: EditorMode[];
    extraControls?: import('svelte').Snippet<[string]>;
    processFn: (input: string, mode: string) => string;
  }

  let {
    tool,
    sampleCode = '',
    language = 'html',
    modes = [],
    extraControls,
    processFn
  }: FormatterProps = $props();

  let wordWrapLeft = $state(true);
  let wordWrapRight = $state(true);

  let isFullFrame = $state(false);

  let previewBg = $state<'white' | 'black' | 'checkered'>('white');
  let outputMode = $state(modes[0]?.value || 'preview');
  let currentModeObj = $derived(modes.find(m => m.value === outputMode));

  const storage = createTool(tool.slug, {
    input: sampleCode
  });

  onMount(() => {
    const passedData = smartInputState.consume();
    if (passedData) {
      storage.value.input = passedData;
    }
  });

  let debounceTimer: ReturnType<typeof setTimeout>;
  let isRealtimeMode = $state(true);
  let appliedCode = $state(storage.value.input);

  let outputResult = $state('');
  let outputEditable = $state(false);

  $effect(() => {
    if (!appliedCode || !processFn) {
      outputResult = '';
      return;
    }
    try {
      outputResult = processFn(appliedCode, outputMode);
    } catch {
      outputResult = '';
    }
  });

  $effect(() => {
    const currentInput = storage.value.input;

    if (isRealtimeMode) {
      clearTimeout(debounceTimer);
      debounceTimer = setTimeout(() => {
        appliedCode = currentInput;
      }, 1000);
    }
  });

  // Utility functions
  function handleApply() {
    appliedCode = storage.value.input;
  }

  function downloadCode() {
    downloadFile(outputResult, generateDownloadFilename(tool.id, language));
  }

  function clearText() {
    storage.value.input = '';
    if (isRealtimeMode) appliedCode = '';
  }

  function loadSample() {
    if (sampleCode) {
      storage.value.input = sampleCode;
      if (isRealtimeMode) appliedCode = sampleCode;
    }
  }
</script>

<SplitWorkspace {tool} bind:isFullFrame>
  {#snippet headerLeftControls()}
    <SegmentedControl bind:value={outputMode} options={modes} class="bg-gray-100 dark:bg-gray-900/80 shadow-sm" />

    {#if extraControls}
      {@render extraControls(outputMode)}
    {/if}

    <Separator orientation="vertical" size="4" class="hidden sm:block -ml-px" />

    <label class="flex items-center gap-2 text-sm font-medium text-gray-600 dark:text-gray-400 cursor-pointer group">
      <input 
        type="checkbox" 
        bind:checked={isRealtimeMode}
        class="w-4 h-4 rounded border-gray-300 text-blue-600 focus:ring-blue-500 dark:border-gray-600 dark:bg-gray-800 transition-colors cursor-pointer"
      />
      <span class="group-hover:text-gray-900 dark:group-hover:text-white transition-colors">
        {i18n.t('common.editor.realtimeMode') || 'Real-time Mode'}
      </span>
    </label>

    <button 
      onclick={handleApply}
      disabled={isRealtimeMode || !storage.value.input}
      class="flex items-center gap-1.5 px-3 py-1.5 text-sm font-semibold text-white bg-blue-600 rounded-md hover:bg-blue-700 shadow-sm transition-all focus:ring-2 focus:ring-blue-500 focus:ring-offset-2 dark:focus:ring-offset-gray-950 active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed"
    >
      <Play class="w-4 h-4 fill-current" /> <span class="hidden sm:inline">{i18n.t('common.action.apply') || 'Apply'}</span>
    </button>
  {/snippet}

  {#snippet headerRightControls()}
    {#if sampleCode}
      <button 
        onclick={loadSample}
        class="flex items-center gap-1.5 px-3 py-1.5 text-sm font-medium text-gray-700 dark:text-gray-300 hover:text-blue-600 dark:hover:text-blue-400 bg-white dark:bg-gray-900 rounded-md border border-gray-200 dark:border-gray-800 hover:border-blue-300 dark:hover:border-blue-800 shadow-sm transition-all"
        title={i18n.t('common.loadSample') || 'Load Sample'}
      >
        <FileCode2 class="w-4 h-4" /> <span class="hidden sm:inline">{i18n.t('common.editor.sample') || 'Sample'}</span>
      </button>
    {/if}
  {/snippet}

  {#snippet leftPanel()}
    <div class="flex items-center justify-between px-4 py-2 bg-gray-50 dark:bg-gray-900 border-b border-gray-200 dark:border-gray-800 h-11">
      <div class="flex items-center gap-3">
        <span class="flex items-center gap-1.5 text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider">
          <Code2 class="w-3.5 h-3.5" /> {i18n.t('common.editor.sourceCode') || 'Source Code'}
        </span>
        
        <div class="hidden sm:flex items-center gap-1 px-2 py-0.5 text-[10px] font-semibold tracking-wider text-gray-500 bg-gray-100/50 dark:text-gray-400 dark:bg-gray-800/50 rounded border border-gray-200 dark:border-gray-700">
          <Command class="w-3 h-3" /> <span class="-mx-0.5">/</span> <span>Ctrl + F to find</span>
        </div>
      </div>
      <div class="flex items-center gap-1">
        <ButtonIcon onclick={() => wordWrapLeft = !wordWrapLeft} color="blue" active={wordWrapLeft} title={wordWrapLeft ? 'Disable Word Wrap' : 'Enable Word Wrap'}>
          <WrapText class="w-4 h-4" />
        </ButtonIcon>
        <ButtonIcon onclick={clearText} disabled={!storage.value.input} color="rose" title={i18n.t('common.action.clear') || 'Clear'}>
          <Trash2 class="w-4 h-4" />
        </ButtonIcon>
      </div>
    </div>
    <div class="flex-1 w-full relative">
      <MonacoEditor bind:value={storage.value.input} {language} wordWrap={wordWrapLeft} />
    </div>
  {/snippet}

  {#snippet rightPanel()}
    <div class="flex items-center justify-between px-4 py-2 bg-gray-50 dark:bg-gray-900 border-b border-gray-200 dark:border-gray-800 h-11">

      <div class="flex items-center gap-2 px-2">
        {#if currentModeObj?.type === 'preview'}
          <span class="flex items-center gap-1.5 text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider">
            <Play class="w-3.5 h-3.5" /> {i18n.t('common.editor.livePreview') || 'Live Preview'}
          </span>
        {:else}
          <button 
            onclick={() => outputEditable = !outputEditable}
            class="flex items-center gap-1 px-2 py-0.5 text-[10px] font-bold uppercase tracking-widest rounded border transition-colors
              {outputEditable 
                ? 'text-green-600 bg-green-50 border-green-200 dark:text-green-400 dark:bg-green-900/20 dark:border-green-900/50 hover:bg-green-100 dark:hover:bg-green-900/40' 
                : 'text-amber-600 bg-amber-50 border-amber-200 dark:text-amber-400 dark:bg-amber-900/20 dark:border-amber-900/50 hover:bg-amber-100 dark:hover:bg-amber-900/40'}"
            title={outputEditable ? 'Click to make read-only' : 'Click to enable editing'}
          >
            {#if outputEditable}
              <Unlock class="w-3 h-3" /> {i18n.t('common.editor.editable') || 'Editable'}
            {:else}
              <Lock class="w-3 h-3" /> {i18n.t('common.editor.readOnly') || 'Read-only'}
            {/if}
          </button>
          
          {#if outputEditable}
          <div transition:fade={{ duration: 150 }} class="hidden sm:flex items-center gap-1 px-2 py-0.5 text-[10px] font-semibold tracking-wider text-gray-500 bg-gray-100/50 dark:text-gray-400 dark:bg-gray-800/50 rounded border border-gray-200 dark:border-gray-700">
            <Command class="w-3 h-3" /> <span class="-mx-0.5">/</span> <span>Ctrl + F to find</span>
          </div>
          {/if}
        {/if}
      </div>
      
      <div class="flex items-center gap-1">
        {#if currentModeObj?.type === 'preview'}
          <div class="flex items-center gap-1.5 mr-2">
            <button class="w-4 h-4 rounded-full border border-gray-300 shadow-sm hover:scale-110 {previewBg === 'white' ? 'ring-2 ring-blue-500 ring-offset-1 dark:ring-offset-gray-900' : ''}" style="background: white;" onclick={() => previewBg = 'white'}></button>
            <button class="w-4 h-4 rounded-full border border-gray-600 shadow-sm hover:scale-110 {previewBg === 'black' ? 'ring-2 ring-blue-500 ring-offset-1 dark:ring-offset-gray-900' : ''}" style="background: black;" onclick={() => previewBg = 'black'}></button>
            <button class="w-4 h-4 rounded-full border border-gray-300 shadow-sm hover:scale-110 {previewBg === 'checkered' ? 'ring-2 ring-blue-500 ring-offset-1 dark:ring-offset-gray-900' : ''}" style="background: repeating-conic-gradient(#e5e7eb 0% 25%, #fff 0% 50%) 50% / 12px 12px;" onclick={() => previewBg = 'checkered'}></button>
          </div>
          <div class="w-px h-4 bg-gray-300 dark:bg-gray-700 mx-1"></div>
        {/if}
        {#if currentModeObj?.type !== 'preview'}
          <ButtonIcon onclick={() => wordWrapRight = !wordWrapRight} color="blue" active={wordWrapRight} title={wordWrapRight ? 'Disable Word Wrap' : 'Enable Word Wrap'}>
            <WrapText class="w-4 h-4" />
          </ButtonIcon>
        {/if}
        <ButtonIcon onclick={downloadCode} disabled={!outputResult} color="green" title={i18n.t('common.action.download') || 'Download'}>
          <Download class="w-4 h-4" />
        </ButtonIcon>
        <ButtonIcon onclick={() => copyText(outputResult)} disabled={!outputResult} color="blue" title={i18n.t('common.action.copy') || 'Copy'}>
          <Copy class="w-4 h-4" />
        </ButtonIcon>
      </div>

    </div>
    
    <div class="flex-1 w-full relative">
      {#if currentModeObj?.type === 'preview'}
        <div class="absolute inset-0 transition-colors duration-200 {previewBg === 'white' ? 'bg-white' : previewBg === 'black' ? 'bg-black' : 'bg-[repeating-conic-gradient(#e5e7eb_0%_25%,_#fff_0%_50%)] bg-[length:16px_16px]'}">
          <iframe title={i18n.t('common.editor.livePreview')} srcdoc={outputResult} class="w-full h-full border-0" sandbox="allow-scripts"></iframe>
        </div>
      {:else}
        <MonacoEditor bind:value={outputResult} {language} readOnly={!outputEditable} wordWrap={wordWrapRight} />
      {/if}
    </div>
  {/snippet}
</SplitWorkspace>