import { browser } from '$app/environment';

import { APP_CONFIG } from '$lib/constants';

export function createTool<T>(toolKey: string, initialValue: T) {
	const key = APP_CONFIG.storageKeys.getToolKey(toolKey);

	// Initialize state
	let state = $state<T>(initialValue);

	// Hydration: Get data from localStorage to state (only run at Client)
	if (browser) {
		try {
			const stored = window.localStorage.getItem(key);
			if (stored) {
				state = JSON.parse(stored);
			}
		} catch (e) {
			console.error(`[Debox] Failed to parse storage for tool: ${toolKey}`, e);
			// Fallback to initialValue if JSON is corrupted
			window.localStorage.removeItem(key);
		}
	}

	// Reactive Sync: Automatically listen to state changes and write to localStorage
	$effect.root(() => {
		$effect(() => {
			if (browser) {
				window.localStorage.setItem(key, JSON.stringify(state));
			}
		});
		return () => {};
	});

	return {
		get value() {
			return state;
		},
		set value(v: T) {
			state = v;
		},
		reset() {
			state = initialValue;
		}
	};
}
