import { toastStore } from '$lib/stores/ui/toast.svelte';
import { i18n } from '$lib/i18n';

/**
 * Copy text to clipboard safely.
 * Returns true if successful, false if failed.
 */
export async function copyText(text: string): Promise<boolean> {
    if (!text || text.startsWith(i18n.t('error.label'))) return false;
    
    try {
        await navigator.clipboard.writeText(text);
        toastStore.success(i18n.t('success.copy'));
        return true;
    } catch (err) {
        toastStore.error(i18n.t('error.copy') + ' ' + i18n.t('error.label') + `: ${err}`);
        return false;
    }
}