<script lang="ts">
	import { fade, scale } from 'svelte/transition';
	import { quintOut } from 'svelte/easing';
	import { X } from 'lucide-svelte';
	import type { Snippet } from 'svelte';
	import { ButtonIcon } from '$lib/components/ui';

	export interface ModalProps {
		isOpen: boolean;
		title?: string;
		description?: string;
		maxWidth?: 'max-w-sm' | 'max-w-md' | 'max-w-lg' | 'max-w-xl' | 'max-w-2xl' | 'max-w-3xl';
		closeOnOutsideClick?: boolean;
		closeOnEscape?: boolean;
		header?: Snippet;
		footer?: Snippet;
		children: Snippet;
	}

	let {
		isOpen = $bindable(false),
		title,
		description,
		maxWidth = 'max-w-md',
		closeOnOutsideClick = true,
		closeOnEscape = true,
		header,
		footer,
		children
	}: ModalProps = $props();

	function handleKeydown(event: KeyboardEvent) {
		if (isOpen && closeOnEscape && event.key === 'Escape') {
			isOpen = false;
		}
	}

	function handleOutsideClick(event: MouseEvent) {
		if (isOpen && closeOnOutsideClick && event.target === event.currentTarget) {
			isOpen = false;
		}
	}

	function close() {
		isOpen = false;
	}

	// Prevent body scroll when modal is open
	$effect(() => {
		if (typeof window !== 'undefined') {
			if (isOpen) {
				document.body.style.overflow = 'hidden';
			} else {
				document.body.style.overflow = '';
			}
		}
		return () => {
			if (typeof window !== 'undefined') document.body.style.overflow = '';
		};
	});
</script>

<svelte:window onkeydown={handleKeydown} />

{#if isOpen}
	<!-- Backdrop -->
	<!-- svelte-ignore a11y_no_static_element_interactions -->
	<!-- svelte-ignore a11y_click_events_have_key_events -->
	<div
		class="fixed inset-0 z-50 flex items-center justify-center bg-gray-900/40 p-4 backdrop-blur-sm sm:p-6"
		transition:fade={{ duration: 200 }}
		onclick={handleOutsideClick}
	>
		<!-- Dialog -->
		<div
			class="relative flex w-full flex-col overflow-hidden rounded-2xl bg-white shadow-2xl dark:bg-[#1a1a1a] dark:border dark:border-gray-800 {maxWidth}"
			transition:scale={{ duration: 300, start: 0.95, easing: quintOut }}
			onclick={(e) => e.stopPropagation()}
		>
			<!-- Header -->
			<div class="flex items-center justify-between border-b border-gray-100 px-6 py-4 dark:border-gray-800/60">
				{#if header}
					{@render header()}
				{:else}
					<div class="flex flex-col gap-1">
						{#if title}
							<h3 class="text-lg font-semibold text-gray-900 dark:text-gray-100">{title}</h3>
						{/if}
						{#if description}
							<p class="text-sm text-gray-500 dark:text-gray-400">{description}</p>
						{/if}
					</div>
				{/if}

				<!-- Close Button -->
				<div class="-mr-2 -mt-2 ml-4 self-start">
					<ButtonIcon onclick={close} color="gray" title="Close" class="!p-1.5 hover:bg-gray-100 dark:hover:bg-gray-800">
						<X class="h-4 w-4" />
					</ButtonIcon>
				</div>
			</div>

			<!-- Body -->
			<div class="px-6 py-5 overflow-y-auto max-h-[calc(100vh-200px)] custom-scrollbar">
				{@render children()}
			</div>

			<!-- Footer -->
			{#if footer}
				<div class="flex items-center justify-end gap-3 border-t border-gray-100 bg-gray-50/50 px-6 py-4 dark:border-gray-800/60 dark:bg-gray-900/20">
					{@render footer()}
				</div>
			{/if}
		</div>
	</div>
{/if}
