<script lang="ts">
  import { i18n } from '$lib/i18n';
  import SplitWorkspace from '$lib/components/layout/templates/SplitWorkspace.svelte';
  import { SegmentedControl, Separator } from '$lib/components/ui';
  import { Copy, Trash2, MonitorPlay, MousePointerClick, Shuffle, Hash } from 'lucide-svelte';
  import { copyText } from '$lib/utils/clipboard';
  import { createTool } from '$lib/stores';
  import type { ToolDefinition } from '$lib/types';

  export interface GradientGeneratorProps {
    tool: ToolDefinition;
  }

  let { tool }: GradientGeneratorProps = $props();

  let isFullFrame = $state(false);

  const typeOptions = [
    { value: 'linear', label: i18n.t('tools.gradientGenerator.linear') },
    { value: 'radial', label: i18n.t('tools.gradientGenerator.radial') }
  ];

  const GRADIENT_SAMPLES = [
    { name: 'Sunset', type: 'linear', angle: 45, stops: [{color:'#ff7b00', opacity:100, position:0, id:1},{color:'#ff0084', opacity:100, position:100, id:2}] },
    { name: 'Ocean', type: 'linear', angle: 90, stops: [{color:'#00c6ff', opacity:100, position:0, id:1},{color:'#0072ff', opacity:100, position:100, id:2}] },
    { name: 'Cyberpunk', type: 'linear', angle: 135, stops: [{color:'#f80ce2', opacity:100, position:0, id:1},{color:'#05d5ff', opacity:100, position:100, id:2}] },
    { name: 'Forest', type: 'linear', angle: 180, stops: [{color:'#5a3f37', opacity:100, position:0, id:1},{color:'#2c7744', opacity:100, position:100, id:2}] },
    { name: 'Mango', type: 'linear', angle: 45, stops: [{color:'#ffe259', opacity:100, position:0, id:1},{color:'#ffa751', opacity:100, position:100, id:2}] },
    { name: 'Amethyst', type: 'radial', angle: 90, stops: [{color:'#9d50bb', opacity:100, position:0, id:1},{color:'#6e48aa', opacity:100, position:100, id:2}] },
    { name: 'Cherry', type: 'linear', angle: 135, stops: [{color:'#eb3349', opacity:100, position:0, id:1},{color:'#f45c43', opacity:100, position:100, id:2}] },
    { name: 'Glass', type: 'linear', angle: 180, stops: [{color:'#ffffff', opacity:80, position:0, id:1},{color:'#ffffff', opacity:0, position:100, id:2}] },
  ];

  type ColorStop = { color: string; opacity: number; position: number; id: number };

  const storage = createTool(tool.slug, {
    type: 'linear' as 'linear' | 'radial',
    angle: 90,
    stops: [
      { color: '#3b82f6', opacity: 100, position: 0, id: 1 },
      { color: '#8b5cf6', opacity: 100, position: 100, id: 2 }
    ] as ColorStop[],
    nextId: 3,
    maxCompatibility: false
  });

  // Migration for old saves missing opacity
  $effect(() => {
    storage.value.stops.forEach(s => {
      if (s.opacity === undefined) s.opacity = 100;
    });
  });

  let activeId = $state(1);

  // Keep activeId valid
  $effect(() => {
    if (storage.value.stops.length > 0 && !storage.value.stops.find(s => s.id === activeId)) {
      activeId = storage.value.stops[0].id;
    }
  });

  let activeIndex = $derived(storage.value.stops.findIndex(s => s.id === activeId));

  function getRgb(hex: string) {
    if (!hex || hex.length < 7) return { r: 255, g: 255, b: 255 };
    return {
      r: parseInt(hex.slice(1, 3), 16) || 0,
      g: parseInt(hex.slice(3, 5), 16) || 0,
      b: parseInt(hex.slice(5, 7), 16) || 0
    };
  }

  function updateRgb(channel: 'r'|'g'|'b', value: number) {
    if (activeIndex === -1) return;
    const current = getRgb(storage.value.stops[activeIndex].color);
    current[channel] = Math.max(0, Math.min(255, isNaN(value) ? 0 : value));
    const rHex = current.r.toString(16).padStart(2, '0');
    const gHex = current.g.toString(16).padStart(2, '0');
    const bHex = current.b.toString(16).padStart(2, '0');
    storage.value.stops[activeIndex].color = `#${rHex}${gHex}${bHex}`;
  }

  function hexToRgbaStr(hex: string, opacity: number = 100) {
    if (!hex || hex.length < 7) return `rgba(255, 255, 255, ${opacity / 100})`;
    const r = parseInt(hex.slice(1, 3), 16) || 0;
    const g = parseInt(hex.slice(3, 5), 16) || 0;
    const b = parseInt(hex.slice(5, 7), 16) || 0;
    return `rgba(${r}, ${g}, ${b}, ${opacity / 100})`;
  }

  let trackCss = $derived.by(() => {
    const sortedStops = [...storage.value.stops].sort((a, b) => a.position - b.position);
    const stopsString = sortedStops.map(s => `${hexToRgbaStr(s.color, s.opacity)} ${s.position}%`).join(', ');
    return `linear-gradient(90deg, ${stopsString})`;
  });

  let gradientCss = $derived.by(() => {
    const sortedStops = [...storage.value.stops].sort((a, b) => a.position - b.position);
    const stopsString = sortedStops.map(s => `${hexToRgbaStr(s.color, s.opacity)} ${s.position}%`).join(', ');
    
    if (storage.value.type === 'linear') {
      return `linear-gradient(${storage.value.angle}deg, ${stopsString})`;
    } else {
      return `radial-gradient(circle, ${stopsString})`;
    }
  });

  let fullCssCode = $derived.by(() => {
    const sortedStops = [...storage.value.stops].sort((a, b) => a.position - b.position);
    const stopsString = sortedStops.map(s => `${hexToRgbaStr(s.color, s.opacity)} ${s.position}%`).join(', ');
    
    let baseGradient = '';
    let webkitGradient = '';
    let mozGradient = '';
    
    if (storage.value.type === 'linear') {
      baseGradient = `linear-gradient(${storage.value.angle}deg, ${stopsString})`;
      webkitGradient = `-webkit-linear-gradient(${storage.value.angle}deg, ${stopsString})`;
      mozGradient = `-moz-linear-gradient(${storage.value.angle}deg, ${stopsString})`;
    } else {
      baseGradient = `radial-gradient(circle, ${stopsString})`;
      webkitGradient = `-webkit-radial-gradient(circle, ${stopsString})`;
      mozGradient = `-moz-radial-gradient(circle, ${stopsString})`;
    }

    if (!storage.value.maxCompatibility) {
      return `background: ${baseGradient};`;
    }

    const fallbackColor = sortedStops[0]?.color || '#ffffff';
    let css = `background: ${fallbackColor}; /* Old browsers */\n`;
    css += `background: ${mozGradient}; /* FF3.6-15 */\n`;
    css += `background: ${webkitGradient}; /* Chrome10-25,Safari5.1-6 */\n`;
    css += `background: ${baseGradient}; /* W3C, IE10+, FF16+, Chrome26+, Opera12+, Safari7+ */`;

    if (storage.value.type === 'linear' && sortedStops.length >= 2) {
      const firstStop = sortedStops[0];
      const lastStop = sortedStops[sortedStops.length - 1];
      const isHorizontal = (storage.value.angle >= 45 && storage.value.angle <= 135) || (storage.value.angle >= 225 && storage.value.angle <= 315);
      const gradientType = isHorizontal ? 1 : 0;
      css += `\nfilter: progid:DXImageTransform.Microsoft.gradient( startColorstr='${firstStop.color}', endColorstr='${lastStop.color}',GradientType=${gradientType} ); /* IE6-9 */`;
    }

    return css;
  });

  function removeStop(id: number) {
    if (storage.value.stops.length > 2) {
      storage.value.stops = storage.value.stops.filter(s => s.id !== id);
    }
  }

  function randomize() {
    storage.value.stops = storage.value.stops.map(s => ({
      ...s,
      color: getRandomColor(),
      opacity: 100 // keep solid color for randomizing simplicity
    }));
    storage.value.angle = Math.floor(Math.random() * 360);
  }

  function getRandomColor() {
    const letters = '0123456789ABCDEF';
    let color = '#';
    for (let i = 0; i < 6; i++) {
      color += letters[Math.floor(Math.random() * 16)];
    }
    return color;
  }

  function applySample(sample: any) {
    storage.value.type = sample.type;
    storage.value.angle = sample.angle;
    storage.value.stops = JSON.parse(JSON.stringify(sample.stops));
    storage.value.nextId = Math.max(...sample.stops.map((s:any) => s.id)) + 1;
    activeId = storage.value.stops[0].id;
  }

  // --- Track Interaction ---
  let trackEl: HTMLElement;
  let draggingId: number | null = $state(null);

  function handleTrackPointerDown(e: PointerEvent) {
    if (e.target !== trackEl) return;
    const rect = trackEl.getBoundingClientRect();
    const x = Math.max(0, Math.min(e.clientX - rect.left, rect.width));
    const position = Math.round((x / rect.width) * 100);
    
    const newId = storage.value.nextId++;
    storage.value.stops.push({
      color: getRandomColor(),
      opacity: 100,
      position,
      id: newId
    });
    
    activeId = newId;
    draggingId = newId;
    trackEl.setPointerCapture(e.pointerId);
  }

  function handleThumbPointerDown(e: PointerEvent, id: number) {
    e.stopPropagation(); 
    activeId = id;
    draggingId = id;
    (e.currentTarget as HTMLElement).setPointerCapture(e.pointerId);
  }

  function onPointerMove(e: PointerEvent) {
    if (draggingId === null || !trackEl) return;
    const rect = trackEl.getBoundingClientRect();
    const x = Math.max(0, Math.min(e.clientX - rect.left, rect.width));
    const position = Math.round((x / rect.width) * 100);
    
    const index = storage.value.stops.findIndex(s => s.id === draggingId);
    if (index !== -1) {
      storage.value.stops[index].position = position;
    }
  }

  function onPointerUp(e: PointerEvent) {
    if (draggingId !== null) {
      if (trackEl) {
        const rect = trackEl.getBoundingClientRect();
        const distanceY = Math.abs(e.clientY - (rect.top + rect.height/2));
        if (distanceY > 50 && storage.value.stops.length > 2) {
          storage.value.stops = storage.value.stops.filter(s => s.id !== draggingId);
        }
      }
      
      const target = e.currentTarget as HTMLElement;
      if (target.hasPointerCapture(e.pointerId)) {
         target.releasePointerCapture(e.pointerId);
      }
      draggingId = null;
    }
  }

  // --- Angle Dial Interaction ---
  let dialEl: HTMLElement;
  let isDialDragging = $state(false);

  function handleDialPointerDown(e: PointerEvent) {
    isDialDragging = true;
    (e.currentTarget as HTMLElement).setPointerCapture(e.pointerId);
    updateAngleFromEvent(e);
  }

  function handleDialPointerMove(e: PointerEvent) {
    if (!isDialDragging) return;
    updateAngleFromEvent(e);
  }

  function handleDialPointerUp(e: PointerEvent) {
    if (!isDialDragging) return;
    isDialDragging = false;
    const target = e.currentTarget as HTMLElement;
    if (target.hasPointerCapture(e.pointerId)) {
       target.releasePointerCapture(e.pointerId);
    }
  }

  function updateAngleFromEvent(e: PointerEvent) {
    if (!dialEl) return;
    const rect = dialEl.getBoundingClientRect();
    const centerX = rect.left + rect.width / 2;
    const centerY = rect.top + rect.height / 2;
    const dx = e.clientX - centerX;
    const dy = e.clientY - centerY;
    let deg = (Math.atan2(dy, dx) * 180) / Math.PI + 90;
    if (deg < 0) deg += 360;
    storage.value.angle = Math.round(deg);
  }

</script>

<SplitWorkspace {tool} bind:isFullFrame>
  {#snippet headerLeftControls()}
    <div class="flex items-center gap-4 w-full">
      <SegmentedControl bind:value={storage.value.type} options={typeOptions} class="shrink-0 bg-gray-100 dark:bg-gray-900/80 shadow-sm" />
      
      <Separator orientation="vertical" size="6" />

      <!-- Samples horizontally scrollable in header -->
      <div class="flex items-center gap-2 overflow-x-auto custom-scrollbar pb-1 px-1 flex-1">
        {#each GRADIENT_SAMPLES as sample (sample.name)}
          <button 
            onclick={() => applySample(sample)}
            class="w-6 h-6 rounded-full border border-gray-300 dark:border-gray-600 shadow-sm hover:scale-110 hover:shadow-md transition-all shrink-0"
            style="background: {sample.type === 'linear' ? `linear-gradient(${sample.angle}deg, ${sample.stops.map(s => `${hexToRgbaStr(s.color, s.opacity)} ${s.position}%`).join(', ')})` : `radial-gradient(circle, ${sample.stops.map(s => `${hexToRgbaStr(s.color, s.opacity)} ${s.position}%`).join(', ')})`};"
            title={sample.name}
          ></button>
        {/each}
      </div>
    </div>
  {/snippet}

  {#snippet leftPanel()}
    <div class="flex flex-col h-full bg-slate-50/50 dark:bg-slate-900/40 overflow-y-auto custom-scrollbar p-5 space-y-6">
      
      <!-- 1. Interactive Track Section -->
      <div class="space-y-4">
        <div class="flex justify-between items-center">
          <label class="text-sm font-semibold text-gray-800 dark:text-gray-200 flex items-center gap-1.5">
            <MousePointerClick class="w-4 h-4 text-blue-500" />
            Gradient Track
          </label>
          <div class="flex items-center gap-3">
            <span class="text-xs text-gray-500 hidden sm:inline">Click track to add, drag down to delete</span>
            <button onclick={randomize} class="flex items-center gap-1.5 px-2.5 py-1.5 text-xs font-medium text-gray-700 dark:text-gray-300 bg-white dark:bg-gray-800 rounded-lg hover:bg-gray-100 dark:hover:bg-gray-700 transition-colors border border-gray-200 dark:border-gray-700 shadow-sm" title={i18n.t('tools.gradientGenerator.randomize')}>
              <Shuffle class="w-3.5 h-3.5" /> Random
            </button>
          </div>
        </div>
        
        <!-- Track Area -->
        <div class="relative h-12 px-2 flex items-center pt-2 pb-6">
          <div 
            bind:this={trackEl}
            onpointerdown={handleTrackPointerDown}
            onpointermove={onPointerMove}
            onpointerup={onPointerUp}
            onpointercancel={onPointerUp}
            class="w-full h-4 rounded border border-gray-300 dark:border-gray-600 shadow-inner cursor-pointer relative bg-[repeating-conic-gradient(#e5e7eb_0%_25%,_#fff_0%_50%)] bg-[length:16px_16px] dark:bg-[repeating-conic-gradient(#1f2937_0%_25%,_#111827_0%_50%)] touch-none"
          >
            <div class="absolute inset-0 rounded pointer-events-none" style="background: {trackCss};"></div>
            
            <!-- Thumbs -->
            {#each storage.value.stops as stop (stop.id)}
              <div
                onpointerdown={(e) => handleThumbPointerDown(e, stop.id)}
                onpointermove={onPointerMove}
                onpointerup={onPointerUp}
                onpointercancel={onPointerUp}
                class="absolute top-1/2 -translate-y-1/2 -translate-x-1/2 w-4 h-6 bg-white border-2 rounded-sm cursor-grab active:cursor-grabbing shadow-md z-10 touch-none transition-shadow {activeId === stop.id ? 'border-blue-500 ring-2 ring-blue-500/30 scale-110 z-20' : 'border-gray-300 dark:border-gray-500 hover:scale-110'}"
                style="left: {stop.position}%;"
              >
                <!-- Indicator triangle pointing down -->
                <div class="absolute -bottom-2 left-1/2 -translate-x-1/2 w-0 h-0 border-l-[4px] border-l-transparent border-r-[4px] border-r-transparent border-t-[4px] {activeId === stop.id ? 'border-t-blue-500' : 'border-t-gray-300 dark:border-t-gray-500'}"></div>
                <!-- Color fill -->
                <div class="w-full h-full rounded-[1px]" style="background-color: {stop.color}; opacity: {stop.opacity / 100};"></div>
              </div>
            {/each}
          </div>
        </div>

        <!-- Single Active Stop Controls -->
        {#if activeIndex !== -1}
          <div class="flex flex-col gap-4 p-4 bg-white dark:bg-gray-800/50 rounded-xl border border-gray-200 dark:border-gray-700 shadow-sm animate-in fade-in slide-in-from-top-2 duration-200">
            <div class="flex flex-wrap items-center gap-3">
              <!-- Color Picker Input -->
              <div class="relative shrink-0 w-9 h-9 rounded-lg overflow-hidden border border-gray-300 dark:border-gray-600 shadow-sm">
                <input type="color" bind:value={storage.value.stops[activeIndex].color} class="absolute -top-2 -left-2 w-14 h-14 cursor-pointer" />
              </div>

              <!-- Hex Text Input -->
              <div class="relative flex-1 min-w-[210px] h-9 shrink-0">
                <div class="absolute inset-y-0 left-0 pl-2.5 flex items-center pointer-events-none">
                  <Hash class="w-3.5 h-3.5 text-gray-400" />
                </div>
                <input 
                  type="text" 
                  value={storage.value.stops[activeIndex].color.replace(/^#/, '')}
                  oninput={(e) => {
                    let val = e.currentTarget.value.replace(/^#/, '').trim();
                    storage.value.stops[activeIndex].color = '#' + val;
                  }}
                  class="w-full h-full pl-7 pr-8 text-sm uppercase font-mono bg-white dark:bg-gray-900 border border-gray-300 dark:border-gray-600 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all"
                  maxlength="7"
                  spellcheck="false"
                />
                <button 
                  onclick={() => copyText(storage.value.stops[activeIndex].color)}
                  class="absolute inset-y-0 right-0 pr-2.5 flex items-center text-gray-400 hover:text-gray-600 dark:hover:text-gray-200 transition-colors"
                  title={i18n.t('ui.tooltips.copy.hex')}
                >
                  <Copy class="w-3.5 h-3.5" />
                </button>
              </div>

              <!-- RGBA Interactive Group -->
              <div class="flex items-center flex-1 min-w-[210px] h-9 rounded-lg border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-900 shadow-sm shrink-0 overflow-hidden focus-within:ring-2 focus-within:ring-blue-500 focus-within:border-blue-500 transition-all">
                <div class="px-2 h-full bg-gray-50 dark:bg-gray-800 border-r border-gray-200 dark:border-gray-700 flex items-center justify-center">
                  <span class="text-[10px] font-bold text-gray-400 dark:text-gray-500 uppercase tracking-wider">RGBA</span>
                </div>
                
                <input 
                  type="number" min="0" max="255"
                  value={getRgb(storage.value.stops[activeIndex].color).r}
                  oninput={(e) => updateRgb('r', parseInt(e.currentTarget.value))}
                  class="flex-1 w-0 h-full px-0.5 text-[11px] sm:text-xs font-mono text-center bg-transparent border-r border-gray-200 dark:border-gray-700 outline-none appearance-none hover:bg-gray-50 dark:hover:bg-gray-800/50"
                  title={i18n.t('ui.colors.red')}
                />
                
                <input 
                  type="number" min="0" max="255"
                  value={getRgb(storage.value.stops[activeIndex].color).g}
                  oninput={(e) => updateRgb('g', parseInt(e.currentTarget.value))}
                  class="flex-1 w-0 h-full px-0.5 text-[11px] sm:text-xs font-mono text-center bg-transparent border-r border-gray-200 dark:border-gray-700 outline-none appearance-none hover:bg-gray-50 dark:hover:bg-gray-800/50"
                  title={i18n.t('ui.colors.green')}
                />

                <input 
                  type="number" min="0" max="255"
                  value={getRgb(storage.value.stops[activeIndex].color).b}
                  oninput={(e) => updateRgb('b', parseInt(e.currentTarget.value))}
                  class="flex-1 w-0 h-full px-0.5 text-[11px] sm:text-xs font-mono text-center bg-transparent border-r border-gray-200 dark:border-gray-700 outline-none appearance-none hover:bg-gray-50 dark:hover:bg-gray-800/50"
                  title={i18n.t('ui.colors.blue')}
                />

                <input 
                  type="number" min="0" max="100"
                  bind:value={storage.value.stops[activeIndex].opacity}
                  class="flex-1 w-0 h-full px-0.5 text-[11px] sm:text-xs font-mono text-center bg-transparent border-r border-gray-200 dark:border-gray-700 outline-none appearance-none hover:bg-gray-50 dark:hover:bg-gray-800/50"
                  title={i18n.t('ui.colors.alpha')}
                />
                
                <button 
                  onclick={() => copyText(hexToRgbaStr(storage.value.stops[activeIndex].color, storage.value.stops[activeIndex].opacity))}
                  class="w-8 h-full flex items-center justify-center text-gray-400 hover:text-gray-600 dark:hover:text-gray-200 bg-gray-50 dark:bg-gray-800 transition-colors shrink-0"
                  title={i18n.t('ui.tooltips.copy.rgba')}
                >
                  <Copy class="w-3.5 h-3.5" />
                </button>
              </div>

              <!-- Position Input -->
              <div class="relative w-20 h-9 shrink-0">
                 <input 
                  type="number" 
                  bind:value={storage.value.stops[activeIndex].position} 
                  min="0" max="100"
                  class="w-full h-full pr-6 pl-3 text-sm font-mono bg-white dark:bg-gray-900 border border-gray-300 dark:border-gray-600 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all text-right appearance-none"
                />
                <div class="absolute inset-y-0 right-0 pr-2.5 flex items-center pointer-events-none">
                  <span class="text-sm font-medium text-gray-400">%</span>
                </div>
              </div>

              <!-- Delete Button -->
              <button 
                onclick={() => removeStop(activeId)} 
                disabled={storage.value.stops.length <= 2}
                class="w-9 h-9 flex items-center justify-center text-gray-400 hover:text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-lg disabled:opacity-30 disabled:hover:text-gray-400 disabled:hover:bg-transparent transition-all shrink-0 border border-transparent disabled:border-transparent hover:border-red-100 dark:hover:border-red-800"
                title={i18n.t('ui.tooltips.color.delete')}
              >
                <Trash2 class="w-4 h-4" />
              </button>
            </div>
            
            <!-- Opacity Slider Row -->
            <div class="flex items-center gap-3">
              <span class="text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider w-16">{i18n.t('common.form.opacity')}</span>
              <div class="relative flex-1 h-2 rounded-lg bg-[repeating-conic-gradient(#e5e7eb_0%_25%,_#fff_0%_50%)] bg-[length:12px_12px] dark:bg-[repeating-conic-gradient(#374151_0%_25%,_#1f2937_0%_50%)] border border-gray-300 dark:border-gray-600">
                 <input type="range" min="0" max="100" bind:value={storage.value.stops[activeIndex].opacity} class="absolute inset-0 w-full h-full opacity-0 cursor-pointer" />
                 <!-- Fake track to show color filling up -->
                 <div class="absolute inset-0 rounded-lg pointer-events-none" style="background: linear-gradient(90deg, rgba(255,255,255,0), {storage.value.stops[activeIndex].color}); opacity: {storage.value.stops[activeIndex].opacity / 100};"></div>
                 <!-- Fake Thumb -->
                 <div class="absolute top-1/2 -translate-y-1/2 w-3 h-3 rounded-full bg-white border border-gray-400 shadow-sm pointer-events-none" style="left: calc({storage.value.stops[activeIndex].opacity}% - 6px);"></div>
              </div>
            </div>
          </div>
        {/if}
      </div>

      <!-- 2. Settings Section (Angle) -->
      {#if storage.value.type === 'linear'}
        <div class="flex items-center gap-6 bg-white dark:bg-gray-800/50 p-4 rounded-xl border border-gray-200 dark:border-gray-700 shadow-sm">
          <!-- Dial -->
          <div class="shrink-0 flex flex-col items-center gap-2">
            <label class="text-xs font-medium text-gray-500 dark:text-gray-400">{i18n.t('common.form.angle')}</label>
            <div 
              class="w-14 h-14 rounded-full border-2 border-gray-300 dark:border-gray-600 bg-gray-50 dark:bg-gray-900 shadow-inner relative cursor-pointer touch-none"
              bind:this={dialEl}
              onpointerdown={handleDialPointerDown}
              onpointermove={handleDialPointerMove}
              onpointerup={handleDialPointerUp}
              onpointercancel={handleDialPointerUp}
            >
              <!-- Center dot -->
              <div class="absolute inset-0 m-auto w-1.5 h-1.5 rounded-full bg-gray-400 dark:bg-gray-500 shadow-sm pointer-events-none"></div>
              <!-- Indicator line & dot -->
              <div 
                class="absolute top-1/2 left-1/2 w-0.5 h-1/2 origin-top -translate-x-1/2 pointer-events-none"
                style="transform: rotate({storage.value.angle + 180}deg);"
              >
                <div class="w-3 h-3 rounded-full bg-blue-500 absolute bottom-0 -translate-x-1/2 left-1/2 shadow-sm border border-white dark:border-gray-800"></div>
              </div>
            </div>
          </div>

          <!-- Dial Value Input -->
          <div class="flex-1 flex flex-col gap-2">
            <div class="flex items-center gap-2">
              <input 
                type="number" 
                bind:value={storage.value.angle} 
                min="0" max="360"
                class="w-20 px-3 py-2 text-sm font-mono bg-white dark:bg-gray-900 border border-gray-300 dark:border-gray-600 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all text-right"
              />
              <span class="text-sm font-medium text-gray-500 dark:text-gray-400">deg</span>
            </div>
            <p class="text-[11px] text-gray-400 dark:text-gray-500 leading-tight">Drag the dial or enter a specific angle in degrees (0-360) to rotate the gradient.</p>
          </div>
        </div>
      {/if}

    </div>
  {/snippet}

  {#snippet rightPanel()}
    <div class="flex flex-col h-full bg-slate-100/50 dark:bg-slate-950/50">
      <div class="flex items-center justify-between px-4 py-2 bg-gray-50 dark:bg-gray-900/50 border-b border-gray-200 dark:border-gray-800 h-11 shrink-0">
        <span class="flex items-center gap-1.5 text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider">
          <MonitorPlay class="w-3.5 h-3.5" /> {i18n.t('common.action.preview')}
        </span>
      </div>

      <div class="flex-1 p-4 flex flex-col gap-4 min-h-0 bg-gray-100/50 dark:bg-[#121212]">
        <!-- Checkerboard background pattern for transparency preview -->
        <div class="flex-1 rounded-2xl shadow-sm border border-gray-200 dark:border-gray-800 overflow-hidden relative bg-[repeating-conic-gradient(#e5e7eb_0%_25%,_#fff_0%_50%)] bg-[length:16px_16px] dark:bg-[repeating-conic-gradient(#1f2937_0%_25%,_#111827_0%_50%)]">
          <div class="absolute inset-0 transition-all duration-300 ease-out" style="background: {gradientCss};"></div>
        </div>
        
        <div class="h-52 shrink-0 flex flex-col bg-white dark:bg-gray-900 border border-gray-200 dark:border-gray-800 rounded-xl overflow-hidden shadow-sm">
          <div class="flex items-center justify-between px-3 py-2 bg-gray-50 dark:bg-gray-800/50 border-b border-gray-200 dark:border-gray-800">
            <div class="flex items-center gap-4">
              <span class="text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider">{i18n.t('tools.gradientGenerator.cssCode')}</span>
              <label class="flex items-center gap-1.5 cursor-pointer group">
                <input type="checkbox" bind:checked={storage.value.maxCompatibility} class="w-3.5 h-3.5 text-blue-600 rounded border-gray-300 focus:ring-blue-500 cursor-pointer" />
                <span class="text-[11px] font-medium text-gray-500 group-hover:text-gray-700 dark:text-gray-400 dark:group-hover:text-gray-300 transition-colors">{i18n.t('tools.gradientGenerator.maxCompatibility')}</span>
              </label>
            </div>
            <button onclick={() => copyText(fullCssCode)} class="flex items-center gap-1.5 px-2 py-1 text-xs font-medium text-gray-600 dark:text-gray-300 hover:text-blue-600 dark:hover:text-blue-400 bg-white dark:bg-gray-800 rounded-md border border-gray-200 dark:border-gray-700 shadow-sm transition-all" title={i18n.t('common.action.copy')}>
              <Copy class="w-3.5 h-3.5" /> {i18n.t('common.action.copy')}
            </button>
          </div>
          <textarea
            value={fullCssCode}
            readonly
            class="flex-1 w-full p-3 resize-none bg-transparent text-gray-800 dark:text-gray-200 font-mono text-xs leading-relaxed outline-none focus:outline-none custom-scrollbar"
            spellcheck="false"
          ></textarea>
        </div>
      </div>
    </div>
  {/snippet}
</SplitWorkspace>
